    // ===== FEE TIER SYSTEM =====
    // ── Fee tiers ──────────────────────────────────────────────────────
    // Standard : 5%   (covers Stripe 2.9% + platform cut) — flat for all tiers
    // Admin    : 0%   (always free)
    function getFeeRate() {
      if (!currentUser) return 0.05;
      if (currentUser.is_admin) return 0;
      if (currentUser.referred_by && currentUser.referral_discount_used === false) return 0; // first-trade referral reward
      return 0.05;
    }
    function calcFee(amount) {
      return Math.round(amount * getFeeRate());
    }
    // ── Subscription tier system ──────────────────────────────────────────────
    // Tiers (in order): 'free' | 'collector' | 'enthusiast' | 'vendor' | 'shop'
    //
    // The old 'vendor' tier ($25/mo) was renamed to 'enthusiast' (now
    // $10/mo as of 2026-06-05) and gained a 40-listing/mo marketplace cap.
    // A NEW 'vendor' tier ($50/mo) sits between enthusiast and shop —
    // adds 150-listing cap, non-TCG product listing, and product scanner
    // access. Shop is the top tier ($150/mo, unlimited).
    //
    // Migration: existing rows with subscription_tier='vendor' are renamed
    // to 'enthusiast' via migration_tier_rename_vendor_to_enthusiast.sql.
    // Legacy boolean fallback (is_vendor) now maps to 'enthusiast' too.
    //
    // Reads subscription_tier from profile; falls back to legacy flags for existing users.
    const TIER_ORDER = ['free', 'collector', 'enthusiast', 'vendor', 'shop'];
    const TIER_COLORS = {
      free:        { label: 'FREE'         },
      collector:   { label: 'COLLECTOR'    },
      enthusiast:  { label: 'ENTHUSIAST'   },
      vendor:      { label: 'VENDOR'       },
      shop:        { label: 'SHOP'         },
    };
    // Concurrent active marketplace listings per tier.
    // 0 = no marketplace selling. Infinity = no cap.
    const TIER_LISTING_CAPS = {
      free:        0,
      collector:   0,
      enthusiast:  40,
      vendor:      150,
      shop:        Infinity,
    };
    // Maximum per-item dollar price by tier. Defense-in-depth: enforced
    // BOTH at listing creation (reject over-ceiling new listings) AND
    // at checkout server-side (so an over-ceiling listing that somehow
    // exists can never actually be purchased). Shop's high ceiling is
    // a feature gate, not a payment gate — sellers don't unlock it by
    // upgrading; they unlock it by passing identity + inventory checks
    // (profiles.verified_high_value flag).
    //
    // SERVER-SIDE MIRROR: TIER_PRICE_CEILINGS in /api/marketplace-checkout.js.
    const TIER_PRICE_CEILINGS = {
      free:        0,
      collector:   0,
      enthusiast:  150,    // entry tier — keeps cheap items in the cheap-flow band
      vendor:      1000,   // mid tier — covers most sealed product and most graded singles
      shop:        50000,  // high tier — additionally requires verified_high_value=true
    };
    function priceCeilingFor(tier, verifiedHighValue) {
      var base = TIER_PRICE_CEILINGS[tier];
      if (typeof base !== 'number') return 0;
      // Without the verified flag, Shop falls back to Vendor's ceiling.
      // The Top-tier high ceiling is gated by verification, not payment.
      if (tier === 'shop' && !verifiedHighValue) return TIER_PRICE_CEILINGS.vendor;
      return base;
    }
    function myPriceCeiling() {
      return priceCeilingFor(userTier(), !!(currentUser && currentUser.verified_high_value));
    }
    // Commission rate (decimal, 0.07 = 7%) charged on each marketplace
    // sale, by seller's tier. Decreases as tier climbs — rewards high-
    // volume sellers + creates a real reason for vendors to upgrade.
    // 0 for tiers that can't sell (free, collector).
    //
    // SERVER-SIDE MIRROR: same rates duplicated in /api/marketplace-
    // checkout.js so the platform fee is actually computed from the
    // seller's tier at charge time. If you change a rate here, change
    // it there too — there's no shared source of truth between
    // browser JS and Vercel serverless.
    const TIER_COMMISSION_RATES = {
      free:        0.00,
      collector:   0.00,
      enthusiast:  0.08,
      vendor:      0.07,
      shop:        0.06,
    };
    function commissionRateFor(tier) {
      return TIER_COMMISSION_RATES[tier] || 0;
    }
    // Buyer-side processing fee (dollars). Added as a separate line item
    // on the Stripe checkout page so the BUYER sees it explicitly — it
    // is NOT deducted from the seller's payout anymore. Surfaced only on
    // the checkout page; sellers don't see it in their fee preview.
    // Server mirror: BUYER_PROCESSING_FEE_CENTS in /api/marketplace-checkout.js.
    const BUYER_PROCESSING_FEE = 0.30;
    // Returns the commission rate for the CURRENT user. Convenience
    // for client-side fee-preview UI ("you'll receive $X after our Y% fee").
    function myCommissionRate() {
      return commissionRateFor(userTier());
    }

    function userTier() {
      if (!currentUser) return 'free';
      if (currentUser.subscription_tier && TIER_ORDER.includes(currentUser.subscription_tier))
        return currentUser.subscription_tier;
      // Legacy fallback. The old is_vendor flag now maps to enthusiast
      // (the tier that inherited the former vendor's feature set).
      if (currentUser.is_admin)   return 'shop';
      if (currentUser.is_vendor)  return 'enthusiast';
      if (currentUser.is_premium || currentUser.membershipActive) return 'collector';
      return 'free';
    }

    // ── Stripe Connect Express status (seller payouts) ──────────────────
    // Single source of truth for the cached Connect state. Populated by
    // refreshConnectStatus() which hits /api/connect-status and updates
    // this object. UI helpers read from here synchronously.
    let connectStatus = {
      loaded:           false,    // true once /api/connect-status returned at least once
      loading:          false,    // true while a fetch is in flight (prevents duplicates)
      accountId:        null,
      chargesEnabled:   false,
      payoutsEnabled:   false,
      detailsSubmitted: false,
      requirements:     null,
      payoutsToBank:    false,
      dashboardUrl:     null,
    };

    // Fetch + cache the seller's Connect status. Safe to call repeatedly;
    // de-duplicates in-flight requests. Invokes `onChange` when the cache
    // actually changes (used by renderMyListings to repaint).
    async function refreshConnectStatus(onChange) {
      if (!currentUser) return;
      if (!tierAtLeast('enthusiast')) return;       // non-sellers don't need it
      if (connectStatus.loading) return;
      connectStatus.loading = true;
      try {
        const sess = sb && sb.auth ? await sb.auth.getSession() : null;
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) { connectStatus.loading = false; return; }
        const r = await fetch('/api/connect-status', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
        });
        if (!r.ok) { connectStatus.loading = false; return; }
        const data = await r.json();
        // Diff against prior snapshot so we only repaint when something
        // meaningful changed (avoids render storms on every tab switch).
        const before = JSON.stringify({
          a: connectStatus.accountId,
          c: connectStatus.chargesEnabled,
          p: connectStatus.payoutsEnabled,
          d: connectStatus.detailsSubmitted,
        });
        connectStatus.loaded           = true;
        connectStatus.accountId        = data.accountId        || null;
        connectStatus.chargesEnabled   = !!data.chargesEnabled;
        connectStatus.payoutsEnabled   = !!data.payoutsEnabled;
        connectStatus.detailsSubmitted = !!data.detailsSubmitted;
        connectStatus.requirements     = data.requirements     || null;
        connectStatus.payoutsToBank    = !!data.payoutsToBank;
        connectStatus.dashboardUrl     = data.dashboardUrl     || null;
        const after = JSON.stringify({
          a: connectStatus.accountId,
          c: connectStatus.chargesEnabled,
          p: connectStatus.payoutsEnabled,
          d: connectStatus.detailsSubmitted,
        });
        if (before !== after && typeof onChange === 'function') onChange();
      } catch (e) {
        // Quiet failure — banner just stays in "checking…" state until the
        // next call. Logged for debugging only.
        console.warn('[connect-status] fetch failed:', e && e.message);
      } finally {
        connectStatus.loading = false;
      }
    }

    // Kicks off Express onboarding for the current seller. Posts to
    // /api/connect-onboard which creates (or reuses) the account and mints
    // a hosted-onboarding link, then redirects the browser there. Stripe
    // bounces back to returnUrl when done; we refresh status on return.
    async function startStripeConnectOnboarding() {
      if (!currentUser) { openModal('loginModal'); return; }
      if (!tierAtLeast('enthusiast')) {
        showToast('Enthusiast tier or higher required to receive payouts');
        return;
      }
      try {
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) { showToast('Sign in again to connect Stripe'); return; }
        showToast('Opening Stripe onboarding…');
        const origin = location.origin;
        const r = await fetch('/api/connect-onboard', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
          body:    JSON.stringify({
            returnUrl:  origin + '/?connect=success',
            refreshUrl: origin + '/?connect=refresh',
          }),
        });
        const data = await r.json();
        if (!r.ok || !data.url) {
          showToast(data.error || 'Could not start Stripe onboarding');
          return;
        }
        // Same-tab redirect — Stripe Express onboarding doesn't play well
        // inside a popup on mobile Safari.
        location.assign(data.url);
      } catch (e) {
        console.error('[connect-onboard] error:', e);
        showToast('Could not start Stripe onboarding');
      }
    }

    // Renders the seller's payout-status banner above My Listings. Pulls
    // from cached connectStatus — no async work here. Returns '' when the
    // user isn't a seller so renderMyListings can safely concatenate it.
    function renderConnectStatusBanner() {
      if (!currentUser) return '';
      if (!tierAtLeast('enthusiast')) return '';

      // While the very first fetch is in flight, show a quiet skeleton so
      // the banner doesn't pop in jarringly on the second render.
      if (!connectStatus.loaded) {
        return '<div style="padding:10px 14px;background:var(--surface2);border:1px solid var(--border);border-left:3px solid var(--muted);margin-bottom:12px;font-family:\'Space Mono\',monospace;font-size:.72rem;color:var(--muted)">'
             + 'Checking payout status&hellip;'
             + '</div>';
      }

      const cs   = connectStatus;
      // Three states the seller can be in:
      //   1. No account at all              → big "Connect Stripe" CTA
      //   2. Account exists but not finished → "Finish setup" CTA
      //   3. Charges + payouts enabled       → "Connected" pill + dashboard link
      // The disabled_reason / past_due / currently_due arrays drive the
      // remediation copy in state 2.
      const fullyReady = cs.chargesEnabled && cs.payoutsEnabled && cs.detailsSubmitted;

      if (!cs.accountId) {
        // State 1
        return ''
          + '<div style="padding:12px 16px;background:var(--surface2);border:1px solid var(--copper-dim);border-left:3px solid var(--copper);margin-bottom:12px;font-family:\'Space Mono\',monospace">'
          +   '<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap">'
          +     '<div>'
          +       '<div style="font-size:.78rem;color:var(--copper);font-weight:700;letter-spacing:.04em;margin-bottom:4px">CONNECT STRIPE TO RECEIVE PAYOUTS</div>'
          +       '<div style="font-size:.7rem;color:var(--muted);line-height:1.5">'
          +         'Sellers need a Stripe Express account so we can route sale proceeds to your bank. Until you connect, sales sit on the platform pending a manual payout.'
          +       '</div>'
          +     '</div>'
          +     '<button onclick="startStripeConnectOnboarding()" style="padding:9px 18px;background:var(--copper);color:var(--surface);border:none;font-family:\'Space Mono\',monospace;font-size:.75rem;font-weight:700;letter-spacing:.04em;cursor:pointer;white-space:nowrap">'
          +       'Connect Stripe &rarr;'
          +     '</button>'
          +   '</div>'
          + '</div>';
      }

      if (!fullyReady) {
        // State 2 — partial onboarding. Surface the requirements list so the
        // seller knows exactly what Stripe is waiting on.
        const req = cs.requirements || {};
        const due = [].concat(req.currently_due || [], req.past_due || []);
        const dueText = due.length
          ? ' Stripe still needs: ' + due.slice(0, 5).join(', ') + (due.length > 5 ? '&hellip;' : '')
          : '';
        const disabled = req.disabled_reason
          ? ' Status: ' + String(req.disabled_reason).replace(/_/g, ' ') + '.'
          : '';
        return ''
          + '<div style="padding:12px 16px;background:var(--surface2);border:1px solid var(--yellow);border-left:3px solid var(--yellow);margin-bottom:12px;font-family:\'Space Mono\',monospace">'
          +   '<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap">'
          +     '<div>'
          +       '<div style="font-size:.78rem;color:var(--yellow);font-weight:700;letter-spacing:.04em;margin-bottom:4px">⚠ STRIPE SETUP INCOMPLETE</div>'
          +       '<div style="font-size:.7rem;color:var(--muted);line-height:1.5">'
          +         'Your account exists but isn&rsquo;t cleared for payouts yet.' + disabled + dueText
          +       '</div>'
          +     '</div>'
          +     '<button onclick="startStripeConnectOnboarding()" style="padding:9px 18px;background:var(--yellow);color:var(--surface);border:none;font-family:\'Space Mono\',monospace;font-size:.75rem;font-weight:700;letter-spacing:.04em;cursor:pointer;white-space:nowrap">'
          +       'Finish Setup &rarr;'
          +     '</button>'
          +   '</div>'
          + '</div>';
      }

      // State 3 — fully onboarded.
      const dashBtn = cs.dashboardUrl
        ? '<a href="' + cs.dashboardUrl + '" target="_blank" rel="noopener" style="padding:7px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.7rem;font-weight:700;text-decoration:none;letter-spacing:.04em">Stripe Dashboard &rarr;</a>'
        : '';
      return ''
        + '<div style="padding:10px 14px;background:var(--surface2);border:1px solid var(--border);border-left:3px solid var(--green);margin-bottom:12px;display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;font-family:\'Space Mono\',monospace;font-size:.72rem;color:var(--muted)">'
        +   '<span><span style="color:var(--green);font-weight:700">✓ Stripe Connected</span> &middot; payouts going to your bank on Stripe&rsquo;s standard schedule</span>'
        +   dashBtn
        + '</div>';
    }

    // ── Account deletion (self-service, App Store-required) ────────────
    // Mirrors the connectStatus pattern — a cached flag the UI renders
    // synchronously, with refresh helpers that re-paint on change.
    // Source of truth lives on profiles.deletion_scheduled_for; we mirror
    // it on currentUser so renderDeletionPendingBanner() doesn't have to
    // round-trip every render.

    function isAccountDeletionPending() {
      if (!currentUser) return false;
      const ts = currentUser.deletion_scheduled_for;
      if (!ts) return false;
      // Defensive: if a stale record somehow has a past date, still treat
      // it as pending so the cancel button stays available.
      return true;
    }

    function deletionScheduledDateLabel() {
      if (!currentUser || !currentUser.deletion_scheduled_for) return '';
      try {
        return new Date(currentUser.deletion_scheduled_for).toLocaleDateString(undefined, {
          year: 'numeric', month: 'long', day: 'numeric',
        });
      } catch (_) { return ''; }
    }

    // The Account Settings modal body — currently just the deletion
    // section. Re-rendered on open + after every state change so the
    // copy stays in sync (pending vs. not pending).
    function renderAccountSettingsModal() {
      const body = document.getElementById('accountSettingsBody');
      if (!body) return;

      const pending = isAccountDeletionPending();
      const dateLbl = deletionScheduledDateLabel();

      // Email row (read-only; we don't yet support changing email).
      const emailRow = currentUser && currentUser.email
        ? '<div style="font-size:.72rem;color:var(--muted);margin-bottom:14px">'
        +   'Signed in as <span style="color:var(--text);font-family:\'Space Mono\',monospace">'
        +   currentUser.email + '</span>'
        + '</div>'
        : '';

      let deletionBlock;
      if (pending) {
        deletionBlock = ''
          + '<div style="border:1px solid rgba(255,60,60,.35);background:rgba(255,60,60,.06);padding:14px 16px;margin-top:8px">'
          +   '<div style="font-family:\'Orbitron\',monospace;font-size:.72rem;font-weight:800;letter-spacing:.1em;color:rgba(255,100,100,.9);margin-bottom:8px;text-transform:uppercase">'
          +     '⚠ Account Deletion Scheduled'
          +   '</div>'
          +   '<div style="font-size:.78rem;color:var(--muted);line-height:1.6;margin-bottom:14px">'
          +     'Your account is set to be permanently deleted on '
          +     '<strong style="color:var(--text)">' + (dateLbl || 'the scheduled date') + '</strong>. '
          +     'Sign in any time before then to cancel.'
          +   '</div>'
          +   '<button type="button" onclick="cancelAccountDeletion()" '
          +     'style="width:100%;padding:11px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.85rem;font-weight:700;cursor:pointer">'
          +     'Cancel Deletion &rarr;'
          +   '</button>'
          + '</div>';
      } else {
        deletionBlock = ''
          + '<div style="border:1px solid rgba(255,60,60,.35);background:rgba(255,60,60,.04);padding:14px 16px;margin-top:8px">'
          +   '<div style="font-family:\'Orbitron\',monospace;font-size:.72rem;font-weight:800;letter-spacing:.1em;color:rgba(255,100,100,.9);margin-bottom:8px;text-transform:uppercase">'
          +     '⚠ Delete Account'
          +   '</div>'
          +   '<div style="font-size:.72rem;color:var(--muted);line-height:1.6;margin-bottom:12px">'
          +     'Permanently delete your PathBinder account and all personal data. '
          +     'You&rsquo;ll have a 30-day grace period to change your mind.'
          +   '</div>'
          +   '<button type="button" onclick="openDeleteAccountModal()" '
          +     'style="width:100%;padding:11px;border:1px solid var(--red);background:transparent;color:var(--red);font-family:\'Space Mono\',monospace;font-size:.85rem;font-weight:700;cursor:pointer">'
          +     'Delete My Account'
          +   '</button>'
          + '</div>';
      }

      // Dashboard preferences — small toggles for visibility prefs that
      // live in localStorage (per-browser). Future: migrate these to
      // profiles columns so they sync across devices.
      const discordHidden = (() => {
        try { return localStorage.getItem('pb_hide_discord_panel') === '1'; }
        catch (_) { return false; }
      })();
      const uncOn = (() => {
        try { return localStorage.getItem('pb_unc_mode') === '1'; }
        catch (_) { return false; }
      })();
      // Shop tier (and Vendor — anyone with active listings) can pause
      // their shop. Read the current pause-until timestamp off the
      // profile so the input pre-fills with the active value.
      const canPauseShop = currentUser && (
        currentUser.subscription_tier === 'shop' ||
        currentUser.subscription_tier === 'vendor'
      );
      const pauseUntilRaw = currentUser && currentUser.vacation_mode_until;
      const pauseActive   = pauseUntilRaw && new Date(pauseUntilRaw) > new Date();
      // Format yyyy-mm-dd for the date input.
      const pauseInputValue = pauseActive
        ? new Date(pauseUntilRaw).toISOString().slice(0, 10)
        : '';
      const maxPauseDate = new Date(Date.now() + 14 * 86400000).toISOString().slice(0, 10);
      const minPauseDate = new Date(Date.now() + 86400000).toISOString().slice(0, 10);
      const prefsBlock = ''
        + '<div style="border:1px solid var(--border);background:var(--surface2);padding:14px 16px;margin-top:14px">'
        +   '<div style="font-family:\'Orbitron\',monospace;font-size:.72rem;font-weight:800;letter-spacing:.1em;color:var(--accent);margin-bottom:10px;text-transform:uppercase">'
        +     '◇ Dashboard preferences'
        +   '</div>'
        +   '<label style="display:flex;align-items:center;gap:8px;font-size:.78rem;color:var(--text);cursor:pointer">'
        +     '<input type="checkbox" id="settingShowDiscordPanel" ' + (discordHidden ? '' : 'checked') + ' onchange="_toggleDiscordPanelVisibility(this.checked)"'
        +     ' style="cursor:pointer">'
        +     '<span>Show Discord card on dashboard</span>'
        +   '</label>'
        +   '<div style="font-size:.66rem;color:var(--muted);margin-top:6px;padding-left:22px;margin-bottom:14px">'
        +     'Turn off to hide the Discord link/status card. Stored in this browser only.'
        +   '</div>'
        +   '<label style="display:flex;align-items:center;gap:8px;font-size:.78rem;color:var(--text);cursor:pointer">'
        +     '<input type="checkbox" id="settingUncMode" ' + (uncOn ? 'checked' : '') + ' onchange="_toggleUncMode(this.checked)"'
        +     ' style="cursor:pointer">'
        +     '<span>Unc Mode (larger text)</span>'
        +   '</label>'
        +   '<div style="font-size:.66rem;color:var(--muted);margin-top:6px;padding-left:22px">'
        +     'Bumps text 25% bigger sitewide. For when your eyes need a break. Stored in this browser only.'
        +   '</div>'
        + '</div>';

      // Shop pause / vacation mode — vendor+ only. Listings hidden
      // from browse + checkout blocked server-side until the picked
      // date. Capped at 14 days out (max two weeks per spec).
      let shopBlock = '';
      if (canPauseShop) {
        shopBlock = ''
          + '<div style="border:1px solid var(--copper-dim);background:rgba(184,115,51,.04);padding:14px 16px;margin-top:14px">'
          +   '<div style="font-family:\'Orbitron\',monospace;font-size:.72rem;font-weight:800;letter-spacing:.1em;color:var(--copper);margin-bottom:10px;text-transform:uppercase">'
          +     '◇ Shop pause' + (pauseActive ? ' — ACTIVE' : '')
          +   '</div>'
          +   '<div style="font-size:.72rem;color:var(--text);margin-bottom:10px;line-height:1.5">'
          +     (pauseActive
                  ? 'Your shop is paused until <strong>' + _fmtDate(pauseUntilRaw) + '</strong>. Listings are hidden from browse and checkout is blocked. Clear the date to resume immediately.'
                  : 'Hide your listings from the marketplace + block purchases until the date you pick. Max 14 days out.')
          +   '</div>'
          +   '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">'
          +     '<input type="date" id="settingShopPauseDate" value="' + pauseInputValue + '" min="' + minPauseDate + '" max="' + maxPauseDate + '"'
          +     ' style="padding:8px 10px;background:var(--surface);border:1px solid var(--border);color:var(--text);font-family:\'Space Mono\',monospace;font-size:.78rem">'
          +     '<button type="button" onclick="_saveShopPause()"'
          +     ' style="padding:8px 14px;border:1px solid var(--copper);background:transparent;color:var(--copper);font-family:\'Space Mono\',monospace;font-size:.75rem;font-weight:700;cursor:pointer">Save</button>'
          +     (pauseActive
                  ? '<button type="button" onclick="_clearShopPause()"'
                  +   ' style="padding:8px 14px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:\'Space Mono\',monospace;font-size:.75rem;cursor:pointer">Resume now</button>'
                  : '')
          +   '</div>'
          + '</div>';
      }

      // Social entry points — Follows list + Messages inbox. The DM
      // badge surfaces the live unread count.
      const unreadBadge = window._dmUnreadCount > 0
        ? '<span data-dm-badge style="background:var(--accent);color:var(--text-on-accent);font-size:.6rem;font-weight:800;padding:2px 7px;border-radius:var(--r-pill,999px);margin-left:6px">'
            + (window._dmUnreadCount > 9 ? '9+' : window._dmUnreadCount) + '</span>'
        : '';
      const followsBlock = ''
        + '<div style="border:1px solid var(--border);background:var(--surface2);padding:14px 16px;margin-top:14px">'
        +   '<div style="font-family:\'Orbitron\',monospace;font-size:.72rem;font-weight:800;letter-spacing:.1em;color:var(--accent);margin-bottom:8px;text-transform:uppercase">'
        +     '◇ Social'
        +   '</div>'
        +   '<div style="display:flex;gap:8px;flex-wrap:wrap">'
        +     '<button type="button" onclick="closeModal(\'accountSettingsModal\');openMyFollowsModal()"'
        +       ' style="padding:8px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.75rem;font-weight:700;cursor:pointer;letter-spacing:.04em">Manage follows →</button>'
        +     '<button type="button" onclick="closeModal(\'accountSettingsModal\');openInboxModal()"'
        +       ' style="padding:8px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.75rem;font-weight:700;cursor:pointer;letter-spacing:.04em">Messages →' + unreadBadge + '</button>'
        +   '</div>'
        + '</div>';

      body.innerHTML = emailRow + prefsBlock + shopBlock + followsBlock + deletionBlock;
    }

    async function _saveShopPause() {
      const el = document.getElementById('settingShopPauseDate');
      const val = el && el.value;
      if (!val) { showToast('Pick a date first'); return; }
      const d = new Date(val + 'T23:59:59');
      if (isNaN(d) || d < new Date()) { showToast('Pick a future date'); return; }
      const cap = new Date(Date.now() + 14 * 86400000 + 86400000);
      if (d > cap) { showToast('Max 14 days out'); return; }
      const upd = await sb.from('profiles')
        .update({ vacation_mode_until: d.toISOString() })
        .eq('id', currentUser.id);
      if (upd.error) { showToast('Save failed: ' + upd.error.message); return; }
      currentUser.vacation_mode_until = d.toISOString();
      showToast('Shop paused until ' + _fmtDate(d));
      renderAccountSettingsModal();
    }
    async function _clearShopPause() {
      const upd = await sb.from('profiles')
        .update({ vacation_mode_until: null })
        .eq('id', currentUser.id);
      if (upd.error) { showToast('Failed: ' + upd.error.message); return; }
      currentUser.vacation_mode_until = null;
      showToast('Shop resumed');
      renderAccountSettingsModal();
    }

    // Toggle Discord-panel visibility from Account Settings. Writes the
    // same localStorage flag the dashboard render reads, then re-renders
    // the dashboard so the change reflects immediately if the user
    // navigates back. Pairs with _hideDiscordPanel (× button on the
    // panel itself) — both touch the same flag, both refresh the same UI.
    function _toggleDiscordPanelVisibility(show) {
      try {
        if (show) localStorage.removeItem('pb_hide_discord_panel');
        else      localStorage.setItem('pb_hide_discord_panel', '1');
      } catch (_) {}
      if (typeof _renderDiscordConnect === 'function') {
        try { _renderDiscordConnect(); } catch (_) {}
      }
    }

    // Unc Mode — bumps the root font-size from 16px to 20px (1.25×) so
    // every rem-based font scales up. Applied via a class on <html> so
    // CSS doesn't need to know about an explicit toggle.
    function _toggleUncMode(on) {
      try {
        if (on) localStorage.setItem('pb_unc_mode', '1');
        else    localStorage.removeItem('pb_unc_mode');
      } catch (_) {}
      _pbApplyUncMode(on);
    }
    function _pbApplyUncMode(on) {
      document.documentElement.classList.toggle('pb-unc-mode', !!on);
    }
    // Apply on load so the setting persists across page navigations.
    try {
      if (localStorage.getItem('pb_unc_mode') === '1') {
        _pbApplyUncMode(true);
      }
    } catch (_) {}

    function openAccountSettingsModal() {
      if (!currentUser) { openModal('loginModal'); return; }
      renderAccountSettingsModal();
      openModal('accountSettingsModal');
    }

    function openDeleteAccountModal() {
      closeModal('accountSettingsModal');
      const inp = document.getElementById('deleteConfirmInput');
      const btn = document.getElementById('deleteConfirmBtn');
      const sts = document.getElementById('deleteAccountStatus');
      if (inp) inp.value = '';
      if (btn) { btn.disabled = true; btn.style.opacity = '.5'; btn.textContent = 'Delete My Account'; }
      if (sts) { sts.textContent = ''; sts.style.color = 'var(--muted)'; }
      openModal('deleteAccountModal');
    }

    async function confirmAccountDeletion() {
      const btn = document.getElementById('deleteConfirmBtn');
      const sts = document.getElementById('deleteAccountStatus');
      const inp = document.getElementById('deleteConfirmInput');
      if (!btn || !sts) return;
      if (inp && inp.value.trim().toUpperCase() !== 'DELETE') {
        sts.textContent = 'Type DELETE to confirm.';
        sts.style.color = 'var(--red)';
        return;
      }
      btn.disabled = true;
      btn.style.opacity = '.5';
      btn.textContent = 'Deleting…';
      sts.textContent = '';
      try {
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) throw new Error('Not signed in');
        const r = await fetch('/api/delete-account', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
          body:    JSON.stringify({ action: 'request' }),
        });
        const data = await r.json();
        if (!r.ok || !data.ok) throw new Error(data.error || 'Server rejected the request');

        // Mirror onto currentUser so the banner + modal flip without
        // having to re-fetch the profile.
        if (currentUser) {
          currentUser.deletion_requested_at  = new Date().toISOString();
          currentUser.deletion_scheduled_for = data.scheduledFor || null;
        }
        sts.textContent = 'Account scheduled for deletion.';
        sts.style.color = 'var(--green)';
        showToast('Account scheduled for deletion. Sign in within 30 days to cancel.');
        setTimeout(function() {
          closeModal('deleteAccountModal');
          renderAccountSettingsModal();
          renderDeletionPendingBanner();
          // Also drop their active listings out of the local cache so the
          // My Listings view reflects reality.
          if (Array.isArray(listings)) {
            listings.forEach(function(l) {
              if ((l.seller_id === currentUser.id || l.sellerId === currentUser.id)
                  && (l.status === 'active' || l.status === 'available')) {
                l.status = 'deactivated';
              }
            });
            if (typeof renderMyListings === 'function') renderMyListings();
          }
        }, 900);
      } catch (e) {
        console.error('[delete-account] error:', e);
        sts.textContent = e.message || 'Could not delete account. Please try again.';
        sts.style.color = 'var(--red)';
        btn.disabled = false;
        btn.style.opacity = '1';
        btn.textContent = 'Delete My Account';
      }
    }

    async function cancelAccountDeletion() {
      if (!currentUser) return;
      try {
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) { showToast('Sign in again to cancel deletion'); return; }
        showToast('Cancelling deletion…');
        const r = await fetch('/api/delete-account', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
          body:    JSON.stringify({ action: 'cancel' }),
        });
        const data = await r.json();
        if (!r.ok || !data.ok) throw new Error(data.error || 'Cancel failed');
        if (currentUser) {
          currentUser.deletion_requested_at  = null;
          currentUser.deletion_scheduled_for = null;
        }
        showToast('Deletion cancelled. Welcome back.');
        renderAccountSettingsModal();
        renderDeletionPendingBanner();
      } catch (e) {
        console.error('[cancel-deletion] error:', e);
        showToast(e.message || 'Could not cancel deletion');
      }
    }

    // Site-wide banner shown above the nav when an account deletion is
    // pending. Single source of truth: isAccountDeletionPending(). Mounted
    // into #deletionPendingBanner (created on demand at the top of <body>).
    function renderDeletionPendingBanner() {
      let host = document.getElementById('deletionPendingBanner');
      if (!isAccountDeletionPending()) {
        if (host) host.remove();
        return;
      }
      if (!host) {
        host = document.createElement('div');
        host.id = 'deletionPendingBanner';
        host.style.cssText = 'position:sticky;top:0;left:0;right:0;z-index:9000;'
          + 'background:rgba(255,60,60,.95);color:#fff;padding:8px 14px;'
          + 'font-family:\'Space Mono\',monospace;font-size:.72rem;'
          + 'text-align:center;letter-spacing:.04em;'
          + 'border-bottom:1px solid rgba(0,0,0,.2)';
        document.body.insertBefore(host, document.body.firstChild);
      }
      const dateLbl = deletionScheduledDateLabel();
      host.innerHTML = ''
        + '⚠ Your account is scheduled for deletion'
        + (dateLbl ? ' on <strong>' + dateLbl + '</strong>' : '')
        + '. <button type="button" onclick="cancelAccountDeletion()" '
        +   'style="background:#fff;color:rgba(255,60,60,.95);border:none;padding:3px 10px;'
        +   'margin-left:8px;font-family:\'Space Mono\',monospace;font-size:.7rem;'
        +   'font-weight:700;cursor:pointer">Cancel Deletion</button>';
    }

    // If the user just returned from Stripe Express onboarding, refresh
    // status immediately so the banner flips to "Connected" without a
    // hard reload. Triggered via the ?connect=success query param set as
    // the return_url in /api/connect-onboard.
    function _handleConnectReturnQuery() {
      try {
        const q = new URLSearchParams(location.search);
        const flag = q.get('connect');
        if (!flag) return;
        // Clean the query off the URL so re-renders don't keep re-firing.
        q.delete('connect');
        const newSearch = q.toString();
        const newUrl = location.pathname + (newSearch ? '?' + newSearch : '') + location.hash;
        history.replaceState(null, '', newUrl);
        if (flag === 'success') {
          showToast('Refreshing Stripe Connect status…');
        } else if (flag === 'refresh') {
          // refresh_url is what Stripe redirects to when the onboarding link
          // expires. Kick off a fresh one transparently.
          startStripeConnectOnboarding();
          return;
        }
        // Defer until currentUser is hydrated; refreshConnectStatus is a
        // no-op when not signed in, so a small delay is enough.
        setTimeout(function() {
          refreshConnectStatus(function() {
            if (typeof renderMyListings === 'function') renderMyListings();
          });
        }, 800);
      } catch (_) { /* no-op */ }
    }
    // Run once on script load.
    _handleConnectReturnQuery();
    function tierAtLeast(tier) {
      return TIER_ORDER.indexOf(userTier()) >= TIER_ORDER.indexOf(tier);
    }

    // Feature gate helpers
    function canAddMoreCards() {
      if (tierAtLeast('collector')) return true;
      const owned = collectionItems.filter(c => !c.sold_offline && !c.is_ghost).length;
      return owned < 200;
    }
    function remainingCardSlots() {
      if (tierAtLeast('collector')) return Infinity;
      const owned = collectionItems.filter(c => !c.sold_offline && !c.is_ghost).length;
      return Math.max(0, 200 - owned);
    }
    function canAddGhostCard() {
      if (tierAtLeast('collector')) return true;
      return collectionItems.filter(c => c.is_ghost && !c.sold_offline).length < 2;
    }
    function canAddCardFund() {
      const funds = collectionItems.filter(c => c.is_ghost && c.savings_goal > 0 && !c.sold_offline).length;
      // Unlimited card funds for enthusiast and up (was 'vendor' pre-rename).
      if (tierAtLeast('enthusiast')) return true;
      if (tierAtLeast('collector'))  return funds < 3;
      return funds < 1;
    }
    // Price tracking is FREE for everyone — a collector binder isn't
    // useful if the values don't update, and we'd rather give it away
    // and earn upgrades on the marketplace / multi-binder / scanner
    // features. Kept as a function (instead of inlining `true`) so any
    // callsite that wants to re-gate it later can do so in one place.
    function hasPriceTracking()  { return true; }
    // Pre-rename, bulk import was the headline 'vendor' feature. It now lives
    // at the enthusiast tier — same features at a lower price, plus the cap.
    function hasBulkImport()     { return tierAtLeast('enthusiast'); }
    // Non-TCG product listings + product scanner access — exclusive to the
    // new vendor tier and above.
    function hasProductScanner() { return tierAtLeast('vendor'); }
    function canListNonTCG()     { return tierAtLeast('vendor'); }
    // Sealed TCG product (booster boxes, ETBs, tins, decks) restricted to
    // vendor+ as well. Enthusiast tier is singles-only. Sealed is higher
    // AOV + slower turnover, so keeping it behind the vendor paywall both
    // matches the "serious seller" framing of vendor and prevents low-tier
    // dumping of bulk product.
    function canListSealed()     { return tierAtLeast('vendor'); }
    function hasMultiBinder()    { return !!currentUser; }

    // ── Marketplace listing cap helpers ─────────────────────────────────
    // Counts the user's current ACTIVE listings (concurrent) so the
    // listing-creation UI can enforce per-tier caps. A sold listing
    // doesn't count against the cap; only active/available ones do.
    function activeListingCount() {
      if (!currentUser) return 0;
      if (!Array.isArray(listings)) return 0;
      return listings.filter(function(l) {
        var mine = (l.seller_id === currentUser.id) || (l.sellerId === currentUser.id);
        if (!mine) return false;
        var status = (l.status || '').toLowerCase();
        // Active = available / active. Sold / cancelled / completed don't count.
        return status === 'active' || status === 'available' || status === '';
      }).length;
    }
    function listingCap()           { return TIER_LISTING_CAPS[userTier()] || 0; }
    function listingsRemaining()    {
      var cap = listingCap();
      if (cap === Infinity) return Infinity;
      return Math.max(0, cap - activeListingCount());
    }
    function canCreateListing()     {
      var cap = listingCap();
      if (cap === Infinity) return true;
      if (cap === 0)        return false;
      return activeListingCount() < cap;
    }

    // ── Monthly usage tracking (localStorage, per-user per-month) ────────────
    function _usageKey(prefix) {
      var now = new Date();
      return 'pb_' + prefix + '_' + (currentUser ? currentUser.id : 'guest')
           + '_' + now.getFullYear() + '-' + (now.getMonth() + 1);
    }
    function getUsageCount(prefix) {
      try { return parseInt(localStorage.getItem(_usageKey(prefix)) || '0', 10); } catch(_) { return 0; }
    }
    function incrementUsage(prefix) {
      try { localStorage.setItem(_usageKey(prefix), String(getUsageCount(prefix) + 1)); } catch(_) {}
    }

    // ── Per-tier limits ──────────────────────────────────────────────────────
    function scannerLimit() {
      if (tierAtLeast('shop'))      return Infinity;   // unlimited
      if (tierAtLeast('collector')) return 1000;       // vendor inherits this too
      return 25;                                       // free — bumped from 5 to 25/month
    }
    function bulkSessionLimit() {
      if (tierAtLeast('shop'))       return Infinity;
      // Bulk-import sessions were the OLD vendor headline feature; that
      // tier got renamed to enthusiast (same features, lower price + cap).
      if (tierAtLeast('enthusiast')) return 1000;
      if (tierAtLeast('collector'))  return 5;
      return 0;  // free: bulk scan not available
    }
    function bulkCardsPerSession() {
      if (tierAtLeast('enthusiast')) return Infinity;
      if (tierAtLeast('collector'))  return 35;
      return 0;
    }

    // ── Upgrade prompt with 25 % first-month discount ────────────────────────
    var _limitPromoTier = null;   // set before opening pricing modal at a limit wall

    function openPricingModalWithPromo(targetTier) {
      _limitPromoTier = targetTier;
      openPricingModal(targetTier);
    }
    function getMaxBinders()    {
      if (!currentUser) return 0;
      const t = currentUser.subscription_tier || 'free';
      return t === 'free' ? 4 : Infinity;
    }

    // Admins are automatically treated as premium (no subscription needed)
    function userIsPremium() {
      return !!(currentUser && (currentUser.is_admin || currentUser.is_premium || currentUser.membershipActive));
    }

    function userIsVendor() {
      return !!(currentUser && (currentUser.is_admin || currentUser.is_vendor));
    }

    // Slots are populated from Supabase in initApp() — no demo data needed

    // ===== AUTH =====
    function openModal(modalId) {
      document.getElementById(modalId).classList.add('open');
      // Side-effect hooks for specific modals — kept here so every
      // openModal call site doesn't have to remember to fire them.
      if (modalId === 'addToCollectionModal' && typeof _atcRefreshVariantChips === 'function') {
        // Fire async; modal is already visible so the chip row appearing
        // a frame later reads as a natural progressive enhancement.
        _atcRefreshVariantChips();
      }
    }

    // Global click-outside-to-close for any .modal-overlay. Bound once
    // at script init so newly-created modals don't have to wire their
    // own backdrop handlers. Also handles the Add Card overlay
    // (different mechanism but same UX expectation).
    (function _wireBackdropDismiss() {
      if (window._backdropDismissWired) return;
      window._backdropDismissWired = true;
      document.addEventListener('click', function(e) {
        // Only fire when the click TARGET is the overlay itself, not
        // any child content. That's the standard modal-backdrop
        // pattern: clicking inside the modal content shouldn't close it.
        if (e.target && e.target.classList && e.target.classList.contains('modal-overlay')) {
          const id = e.target.id;
          if (id && typeof closeModal === 'function') {
            try { closeModal(id); } catch (_) { e.target.classList.remove('open'); }
          } else {
            e.target.classList.remove('open');
          }
        }
        // Add Card overlay — body class gates it, click on backdrop
        // (which is body::before, not directly clickable) falls
        // through to body. So instead: catch clicks on body while
        // overlay is open AND outside #addCardPage content.
        if (document.body.classList.contains('pb-addcard-overlay')) {
          const page = document.getElementById('addCardPage');
          if (page && !page.contains(e.target) && !e.target.closest('.pb-addcard-overlay-close')) {
            // Also ignore clicks bubbling from popovers / scanner / nested modals
            // that may have opened on top. Cheapest check: only close when the
            // target is body or html.
            if (e.target === document.body || e.target === document.documentElement) {
              if (typeof closeAddCardOverlay === 'function') closeAddCardOverlay();
            }
          }
        }
      }, true); // capture phase so it runs before stopPropagation handlers
      // Esc closes the topmost open modal.
      document.addEventListener('keydown', function(e) {
        if (e.key !== 'Escape') return;
        const open = document.querySelectorAll('.modal-overlay.open');
        if (open.length) {
          const last = open[open.length - 1];
          if (last.id && typeof closeModal === 'function') {
            try { closeModal(last.id); } catch(_) { last.classList.remove('open'); }
          } else {
            last.classList.remove('open');
          }
        }
      });
    })();
    // Convenience wrapper for landing page CTA buttons
    function openAuthModal(tab) {
      if (tab === 'signup') {
        openModal('registerModal');
      } else {
        openModal('loginModal');
      }
    }

    function setTopNavActive(pageId) {
      document.querySelectorAll('.top-nav-tab').forEach(t => t.classList.remove('active'));
      const tab = document.getElementById('topNavTab' + pageId.charAt(0).toUpperCase() + pageId.slice(1));
      if (tab) tab.classList.add('active');
    }
    function closeModal(modalId) {
      document.getElementById(modalId).classList.remove('open');
      // Reset edit mode whenever the add/edit modal is dismissed
      if (modalId === 'addToCollectionModal') {
        _atcEditMode = false; _atcEditItemId = null;
        const h3e = document.querySelector('#addToCollectionModal h3');
        if (h3e) h3e.textContent = 'Add to My Binder';
        const sBtnE = document.querySelector('#addToCollectionModal button[onclick="saveToCollection()"]');
        if (sBtnE && !sBtnE.disabled) { sBtnE.textContent = 'Add to My Binder'; }
      }
      // If scanner was hidden to show this modal, bring it back
      if (_returnToScanner && (modalId === 'addToCollectionModal' || modalId === 'addToWishlistModal')) {
        _returnToScanner = false;
        const scanModal = document.getElementById('scannerModal');
        if (scanModal) scanModal.style.display = 'flex';
      }
    }
    function switchModal(from, to) {
      closeModal(from);
      openModal(to);
    }
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') {
        document.querySelectorAll('.modal-overlay.open').forEach(m => {
          m.classList.remove('open');
        });
        if (document.querySelector('.lightbox.open')) closeLightbox();
      }
    });
    document.querySelectorAll('.modal-overlay').forEach(overlay => {
      overlay.addEventListener('click', (e) => {
        if (e.target === overlay) overlay.classList.remove('open');
      });
    });

    async function handleLogin() {
      const email = document.getElementById('loginEmail').value.trim();
      const password = document.getElementById('loginPassword').value;
      const errorEl = document.getElementById('loginError');
      errorEl.textContent = '';

      if (!email || !password) {
        errorEl.textContent = 'Please enter your email and password.';
        return;
      }

      // Close modal before the async call so timing can never leave it open
      freshSignIn = true;
      closeModal('loginModal');
      showToast('Signing in...');

      const { data: authData, error } = await sb.auth.signInWithPassword({ email, password }).catch(e => ({ data: null, error: e }));

      if (error || !authData?.user) {
        // Re-open modal and show error if auth failed
        openModal('loginModal');
        errorEl.textContent = error?.message || 'Sign in failed. Please try again.';
        freshSignIn = false;
        return;
      }

      // Block sign-in for accounts that already finished the 30-day grace
      // and got purged. The auth row still exists in Supabase auth.users
      // (we don't delete it during the purge — that breaks RLS for the
      // counterparty's orders) but the profile row is_deleted = true.
      // ALSO blocks banned accounts (is_banned = true) so a ToS violator
      // can't sign back in until an admin clears the flag.
      try {
        const { data: prof } = await sb
          .from('profiles')
          .select('is_deleted, is_banned')
          .eq('id', authData.user.id)
          .maybeSingle();
        if (prof && prof.is_deleted) {
          await sb.auth.signOut().catch(() => {});
          openModal('loginModal');
          errorEl.textContent = 'This account has been deleted.';
          freshSignIn = false;
          return;
        }
        if (prof && prof.is_banned) {
          await sb.auth.signOut().catch(() => {});
          openModal('loginModal');
          errorEl.textContent = 'This account has been suspended. Contact support if you believe this is in error.';
          freshSignIn = false;
          return;
        }
      } catch (_) {
        // Lookup failed — proceed with sign-in rather than locking the
        // user out over a transient error. Restore-session path will
        // re-check.
      }

      // Update UI immediately — onAuthStateChange (SIGNED_IN) will re-fetch
      // listings, profile data, and re-render once the full data is ready
      currentUser = { ...authData.user };
      updateAuthUI();
      showPage('account'); setMobileNav('account');
      showToast('Welcome back!');
    }

    // ── Password reset flow ────────────────────────────────────────────
    // Two-stage:
    //   1. User clicks "Forgot password?" → requestPasswordReset() fires
    //      Supabase's resetPasswordForEmail. They get an email with a
    //      one-click recovery link pointing back to pathbinder.gg/?type=recovery.
    //   2. checkPasswordRecoveryHash() runs on page load — if the URL
    //      hash contains a recovery access_token, the supabase-js client
    //      auto-authenticates the user and we open the new-password modal.
    //      User picks a new password, submitNewPassword() persists it.
    //
    // Supabase handles the actual email send via its built-in SMTP (the
    // default sender is noreply@mail.app.supabase.io). To rebrand the
    // sender to @pathbinder.gg, configure Resend as the SMTP server in
    // Supabase Dashboard → Auth → SMTP Settings.
    async function requestPasswordReset() {
      const email   = (document.getElementById('forgotPasswordEmail').value || '').trim();
      const status  = document.getElementById('forgotPasswordStatus');
      if (!email || !email.includes('@')) {
        if (status) { status.textContent = 'Enter the email on your account.'; status.style.color = 'var(--red)'; }
        return;
      }
      if (status) { status.textContent = 'Sending…'; status.style.color = 'var(--muted)'; }
      // redirectTo lands on the live site with the recovery token in
      // the URL hash; checkPasswordRecoveryHash() picks it up there.
      const origin = location.origin;
      const { error } = await sb.auth.resetPasswordForEmail(email, {
        redirectTo: origin + '/?type=recovery',
      });
      if (error) {
        console.error('[reset] error:', error);
        if (status) { status.textContent = 'Could not send: ' + (error.message || 'try again'); status.style.color = 'var(--red)'; }
        return;
      }
      // Supabase always responds OK even if the email doesn't exist —
      // to avoid leaking which addresses have accounts. So we always
      // show the same generic confirmation here.
      if (status) {
        status.innerHTML = '<span style="color:var(--accent)">✓</span> If that email has an account, a reset link is on the way. Check your inbox + spam folder.';
        status.style.color = 'var(--muted)';
      }
      // Clear the input so a successful flow doesn't leave it filled.
      const inp = document.getElementById('forgotPasswordEmail');
      if (inp) inp.value = '';
    }

    async function submitNewPassword() {
      const pw1    = document.getElementById('newPasswordInput').value;
      const pw2    = document.getElementById('newPasswordConfirm').value;
      const status = document.getElementById('newPasswordStatus');
      if (!pw1 || pw1.length < 8) {
        if (status) { status.textContent = 'Password must be at least 8 characters.'; status.style.color = 'var(--red)'; }
        return;
      }
      if (pw1 !== pw2) {
        if (status) { status.textContent = 'Passwords don\'t match.'; status.style.color = 'var(--red)'; }
        return;
      }
      if (status) { status.textContent = 'Saving…'; status.style.color = 'var(--muted)'; }
      const { error } = await sb.auth.updateUser({ password: pw1 });
      if (error) {
        if (status) { status.textContent = 'Save failed: ' + (error.message || 'try again'); status.style.color = 'var(--red)'; }
        return;
      }
      if (status) {
        status.innerHTML = '<span style="color:var(--accent)">✓</span> Password updated. Redirecting…';
        status.style.color = 'var(--muted)';
      }
      // Clear fields + close modal after a beat so the success state
      // is visible. The user is now signed in (Supabase auto-auths them
      // via the recovery token) so we just bounce them to their dashboard.
      setTimeout(function () {
        closeModal('newPasswordModal');
        try { showPage('account'); setMobileNav && setMobileNav('account'); } catch(_) {}
      }, 900);
    }

    // Run on page load. Supabase puts the recovery access_token in the
    // URL hash and the supabase-js client auto-establishes a session.
    // We just detect the recovery type and open the new-password modal.
    function checkPasswordRecoveryHash() {
      try {
        // Recovery flow uses ?type=recovery on the query OR #type=recovery
        // in the hash — Supabase varies by version. Check both.
        const search = location.search || '';
        const hash   = location.hash   || '';
        const isRecovery =
          /\btype=recovery\b/.test(search) ||
          /\btype=recovery\b/.test(hash)   ||
          /\baccess_token=[^&]+&.*?\btype=recovery\b/.test(hash);
        if (!isRecovery) return;
        // Open the modal once the page has hydrated enough for it to
        // be findable. supabase-js fires the SIGNED_IN event by then.
        setTimeout(function () {
          openModal('newPasswordModal');
          // Strip the recovery params off the URL so a refresh doesn't
          // re-trigger the modal after the user already set their pw.
          try {
            const cleaned = location.pathname;
            history.replaceState(null, '', cleaned);
          } catch (_) {}
        }, 600);
      } catch (_) { /* no-op */ }
    }
    // Kick it off on script load.
    checkPasswordRecoveryHash();

    async function handleRegister(e) {
      e.preventDefault();
      const name = document.getElementById('regName').value;
      const email = document.getElementById('regEmail').value;
      const username = document.getElementById('regUsername').value;
      const password = document.getElementById('regPassword').value;
      const confirm = document.getElementById('regConfirm').value;
      const referralCode = document.getElementById('regReferralCode')?.value || '';

      const errorEl = document.getElementById('registerError');
      errorEl.textContent = '';

      if (password !== confirm) {
        errorEl.textContent = 'Passwords do not match';
        return;
      }

      try {
        const { data, error } = await sb.auth.signUp({
          email, password,
          options: { data: { name, username } }
        });
        if (error) {
          errorEl.textContent = error.message || 'Registration failed';
          return;
        }

        if (referralCode) {
          const { data: referrer } = await sb.from('profiles').select('id').eq('referral_code', referralCode).single().catch(() => ({ data: null }));
          if (referrer && data.user) {
            await sb.from('profiles').update({ referred_by: referralCode, referral_discount_used: false }).eq('id', data.user.id).catch(err => console.error('Referral link error:', err));
          }
        }

        showToast('Account created! Check your email to confirm.');
        freshSignIn = true;
        closeModal('registerModal');
        showPage('account'); setMobileNav('account');
      } catch (err) {
        console.error('Register error:', err);
        errorEl.textContent = 'An error occurred. Please try again.';
      }
    }

