    document.getElementById('signOutBtn').addEventListener('click', () => {
      currentUser = null;
      cart = [];
      tradeOffers = [];
      listings = [];
      slots = [];
      collectionItems = [];
      // Reset the syncUserDataFromCloud cache key so the NEXT user
      // signing in on this tab triggers a fresh sync (otherwise we'd
      // skip the cloud-data hydration for the new account).
      try { _syncDoneFor = null; } catch(_) {}
      // Same reasoning for the collection/orders/binders/snapshots
      // bulk loader and the profile+listings hydration — next user
      // gets fresh data, no stale "already loaded" short-circuits.
      try { _userDataLoadedFor = null; } catch(_) {}
      try { _initialUserDataLoaded = false; } catch(_) {}
      try { _profileListingsHydratedFor = null; } catch(_) {}
      updateCartBar();
      // Wipe personal localStorage so the next user signing in on this
      // device doesn't inherit the previous user's avatar / badges.
      // These keys are NOT namespaced by user id (legacy design), so
      // the only safe move at sign-out is to remove them entirely.
      // Server-side they're persisted on the profiles row and get
      // re-fetched + re-cached by syncUserDataFromCloud after the next
      // sign-in, so nothing is lost — just isolated per session.
      try { localStorage.removeItem('pathbinder_avatar_pfp_v1'); } catch(_) {}
      try { localStorage.removeItem('pathbinder_avatar_v2'); } catch(_) {}
      try { localStorage.removeItem('pathbinder_badges_v1'); } catch(_) {}
      // Reset the visible avatar chips so the old PFP doesn't linger
      // in the UI between the click and the page refresh.
      ['avatarInitials','mobileUserChip','sidebarAvatarImg'].forEach(id => {
        const el = document.getElementById(id);
        if (!el) return;
        if (el.tagName === 'IMG') el.removeAttribute('src');
      });
      updateAuthUI();
      // Clear personal data from badge dropdown so it doesn't persist
      const ddBg = document.getElementById('ddBadgeGrid');
      if (ddBg) ddBg.innerHTML = '';
      document.getElementById('avatarDropdown').classList.remove('open');
      showPage('landing'); setMobileNav('');
      showToast('Signed out');
      sb.auth.signOut().catch(err => console.error('Logout error:', err));
    });
