    function _getBadges() {
      try { return JSON.parse(localStorage.getItem(_BADGE_KEY) || '[]'); } catch { return []; }
    }
    function _hasBadge(id) { return _getBadges().includes(id); }
    function _awardBadge(id) {
      if (_hasBadge(id)) return false;
      const badges = _getBadges();
      badges.push(id);
      localStorage.setItem(_BADGE_KEY, JSON.stringify(badges));
      _showBadgeUnlock(id);
      // Sound cue on unlock. _awardBadge is the single chokepoint for
      // every badge unlock and the _hasBadge() guard above ensures it
      // only runs once per badge. Multi-step badges (e.g. PHANTOM)
      // are naturally gated: their p1 helper just toggles a localStorage
      // flag and never calls _awardBadge, so no sound fires on partial
      // progress — only when p2 completes the unlock.
      try { _pbPlayScratch(); } catch(_) {}
      try { syncUserDataToCloud(); } catch(_) {}
      // Refresh badge grid if open
      const grid = document.getElementById('badgesGrid');
      if (grid && grid.innerHTML !== '') renderBadges();
      return true;
    }
    function _showBadgeUnlock(id) {
      const def = BADGE_DEFS.find(b => b.id === id);
      if (!def) return;
      const existing = document.getElementById('_badgeUnlockToast');
      if (existing) existing.remove();
      const toast = document.createElement('div');
      toast.id = '_badgeUnlockToast';
      toast.className = 'badge-unlock-toast';
      const displayName = def.hidden ? '[DATA EXPUNGED]' : def.name;
      toast.innerHTML = `
        <div class="but-icon">${def.svg}</div>
        <div class="but-text">
          <div class="but-label">★ BADGE UNLOCKED</div>
          <div class="but-name">${displayName}</div>
        </div>`;
      document.body.appendChild(toast);
      setTimeout(() => {
        toast.style.transition = 'opacity .4s';
        toast.style.opacity = '0';
        setTimeout(() => toast.remove(), 450);
      }, 3500);
    }

    // ── Badge check functions ────────────────────────────────────────
    function checkBadge_stacked() {
      if (_hasBadge('stacked')) return;
      const owned = collectionItems.filter(c => !c.is_ghost && !c.sold_offline).length;
      if (owned >= 50) _awardBadge('stacked');
    }
    function checkBadge_phantom_p1() {
      localStorage.setItem(_GHOST_P1_KEY, '1');
      // update badge tile if visible
      const grid = document.getElementById('badgesGrid');
      if (grid && grid.innerHTML !== '') renderBadges();
    }
    function checkBadge_phantom_p2() {
      if (!_hasBadge('phantom') && localStorage.getItem(_GHOST_P1_KEY) === '1') {
        _awardBadge('phantom');
      }
    }
    function checkBadge_linked()   { if (!_hasBadge('linked'))   _awardBadge('linked');   }
    function checkBadge_init()     { if (!_hasBadge('init'))     _awardBadge('init');     }
    function checkBadge_archived() { if (!_hasBadge('archived')) _awardBadge('archived'); }
    function checkBadge_rendered() { if (!_hasBadge('rendered')) _awardBadge('rendered'); }
    // Debounce slot for scan-counter cloud syncs. Without this, a burst of
    // 20 scans would fire 20 cloud writes. With it, multiple scans within
    // 4 seconds collapse to a single PATCH that captures the final total.
    let _scanSyncTimer = null;
    function checkBadge_scanner() {
      const key = _scanKey();
      let total = parseInt(localStorage.getItem(key) || '0', 10) + 1;
      localStorage.setItem(key, String(total));
      if (!_hasBadge('scanner') && total >= 50) _awardBadge('scanner');
      // Debounced cloud sync. Previously this counter only synced to
      // profiles.scan_total when a badge was awarded — meaning users who
      // never crossed the 50-scan threshold had their counts wiped on
      // every fresh-browser login. Sync after every scan (debounced) so
      // the cloud copy stays close to local truth.
      if (typeof syncUserDataToCloud === 'function' && typeof currentUser !== 'undefined' && currentUser) {
        if (_scanSyncTimer) clearTimeout(_scanSyncTimer);
        _scanSyncTimer = setTimeout(function() {
          try { syncUserDataToCloud(); } catch(_) {}
        }, 4000);
      }
    }
    function unlockDiscordBadge(e) {
      e.preventDefault();
      checkBadge_signal_discord();
      setTimeout(() => { window.open('https://discord.gg/JEwDTxWs4', '_blank', 'noopener'); }, 600);
    }
    function checkBadge_signal_discord() { if (!_hasBadge('signal')) _awardBadge('signal'); }

    // ── Badge renderer ───────────────────────────────────────────────
    function renderBadges() {
      const grid = document.getElementById('badgesGrid');
      if (!grid) return;
      let earned = [], ghostP1Done = false;
      try { earned = JSON.parse(localStorage.getItem(_BADGE_KEY) || '[]'); } catch(e) {}
      try { ghostP1Done = localStorage.getItem(_GHOST_P1_KEY) === '1'; } catch(e) {}

      try {
        grid.innerHTML = BADGE_DEFS.map(def => {
          const isEarned  = earned.includes(def.id);
          const isHidden  = !!(def.hidden && !isEarned);
          const isPartial = def.id === 'phantom' && !isEarned && ghostP1Done;

          // Progress bar for multi-part badges OR badges with a progressFn
          let progressHtml = '';
          if (def.maxPart > 1) {
            const done  = isEarned ? def.maxPart : (isPartial ? 1 : 0);
            const pct   = Math.round((done / def.maxPart) * 100);
            progressHtml = `<div style="width:100%;background:#111;height:6px;border:1px solid #222;margin-top:-2px">
              <div style="height:100%;width:${pct}%;background:#1AC7A0;transition:width .4s"></div>
            </div>
            <div style="font-size:.55rem;color:${pct===100?'#1AC7A0':'#555'};font-family:'Press Start 2P',monospace;letter-spacing:.05em">${done}/${def.maxPart}</div>`;
          } else if (def.progressFn && !isHidden) {
            try {
              const prog = def.progressFn();
              const pct  = Math.round(Math.min(prog.current / prog.max, 1) * 100);
              progressHtml = `<div style="width:100%;background:#111;height:6px;border:1px solid #222;margin-top:-2px">
                <div style="height:100%;width:${pct}%;background:#1AC7A0;transition:width .4s"></div>
              </div>
              <div style="font-size:.55rem;color:${pct>=100?'#1AC7A0':'#555'};font-family:'Press Start 2P',monospace;letter-spacing:.05em">${prog.current}/${prog.max}</div>`;
            } catch(e) {}
          }

          const hintHtml = def.hint && isEarned
            ? `<div style="font-size:.5rem;color:#FF5722;text-align:center;font-family:'Press Start 2P',monospace;margin-top:2px">${def.hint}</div>` : '';

          // SVG display: full color when earned, gradually revealed when
          // not. For badges with a progressFn (stacked, scanner), the
          // SVG fades from locked baseline (22% opacity, full grayscale,
          // dim) to fully colored as progress accumulates. Without this
          // every locked badge looked identical, which is why STACKED
          // appeared "complete" before actually being complete — the
          // dim+gray state masked the difference between 0/50 and 49/50.
          let svgStyle = '';
          if (!isEarned) {
            let opacity = 0.22;
            let gray = 1;
            let bright = 0.5;
            if (def.progressFn) {
              try {
                const p = def.progressFn();
                const ratio = Math.max(0, Math.min(1, p.current / p.max));
                opacity = 0.22 + (ratio * 0.78);  // 0.22 → 1.00
                gray    = 1 - ratio;              // 1 → 0
                bright  = 0.5 + (ratio * 0.5);    // 0.5 → 1.0
              } catch(e) {}
            }
            svgStyle = `style="opacity:${opacity.toFixed(2)};filter:grayscale(${gray.toFixed(2)}) brightness(${bright.toFixed(2)})"`;
          }

          const displayName = isHidden ? '???' : def.name;
          const displayDesc = isHidden
            ? '<span style="letter-spacing:.06em">keep exploring...</span>'
            : def.desc;

          return `<div class="badge-tile${isEarned?' earned':''}${isPartial?' partial':''}">
            <div class="badge-hex" ${svgStyle}>${def.svg}</div>
            <div class="badge-name" style="color:${isEarned?'#1AC7A0':isPartial?'#888':'#444'}">${displayName}</div>
            ${progressHtml}
            <div class="badge-desc" style="color:${isEarned?'var(--muted)':'#333'}">${displayDesc}</div>
            ${hintHtml}
          </div>`;
        }).join('');
      } catch(err) {
        grid.innerHTML = '<div style="color:var(--muted);padding:20px;font-size:.8rem">Could not render badges: ' + (err && err.message || err) + '</div>';
        console.error('[PathBinder] renderBadges error:', err);
      }
    }

    // ─── Mini badge grid in dropdown ────────────────────────────────
    function renderDdBadges() {
      const grid = document.getElementById('ddBadgeGrid');
      if (!grid || typeof BADGE_DEFS === 'undefined') return;
      let earned = [];
      try { earned = JSON.parse(localStorage.getItem(_BADGE_KEY) || '[]'); } catch(e) {}
      grid.innerHTML = BADGE_DEFS.map(def => {
        const isEarned = earned.includes(def.id);
        const isHidden = !!(def.hidden && !isEarned);
        const nameClass = isEarned ? 'dd-bname earned' : 'dd-bname';
        const displayName = isHidden ? '???' : def.name;
        // Match the full-grid behavior: gradual opacity reveal as a
        // progressFn-driven badge accumulates progress. Inline style
        // overrides the .dd-locked CSS class's hardcoded opacity.
        let hexInlineStyle = '';
        if (!isEarned) {
          let opacity = 0.22, gray = 1, bright = 0.5;
          if (def.progressFn) {
            try {
              const p = def.progressFn();
              const ratio = Math.max(0, Math.min(1, p.current / p.max));
              opacity = 0.22 + (ratio * 0.78);
              gray    = 1 - ratio;
              bright  = 0.5 + (ratio * 0.5);
            } catch(e) {}
          }
          hexInlineStyle = ` style="opacity:${opacity.toFixed(2)};filter:grayscale(${gray.toFixed(2)}) brightness(${bright.toFixed(2)})"`;
        }
        return `<div class="dd-badge-pip" title="${isHidden ? '???' : def.desc}" onclick="document.getElementById('avatarDropdown').classList.remove('open');showPage('account');setMobileNav('account');setTimeout(()=>switchAccountTab('badges'),120)">
          <div class="dd-hex"${hexInlineStyle}>${def.svg}</div>
          <div class="${nameClass}">${displayName}</div>
        </div>`;
      }).join('');
    }

    // ─── Check init badge on auth ────────────────────────────────────
    // (called after user signs in — if they just created account they get it)

    // ═══════════════════════════════════════════════════════════════
    // ===== ACCOUNT PAGE =====
    let activeOrdersTab = 'buying';

    async function renderTradeHistory() {
      const el = document.getElementById('tradeHistoryContent');
      if (!el) return;
      if (!currentUser) {
        el.innerHTML = '<div style="text-align:center;padding:40px;color:var(--muted)">Log in to view your trade history.</div>';
        return;
      }

      el.innerHTML = '<div style="text-align:center;padding:32px;color:var(--muted)">Loading…</div>';

      try {
        const { data: rows, error } = await sb
          .from('trade_history')
          .select('*')
          .eq('user_id', currentUser.id)
          .order('created_at', { ascending: false })
          .limit(50);

        if (error) throw error;

        if (!rows || !rows.length) {
          el.innerHTML = `<div style="text-align:center;padding:60px 20px;color:var(--muted)">
            <div style="font-size:2rem;margin-bottom:12px">[ TRADE ]</div>
            <div style="font-size:.9rem;margin-bottom:6px">No trades yet</div>
            <div style="font-size:.78rem">Use the Trade Analyzer and hit <strong>Accept Trade</strong> to log your trades here.</div>
          </div>`;
          return;
        }

        const cards = rows.map(r => {
          const date = _fmtDate(r.created_at);
          const offered  = Array.isArray(r.offered_cards)  ? r.offered_cards  : [];
          const received = Array.isArray(r.received_cards) ? r.received_cards : [];
          const offVal = r.offered_value  != null ? '$' + Number(r.offered_value).toFixed(2)  : '—';
          const recVal = r.received_value != null ? '$' + Number(r.received_value).toFixed(2) : '—';
          const verdict = r.verdict || '';
          const verdictColor = verdict.toLowerCase().includes('even') ? 'var(--muted)'
            : verdict.toLowerCase().includes('favor') && verdict.includes('A') ? 'var(--teal)'
            : verdict.toLowerCase().includes('favor') && verdict.includes('B') ? 'var(--gold)'
            : 'var(--accent2)';
          const partner = r.partner_name ? `<span style="color:var(--text)">${_escHtml(r.partner_name)}</span>` : '<span style="color:var(--muted)">Solo</span>';

          // Each card line is click-to-preview — looks up the catalog
          // by name and opens the existing movers detail modal (image
          // + current_value + add-to-wishlist). Hover affordance via
          // text-decoration: underline + accent color on hover so the
          // line clearly reads as a link.
          var _renderTradeCardLine = function(c, arrow) {
            var nameAttr = String(c.name || '').replace(/'/g, "\\'");
            var line = arrow + ' ' + _escHtml(c.name)
              + (c.qty > 1 ? ' ×' + c.qty : '')
              + (c.avg ? ' · $' + Number(c.avg).toFixed(2) : '');
            return '<div onclick="openTradeCardDetail(\'' + nameAttr + '\')"'
              + ' style="font-size:.7rem;color:var(--muted);cursor:pointer;padding:1px 0"'
              + ' onmouseover="this.style.color=\'var(--accent)\';this.style.textDecoration=\'underline\'"'
              + ' onmouseout="this.style.color=\'var(--muted)\';this.style.textDecoration=\'none\'"'
              + ' title="Click to see current price">' + line + '</div>';
          };
          const offerList = offered.length
            ? offered.map(c => _renderTradeCardLine(c, '↗')).join('')
            : '<div style="font-size:.7rem;color:var(--muted)">—</div>';
          const recvList = received.length
            ? received.map(c => _renderTradeCardLine(c, '↙')).join('')
            : '<div style="font-size:.7rem;color:var(--muted)">—</div>';

          return `<div style="padding:14px 16px;border-bottom:1px solid var(--border);background:var(--surface)">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px;flex-wrap:wrap;gap:4px">
              <div>
                <span style="font-size:.76rem;font-weight:700">${date}</span>
                <span style="font-size:.72rem;color:var(--muted);margin-left:10px">with ${partner}</span>
              </div>
              ${verdict ? `<span style="font-size:.67rem;font-weight:700;color:${verdictColor};border:1px solid ${verdictColor};padding:2px 8px;letter-spacing:.05em">${_escHtml(verdict)}</span>` : ''}
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
              <div>
                <div style="font-size:.63rem;font-weight:700;letter-spacing:.08em;color:var(--teal);margin-bottom:4px">YOU OFFERED · ${offVal}</div>
                ${offerList}
              </div>
              <div>
                <div style="font-size:.63rem;font-weight:700;letter-spacing:.08em;color:var(--gold);margin-bottom:4px">YOU RECEIVED · ${recVal}</div>
                ${recvList}
              </div>
            </div>
          </div>`;
        }).join('');

        el.innerHTML = `<div>
          <div style="font-size:.72rem;font-weight:700;letter-spacing:.1em;color:var(--muted);padding:10px 16px 8px">TRADE HISTORY (${rows.length})</div>
          <div style="border:1px solid var(--border)">${cards}</div>
        </div>`;
      } catch(e) {
        el.innerHTML = `<div style="text-align:center;padding:40px;color:var(--muted)">
          Could not load trade history.<br>
          <span style="font-size:.72rem">${e.message && e.message.includes('does not exist') ? 'Run the SQL migration to create the trade_history table first.' : _escHtml(e.message || '')}</span>
        </div>`;
      }
    }

    function renderAccount() {
      if (!currentUser) {
        // Show the account page with a sign-in prompt instead of silently
        // redirecting to Browse (which made the Dashboard nav button appear broken)
        const wrap = document.getElementById('dashboardContent');
        if (wrap) wrap.innerHTML = `
          <div style="text-align:center;padding:60px 20px">
            <div style="font-size:.8rem;color:var(--accent);letter-spacing:.1em;margin-bottom:12px">// DASHBOARD</div>
            <div style="color:var(--muted);font-size:.9rem;margin-bottom:24px">Sign in to view your dashboard, orders, and collection stats.</div>
            <button onclick="openModal('loginModal')"
              style="padding:11px 28px;border:none;background:var(--accent);color:var(--text-on-accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.88rem;font-weight:700;cursor:pointer;letter-spacing:.04em">
              Sign In →
            </button>
          </div>`;
        return;
      }
      renderDashboard();
      renderMyListings();
      renderOrders();
      renderHistory();
      renderWatchlist();
      updateOrderNotification();
      // Vendor+ users see an Inventory tab; everyone else has it hidden.
      try { _showInventoryTab(); } catch(_) {}
    }

    function switchAccountTab(tab) {
      document.querySelectorAll('.account-tab').forEach(t => t.classList.remove('active'));
      const tabEl = document.querySelector(`[onclick="switchAccountTab('${tab}')"]`);
      if (tabEl) tabEl.classList.add('active');
      document.querySelectorAll('.account-content').forEach(c => c.classList.remove('active'));
      const contentEl = document.getElementById(tab);
      if (contentEl) contentEl.classList.add('active');
      // Stamp the active tab onto the page so CSS can paint per-tab
      // background images (dashboard.webp for Dashboard, dash2.webp for
      // the transaction tabs). Rules live in the stylesheet keyed by
      // #accountPage[data-tab="..."] for the per-tab content layout +
      // body[data-page-bg="..."] for the artwork so the bg covers the
      // social footer + any below-content padding instead of stopping
      // at #accountPage's bottom edge.
      const accountPageEl = document.getElementById('accountPage');
      if (accountPageEl) accountPageEl.setAttribute('data-tab', tab);
      const BG_TABS = ['dashboard','myListings','myStore','myOrders','sales','salesArchive','payments','watchlist','purchases','history','tradeHistory','inventory','salesLog'];
      if (BG_TABS.indexOf(tab) >= 0) {
        document.body.setAttribute('data-page-bg', tab);
      } else {
        document.body.removeAttribute('data-page-bg');
      }
      if (tab === 'myOrders') renderOrders();
      if (tab === 'myListings') renderMyListings();
      if (tab === 'salesArchive') renderSalesArchive();  // legacy
      if (tab === 'payments') renderPayments();
      if (tab === 'tradeHistory') renderTradeHistory();
      if (tab === 'badges') renderBadges();
      // 'inventory' tab retired — view lives in #myStore now.
      if (tab === 'salesLog')  renderSalesLog();          // legacy
      // Unified Sales tab — consolidates the old Sales Log + Sales
      // Archive into one view with source-filter chips.
      if (tab === 'sales')     renderSales();
      // Renamed History → Purchases. Old #history div is hidden but
      // we keep the renderHistory() function and proxy to it.
      if (tab === 'purchases') renderPurchases();
      // My Store — lazy-loads pb-store.js the first time the tab is
      // activated. Stub at the bottom of pb-app.js handles the load.
      if (tab === 'myStore') {
        _ensureStore()
          .then(function() {
            if (typeof window.renderMyStore !== 'function') {
              const wrap = document.getElementById('myStoreContent');
              if (wrap) wrap.innerHTML = '<div style="padding:24px;color:var(--muted);font-size:.78rem;text-align:center">Store script loaded but no renderer — try a hard refresh.</div>';
              return;
            }
            return Promise.resolve(window.renderMyStore()).catch(function(err) {
              console.error('[store] renderMyStore rejected:', err);
              const wrap = document.getElementById('myStoreContent');
              if (wrap) {
                const msg = (err && err.message) ? err.message : String(err || 'unknown');
                wrap.innerHTML = '<div style="padding:24px;color:var(--red,#ef4444);font-size:.78rem;font-family:\'Space Mono\',monospace">'
                  + '<div style="font-weight:700;letter-spacing:.08em;margin-bottom:8px">⚠ Store failed to render</div>'
                  + '<div style="color:var(--muted);font-size:.7rem;word-break:break-word">' + (msg || '') + '</div>'
                  + '</div>';
              }
            });
          })
          .catch(function(err) {
            console.error('[store] _ensureStore failed:', err);
            const wrap = document.getElementById('myStoreContent');
            if (wrap) {
              wrap.innerHTML = '<div style="padding:24px;color:var(--red,#ef4444);font-size:.78rem;font-family:\'Space Mono\',monospace">'
                + '<div style="font-weight:700;letter-spacing:.08em;margin-bottom:8px">⚠ Couldn\'t load store module</div>'
                + '<div style="color:var(--muted);font-size:.7rem">Check your connection and refresh the page.</div>'
                + '<button onclick="location.reload()" class="pb-panel-link" style="margin-top:14px;border-color:var(--accent);color:var(--accent)">Refresh</button>'
                + '</div>';
            }
          });
      }
    }

    // ── Inventory tab (Vendor+) ──────────────────────────────────────
    // Shows the per-row split of TOTAL quantity into "on shelf"
    // (physical units in the shop) and "listed online" (units active
    // on PathBinder). Step 1 ships as read-only; Step 2 adds the
    // Mark-N-Sold modal + shop_sales writes; Step 3 adds POS scan.
    function _showInventoryTab() {
      // Name kept for backward compat — toggles ALL vendor-only
      // elements based on tier. The Inventory tab itself was
      // retired (merged into My Store) but other vendor-only
      // elements (My Store tab button, listing-cap pills, etc.)
      // still use the .js-vendor-only class.
      try {
        const visible = typeof tierAtLeast === 'function' && tierAtLeast('vendor');
        document.querySelectorAll('.js-vendor-only').forEach(function(el) {
          el.style.display = visible ? '' : 'none';
        });
      } catch(_) {}
    }

    // renderInventory + _invRowHtml retired — the inventory view lives
    // in /pb-store.js now (My Store tab). Only _invSummaryTile stays
    // because renderSales still uses it for its summary tiles row.
    function _invSummaryTile(label, value, color) {
      return ''
        + '<div style="padding:10px 12px;border:1px solid var(--border);background:var(--surface)">'
        +   '<div style="font-size:.58rem;color:var(--muted);letter-spacing:.08em">' + label + '</div>'
        +   '<div style="font-size:1rem;color:' + color + ';font-weight:700;font-family:\'Orbitron\',monospace;margin-top:4px">' + value + '</div>'
        + '</div>';
    }

    // ── Shop inventory bookkeeping (Step 4) ─────────────────────────
    // Shared helpers that move stock between on_shelf_qty and
    // listed_online_qty on the matching collection_items row as
    // marketplace activity happens. Called from the listing
    // create/cancel paths and the order ship path. Vendor+ tier
    // only — for everyone else the columns are dormant and these
    // helpers no-op.
    async function _invFindCollectionRow(userId, apiCardId, variant) {
      if (!userId || !apiCardId) return null;
      const v = variant || 'normal';
      const r = await sb.from('collection_items')
        .select('id, quantity, on_shelf_qty, listed_online_qty')
        .eq('user_id', userId)
        .eq('api_card_id', apiCardId)
        .eq('variant', v)
        .limit(1)
        .maybeSingle();
      if (r.error) { console.warn('[inv] lookup error:', r.error.message); return null; }
      return r.data || null;
    }

    // Listing created → move qty from on_shelf → listed_online.
    async function _invOnListingCreated(userId, apiCardId, variant, qty) {
      if (!apiCardId || !qty) return;
      const row = await _invFindCollectionRow(userId, apiCardId, variant);
      if (!row) return;
      const moved = Math.min(qty, row.on_shelf_qty || 0);
      if (moved <= 0) return;
      const r = await sb.from('collection_items')
        .update({
          on_shelf_qty:      Math.max(0, (row.on_shelf_qty || 0) - moved),
          listed_online_qty: (row.listed_online_qty || 0) + moved,
        })
        .eq('id', row.id);
      if (r.error) console.warn('[inv] move on-list error:', r.error.message);
    }

    // Listing cancelled / qty reduced → move qty from listed_online → on_shelf.
    async function _invOnListingReleased(userId, apiCardId, variant, qty) {
      if (!apiCardId || !qty) return;
      const row = await _invFindCollectionRow(userId, apiCardId, variant);
      if (!row) return;
      const released = Math.min(qty, row.listed_online_qty || 0);
      if (released <= 0) return;
      const r = await sb.from('collection_items')
        .update({
          on_shelf_qty:      (row.on_shelf_qty || 0) + released,
          listed_online_qty: Math.max(0, (row.listed_online_qty || 0) - released),
        })
        .eq('id', row.id);
      if (r.error) console.warn('[inv] release error:', r.error.message);
    }

    // Listing shipped → that unit is gone for good. Decrement
    // listed_online AND quantity (the inventory's source of truth).
    async function _invOnListingShipped(userId, apiCardId, variant, qty) {
      if (!apiCardId || !qty) return;
      const row = await _invFindCollectionRow(userId, apiCardId, variant);
      if (!row) return;
      const dropped = Math.min(qty, row.listed_online_qty || 0, row.quantity || 0);
      if (dropped <= 0) return;
      const r = await sb.from('collection_items')
        .update({
          listed_online_qty: Math.max(0, (row.listed_online_qty || 0) - dropped),
          quantity:          Math.max(0, (row.quantity || 0) - dropped),
        })
        .eq('id', row.id);
      if (r.error) console.warn('[inv] ship error:', r.error.message);
    }

    // ── Per-unit metadata (Vendor+) ─────────────────────────────────
    // When a collection_items row carries qty > 1, vendor+ users can
    // mark each physical card with its own condition, notes, and
    // photo via collection_item_units. Lazy: rows are created on
    // first edit. Free / Collector / Enthusiast tiers never touch
    // this table — the consolidated row model still holds for them.
    async function _loadUnitsForItem(itemId) {
      if (!itemId) return [];
      try {
        const r = await sb.from('collection_item_units')
          .select('*')
          .eq('collection_item_id', itemId)
          .order('ordinal', { ascending: true });
        if (r.error) {
          // Schema-missing fallback — let the caller treat it as
          // "no units" so opens don't blow up before the migration runs.
          if (/relation .* does not exist|collection_item_units|schema cache/i.test(r.error.message || '')) {
            return [];
          }
          console.warn('[units] load error:', r.error.message);
          return [];
        }
        return r.data || [];
      } catch (e) {
        console.warn('[units] load threw:', e && e.message);
        return [];
      }
    }

    // Creates N rows (ordinals 1..qty) for the given item if none
    // exist yet. Each row inherits NULL (= parent values). Returns
    // the loaded units array. Idempotent — safe to call repeatedly.
    async function _ensureUnitsForItem(item) {
      if (!item || !item.id) return [];
      const qty = item.quantity || 1;
      if (qty < 2) return [];
      const existing = await _loadUnitsForItem(item.id);
      if (existing.length >= qty) return existing;
      // Top up missing ordinals — handles "had 3 units, added 2 more
      // to qty, now need 5" without overwriting existing edits.
      const have = new Set(existing.map(function(u){ return u.ordinal; }));
      const toCreate = [];
      for (let i = 1; i <= qty; i++) {
        if (!have.has(i)) toCreate.push({ collection_item_id: item.id, ordinal: i, status: 'in_stock' });
      }
      if (toCreate.length === 0) return existing;
      try {
        const r = await sb.from('collection_item_units').insert(toCreate);
        if (r.error) console.warn('[units] insert error:', r.error.message);
      } catch (e) {
        console.warn('[units] insert threw:', e && e.message);
      }
      return _loadUnitsForItem(item.id);
    }

    async function _updateUnit(unitId, patch) {
      if (!unitId || !patch) return null;
      try {
        const r = await sb.from('collection_item_units')
          .update(patch)
          .eq('id', unitId)
          .select()
          .single();
        if (r.error) {
          console.warn('[units] update error:', r.error.message);
          return null;
        }
        return r.data;
      } catch (e) {
        console.warn('[units] update threw:', e && e.message);
        return null;
      }
    }

    // Resolve a unit's effective display values. Per-unit overrides
    // win; falls back to the parent collection_items row for any
    // NULL fields. The badge label uses the standard condition copy
    // (NM / LP / HP / PSA 10 etc.).
    function _resolveUnitDisplay(unit, parent) {
      const u = unit || {};
      const p = parent || {};
      const condition = u.condition || p.condition || 'NM';
      const grade     = (u.grade_value != null) ? u.grade_value : p.grade_value;
      const isGraded  = condition === 'graded' || (grade && grade > 0);
      const condLabel = isGraded
        ? ('Graded ' + (grade != null ? grade : ''))
        : String(condition || 'NM').toUpperCase();
      return {
        condition:      condition,
        grade_value:    grade,
        cert_number:    u.cert_number   != null ? u.cert_number   : p.cert_number,
        notes:          u.notes         != null ? u.notes         : p.notes,
        card_image_url: u.card_image_url || p.card_image_url || '',
        condLabel:      condLabel.trim(),
        isGraded:       isGraded,
      };
    }

    // ── Per-unit swipe stack (mount + render) ──────────────────────
    // Lives inside the binder detail modal for vendor+ users when
    // qty > 1. Replaces the single photo slot with a stacked deck.
    // State is per-modal-open (cached on window so the navigation
    // buttons + edit modal can read it back).
    let _binderUnitStackState = null;  // { itemId, units, index, item }

    async function _mountUnitStackIntoBinderDetail(item) {
      const slotWrap = document.getElementById('binderUnitStack_' + item.id);
      const fallback = document.getElementById('binderPhotoSlot_' + item.id);
      if (!slotWrap) return;
      const units = await _ensureUnitsForItem(item);
      if (!units || units.length === 0) return;  // schema missing / qty=1 race — keep fallback

      // Hide the fallback single-photo slot — the stack replaces it.
      // The .pb-detail-photo-slot CSS has `display: block !important`
      // which beats inline style.display, so we have to set the
      // property with `important` priority. (Without this the stack
      // and the single photo both render — see the v442 bug report.)
      if (fallback) fallback.style.setProperty('display', 'none', 'important');

      _binderUnitStackState = {
        itemId: item.id,
        item:   item,
        units:  units,
        index:  0,
      };
      _renderUnitStack();
      _attachUnitStackSwipe(slotWrap);
    }

    function _renderUnitStack() {
      const s = _binderUnitStackState;
      if (!s) return;
      const slotWrap = document.getElementById('binderUnitStack_' + s.itemId);
      if (!slotWrap) return;
      const current = s.units[s.index];
      const display = _resolveUnitDisplay(current, s.item);
      const total = s.units.length;
      // Back-card shadows (visual stack depth). We render up to 2
      // ghost layers to suggest there are more cards behind. They
      // don't reflect actual unit data — purely a visual cue.
      const back1 = total > 1 ? '<div class="pb-unit-slide is-back-1"><img src="' + _escHtml(display.card_image_url || '') + '" alt="" loading="lazy" decoding="async"></div>' : '';
      const back2 = total > 2 ? '<div class="pb-unit-slide is-back-2"><img src="' + _escHtml(display.card_image_url || '') + '" alt="" loading="lazy" decoding="async"></div>' : '';

      const badgeClass = display.isGraded ? 'pb-unit-badge is-graded' : 'pb-unit-badge';
      // Inline onclick handlers need single-quoted args because the
      // attribute itself is wrapped in double quotes. JSON.stringify
      // emits "..."-quoted strings which then collide with the
      // attribute boundary and break the handler entirely (which is
      // what made the EDIT button silently no-op in v442). Use
      // _escJsAttr (already used elsewhere for the same reason) to
      // escape any embedded single quotes in the value.
      const imgUrlAttr = _escJsAttr(display.card_image_url || '');
      const unitIdAttr = _escJsAttr(current.id);
      // Entry animation — set by _animateUnitStackTransition when an
      // arrow tap or swipe triggers a re-render. The new front renders
      // OFF-SCREEN (translateX(±110%)) and a post-render rAF nudges it
      // back to translateX(0), triggering a CSS transition. Inline-style
      // approach because v458's CSS keyframes were getting pre-empted
      // by the innerHTML replace mid-animation.
      const enterDir = s._enterDir || 0;
      s._enterDir = 0;
      let frontInitialTransform = '';
      if (enterDir === 1)  frontInitialTransform = 'translateX(110%) rotate(4deg)';
      if (enterDir === -1) frontInitialTransform = 'translateX(-110%) rotate(-4deg)';
      const frontStyleAttr = frontInitialTransform
        ? ' style="transform:' + frontInitialTransform + ';opacity:0;transition:transform .3s cubic-bezier(.2,.7,.3,1),opacity .3s cubic-bezier(.2,.7,.3,1)"'
        : '';
      const front = ''
        + '<div class="pb-unit-slide is-front"' + frontStyleAttr + (display.card_image_url ? " onclick=\"openImageLightbox('" + imgUrlAttr + "')\"" : '') + '>'
        +   '<img src="' + _escHtml(display.card_image_url || '') + '" alt="" onerror="this.style.display=\'none\'" loading="lazy" decoding="async">'
        +   '<span class="' + badgeClass + '">' + _escHtml(display.condLabel) + '</span>'
        +   '<span class="pb-unit-ordinal">' + (s.index + 1) + ' / ' + total + '</span>'
        +   "<button class=\"pb-unit-edit\" onclick=\"event.stopPropagation();openEditUnitModal('" + unitIdAttr + "')\">EDIT</button>"
        + '</div>';

      const dots = s.units.map(function(u, i) {
        let cls = 'pb-unit-dot';
        if (u.status === 'sold')   cls += ' is-sold';
        if (u.status === 'listed') cls += ' is-listed';
        if (i === s.index)         cls += ' is-active';
        return '<span class="' + cls + '" onclick="_setUnitStackIndex(' + i + ')" title="Unit ' + (i+1) + (u.status !== 'in_stock' ? ' (' + u.status + ')' : '') + '"></span>';
      }).join('');

      // Arrows are positioned absolute on .pb-unit-stack-wrap so they
      // overlay the left/right edges of the card; dots sit below as
      // a separate row.
      const prevDis = s.index === 0          ? ' disabled' : '';
      const nextDis = s.index === total - 1  ? ' disabled' : '';
      slotWrap.innerHTML = ''
        + '<div class="pb-unit-stack-wrap">'
        +   '<button class="pb-unit-nav-arrow pb-unit-nav-prev" onclick="_advanceUnitStack(-1)"' + prevDis + ' aria-label="Previous unit">‹</button>'
        +   '<div class="pb-unit-stack-frame">'
        +     back2 + back1 + front
        +   '</div>'
        +   '<button class="pb-unit-nav-arrow pb-unit-nav-next" onclick="_advanceUnitStack(1)"' + nextDis + ' aria-label="Next unit">›</button>'
        +   '<div class="pb-unit-dots">' + dots + '</div>'
        + '</div>';

      // If the new front was rendered off-screen for an entry animation,
      // nudge it back to translateX(0) on the next paint frame. The CSS
      // transition inline-styled above handles the motion.
      if (frontInitialTransform) {
        const newFront = slotWrap.querySelector('.pb-unit-slide.is-front');
        if (newFront) {
          // Two rAFs: the first ensures the initial off-screen state
          // is committed; the second triggers the transition to 0.
          // Single rAF was sometimes coalesced with the initial paint
          // and skipped the animation.
          requestAnimationFrame(function() {
            requestAnimationFrame(function() {
              newFront.style.transform = 'translateX(0) rotate(0deg)';
              newFront.style.opacity   = '1';
            });
          });
        }
      }
    }

    // Animation guard — coalesce rapid arrow taps so we don't queue
    // up overlapping exit/enter cycles. Tracks the in-flight transition.
    // Has a safety release so the lock cannot get stuck forever.
    let _unitStackAnimating = false;
    let _unitStackAnimResetTimer = null;
    function _setStackAnimating(on) {
      _unitStackAnimating = !!on;
      if (_unitStackAnimResetTimer) {
        clearTimeout(_unitStackAnimResetTimer);
        _unitStackAnimResetTimer = null;
      }
      // Safety: even if transitionend never fires (DOM yanked, browser
      // tab backgrounded, animation cancelled), the lock auto-clears
      // after 600ms so the user is never stuck.
      if (on) {
        _unitStackAnimResetTimer = setTimeout(function() {
          _unitStackAnimating = false;
          _unitStackAnimResetTimer = null;
        }, 600);
      }
    }

    function _advanceUnitStack(delta) {
      const s = _binderUnitStackState;
      if (!s) return;
      if (_unitStackAnimating) return;
      const next = s.index + delta;
      if (next < 0 || next >= s.units.length) return;
      _animateUnitStackTransition(delta, function() {
        s.index = next;
        _renderUnitStack();
      });
    }

    function _setUnitStackIndex(i) {
      const s = _binderUnitStackState;
      if (!s) return;
      if (_unitStackAnimating) return;
      if (i < 0 || i >= s.units.length) return;
      const delta = i > s.index ? 1 : (i < s.index ? -1 : 0);
      if (delta === 0) return;
      _animateUnitStackTransition(delta, function() {
        s.index = i;
        _renderUnitStack();
      });
    }

    // Plays the exit animation on the current front slide via inline
    // transform + the existing CSS transition (transform .25s ease).
    // Uses transitionend to know when to swap — avoids the
    // "setTimeout ran but the browser hadn't actually started the
    // animation" race that made v458 look like nothing happened.
    // The new front gets _enterDir set so _renderUnitStack starts it
    // off-screen and animates back to translateX(0).
    function _animateUnitStackTransition(delta, afterExit) {
      const s = _binderUnitStackState;
      if (!s) { afterExit(); _setStackAnimating(false); return; }
      const slot = document.getElementById('binderUnitStack_' + s.itemId);
      if (!slot) { afterExit(); _setStackAnimating(false); return; }
      const front = slot.querySelector('.pb-unit-slide.is-front');
      if (!front) { afterExit(); _setStackAnimating(false); return; }
      _setStackAnimating(true);
      // Promote the slide's transition speed slightly so the user
      // actually SEES the exit. The base rule sets .25s ease but the
      // is-front rule overrides z-index only; transform inherits the
      // base transition. Override here for a clearer beat.
      front.style.transition = 'transform .28s cubic-bezier(.5,0,.6,1), opacity .28s cubic-bezier(.5,0,.6,1)';
      // Force a reflow so the browser registers the starting transform
      // (translateX(0)) before we set the destination. Without this,
      // the browser sometimes coalesces the change with the next paint
      // and skips the animation entirely.
      front.style.transform = 'translateX(0) rotate(0deg)';
      void front.offsetHeight;
      // Set the exit destination — the slide flies off-screen in the
      // direction OPPOSITE to where the new card will come in.
      const exitX  = delta > 0 ? '-110%' : '110%';
      const exitRot = delta > 0 ? '-4deg' : '4deg';
      front.style.transform = 'translateX(' + exitX + ') rotate(' + exitRot + ')';
      front.style.opacity   = '0';
      // Hint the next render to play the entry animation from the
      // opposite side.
      s._enterDir = delta;
      let fired = false;
      const swap = function() {
        if (fired) return;
        fired = true;
        try { front.removeEventListener('transitionend', swap); } catch(_) {}
        afterExit();
        // Tiny grace period so the enter animation gets a clean start
        // before another tap can interrupt.
        setTimeout(function() { _setStackAnimating(false); }, 280);
      };
      front.addEventListener('transitionend', swap, { once: true });
      // Belt-and-suspenders: transitionend doesn't fire if the element
      // gets removed from the DOM mid-transition. Fall back to a timer.
      setTimeout(swap, 320);
    }

    // Lightweight horizontal-swipe handler. Threshold = 40px so
    // small vertical scrolls don't trigger an accidental advance.
    function _attachUnitStackSwipe(wrap) {
      if (!wrap || wrap._pbSwipeBound) return;
      wrap._pbSwipeBound = true;
      let startX = 0, startY = 0, tracking = false;
      wrap.addEventListener('touchstart', function(e) {
        if (!e.touches || e.touches.length !== 1) return;
        startX = e.touches[0].clientX;
        startY = e.touches[0].clientY;
        tracking = true;
      }, { passive: true });
      wrap.addEventListener('touchend', function(e) {
        if (!tracking) return;
        tracking = false;
        const t = (e.changedTouches && e.changedTouches[0]) || null;
        if (!t) return;
        const dx = t.clientX - startX;
        const dy = t.clientY - startY;
        if (Math.abs(dx) < 40 || Math.abs(dx) < Math.abs(dy)) return;  // not a horizontal swipe
        _advanceUnitStack(dx < 0 ? 1 : -1);
      }, { passive: true });
    }

    // ── Edit Unit modal handlers ────────────────────────────────────
    let _euContext = { unitId: null, parent: null, unit: null };

    function openEditUnitModal(unitId) {
      const s = _binderUnitStackState;
      if (!s) return;
      const unit = s.units.find(function(u) { return String(u.id) === String(unitId); });
      if (!unit) return;
      _euContext = { unitId: unitId, parent: s.item, unit: unit };

      const titleEl = document.getElementById('editUnitTitle');
      if (titleEl) titleEl.textContent = 'Edit Unit ' + (unit.ordinal || '?') + ' / ' + s.units.length;
      const labelEl = document.getElementById('editUnitCardLabel');
      if (labelEl) labelEl.textContent = s.item.card_name || '?';

      const condEl = document.getElementById('euCondition');
      if (condEl) condEl.value = unit.condition || '';
      const gradeEl = document.getElementById('euGradeValue');
      if (gradeEl) gradeEl.value = unit.grade_value != null ? unit.grade_value : '';
      const certEl = document.getElementById('euCertNumber');
      if (certEl) certEl.value = unit.cert_number || '';
      const notesEl = document.getElementById('euNotes');
      if (notesEl) notesEl.value = unit.notes || '';

      const errEl = document.getElementById('euError');
      if (errEl) errEl.style.display = 'none';

      openModal('editUnitModal');
    }

    async function saveUnitEdit() {
      const ctx = _euContext;
      if (!ctx || !ctx.unitId) { showToast('Unit context lost'); return; }
      const _err = function(msg) {
        const errEl = document.getElementById('euError');
        if (errEl) { errEl.textContent = msg; errEl.style.display = 'block'; }
      };
      const conditionRaw = document.getElementById('euCondition').value;
      const gradeRaw     = document.getElementById('euGradeValue').value.trim();
      const certRaw      = document.getElementById('euCertNumber').value.trim();
      const notesRaw     = document.getElementById('euNotes').value.trim();
      const patch = {
        condition:   conditionRaw || null,
        grade_value: (gradeRaw && isFinite(parseFloat(gradeRaw))) ? parseFloat(gradeRaw) : null,
        cert_number: certRaw || null,
        notes:       notesRaw || null,
      };
      const btn = document.getElementById('euSubmitBtn');
      if (btn) { btn.textContent = 'Saving…'; btn.disabled = true; }
      const updated = await _updateUnit(ctx.unitId, patch);
      if (btn) { btn.textContent = '✓ Save Unit'; btn.disabled = false; }
      if (!updated) { _err('Save failed — see console'); return; }
      // Update in-memory stack state + re-render.
      const s = _binderUnitStackState;
      if (s) {
        const idx = s.units.findIndex(function(u) { return String(u.id) === String(ctx.unitId); });
        if (idx >= 0) s.units[idx] = updated;
        _renderUnitStack();
      }
      closeModal('editUnitModal');
      showToast('Unit ' + (updated.ordinal || '') + ' updated');
    }

    // ── Mark N Sold modal ───────────────────────────────────────────
    // Step 2 of shop inventory: vendors record an in-store sale that
    // decrements on_shelf_qty + quantity via the shop_sales trigger.
    // The modal is reused later (Step 3) by the POS scan path.
    let _msContext = { itemId: null, item: null };

    function openMarkSoldModal(itemId) {
      if (!currentUser) return;
      if (typeof tierAtLeast !== 'function' || !tierAtLeast('vendor')) {
        showToast('Vendor tier required to record in-store sales');
        return;
      }
      const item = (collectionItems || []).find(function(c) { return String(c.id) === String(itemId); });
      if (!item) { showToast('Item not found'); return; }
      const onShelf = (item.on_shelf_qty != null) ? item.on_shelf_qty : (item.quantity || 1);
      if (onShelf <= 0) { showToast('No stock on shelf for this card'); return; }

      _msContext = { itemId: itemId, item: item };

      const label = (item.card_name || '?') + (item.variant && item.variant !== 'normal'
        ? ' · ' + String(item.variant).toUpperCase().replace('_', ' ') : '');
      const labelEl = document.getElementById('msCardLabel');
      if (labelEl) labelEl.textContent = label;

      const listed = item.listed_online_qty || 0;
      const availEl = document.getElementById('msAvailLabel');
      if (availEl) {
        var parts = ['On shelf: ' + onShelf];
        if (listed > 0) parts.push(listed + ' listed online');
        if (item.set_name) parts.push(item.set_name);
        availEl.textContent = parts.join('  ·  ');
      }

      const qtyEl = document.getElementById('msQty');
      if (qtyEl) {
        qtyEl.value = '1';
        // Allow up to on_shelf + listed_online; selling more than the
        // shelf qty triggers the delist prompt at submit time. Cap is
        // a hard ceiling so the qty never exceeds what the vendor
        // actually owns.
        qtyEl.max = Math.max(1, onShelf + listed);
      }
      const unitPriceEl = document.getElementById('msUnitPrice');
      if (unitPriceEl) {
        const suggested = item.current_value || item._compEstimate || item.purchase_price || 0;
        unitPriceEl.value = suggested ? suggested.toFixed(2) : '';
      }
      const dateEl = document.getElementById('msSoldAt');
      if (dateEl) dateEl.value = new Date().toISOString().slice(0, 10);
      const payEl = document.getElementById('msPaymentMethod');
      if (payEl) payEl.value = 'card';
      const notesEl = document.getElementById('msNotes');
      if (notesEl) notesEl.value = '';
      const errEl = document.getElementById('msError');
      if (errEl) errEl.style.display = 'none';

      _msRecalcTotal();
      openModal('markSoldModal');
    }

    function _msRecalcTotal() {
      const q  = parseInt(document.getElementById('msQty')?.value, 10) || 0;
      const up = parseFloat(document.getElementById('msUnitPrice')?.value) || 0;
      const totalEl = document.getElementById('msTotalDisplay');
      if (totalEl) totalEl.textContent = '$' + (q * up).toFixed(2);
    }

    async function submitMarkSold() {
      if (!_msContext || !_msContext.item || !currentUser) {
        showToast('Sale context missing — close and reopen'); return;
      }
      const item = _msContext.item;
      const qty  = parseInt(document.getElementById('msQty').value, 10);
      const unit = parseFloat(document.getElementById('msUnitPrice').value);
      const dateStr = document.getElementById('msSoldAt').value;
      const payment = document.getElementById('msPaymentMethod').value || 'card';
      const notes   = document.getElementById('msNotes').value.trim() || null;
      const onShelf = (item.on_shelf_qty != null) ? item.on_shelf_qty : (item.quantity || 1);

      const errEl = document.getElementById('msError');
      const _err = function(msg) {
        if (errEl) { errEl.textContent = msg; errEl.style.display = 'block'; }
      };
      if (errEl) errEl.style.display = 'none';

      if (!isFinite(qty) || qty < 1)     { _err('Quantity must be at least 1'); return; }
      if (!isFinite(unit) || unit < 0)   { _err('Enter a valid unit price'); return; }

      const btn = document.getElementById('msSubmitBtn');
      const total = +(qty * unit).toFixed(2);
      const soldAtIso = dateStr
        ? new Date(dateStr + 'T12:00:00').toISOString()  // midday avoids tz-edge shifting the date
        : new Date().toISOString();

      // ── Cross-channel pre-flight ──────────────────────────────────
      // If the requested qty exceeds on_shelf, the difference has to
      // come out of an active listing (or get blocked if there's an
      // online order in flight). Pre-flight checks for both cases
      // and either branches into the delist prompt or aborts.
      if (qty > onShelf) {
        const shortfall = qty - onShelf;
        const preflight = await _posPreflightListings(item, shortfall);
        if (preflight.blocked) {
          _err(preflight.message || 'Cannot complete sale');
          return;
        }
        if (preflight.needsPrompt) {
          // Stash the in-flight sale context so the delist modal can
          // pick it up after the user confirms or cancels.
          _msPendingSale = {
            qty: qty, unit: unit, total: total, soldAtIso: soldAtIso,
            payment: payment, notes: notes, item: item, shortfall: shortfall,
            listings: preflight.listings,
          };
          // Auto-delist skip: vendor previously checked "don't ask again".
          if (localStorage.getItem('pb_auto_delist_on_pos') === '1') {
            return _executeDelistAndSell();
          }
          _openDelistConfirm(preflight, shortfall, item);
          return;
        }
        // preflight.ok but no listings either → must be a stale state;
        // fall through and let the trigger reject with a clear message.
      }

      if (btn) { btn.textContent = 'Recording…'; btn.disabled = true; }

      const payload = {
        user_id:            currentUser.id,
        collection_item_id: item.id,
        api_card_id:        item.api_card_id || null,
        variant:            item.variant || 'normal',
        qty:                qty,
        unit_price:         +unit.toFixed(2),
        total_price:        total,
        payment_method:     payment,
        notes:              notes,
        sold_at:            soldAtIso,
      };

      try {
        const r = await sb.from('shop_sales').insert(payload).select().single();
        if (r.error) {
          // Trigger raises clean exceptions like
          // "shop_sales: only 2 on shelf, cannot sell 3" — surface them.
          _err(r.error.message.replace(/^shop_sales:\s*/, ''));
          if (btn) { btn.textContent = '✓ Record Sale'; btn.disabled = false; }
          return;
        }
        // Re-pull collection so the inventory tile + row qty refresh.
        // loadCollection() is the same path the binder uses, so the
        // updated on_shelf_qty / quantity propagate everywhere.
        try { await loadCollection(); } catch(_) {}
        // Re-render My Store (was Inventory) if the vendor is still
        // on that tab so the stock counts and SOLD button state
        // reflect the new sale immediately.
        try { if (document.getElementById('myStore')?.classList.contains('active') && typeof window.renderMyStore === 'function') window.renderMyStore(); } catch(_) {}
        // Re-render sales log if open.
        try { if (document.getElementById('salesLog')?.classList.contains('active')) renderSalesLog(true); } catch(_) {}

        closeModal('markSoldModal');
        showToast('Recorded $' + total.toFixed(2) + ' sale');

        // POS-mode loop — reopen the scanner for the next sale
        // instead of dropping the vendor back to the Inventory tab.
        // Persists POS mode until they explicitly tap EXIT POS.
        if (window._posSaleMode) {
          setTimeout(function() {
            try {
              openCardScanner();
              _setPosBanner(true);
              // Re-trigger camera so the workflow is "scan, confirm,
              // sale, next scan" without intermediate taps.
              const inp = document.getElementById('navScanCardInput');
              if (inp) inp.click();
            } catch(_) {}
          }, 300);
        }
      } catch (e) {
        _err((e && e.message) || 'Unexpected error');
        if (btn) { btn.textContent = '✓ Record Sale'; btn.disabled = false; }
      }
    }

    // ── POS cross-channel pre-flight (Step 4) ───────────────────────
    // Called by submitMarkSold when the requested qty exceeds the
    // on_shelf number. Pulls every active listing for this user +
    // card + variant, plus every paid-but-unshipped order against
    // those listings. Returns one of three outcomes:
    //   { blocked: true,  message }      — paid order awaiting ship
    //   { needsPrompt: true, listings }  — listings exist, can delist
    //   { ok: true }                     — no listings either; let the
    //                                      DB trigger surface the issue
    let _msPendingSale = null;

    async function _posPreflightListings(item, shortfall) {
      try {
        const lr = await sb.from('listings')
          .select('id, quantity, value, status, variant')
          .eq('seller_id', currentUser.id)
          .eq('api_card_id', item.api_card_id)
          .eq('variant', item.variant || 'normal')
          .in('status', ['active','available']);
        const listings = lr.data || [];
        if (listings.length === 0) {
          return { ok: true };
        }
        // Check for paid-but-unshipped orders against these listings.
        // We block aggressively — even one unshipped order means the
        // POS sale would create a double-sell.
        const listingIds = listings.map(function(l){ return l.id; });
        const or = await sb.from('orders')
          .select('id, status, listing_id')
          .in('listing_id', listingIds)
          .in('status', ['paid','pending_payment']);
        const pendingOrders = or.data || [];
        if (pendingOrders.length > 0) {
          return {
            blocked:  true,
            message:  'This card has been paid for online. Ship the order instead of selling in-store.',
            orders:   pendingOrders,
          };
        }
        return { needsPrompt: true, listings: listings, shortfall: shortfall };
      } catch (e) {
        console.warn('[pos] preflight error:', e && e.message);
        return { ok: true };  // fail-open: trigger still guards on_shelf invariant
      }
    }

    function _openDelistConfirm(preflight, shortfall, item) {
      const labelEl = document.getElementById('delistCardLabel');
      if (labelEl) labelEl.textContent = item.card_name || '?';
      const totalListed = preflight.listings.reduce(function(s,l){ return s + (l.quantity||1); }, 0);
      const explainEl = document.getElementById('delistExplain');
      if (explainEl) {
        explainEl.textContent = 'This sale needs ' + shortfall + ' more unit'
          + (shortfall === 1 ? '' : 's') + ' than you have on shelf. We\'ll pull '
          + shortfall + ' from your active marketplace listing'
          + (preflight.listings.length === 1 ? '' : 's') + '.';
      }
      const detailEl = document.getElementById('delistDetail');
      if (detailEl) {
        detailEl.innerHTML = preflight.listings.map(function(l) {
          return '· Listing #' + String(l.id).slice(0,8) + ' — qty ' + (l.quantity||1) + ' @ $' + Number(l.value||0).toFixed(2);
        }).join('<br>') + '<br><br>Total listed: ' + totalListed + ' unit' + (totalListed === 1 ? '' : 's');
      }
      const dontAskEl = document.getElementById('delistDontAsk');
      if (dontAskEl) dontAskEl.checked = false;
      openModal('delistConfirmModal');
    }

    async function confirmDelistAndSell() {
      // Persist the don't-ask-again preference before tearing down.
      const dontAskEl = document.getElementById('delistDontAsk');
      if (dontAskEl && dontAskEl.checked) {
        try { localStorage.setItem('pb_auto_delist_on_pos', '1'); } catch(_) {}
      }
      closeModal('delistConfirmModal');
      await _executeDelistAndSell();
    }

    // Pulls `shortfall` units across the cached active listings (in
    // ascending qty order — exhaust the smallest first so single-card
    // listings clear out cleanly), records the sale, and reopens the
    // scanner if POS mode is still active.
    async function _executeDelistAndSell() {
      const ctx = _msPendingSale;
      if (!ctx) { showToast('Sale context lost — try again'); return; }
      _msPendingSale = null;

      const sortedListings = (ctx.listings || []).slice().sort(function(a,b) {
        return (a.quantity||1) - (b.quantity||1);
      });
      let remaining = ctx.shortfall;
      for (let i = 0; i < sortedListings.length && remaining > 0; i++) {
        const l    = sortedListings[i];
        const lQty = l.quantity || 1;
        const pull = Math.min(lQty, remaining);
        if (pull >= lQty) {
          // Listing fully consumed → flip to inactive.
          const r = await sb.from('listings').update({ status: 'inactive' }).eq('id', l.id);
          if (r.error) { showToast('Couldn\'t pull listing #' + String(l.id).slice(0,8) + ': ' + r.error.message); return; }
          // Mirror the local cache so renderBrowse / renderMyListings
          // stay in sync without a full reload.
          listings = (listings || []).filter(function(x) { return String(x.id) !== String(l.id); });
        } else {
          // Partial pull — reduce qty in place, listing stays active.
          const newQty = lQty - pull;
          const r = await sb.from('listings').update({ quantity: newQty }).eq('id', l.id);
          if (r.error) { showToast('Couldn\'t adjust listing #' + String(l.id).slice(0,8) + ': ' + r.error.message); return; }
          const idx = (listings || []).findIndex(function(x) { return String(x.id) === String(l.id); });
          if (idx >= 0) listings[idx].quantity = newQty;
        }
        // Move the pulled units from listed_online → on_shelf so the
        // sale insert below can decrement them legally.
        try {
          await _invOnListingReleased(currentUser.id, ctx.item.api_card_id, ctx.item.variant || 'normal', pull);
        } catch (e) {
          console.warn('[pos] release after pull failed:', e && e.message);
        }
        remaining -= pull;
      }

      // Refresh collection so the now-bumped on_shelf_qty is in the
      // local cache before the shop_sales insert fires its trigger
      // check.
      try { await loadCollection(); } catch(_) {}

      // Re-run the sale insert using the stashed context.
      const payload = {
        user_id:            currentUser.id,
        collection_item_id: ctx.item.id,
        api_card_id:        ctx.item.api_card_id || null,
        variant:            ctx.item.variant || 'normal',
        qty:                ctx.qty,
        unit_price:         +ctx.unit.toFixed(2),
        total_price:        ctx.total,
        payment_method:     ctx.payment,
        notes:              ctx.notes,
        sold_at:            ctx.soldAtIso,
      };
      const r = await sb.from('shop_sales').insert(payload).select().single();
      if (r.error) {
        showToast('Sale insert failed: ' + r.error.message.replace(/^shop_sales:\s*/, ''));
        return;
      }
      try { await loadCollection(); } catch(_) {}
      try { if (document.getElementById('inventory')?.classList.contains('active')) renderInventory(); } catch(_) {}
      try { if (document.getElementById('salesLog')?.classList.contains('active')) renderSalesLog(true); } catch(_) {}
      showToast('Pulled ' + ctx.shortfall + ' from listings · sale recorded ($' + ctx.total.toFixed(2) + ')');

      // POS loop — reopen scanner if we got here via a scan.
      if (window._posSaleMode) {
        setTimeout(function() {
          try {
            openCardScanner();
            _setPosBanner(true);
            const inp = document.getElementById('navScanCardInput');
            if (inp) inp.click();
          } catch(_) {}
        }, 300);
      }
    }

    // ── Sales Log tab ───────────────────────────────────────────────
    // Fetches shop_sales rows for the active user, optionally
    // bounded by the date range filters. Cached in a module-level
    // array so the CSV export uses the same dataset the user sees.
    let _salesLogRows = [];
    let _salesLogInflight = null;

    async function _fetchSalesLog(fromIso, toIso) {
      if (!currentUser) return [];
      let q = sb.from('shop_sales')
        .select('*')
        .eq('user_id', currentUser.id)
        .order('sold_at', { ascending: false })
        .limit(2000);
      if (fromIso) q = q.gte('sold_at', fromIso);
      if (toIso)   q = q.lte('sold_at', toIso);
      const r = await q;
      if (r.error) {
        console.warn('[sales-log] fetch error:', r.error.message);
        return [];
      }
      return r.data || [];
    }

    // ── Unified Sales tab (renderSales) ────────────────────────────
    // Replaces the legacy "Sales Archive" + "Sales Log" split with a
    // single tab that pulls from all three sources:
    //   • shop_sales            (in-store sales — Vendor+ only)
    //   • orders                (marketplace sales — Enthusiast+)
    //   • collection_items where sold_offline=true (offline — Enthusiast+)
    //
    // Source filter chips at the top let the user narrow to one. Free
    // tier sees the chips disabled with a "Vendor+" tier badge so the
    // affordance is visible (upsell hook). renderSales() reads the
    // current chip and the date inputs (#salesFrom / #salesTo) to
    // decide what to query, then renders a unified table.
    // _salesActiveSource — 'all' | 'in-store' | 'marketplace'
    // (Offline + In-Store collapsed into 'in-store' — both are
    // off-platform sales just from different schemas.)
    let _salesActiveSource = 'all';
    let _salesCachedRows   = [];           // currently displayed merged rows

    function _setSalesSource(src) {
      // Tier gate — In-Store (shop_sales + legacy sold_offline) and
      // Marketplace both require Enthusiast+. Vendor+ users get the
      // richer shop_sales data within In-Store; Enthusiast users
      // still see their legacy offline sales.
      if ((src === 'in-store' || src === 'marketplace') &&
          (typeof tierAtLeast !== 'function' || !tierAtLeast('enthusiast'))) {
        if (typeof openPricingModalWithPromo === 'function') openPricingModalWithPromo('enthusiast');
        return;
      }
      _salesActiveSource = src;
      // Re-paint chip active states without a full rerender of the chips
      // bar (the chips live in HTML, we just toggle classes).
      const chips = document.querySelectorAll('#salesFilterChips .sales-chip');
      chips.forEach(function(c) {
        c.classList.toggle('is-active', c.getAttribute('data-source') === src);
      });
      renderSales();
    }

    // Decorate chips with tier badges + disabled state based on the
    // current user. Called from renderSales each render so tier
    // changes (e.g. after upgrade) propagate without a reload.
    function _paintSalesChipGates() {
      const wrap = document.getElementById('salesFilterChips');
      if (!wrap) return;
      const isEnthusiast = typeof tierAtLeast === 'function' && tierAtLeast('enthusiast');
      wrap.querySelectorAll('.sales-chip').forEach(function(c) {
        const src = c.getAttribute('data-source');
        let locked = false, badge = '';
        if ((src === 'in-store' || src === 'marketplace') && !isEnthusiast) {
          locked = true;
          badge = 'Enthusiast+';
        }
        c.classList.toggle('is-locked', locked);
        const oldBadge = c.querySelector('.sales-chip-tier');
        if (oldBadge) oldBadge.remove();
        if (badge) {
          const span = document.createElement('span');
          span.className = 'sales-chip-tier';
          span.textContent = badge;
          c.appendChild(span);
        }
      });
    }

    async function renderSales(forceRefresh) {
      const wrap = document.getElementById('salesContent');
      if (!wrap) return;
      if (!currentUser) {
        wrap.innerHTML = '<div style="padding:32px;text-align:center;color:var(--muted)">Sign in to view sales.</div>';
        return;
      }
      _paintSalesChipGates();

      const src      = _salesActiveSource;
      const fromStr  = document.getElementById('salesFrom')?.value || '';
      const toStr    = document.getElementById('salesTo')?.value   || '';
      const fromIso  = fromStr ? new Date(fromStr + 'T00:00:00').toISOString() : null;
      const toIso    = toStr   ? new Date(toStr   + 'T23:59:59').toISOString() : null;
      const isVendor      = typeof tierAtLeast === 'function' && tierAtLeast('vendor');
      const isEnthusiast  = typeof tierAtLeast === 'function' && tierAtLeast('enthusiast');

      // Decide which sources to query based on chip + tier. In-Store
      // pulls from BOTH shop_sales (Vendor+ richer data) AND
      // collection_items.sold_offline (legacy Enthusiast+ flag) —
      // they're conceptually the same off-platform sale.
      const wantShopSales   = (src === 'all' || src === 'in-store')    && isVendor;
      const wantOffline     = (src === 'all' || src === 'in-store')    && isEnthusiast;
      const wantMarketplace = (src === 'all' || src === 'marketplace') && isEnthusiast;

      const [shopSalesRows, orderRows] = await Promise.all([
        wantShopSales   ? _fetchSalesLog(fromIso, toIso) : Promise.resolve([]),
        wantMarketplace ? _fetchMarketplaceSales(fromIso, toIso) : Promise.resolve([]),
      ]);
      // Offline sales live on collection_items (sold_offline=true) — already
      // loaded into the local collectionItems array. Filter in memory.
      const offlineRows = wantOffline
        ? (collectionItems || []).filter(function(c) {
            if (!c.sold_offline || !c.offline_sale_date) return false;
            const d = c.offline_sale_date;
            if (fromStr && d < fromStr) return false;
            if (toStr   && d > toStr)   return false;
            return true;
          })
        : [];

      // Resolve catalog metadata for the in-store rows (already keyed
      // by collection_item_id — same trick renderSalesLog used).
      const itemById = {};
      (collectionItems || []).forEach(function(c) { itemById[c.id] = c; });

      // Normalize all three sources into one shape: { date, source,
      // name, set, variant, qty, unit_price, total, payment_method,
      // notes, _raw }.
      const rows = [];
      shopSalesRows.forEach(function(s) {
        const it = itemById[s.collection_item_id] || {};
        rows.push({
          date:           s.sold_at,
          source:         'in-store',
          name:           it.card_name || s.api_card_id || '?',
          set_name:       it.set_name || '',
          variant:        s.variant || 'normal',
          qty:            s.qty || 1,
          unit_price:     Number(s.unit_price) || 0,
          total:          Number(s.total_price) || 0,
          payment_method: s.payment_method || '',
          notes:          s.notes || '',
          _raw:           s,
        });
      });
      orderRows.forEach(function(o) {
        rows.push({
          date:           o.shipped_at || o.completed_at || o.created_at,
          source:         'marketplace',
          name:           o.listing_name || o.item_name || '?',
          set_name:       o.listing_set || '',
          variant:        o.listing_variant || 'normal',
          qty:            o.quantity || 1,
          unit_price:     Number(o.unit_price || o.seller_payout || 0),
          total:          Number(o.seller_payout || o.total_amount || 0),
          payment_method: 'card',
          notes:          o.notes || '',
          _raw:           o,
        });
      });
      // Legacy sold_offline rows tagged as 'in-store' so they merge
      // visually with shop_sales rows. The user doesn't care which
      // schema fed the row — they're all off-platform sales.
      offlineRows.forEach(function(c) {
        rows.push({
          date:           c.offline_sale_date,
          source:         'in-store',
          name:           c.card_name || '?',
          set_name:       c.set_name || '',
          variant:        c.variant || 'normal',
          qty:            c.quantity || 1,
          unit_price:     Number(c.offline_sale_price || 0),
          total:          Number(c.offline_sale_price || 0),
          payment_method: '',
          notes:          c.offline_buyer || '',
          _raw:           c,
        });
      });

      // Sort newest first
      rows.sort(function(a, b) {
        return String(b.date || '').localeCompare(String(a.date || ''));
      });
      _salesCachedRows = rows;

      // Summary
      let totalRev = 0, totalQty = 0;
      const byMethod = { card: 0, cash: 0, trade: 0, other: 0 };
      const bySource = { 'in-store': 0, marketplace: 0 };
      rows.forEach(function(r) {
        totalRev += r.total;
        totalQty += r.qty;
        const m = r.payment_method || 'other';
        byMethod[m] = (byMethod[m] || 0) + r.total;
        bySource[r.source] = (bySource[r.source] || 0) + r.total;
      });
      const summary = ''
        + '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px;margin-bottom:14px">'
        +   _invSummaryTile('Sales',       String(rows.length),         'var(--text)')
        +   _invSummaryTile('Units',       String(totalQty),            'var(--accent)')
        +   _invSummaryTile('Revenue',     '$' + totalRev.toFixed(2),   'var(--green)')
        +   _invSummaryTile('In-Store',    '$' + bySource['in-store'].toFixed(2),    'var(--muted)')
        +   _invSummaryTile('Marketplace', '$' + bySource['marketplace'].toFixed(2), 'var(--muted)')
        + '</div>';

      if (rows.length === 0) {
        wrap.innerHTML = summary
          + '<div style="padding:40px;text-align:center;color:var(--muted);font-size:.78rem">'
          + (isVendor || isEnthusiast
              ? 'No sales recorded in this range.'
              : 'Sales tracking is a paid feature. Upgrade to Enthusiast or Vendor to start logging sales.')
          + '</div>';
        return;
      }

      // Table
      const body = rows.map(function(r) {
        const variant = (r.variant && r.variant !== 'normal')
          ? ' <span style="font-size:.55rem;color:var(--copper, #d97e3e);letter-spacing:.06em">' + _escHtml(String(r.variant).toUpperCase().replace(/_/g,' ')) + '</span>'
          : '';
        const dateLabel = (typeof _pbCompactDate === 'function') ? _pbCompactDate(r.date) : String(r.date || '').slice(0,10);
        const srcLabel = r.source === 'in-store'    ? '<span style="color:var(--accent)">IN-STORE</span>'
                      :  r.source === 'marketplace' ? '<span style="color:var(--copper, #d97e3e)">MARKET</span>'
                      :                                '<span style="color:var(--muted)">OFFLINE</span>';
        return ''
          + '<tr style="border-top:1px solid var(--border)">'
          +   '<td style="padding:8px 12px;color:var(--muted);font-size:.7rem">' + dateLabel + '</td>'
          +   '<td style="padding:8px 12px;font-size:.62rem;letter-spacing:.06em">' + srcLabel + '</td>'
          +   '<td style="padding:8px 12px;color:var(--text)">' + _escHtml(r.name) + variant + '</td>'
          +   '<td style="padding:8px 12px;color:var(--muted)">' + _escHtml(r.set_name) + '</td>'
          +   '<td style="padding:8px 12px;text-align:right;color:var(--text)">' + r.qty + '</td>'
          +   '<td style="padding:8px 12px;text-align:right;color:var(--muted)">$' + r.unit_price.toFixed(2) + '</td>'
          +   '<td style="padding:8px 12px;text-align:right;color:var(--green);font-weight:700">$' + r.total.toFixed(2) + '</td>'
          +   '<td style="padding:8px 12px;color:var(--muted);font-size:.65rem;letter-spacing:.06em">' + _escHtml(String(r.payment_method||'').toUpperCase()) + '</td>'
          + '</tr>';
      }).join('');
      wrap.innerHTML = summary
        + '<div style="overflow-x:auto;border:1px solid var(--border);background:var(--surface);border-radius:8px">'
        +   '<table style="width:100%;border-collapse:collapse;font-family:\'Space Mono\',monospace;font-size:.72rem">'
        +     '<thead><tr style="background:var(--surface2);color:var(--muted);letter-spacing:.06em">'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">DATE</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">SOURCE</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">CARD</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">SET</th>'
        +       '<th style="text-align:right;padding:10px 12px;font-weight:600;font-size:.62rem">QTY</th>'
        +       '<th style="text-align:right;padding:10px 12px;font-weight:600;font-size:.62rem">UNIT $</th>'
        +       '<th style="text-align:right;padding:10px 12px;font-weight:600;font-size:.62rem">TOTAL $</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">PAY</th>'
        +     '</tr></thead>'
        +     '<tbody>' + body + '</tbody>'
        +   '</table>'
        + '</div>';
    }

    // Marketplace order fetch — used by renderSales for the marketplace
    // source. Pulls completed/shipped/paid seller orders in the date
    // range. Mirrors what the old renderSalesArchive did but isolated
    // so renderSales can call it cleanly.
    async function _fetchMarketplaceSales(fromIso, toIso) {
      if (!currentUser) return [];
      let q = sb.from('orders')
        .select('*')
        .eq('seller_id', currentUser.id)
        .in('status', ['paid','shipped','completed'])
        .order('created_at', { ascending: false })
        .limit(2000);
      if (fromIso) q = q.gte('created_at', fromIso);
      if (toIso)   q = q.lte('created_at', toIso);
      const r = await q;
      if (r.error) {
        console.warn('[sales] marketplace fetch error:', r.error.message);
        return [];
      }
      return r.data || [];
    }

    // Unified CSV export — dumps whatever is in _salesCachedRows.
    function exportSalesCsv() {
      const rows = _salesCachedRows || [];
      if (!rows.length) { if (typeof showToast === 'function') showToast('No sales to export'); return; }
      const header = ['sold_at','source','card_name','set_name','variant','qty','unit_price','total','payment_method','notes'];
      const esc = function(v) {
        if (v == null) return '';
        const s = String(v).replace(/"/g, '""');
        return '"' + s + '"';
      };
      const lines = [header.map(esc).join(',')];
      rows.forEach(function(r) {
        lines.push([
          (String(r.date||'')).slice(0,19).replace('T',' '),
          r.source,
          r.name,
          r.set_name,
          r.variant || 'normal',
          r.qty,
          r.unit_price.toFixed(2),
          r.total.toFixed(2),
          r.payment_method,
          r.notes,
        ].map(esc).join(','));
      });
      const csv  = lines.join('\n');
      const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
      const url  = URL.createObjectURL(blob);
      const a    = document.createElement('a');
      a.href = url;
      a.download = 'pathbinder-sales-' + (new Date().toISOString().slice(0,10)) + '.csv';
      document.body.appendChild(a); a.click(); a.remove();
      setTimeout(function(){ URL.revokeObjectURL(url); }, 1000);
    }

    // Purchases = old "Activity History" buyer-side feed.
    // Thin wrapper that delegates to the existing renderHistory() so
    // we don't duplicate its logic — just retargets the output to
    // the new #purchasesContent div.
    function renderPurchases() {
      const purchasesDiv = document.getElementById('purchasesContent');
      const historyDiv   = document.getElementById('historyContent');
      // Render into the old container then move the resulting HTML.
      // renderHistory expects #historyContent — let it run, then copy.
      try {
        if (typeof renderHistory === 'function') renderHistory();
        if (purchasesDiv && historyDiv) purchasesDiv.innerHTML = historyDiv.innerHTML;
      } catch (e) {
        console.warn('[purchases] renderHistory failed:', e && e.message);
      }
    }

    async function renderSalesLog(forceRefresh) {
      const wrap = document.getElementById('salesLogContent');
      if (!wrap) return;
      if (!currentUser) { wrap.innerHTML = '<div style="padding:32px;text-align:center;color:var(--muted)">Sign in to view sales.</div>'; return; }
      if (typeof tierAtLeast !== 'function' || !tierAtLeast('vendor')) {
        wrap.innerHTML = '<div style="padding:32px;text-align:center;color:var(--muted)">'
          + 'Sales tracking is a Vendor+ feature.<br>'
          + '<button onclick="openPricingModalWithPromo(\'vendor\')" class="pb-panel-link" style="border-color:var(--accent);color:var(--accent);margin-top:14px;display:inline-block">Upgrade to Vendor →</button>'
          + '</div>';
        return;
      }

      const fromStr = document.getElementById('slFrom')?.value || '';
      const toStr   = document.getElementById('slTo')?.value   || '';
      const fromIso = fromStr ? new Date(fromStr + 'T00:00:00').toISOString() : null;
      const toIso   = toStr   ? new Date(toStr   + 'T23:59:59').toISOString() : null;

      if (forceRefresh || _salesLogRows.length === 0 || _salesLogInflight === null) {
        wrap.innerHTML = '<div style="text-align:center;padding:40px;color:var(--muted);font-size:.78rem">Loading sales…</div>';
        _salesLogInflight = _fetchSalesLog(fromIso, toIso);
        _salesLogRows = await _salesLogInflight;
        _salesLogInflight = null;
      }
      const rows = _salesLogRows;

      // Resolve card name + image for each sale row by looking up the
      // matching collection_items row (id match). Sales whose
      // collection row was deleted gracefully show api_card_id.
      const itemById = {};
      (collectionItems || []).forEach(function(c) { itemById[c.id] = c; });

      let totalRev = 0, totalQty = 0;
      const byMethod = { card: 0, cash: 0, trade: 0, other: 0 };
      rows.forEach(function(s) {
        totalRev += Number(s.total_price) || 0;
        totalQty += Number(s.qty) || 0;
        const m = s.payment_method || 'other';
        byMethod[m] = (byMethod[m] || 0) + (Number(s.total_price) || 0);
      });

      const summary = ''
        + '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px;margin-bottom:14px">'
        +   _invSummaryTile('Sales',    rows.length.toLocaleString(),     'var(--text)')
        +   _invSummaryTile('Units',    totalQty.toLocaleString(),         'var(--accent)')
        +   _invSummaryTile('Revenue', '$' + totalRev.toFixed(2),          'var(--green)')
        +   _invSummaryTile('Card',    '$' + (byMethod.card||0).toFixed(2),'var(--muted)')
        +   _invSummaryTile('Cash',    '$' + (byMethod.cash||0).toFixed(2),'var(--muted)')
        + '</div>';

      if (rows.length === 0) {
        wrap.innerHTML = summary
          + '<div style="padding:40px;text-align:center;color:var(--muted);font-size:.78rem">'
          + 'No sales recorded yet. Use the $ SOLD button in the Inventory tab to log your first one.'
          + '</div>';
        return;
      }

      const body = rows.map(function(s) {
        const it = itemById[s.collection_item_id] || {};
        const name = _escHtml(it.card_name || s.api_card_id || '?');
        const variant = (s.variant && s.variant !== 'normal')
          ? ' <span style="font-size:.55rem;color:var(--copper, #d97e3e);letter-spacing:.06em">' + _escHtml(String(s.variant).toUpperCase().replace('_',' ')) + '</span>'
          : '';
        const setN = _escHtml(it.set_name || '');
        const dateLabel = _pbCompactDate ? _pbCompactDate(s.sold_at) : String(s.sold_at).slice(0,10);
        return ''
          + '<tr style="border-top:1px solid var(--border)">'
          +   '<td style="padding:8px 12px;color:var(--muted);font-size:.7rem">' + dateLabel + '</td>'
          +   '<td style="padding:8px 12px;color:var(--text)">' + name + variant + '</td>'
          +   '<td style="padding:8px 12px;color:var(--muted)">' + setN + '</td>'
          +   '<td style="padding:8px 12px;text-align:right;color:var(--text)">' + (s.qty || 0) + '</td>'
          +   '<td style="padding:8px 12px;text-align:right;color:var(--muted)">$' + Number(s.unit_price||0).toFixed(2) + '</td>'
          +   '<td style="padding:8px 12px;text-align:right;color:var(--green);font-weight:700">$' + Number(s.total_price||0).toFixed(2) + '</td>'
          +   '<td style="padding:8px 12px;color:var(--muted);font-size:.65rem;letter-spacing:.06em">' + _escHtml(String(s.payment_method||'').toUpperCase()) + '</td>'
          + '</tr>';
      }).join('');

      wrap.innerHTML = summary
        + '<div style="overflow-x:auto;border:1px solid var(--border);background:var(--surface);border-radius:8px">'
        +   '<table style="width:100%;border-collapse:collapse;font-family:\'Space Mono\',monospace;font-size:.72rem">'
        +     '<thead><tr style="background:var(--surface2);color:var(--muted);letter-spacing:.06em">'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">DATE</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">CARD</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">SET</th>'
        +       '<th style="text-align:right;padding:10px 12px;font-weight:600;font-size:.62rem">QTY</th>'
        +       '<th style="text-align:right;padding:10px 12px;font-weight:600;font-size:.62rem">UNIT $</th>'
        +       '<th style="text-align:right;padding:10px 12px;font-weight:600;font-size:.62rem">TOTAL $</th>'
        +       '<th style="text-align:left;padding:10px 12px;font-weight:600;font-size:.62rem">PAY</th>'
        +     '</tr></thead>'
        +     '<tbody>' + body + '</tbody>'
        +   '</table>'
        + '</div>';
    }

    function exportSalesLogCsv() {
      if (!_salesLogRows || _salesLogRows.length === 0) {
        showToast('No sales to export');
        return;
      }
      const itemById = {};
      (collectionItems || []).forEach(function(c) { itemById[c.id] = c; });

      // CSV is meant to be opened in Excel / Sheets / handed to an
      // accountant, so keep the columns plain-language. Notes can
      // contain commas + quotes, so quote every cell defensively.
      const header = ['sold_at','card_name','set_name','variant','qty','unit_price','total_price','payment_method','notes','api_card_id'];
      const esc = function(v) {
        if (v == null) return '';
        const s = String(v).replace(/"/g, '""');
        return '"' + s + '"';
      };
      const lines = [header.map(esc).join(',')];
      _salesLogRows.forEach(function(s) {
        const it = itemById[s.collection_item_id] || {};
        lines.push([
          (s.sold_at || '').slice(0, 19).replace('T', ' '),
          it.card_name || '',
          it.set_name  || '',
          s.variant    || 'normal',
          s.qty        || 0,
          Number(s.unit_price  || 0).toFixed(2),
          Number(s.total_price || 0).toFixed(2),
          s.payment_method || '',
          s.notes      || '',
          s.api_card_id || '',
        ].map(esc).join(','));
      });

      const csv  = lines.join('\n');
      const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
      const url  = URL.createObjectURL(blob);
      const a    = document.createElement('a');
      const stamp = new Date().toISOString().slice(0, 10);
      a.href = url;
      a.download = 'pathbinder-sales-' + stamp + '.csv';
      document.body.appendChild(a);
      a.click();
      a.remove();
      setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
    }

    function switchOrdersTab(tab) {
      activeOrdersTab = tab;
      document.getElementById('ordersTabBuying').classList.toggle('active', tab === 'buying');
      document.getElementById('ordersTabSelling').classList.toggle('active', tab === 'selling');
      renderOrders();
    }

    function updateOrderNotification() {
      const pending = orders.filter(o =>
        (o.status === 'shipped' && o.buyer_id === currentUser?.id) ||
        (o.status === 'paid' && o.seller_id === currentUser?.id)
      ).length;
      // Roll unread messages into the same badge. Easier mental model:
      // the Orders tab badge shows "things needing your attention" —
      // whether that's an awaiting-ship order or an unread message.
      const totalBadge = pending + (typeof _totalUnreadMessages === 'number' ? _totalUnreadMessages : 0);
      const badge = document.getElementById('orderNotification');
      if (badge) {
        badge.textContent = totalBadge > 99 ? '99+' : String(totalBadge);
        badge.style.display = totalBadge > 0 ? 'flex' : 'none';
      }
    }

    // Tiny helper for the dashboard first-run welcome card. Builds one
    // CTA tile with a title, sub-copy, and a single primary button that
    // fires `onclick`. Returns an HTML string (not a node) so the caller
    // can concatenate multiples.
    function _firstRunCard(title, body, onclick, btnLabel) {
      return ''
        + '<div style="padding:14px 16px;border:1px solid var(--border);background:var(--surface2);display:flex;flex-direction:column;justify-content:space-between;min-height:140px">'
        +   '<div>'
        +     '<div style="font-family:\'Orbitron\',monospace;font-size:.78rem;color:var(--accent);font-weight:700;margin-bottom:6px;letter-spacing:.04em">' + title + '</div>'
        +     '<div style="font-size:.74rem;color:var(--muted);line-height:1.5">' + body + '</div>'
        +   '</div>'
        +   '<button type="button" onclick="' + onclick + '" style="margin-top:12px;padding:8px 12px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.72rem;font-weight:700;cursor:pointer;letter-spacing:.04em;align-self:flex-start">' + btnLabel + '</button>'
        + '</div>';
    }

    // ── Subsidiary beta invites ─────────────────────────────────────
    // Beta testers in select tiers can share invite codes with friends.
    // Quota + tier + duration come from public.subsidiary_invite_config
    // (see migration_subsidiary_invites.sql). Helpers below fetch and
    // cache the quota, render the dashboard banner, and drive the
    // generation flow. Banner is hidden for users who aren't beta
    // testers or whose tier doesn't include invites.
    let _subsidiaryQuotaCache = null;
    let _subsidiaryQuotaInflight = null;
    async function _loadSubsidiaryQuota(force) {
      if (!currentUser) return null;
      if (!force && _subsidiaryQuotaCache && _subsidiaryQuotaCache.user_id === currentUser.id) {
        return _subsidiaryQuotaCache;
      }
      if (_subsidiaryQuotaInflight) return _subsidiaryQuotaInflight;
      _subsidiaryQuotaInflight = (async function() {
        try {
          const r = await sb.rpc('beta_subsidiary_quota');
          if (r.error || !r.data || !r.data[0]) return null;
          const row = r.data[0];
          _subsidiaryQuotaCache = {
            user_id:         currentUser.id,
            used:            row.used || 0,
            remaining:       row.remaining || 0,
            granted_tier:    row.granted_tier || null,
            duration_months: row.duration_months || 0,
          };
          return _subsidiaryQuotaCache;
        } catch(_) { return null; }
        finally   { _subsidiaryQuotaInflight = null; }
      })();
      return _subsidiaryQuotaInflight;
    }
    function _subsidiaryInvitesBanner() {
      // Synchronous render — uses whatever cache value we have. The
      // caller schedules _loadSubsidiaryQuota() async on first
      // renderDashboard so the next render shows the real numbers.
      const q = _subsidiaryQuotaCache;
      if (!q || q.user_id !== currentUser?.id) return '';
      if (!q.granted_tier || (q.remaining + q.used) === 0) return '';
      const tierUpper = q.granted_tier.toUpperCase();
      const dur = q.duration_months + ' month' + (q.duration_months === 1 ? '' : 's');
      const totalSlots = q.remaining + q.used;
      const cta = q.remaining > 0
        ? `<button type="button" onclick="openGenerateSubsidiaryInviteModal()" class="ndash-banner-cta">Generate Invite Code &rarr;</button>`
        : `<div style="font-size:.7rem;color:var(--muted)">All invites used. Manage from <a href="#" onclick="openMySubsidiaryInvitesModal();return false" style="color:var(--accent)">My Invites</a>.</div>`;
      return `<div class="ndash-invite-banner" style="margin-bottom:14px;border:1.5px solid var(--copper);border-left:3px solid var(--copper);background:rgba(184,115,51,.06);padding:14px 18px;display:flex;justify-content:space-between;align-items:center;gap:14px;flex-wrap:wrap">
        <div style="flex:1;min-width:240px">
          <div style="font-family:'Orbitron',monospace;font-size:.62rem;letter-spacing:.14em;color:var(--copper);text-transform:uppercase;margin-bottom:4px">
            &#9672; Beta perk &mdash; share with a friend
          </div>
          <div style="font-size:.85rem;color:var(--text);font-weight:700;margin-bottom:2px">
            ${q.remaining}/${totalSlots} invite${totalSlots === 1 ? '' : 's'} left
          </div>
          <div style="font-size:.72rem;color:var(--muted);line-height:1.5">
            Each grants <strong style="color:var(--accent)">${tierUpper}</strong> tier for ${dur}. After that, they're prompted to subscribe or revert to free.
          </div>
        </div>
        <div style="flex-shrink:0">${cta}</div>
      </div>`;
    }
    // Modal — generate a new code
    async function openGenerateSubsidiaryInviteModal() {
      const q = await _loadSubsidiaryQuota(true);
      if (!q || q.remaining <= 0) {
        showToast('You\'ve used all your invites.');
        return;
      }
      const dur = q.duration_months + ' month' + (q.duration_months === 1 ? '' : 's');
      // Render an inline modal — keeps the panel self-contained
      const html = `
        <div class="modal-overlay" id="subsidiaryInviteGenModal" style="display:flex">
          <div class="modal" style="max-width:480px">
            <button class="modal-close" onclick="document.getElementById('subsidiaryInviteGenModal').remove()">&times;</button>
            <div style="font-size:.7rem;color:var(--copper);letter-spacing:.14em;margin-bottom:4px;text-transform:uppercase">&#9672; Generate Invite</div>
            <h3 style="margin-bottom:4px;font-size:1.1rem">Invite a friend to PathBinder</h3>
            <p class="modal-sub" style="margin-bottom:14px">
              They'll get <strong style="color:var(--accent)">${q.granted_tier.toUpperCase()}</strong> tier for ${dur}.
              You have <strong style="color:var(--text)">${q.remaining}</strong> invite${q.remaining === 1 ? '' : 's'} remaining.
            </p>
            <div id="subsidiaryInviteCodeBox" style="margin:18px 0"></div>
            <div id="subsidiaryInviteEmailBox" style="display:none;margin-bottom:14px">
              <label style="font-size:.72rem;color:var(--muted);letter-spacing:.05em;display:block;margin-bottom:6px">Email this code to your friend (optional)</label>
              <input type="email" id="subsidiaryInviteEmail" placeholder="friend@example.com" style="width:100%;padding:9px 12px;background:var(--surface);border:1px solid var(--border);color:var(--text);font-family:'Space Mono',monospace;font-size:.78rem" />
              <button type="button" onclick="sendSubsidiaryInviteEmail()" class="btn btn-secondary" style="margin-top:8px;width:100%">Send Email</button>
              <div id="subsidiaryInviteEmailStatus" style="font-size:.7rem;min-height:16px;margin-top:6px;color:var(--muted)"></div>
            </div>
            <button type="button" id="subsidiaryInviteGenBtn" onclick="generateSubsidiaryInvite()" class="btn btn-primary" style="width:100%">Generate Code</button>
          </div>
        </div>`;
      document.body.insertAdjacentHTML('beforeend', html);
    }
    let _lastGeneratedSubsidiaryCode = '';
    async function generateSubsidiaryInvite() {
      const btn = document.getElementById('subsidiaryInviteGenBtn');
      if (btn) { btn.disabled = true; btn.textContent = 'Generating…'; }
      try {
        const r = await sb.rpc('create_subsidiary_invite');
        if (r.error || !r.data || !r.data[0]) {
          showToast('Failed to generate: ' + (r.error?.message || 'unknown'));
          if (btn) { btn.disabled = false; btn.textContent = 'Generate Code'; }
          return;
        }
        const row = r.data[0];
        _lastGeneratedSubsidiaryCode = row.code;
        const box = document.getElementById('subsidiaryInviteCodeBox');
        if (box) {
          box.innerHTML = `
            <div style="background:rgba(26,199,160,.08);border:1px dashed var(--accent);padding:14px;text-align:center;border-radius:6px">
              <div style="font-size:.62rem;color:var(--muted);letter-spacing:.12em;margin-bottom:6px;text-transform:uppercase">Invite Code</div>
              <div style="font-family:'Courier New',monospace;font-size:1.25rem;letter-spacing:.18em;color:var(--accent);font-weight:700;margin-bottom:8px">${row.code}</div>
              <button type="button" onclick="navigator.clipboard.writeText('${row.code}').then(function(){showToast('Code copied')})" style="background:transparent;border:1px solid var(--accent);color:var(--accent);font-family:'Space Mono',monospace;font-size:.66rem;padding:5px 12px;cursor:pointer;letter-spacing:.04em">Copy</button>
            </div>`;
        }
        if (btn) { btn.style.display = 'none'; }
        const emailBox = document.getElementById('subsidiaryInviteEmailBox');
        if (emailBox) emailBox.style.display = '';
        // Refresh the cached quota so the banner re-renders correctly
        // next time renderDashboard fires.
        await _loadSubsidiaryQuota(true);
      } catch (e) {
        showToast('Generate failed: ' + e.message);
        if (btn) { btn.disabled = false; btn.textContent = 'Generate Code'; }
      }
    }
    async function sendSubsidiaryInviteEmail() {
      const emailInput = document.getElementById('subsidiaryInviteEmail');
      const status = document.getElementById('subsidiaryInviteEmailStatus');
      const email = (emailInput?.value || '').trim();
      if (!email || email.indexOf('@') < 0) {
        if (status) { status.style.color = 'var(--red)'; status.textContent = 'Enter a valid email.'; }
        return;
      }
      if (!_lastGeneratedSubsidiaryCode) {
        if (status) { status.style.color = 'var(--red)'; status.textContent = 'Generate a code first.'; }
        return;
      }
      if (status) { status.style.color = 'var(--muted)'; status.textContent = 'Sending…'; }
      try {
        const session = (await sb.auth.getSession()).data.session;
        const r = await fetch('/api/send-subsidiary-invite', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': 'Bearer ' + (session?.access_token || ''),
          },
          body: JSON.stringify({ email: email, code: _lastGeneratedSubsidiaryCode }),
        });
        if (!r.ok) {
          const body = await r.text();
          if (status) { status.style.color = 'var(--red)'; status.textContent = 'Send failed: ' + body.slice(0, 120); }
          return;
        }
        if (status) { status.style.color = 'var(--accent)'; status.textContent = 'Email sent to ' + email; }
      } catch (e) {
        if (status) { status.style.color = 'var(--red)'; status.textContent = 'Network error: ' + e.message; }
      }
    }
    async function openMySubsidiaryInvitesModal() {
      try {
        const { data } = await sb.from('subsidiary_invites')
          .select('id, code, granted_tier, duration_months, created_at, claimed_at, claimed_by, expires_at')
          .eq('inviter_id', currentUser.id)
          .order('created_at', { ascending: false });
        const rows = (data || []).map(function(r) {
          const status = r.claimed_at
            ? `<span style="color:var(--accent)">Claimed ${_fmtDate(r.claimed_at)}</span>${r.expires_at ? ' &middot; expires ' + _fmtDate(r.expires_at) : ''}`
            : '<span style="color:var(--muted)">Unclaimed</span>';
          return `<tr><td style="padding:8px;font-family:'Courier New',monospace">${r.code}</td><td style="padding:8px;color:var(--accent)">${(r.granted_tier||'').toUpperCase()}</td><td style="padding:8px;font-size:.74rem">${status}</td></tr>`;
        }).join('') || '<tr><td colspan="3" style="padding:14px;color:var(--muted);text-align:center">No invites generated yet.</td></tr>';
        const html = `
          <div class="modal-overlay" id="mySubsidiaryInvitesModal" style="display:flex">
            <div class="modal" style="max-width:600px">
              <button class="modal-close" onclick="document.getElementById('mySubsidiaryInvitesModal').remove()">&times;</button>
              <div style="font-size:.7rem;color:var(--copper);letter-spacing:.14em;margin-bottom:4px;text-transform:uppercase">&#9672; My Invites</div>
              <h3 style="margin-bottom:12px;font-size:1.1rem">Codes you've shared</h3>
              <table style="width:100%;border-collapse:collapse;font-size:.78rem">
                <thead><tr><th style="text-align:left;padding:8px;color:var(--muted);font-size:.66rem;letter-spacing:.08em;border-bottom:1px solid var(--border)">CODE</th><th style="text-align:left;padding:8px;color:var(--muted);font-size:.66rem;letter-spacing:.08em;border-bottom:1px solid var(--border)">TIER</th><th style="text-align:left;padding:8px;color:var(--muted);font-size:.66rem;letter-spacing:.08em;border-bottom:1px solid var(--border)">STATUS</th></tr></thead>
                <tbody>${rows}</tbody>
              </table>
            </div>
          </div>`;
        document.body.insertAdjacentHTML('beforeend', html);
      } catch (e) {
        showToast('Failed to load: ' + e.message);
      }
    }

    // ── Granted-tier expiry warning ────────────────────────────────
    // Renders an inline banner when the user's subsidiary-granted tier
    // is within 14 days of expiring. Empty string otherwise (paid
    // users, non-granted, or > 14 days out).
    function _grantedTierExpiryWarning() {
      if (!currentUser) return '';
      const exp = currentUser.granted_tier_expires_at;
      if (!exp) return '';
      const expMs = new Date(exp).getTime();
      if (isNaN(expMs)) return '';
      const now    = Date.now();
      const dayMs  = 24 * 60 * 60 * 1000;
      const remain = (expMs - now) / dayMs;
      if (remain <= 0)  return ''; // expired case handled by downgrade modal
      if (remain > 14)  return '';
      const tier   = (currentUser.subscription_tier || 'collector').toUpperCase();
      const days   = Math.ceil(remain);
      return `<div style="margin-bottom:14px;border:1.5px solid var(--yellow);border-left:3px solid var(--yellow);background:rgba(255,217,61,.06);padding:14px 18px;display:flex;justify-content:space-between;align-items:center;gap:14px;flex-wrap:wrap">
        <div style="flex:1;min-width:240px">
          <div style="font-family:'Orbitron',monospace;font-size:.62rem;letter-spacing:.14em;color:var(--yellow);text-transform:uppercase;margin-bottom:4px">
            &#9888; Your ${tier} access expires soon
          </div>
          <div style="font-size:.78rem;color:var(--text);font-weight:700;margin-bottom:2px">
            ${days} day${days === 1 ? '' : 's'} remaining
          </div>
          <div style="font-size:.72rem;color:var(--muted);line-height:1.5">
            After expiration you'll revert to the free tier. Subscribe to keep your scanner credits, listing caps, and price tracking depth.
          </div>
        </div>
        <div style="flex-shrink:0">
          <button type="button" onclick="openPricingModalWithPromo('${(currentUser.subscription_tier || 'collector').toLowerCase()}')" style="background:var(--yellow);color:#000;border:none;padding:9px 18px;font-family:'Space Mono',monospace;font-size:.72rem;font-weight:700;cursor:pointer;letter-spacing:.06em">
            Subscribe to keep it &rarr;
          </button>
        </div>
      </div>`;
    }
    // ── Post-expiry "here's what you're missing" modal ────────────
    // Called once when a user's granted tier has elapsed and they've
    // been auto-downgraded by the server-side cron. Only fires when
    // we haven't already shown it for this expiry (localStorage gate).
    function maybeShowGrantedTierExpiredModal() {
      if (!currentUser) return;
      // Trigger condition: profile has granted_tier_source=
      // 'subsidiary_invite' AND granted_tier_expires_at is in the past.
      // The cron clears both fields once it processes the expiry, so
      // if either field survives a past-due timestamp, the user just
      // landed on the new state and hasn't seen the message yet.
      const exp = currentUser.granted_tier_expires_at;
      const src = currentUser.granted_tier_source;
      if (!exp || src !== 'subsidiary_invite') return;
      if (Date.parse(exp) > Date.now()) return;
      // localStorage gate so we don't re-show on every page load
      const key = 'pathbinder_subsidiary_expired_seen_' + exp;
      try { if (localStorage.getItem(key)) return; } catch(_) {}
      try { localStorage.setItem(key, '1'); } catch(_) {}
      const html = `
        <div class="modal-overlay" id="grantedExpiredModal" style="display:flex">
          <div class="modal" style="max-width:520px">
            <button class="modal-close" onclick="document.getElementById('grantedExpiredModal').remove()">&times;</button>
            <div style="font-size:.7rem;color:var(--copper);letter-spacing:.14em;margin-bottom:4px;text-transform:uppercase">&#9672; Your trial just ended</div>
            <h3 style="margin-bottom:8px;font-size:1.15rem">Free again &mdash; here's what changes</h3>
            <p class="modal-sub" style="margin-bottom:12px">Your friend's invite gave you a taste of the paid tier. Your binder data, listings, and scans are all preserved &mdash; but the perks revert.</p>
            <div style="background:rgba(255,77,61,.06);border:1px solid var(--border);border-left:3px solid var(--red,#FF4D3D);padding:12px 16px;margin-bottom:14px">
              <div style="font-size:.66rem;letter-spacing:.12em;color:var(--red,#FF4D3D);text-transform:uppercase;margin-bottom:6px;font-weight:700">No longer available</div>
              <ul style="margin:0;padding-left:18px;font-size:.78rem;color:var(--text);line-height:1.7">
                <li>1,000 photo scans / month &rarr; 25 / month</li>
                <li>Bulk photo scan sessions &rarr; unavailable</li>
                <li>Unlimited Wishlist + Card Fund goals &rarr; 2 + 1</li>
                <li>Marketplace listing cap (if you had a paid tier)</li>
                <li>Sales archive + multi-binder organization (Enthusiast+)</li>
              </ul>
            </div>
            <div style="display:flex;gap:10px;flex-wrap:wrap">
              <button type="button" onclick="document.getElementById('grantedExpiredModal').remove();openPricingModal()" class="btn btn-primary" style="flex:1;min-width:180px">See Plans &rarr;</button>
              <button type="button" onclick="document.getElementById('grantedExpiredModal').remove()" class="btn btn-secondary" style="flex:1;min-width:140px">Continue Free</button>
            </div>
          </div>
        </div>`;
      document.body.insertAdjacentHTML('beforeend', html);
    }

    let dashboardRefreshing = false;
    function renderDashboard() {
      if (!currentUser) return;
      // Kick off subsidiary-invite quota lookup on first dashboard render
      // so the banner appears as soon as the user lands. Re-render via
      // renderDashboard once it resolves; subsequent renders use the cache.
      if (!_subsidiaryQuotaCache || _subsidiaryQuotaCache.user_id !== currentUser.id) {
        _loadSubsidiaryQuota().then(function(q) { if (q && q.granted_tier) renderDashboard(); });
      }
      // Once-per-expiry "your trial just ended" modal. No-op for users
      // who aren't on a recently-expired subsidiary grant, or who've
      // already seen it (localStorage gated).
      try { maybeShowGrantedTierExpiredModal(); } catch(_) {}
      const myListingItems = listings.filter(l => l.seller_id === currentUser.id || l.sellerId === currentUser.id);
      const activeSales    = myListingItems.filter(l => l.status === 'active' || l.status === 'available').length;
      // Awaiting-shipment count replaces the old "pending payout" alert.
      // Payouts now go on Stripe's standard schedule — sellers don't wait
      // on platform action, so the old alert was misleading.
      const awaitingShip   = orders.filter(o => o.seller_id === currentUser.id && o.status === 'paid').length;
      const totalEarned    = orders.filter(o => o.seller_id === currentUser.id && o.status === 'completed')
        .reduce((s, o) => s + (o.seller_payout || 0), 0);

      // Owned vs ghost vs sold split
      const ownedCards  = collectionItems.filter(c => !c.is_ghost && !c.sold_offline);
      const ghostCards  = collectionItems.filter(c => c.is_ghost  && !c.sold_offline);
      const soldOffline = collectionItems.filter(c => c.sold_offline);
      const totalValue = ownedCards.reduce((s, c) => s + ((c.current_value || c.purchase_price || 0) * (c.quantity || 1)), 0);
      const totalCost  = ownedCards.reduce((s, c) => s + ((c.purchase_price || 0) * (c.quantity || 1)), 0);
      const totalGain  = totalValue - totalCost;
      const gainSign   = totalGain >= 0 ? '+' : '';
      const gainPct    = totalCost > 0 ? ((totalGain / totalCost) * 100).toFixed(1) : null;

      // Top 5 by value (owned only), with condition label
      const top5 = [...ownedCards]
        .sort((a, b) => ((b.current_value || b.purchase_price || 0) * (b.quantity || 1)) - ((a.current_value || a.purchase_price || 0) * (a.quantity || 1)))
        .slice(0, 5);

      // Bar chart: top 8 per-card value
      const chartItems = [...ownedCards]
        .sort((a, b) => (b.current_value || b.purchase_price || 0) - (a.current_value || a.purchase_price || 0))
        .slice(0, 8);
      const maxVal = chartItems.length > 0 ? Math.max(...chartItems.map(c => c.current_value || c.purchase_price || 0)) : 1;
      const chartBars = chartItems.map(c => {
        const v = c.current_value || c.purchase_price || 0;
        const pct = maxVal > 0 ? (v / maxVal * 100).toFixed(1) : 0;
        const isGraded = c.condition && c.condition !== 'raw';
        const condChip = isGraded
          ? `<span class="grade-badge" style="font-size:.52rem;padding:1px 4px;margin-left:4px">${c.condition.toUpperCase()}${c.grade_value != null ? ' ' + c.grade_value : ''}</span>`
          : `<span class="raw-badge"  style="font-size:.52rem;padding:1px 4px;margin-left:4px">Raw</span>`;
        const name = c.card_name.length > 14 ? c.card_name.slice(0, 13) + '…' : c.card_name;
        return `<div class="dash-chart-row" style="grid-template-columns:130px 1fr 72px">
          <div class="dash-chart-label">${name}${condChip}</div>
          <div class="dash-chart-bar-wrap"><div class="dash-chart-bar" style="width:${pct}%"></div></div>
          <div class="dash-chart-val">$${Number(v).toLocaleString()}</div>
        </div>`;
      }).join('');

      // YTD chart from portfolio_snapshots
      const snapshots = (window._portfolioSnapshots || []);
      const ytdHtml = buildYtdChart(snapshots, totalValue);

      // Biggest movers (7-day) — all cards with price history
      const moversHtml = buildMovers(collectionItems);

      // Price alerts for ghost cards
      const alertsHtml = buildPriceAlerts(ghostCards);

      // ── New dashboard data prep ──────────────────────────────────────────
      const top8 = [...ownedCards]
        .sort((a,b) => ((b.current_value||b.purchase_price||0)*(b.quantity||1)) - ((a.current_value||a.purchase_price||0)*(a.quantity||1)))
        .slice(0,8);
      const topGhost = [...ghostCards].sort((a,b) => (b.savings_goal||0)-(a.savings_goal||0))[0] || null;
      const movers = ownedCards
        .filter(c => c.current_value && c.purchase_price && Math.abs(c.current_value - c.purchase_price) > 0.01)
        .sort((a,b) => Math.abs((b.current_value-b.purchase_price)/b.purchase_price) - Math.abs((a.current_value-a.purchase_price)/a.purchase_price))
        .slice(0,5);
      // Condition/grade breakdown
      const condMap = {};
      ownedCards.forEach(c => {
        const k = (c.condition && c.condition !== 'raw') ? c.condition.toUpperCase() : 'Raw';
        if (!condMap[k]) condMap[k] = 0;
        condMap[k] += (c.quantity||1);
      });
      const condColors = {Raw:'#1AC7A0',NM:'#4DD0E1','NEAR MINT':'#4DD0E1',LP:'#B388FF',MP:'#FFB020',HP:'var(--red,#FF4D3D)',PSA:'#FFD23F',BGS:'#B388FF',CGC:'#4DD0E1'};
      const avgVal = ownedCards.length > 0 ? totalValue / ownedCards.length : 0;
      const totalCards = ownedCards.reduce((s,c)=>s+(c.quantity||1),0);
      // Build alert items
      const dashAlerts = [];
      if (awaitingShip > 0) dashAlerts.push({ico:'warn',title:`${awaitingShip} order${awaitingShip>1?'s':''} awaiting shipment`,sub:'Add tracking once shipped — payouts go via Stripe\'s normal schedule'});
      movers.slice(0,2).forEach(c => {
        const d = ((c.current_value-c.purchase_price)/c.purchase_price*100).toFixed(1);
        const up = Number(d) >= 0;
        dashAlerts.push({ico:up?'accent':'warn',title:c.card_name,sub:`Price ${up?'↑':'↓'} ${Math.abs(d)}% vs purchase`,delta:(up?'+':'')+d+'%',up});
      });
      // Wishlist-in-marketplace alerts. For each ghost card (wishlist),
      // check whether an active marketplace listing matches by name +
      // game. When a listing exists, surface it so the user knows their
      // wishlist card is for sale. Match is case-insensitive name with
      // optional game_type tie-break, and we only show ACTIVE listings
      // (not sold / paused). Listings sorted by price ascending so the
      // user sees the cheapest first.
      try {
        const _wishMap = new Map();   // normalized name → wishlist card
        ghostCards.forEach(c => {
          const k = (c.card_name || '').toLowerCase().trim();
          if (k) _wishMap.set(k, c);
        });
        const _activeListings = (listings || []).filter(l =>
          (l.status === 'active' || l.status === 'available')
        );
        const _matched = [];
        for (const l of _activeListings) {
          const k = (l.name || '').toLowerCase().trim();
          const wish = _wishMap.get(k);
          if (!wish) continue;
          // Optional game-type sanity check when both sides have one
          if (wish.game_type && l.gameType && wish.game_type !== l.gameType) continue;
          _matched.push({
            wish,
            listing:  l,
            price:    l.list_price || l.value || 0,
            sellerId: l.seller_id || l.sellerId,
          });
        }
        // Cheapest matches first, cap to 4 alert rows so the panel
        // doesn't drown the rest of the alerts.
        _matched.sort((a, b) => a.price - b.price);
        _matched.slice(0, 4).forEach(m => {
          dashAlerts.push({
            ico:   'info',
            title: m.wish.card_name,
            sub:   `Your wishlist card is for sale — $${Number(m.price).toLocaleString()} on the marketplace`,
          });
        });
      } catch(_) { /* best-effort — don't break alerts on edge cases */ }

      const _ico = (type) => {
        if (type==='warn')   return `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>`;
        if (type==='info')   return `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 8v4M12 16h.01"/></svg>`;
        return `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg>`;
      };

      const _dh = `<div style="display:flex;align-items:center;gap:3px;flex-shrink:0;margin-left:auto"><span class="ndash-drag-handle" title="Drag to move">⠿</span><button class="ndash-collapse-btn" title="Collapse panel" onclick="dashToggleCollapse(this)">▾</button></div>`;

      const content = document.getElementById('dashboardContent');
      if (!content) return;

      // First-run welcome card. Triggers when the user has zero cards,
      // zero listings, zero orders, and zero binders — i.e. nothing to
      // surface on the dashboard yet. Shows a copper-bordered panel with
      // three clear next-actions instead of dumping a wall of $0/0/0.
      // Once the user has ANY data, the regular dashboard renders.
      const _bindersLen = (typeof binders !== 'undefined' && Array.isArray(binders)) ? binders.length : 0;
      // Gate the welcome card on actual data hydration. Without this,
      // returning users briefly flash the "Welcome to PathBinder"
      // empty-state during the async loadUserDataOnce() window — every
      // array is technically empty for ~200-800ms before the fetches
      // resolve. _initialUserDataLoaded flips true once loadCollection
      // / loadOrders / loadPortfolioSnapshots / loadBinders settle, at
      // which point the brand-new check is meaningful. While it's still
      // false we fall through to the normal dashboard render which
      // shows skeleton/zero rows that get filled in as data arrives.
      const _isBrandNew = (typeof _initialUserDataLoaded === 'undefined' || _initialUserDataLoaded)
                       && collectionItems.length === 0
                       && myListingItems.length === 0
                       && orders.length === 0
                       && _bindersLen === 0;
      if (_isBrandNew) {
        const firstName = (currentUser && (currentUser.name || currentUser.username) || '').split(' ')[0];
        const greeting  = firstName ? ('Welcome to PathBinder, ' + firstName + '.') : 'Welcome to PathBinder.';
        content.innerHTML = ''
          + '<div style="max-width:720px;margin:24px auto;padding:24px 22px;border:1px solid var(--copper-dim);background:var(--surface);border-left:3px solid var(--copper);font-family:\'Space Mono\',monospace">'
          +   '<div style="font-family:\'Orbitron\',monospace;font-size:.72rem;font-weight:800;letter-spacing:.14em;color:var(--copper);margin-bottom:6px;text-transform:uppercase">◈ Getting Started</div>'
          +   '<h2 style="font-family:\'Orbitron\',monospace;font-size:1.3rem;color:var(--text);margin:0 0 10px;letter-spacing:.04em">' + greeting + '</h2>'
          +   '<p style="font-size:.85rem;color:var(--muted);line-height:1.6;margin-bottom:22px">'
          +     'Your dashboard fills in as you add cards, list on the marketplace, or organize a binder. Pick a starting point below &mdash; you can always come back to this page from the nav.'
          +   '</p>'
          +   '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px">'
          + _firstRunCard(
              'Scan or add a card',
              'Use the phone scanner to import cards from a binder, or type one in manually.',
              'showPage(\'addCard\')',
              'Add Card &rarr;'
            )
          + _firstRunCard(
              'Browse the marketplace',
              'See what other collectors are selling. Watch listings or buy outright.',
              'showPage(\'browse\')',
              'Browse &rarr;'
            )
          + _firstRunCard(
              'Organize with a binder',
              'Create a digital binder to track sets, builds, or trade piles.',
              'showPage(\'collection\')',
              'Open Binders &rarr;'
            )
          + (tierAtLeast('enthusiast')
              ? _firstRunCard(
                  'Start selling',
                  'Connect Stripe to receive payouts, then list your first card.',
                  'openListCardModal()',
                  'List a Card &rarr;')
              : _firstRunCard(
                  'Unlock more features',
                  'Enthusiast+ tiers add bulk CSV import, multi-binder organization, and marketplace selling.',
                  'openPricingModalWithPromo(\'enthusiast\')',
                  'See Plans &rarr;'))
          + '</div>'
          + '</div>';
        return;
      }

      content.innerHTML = `<div class="ndash-wrap">

        <!-- ── Stat Ribbon ───────────────────────────────── -->
        ${_grantedTierExpiryWarning()}
        ${_subsidiaryInvitesBanner()}
        <div class="ndash-ribbon-wrap">
          <div class="ndash-ribbon-photo">
            <img src="data:image/jpeg;base64," alt="" loading="lazy" decoding="async">
            <div class="ndash-ribbon-title">
              <div class="ndash-ribbon-title-ico">◧</div>
              <div class="ndash-ribbon-title-text">My Binder</div>
            </div>
          </div>
          <div class="ndash-ribbon">
          <div class="ndash-stat primary">
            <div class="ndash-stat-lbl">Collection Value</div>
            <div class="ndash-stat-val">${totalValue > 0 ? '$'+totalValue.toLocaleString('en-US',{maximumFractionDigits:0}) : '$0'}</div>
            ${gainPct !== null ? `<div class="ndash-stat-delta ${totalGain<0?'neg':''}">${gainSign}${gainPct}% all time</div>` : ''}
          </div>
          <div class="ndash-stat">
            <div class="ndash-stat-lbl">Total Cards</div>
            <div class="ndash-stat-val">${totalCards.toLocaleString()}</div>
          </div>
          <div class="ndash-stat">
            <div class="ndash-stat-lbl">Ghost Cards</div>
            <div class="ndash-stat-val">${ghostCards.length}</div>
          </div>
          <div class="ndash-stat">
            <div class="ndash-stat-lbl">Listings</div>
            <div class="ndash-stat-val">${activeSales}</div>
          </div>
          <div class="ndash-stat">
            <div class="ndash-stat-lbl">Net Gain</div>
            <div class="ndash-stat-val" style="color:${totalGain>=0?'var(--accent)':'var(--red,#FF4D3D)'}">${gainPct !== null ? gainSign+'$'+Math.abs(totalGain).toLocaleString('en-US',{maximumFractionDigits:0}) : '—'}</div>
          </div>
          </div>
        </div>

        <!-- ── Two-column grid ──────────────────────────── -->
        <div class="ndash-grid">

          <!-- Main column: binder → price-movers (default layout) -->
          <div class="ndash-main" id="dashMain">

            <!-- My Binder top cards -->
            <div class="ndash-panel" data-panel-id="binder">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">
                  <div class="ndash-panel-title-ico"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg></div>
                  My Binder
                </div>
                <div style="display:flex;align-items:center;gap:6px">
                  <button class="ndash-panel-link" onclick="showPage('addCard');setMobileNav('addCard')">+ ADD</button>
                  <button class="ndash-panel-link" onclick="showPage('collection');setMobileNav('collection')">VIEW ALL →</button>
                  ${_dh}
                </div>
              </div>
              <div class="ndash-panel-body">
                ${top8.length > 0 ? `<div class="ndash-card-grid">
                  ${top8.map((item,i) => {
                    const v = (item.current_value||item._compEstimate||item.purchase_price||0)*(item.quantity||1);
                    return `<div class="ndash-tcard" onclick="openBinderCardDetail('${item.id}')">
                      <div class="ndash-tcard-art">
                        ${item.card_image_url
                          ? `<img src="${_pickThumbVariant(item.card_image_url, 200)}" data-fallback="${item.card_image_url}" alt="${_escHtml(item.card_name)}" loading="lazy" decoding="async" onerror="if(this.dataset.fallback&&this.src!==this.dataset.fallback){this.src=this.dataset.fallback}else{_binderImgFail(this,'${item.id}')}">`
                          : `<div class="ndash-tcard-art-ph">${_escHtml(item.card_name.slice(0,12))}</div>`}
                      </div>
                      <div class="ndash-tcard-foot">
                        <div class="ndash-tcard-name">${_escHtml(item.card_name.slice(0,16))}</div>
                        ${v>0?`<div class="ndash-tcard-val">$${v.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}</div>`:''}
                      </div>
                    </div>`;
                  }).join('')}
                </div>` : `<div style="text-align:center;padding:32px;color:var(--muted);font-size:.8rem">No cards yet — add your first card to get started</div>`}
              </div>
            </div>

            <!-- Price Movers — toggle between GLOBAL market and YOUR
                 collection, swap period (24h / 7d) and sort (% / $).
                 Mobile-friendly: three 2-state pill toggles that wrap. -->
            <div class="ndash-panel" data-panel-id="price-movers">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">Price Movers</div>
                <div style="display:flex;align-items:center;gap:6px">
                  <button class="ndash-panel-link" onclick="showPage('browse');setMobileNav('browse')">BROWSE →</button>
                  ${_dh}
                </div>
              </div>
              <!-- Toggle row: scope / direction / period / product_type.
                   Wraps on mobile so each pair drops to its own line if
                   width is tight. Direction = ↑/↓ swap, shows only the
                   selected list (top up-movers OR top down-movers).
                   Product type = Singles (TCG cards) / Sealed (boxes,
                   ETBs, tins, decks, etc.). -->
              <div class="movers-toggles">
                <div class="movers-toggle-pair">
                  <button class="movers-toggle ${_moversScope==='global'?'active':''}"   onclick="setMoversScope('global')">Global</button>
                  <button class="movers-toggle ${_moversScope==='personal'?'active':''}" onclick="setMoversScope('personal')">Yours</button>
                </div>
                <div class="movers-toggle-pair">
                  <button class="movers-toggle ${_moversDirection==='up'?'active':''}"   onclick="setMoversDirection('up')"   title="Top gainers">↑</button>
                  <button class="movers-toggle ${_moversDirection==='down'?'active':''}" onclick="setMoversDirection('down')" title="Top losers">↓</button>
                </div>
                <div class="movers-toggle-pair">
                  <button class="movers-toggle ${_moversPeriod===1?'active':''}" onclick="setMoversPeriod(1)">24h</button>
                  <button class="movers-toggle ${_moversPeriod===7?'active':''}" onclick="setMoversPeriod(7)">7d</button>
                </div>
                <div class="movers-toggle-pair" title="TCG singles vs sealed product (booster boxes, ETBs, tins, decks)">
                  <button class="movers-toggle ${_moversProductType==='single'?'active':''}" onclick="setMoversProductType('single')">SNG</button>
                  <button class="movers-toggle ${_moversProductType==='sealed'?'active':''}" onclick="setMoversProductType('sealed')">SLD</button>
                </div>
              </div>
              <div class="ndash-panel-body">
                ${moversHtml || `<div style="text-align:center;padding:20px;color:var(--muted);font-size:.75rem">Price data builds as cards are refreshed</div>`}
              </div>
            </div>

          </div><!-- /ndash-main -->

          <!-- Right Rail: scan-cta → alerts → storefront → portfolio → ghost-fund → breakdown → value-summary -->
          <div class="ndash-rail" id="dashRail">

            <!-- Scan CTA -->
            <div class="ndash-panel ndash-scan-wrap" data-panel-id="scan-cta" style="position:relative">
              <div style="position:absolute;top:7px;right:8px;z-index:3;display:flex;align-items:center">
                <span class="ndash-drag-handle" title="Drag to move" style="color:rgba(0,0,0,0.45);font-size:13px">⠿</span>
              </div>
              <div class="ndash-panel-body" style="padding:0">
                <button class="ndash-scan-cta" onclick="showPage('addCard');setMobileNav('addCard')">
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><circle cx="17.5" cy="17.5" r="2.5"/></svg>
                  SCAN CARD
                </button>
              </div>
            </div>

            <!-- Scan Product CTA — shop tier only. Hidden for free /
                 collector / vendor users via inline style decision below.
                 Routes to the SEPARATE product scanner (not the card
                 scanner) so shops can OCR Funko Pops + other non-TCG
                 products to autofill their listings. -->
            ${(() => {
              // Product scanner moved from shop-only to vendor+ as part of
              // the new tier structure. Vendor tier ($50/mo) and Shop tier
              // ($150/mo) both unlock the non-TCG product scanner. Admins
              // always qualify regardless of tier.
              if (!hasProductScanner() && !(currentUser && currentUser.is_admin)) return '';
              return `<div class="ndash-panel ndash-scan-wrap" data-panel-id="scan-product-cta" style="position:relative;margin-top:10px">
                <div style="position:absolute;top:7px;right:8px;z-index:3;display:flex;align-items:center">
                  <span class="ndash-drag-handle" title="Drag to move" style="color:rgba(0,0,0,0.45);font-size:13px">⠿</span>
                </div>
                <div class="ndash-panel-body" style="padding:0">
                  <button class="ndash-scan-cta" onclick="openProductScanner()" style="background:var(--copper);color:#1a0a00;box-shadow:4px 4px 0 #000,0 0 24px rgba(184,115,51,.35)">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18l-2 14H5L3 6z"/><path d="M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                    SCAN PRODUCT
                  </button>
                </div>
              </div>`;
            })()}

            <!-- Alerts -->
            <div class="ndash-panel" data-panel-id="alerts">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">
                  Alerts
                  ${dashAlerts.length>0?`<span style="background:var(--accent);color:var(--text-on-accent);font-family:'Press Start 2P',monospace;font-size:7px;padding:3px 6px;margin-left:6px">${Math.min(dashAlerts.length,9)}</span>`:''}
                </div>
                ${_dh}
              </div>
              <div class="ndash-panel-body">
                ${dashAlerts.length>0 ? dashAlerts.slice(0,6).map(a=>`
                <div class="ndash-alert-row">
                  <div class="ndash-alert-ico ${a.ico==='warn'?'warn':a.ico==='info'?'info':''}">${_ico(a.ico)}</div>
                  <div class="ndash-alert-body">
                    <div class="ndash-alert-title">${_escHtml(a.title)}${a.delta?` <span style="color:${a.up?'var(--accent)':'var(--red,#FF4D3D)'}">${a.delta}</span>`:''}</div>
                    <div class="ndash-alert-sub">${_escHtml(a.sub)}</div>
                  </div>
                </div>`).join('') : '<div style="text-align:center;padding:16px;color:var(--muted);font-size:.75rem">No alerts</div>'}
              </div>
            </div>

            ${tierAtLeast('shop') ? `<div class="ndash-panel" data-panel-id="storefront">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">Storefront</div>
                <div style="display:flex;align-items:center;gap:6px">
                  <button class="ndash-panel-link" onclick="previewStorefront()">PREVIEW →</button>
                  ${_dh}
                </div>
              </div>
              <div class="ndash-panel-body" style="display:grid;gap:7px">
                <div class="ndash-sum-row"><div class="ndash-sum-l">Listings</div><div class="ndash-sum-r">${activeSales}</div></div>
                ${totalEarned>0?`<div class="ndash-sum-row"><div class="ndash-sum-l">Earned</div><div class="ndash-sum-r" style="color:var(--accent)">$${totalEarned.toFixed(2)}</div></div>`:''}
                ${awaitingShip>0?`<div class="ndash-sum-row"><div class="ndash-sum-l">To Ship</div><div class="ndash-sum-r" style="color:var(--yellow,#FFDD44)">${awaitingShip} order${awaitingShip>1?'s':''}</div></div>`:''}
                <div style="display:flex;gap:6px;margin-top:4px">
                  <button class="ndash-panel-link" style="border-color:var(--border);flex:1;text-align:center" onclick="copyStoreLink()">⬡ COPY LINK</button>
                  <button class="ndash-panel-link" style="border-color:var(--border);flex:1;text-align:center" onclick="openListCardModal()">+ LIST CARD</button>
                </div>
              </div>
            </div>` : ''}

            <!-- P&L Overview — collector+ -->
            ${tierAtLeast('collector') ? (() => {
              // Build last-6-months P&L from offline sales + marketplace orders
              const now = new Date();
              const months = Array.from({length:6}, (_,i) => {
                const d = new Date(now.getFullYear(), now.getMonth() - (5-i), 1);
                return { key: d.toISOString().slice(0,7), label: d.toLocaleString('default',{month:'short'}), rev:0, cost:0 };
              });
              const mMap = Object.fromEntries(months.map(m => [m.key, m]));
              collectionItems.filter(c => c.sold_offline && c.offline_sale_date).forEach(c => {
                const mk = (c.offline_sale_date||'').slice(0,7);
                if (mMap[mk]) { mMap[mk].rev += (c.offline_sale_price||0); mMap[mk].cost += (c.purchase_price||0); }
              });
              orders.filter(o => o.seller_id===currentUser.id && o.status==='completed').forEach(o => {
                const mk = new Date(o.created_at).toISOString().slice(0,7);
                if (mMap[mk]) mMap[mk].rev += (o.seller_payout||0);
              });
              const realizedTotal = months.reduce((s,m) => s + m.rev - m.cost, 0);
              const unrealized    = totalGain;
              const maxAbs = Math.max(1, ...months.map(m => Math.abs(m.rev - m.cost)));
              const bars = months.map(m => {
                const profit = m.rev - m.cost;
                const pct    = Math.min(100, Math.abs(profit) / maxAbs * 100).toFixed(1);
                const color  = profit >= 0 ? 'var(--accent)' : 'var(--red,#FF4D3D)';
                return `<div style="display:flex;flex-direction:column;align-items:center;gap:3px;flex:1">
                  <div style="font-size:8px;color:${color};font-weight:700;white-space:nowrap">${profit===0?'':((profit>0?'+':'')+'$'+Math.abs(profit).toFixed(0))}</div>
                  <div style="flex:1;width:100%;display:flex;align-items:flex-end;justify-content:center">
                    <div style="width:80%;background:${color};opacity:.85;border-radius:2px 2px 0 0;height:${profit===0?'2px':pct+'%'};min-height:${profit===0?'2px':'3px'};transition:height .3s"></div>
                  </div>
                  <div style="font-size:8px;color:var(--muted);letter-spacing:.04em">${m.label}</div>
                </div>`;
              }).join('');
              return `<div class="ndash-panel" data-panel-id="pnl">
                <div class="ndash-panel-h">
                  <div class="ndash-panel-title">
                    <span class="ndash-panel-title-ico"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg></span>
                    P&L
                  </div>
                  ${_dh}
                </div>
                <div class="ndash-panel-body">
                  <!-- 6-month bar chart -->
                  <div style="display:flex;height:72px;gap:3px;margin-bottom:10px;padding:0 2px">${bars}</div>
                  <div style="height:1px;background:rgba(26,199,160,.1);margin-bottom:10px"></div>
                  <!-- Summary rows -->
                  <div class="ndash-sum-row"><div class="ndash-sum-l">Realized</div><div class="ndash-sum-r" style="color:${realizedTotal>=0?'var(--accent)':'var(--red,#FF4D3D)'}">${realizedTotal>=0?'+':''}$${Math.abs(realizedTotal).toFixed(2)}</div></div>
                  <div class="ndash-sum-row"><div class="ndash-sum-l">Unrealized</div><div class="ndash-sum-r" style="color:${unrealized>=0?'var(--accent)':'var(--red,#FF4D3D)'}">${unrealized>=0?'+':''}$${Math.abs(unrealized).toFixed(2)}</div></div>
                  <div class="ndash-sum-row"><div class="ndash-sum-l">Combined</div><div class="ndash-sum-r" style="font-weight:700;color:${(realizedTotal+unrealized)>=0?'var(--accent)':'var(--red,#FF4D3D)'}">${(realizedTotal+unrealized)>=0?'+':''}$${Math.abs(realizedTotal+unrealized).toFixed(2)}</div></div>
                  ${soldOffline.length>0||totalEarned>0?`<div style="margin-top:8px;padding-top:8px;border-top:1px solid rgba(26,199,160,.08)">
                    <button class="ndash-panel-link" onclick="showPage('account');setMobileNav('account');setTimeout(()=>document.querySelector('[data-tab=sales]')?.click(),200)">FULL REPORT →</button>
                  </div>`:''}
                </div>
              </div>`;
            })() : ''}

            <!-- Portfolio Value chart -->
            ${ytdHtml ? `<div class="ndash-panel ndash-ytd-wrap" data-panel-id="portfolio">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">Portfolio Value</div>
                ${_dh}
              </div>
              <div class="ndash-panel-body ndash-ytd-compact">${ytdHtml}</div>
            </div>` : ''}

            <!-- Ghost Card Fund — multi-card list, populates more rows
                 as the panel is stretched (see _refreshGhostFundList) -->
            <div class="ndash-panel" data-panel-id="ghost-fund">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">Ghost Card Fund</div>
                <div style="display:flex;align-items:center;gap:6px">
                  ${ghostCards.length>1?`<button class="ndash-panel-link" onclick="showPage('collection');setMobileNav('collection')">${ghostCards.length} CARDS</button>`:''}
                  ${_dh}
                </div>
              </div>
              <div class="ndash-panel-body">
                ${ghostCards.length > 0
                  ? `<div class="ndash-fund-list" id="ndashFundList"></div>`
                  : `<div style="text-align:center;padding:20px;color:var(--muted);font-size:.75rem">No wishlist cards yet</div>`}
              </div>
            </div>

            <!-- Condition Breakdown -->
            <div class="ndash-panel" data-panel-id="breakdown">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">Breakdown</div>
                ${_dh}
              </div>
              <div class="ndash-panel-body">
                ${Object.entries(condMap).length>0 ? Object.entries(condMap).map(([k,cnt]) => {
                  const col = condColors[k] || '#1AC7A0';
                  return `<div class="ndash-bk-row">
                    <div class="ndash-bk-l">
                      <div class="ndash-bk-dot" style="background:${col};box-shadow:0 0 5px ${col}"></div>
                      <span>${_escHtml(k)}</span>
                    </div>
                    <div class="ndash-bk-val">${cnt}</div>
                  </div>`;
                }).join('') : '<div style="color:var(--muted);font-size:10px;text-align:center;padding:10px 0">No cards yet</div>'}
                ${ghostCards.length>0?`<div class="ndash-bk-row">
                  <div class="ndash-bk-l"><div class="ndash-bk-dot" style="background:#4DD0E1;box-shadow:0 0 5px #4DD0E1"></div><span>Ghost</span></div>
                  <div class="ndash-bk-val">${ghostCards.length}</div>
                </div>`:''}
              </div>
            </div>

            <!-- Value Summary -->
            <div class="ndash-panel" data-panel-id="value-summary">
              <div class="ndash-panel-h">
                <div class="ndash-panel-title">Value Summary</div>
                ${_dh}
              </div>
              <div class="ndash-panel-body" style="display:grid;gap:7px">
                <div class="ndash-sum-row"><div class="ndash-sum-l">Portfolio</div><div class="ndash-sum-r" style="color:var(--accent)">${totalValue>0?'$'+totalValue.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}):'—'}</div></div>
                <div class="ndash-sum-row"><div class="ndash-sum-l">Cost Basis</div><div class="ndash-sum-r">$${totalCost.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}</div></div>
                <div class="ndash-sum-row"><div class="ndash-sum-l">Net Gain</div><div class="ndash-sum-r" style="color:${totalGain>=0?'var(--accent)':'var(--red,#FF4D3D)'}">${gainSign}$${Math.abs(totalGain).toFixed(2)}</div></div>
                <div class="ndash-sum-row"><div class="ndash-sum-l">Avg Card</div><div class="ndash-sum-r">${avgVal>0?'$'+avgVal.toFixed(2):'—'}</div></div>
                <div class="ndash-sum-row"><div class="ndash-sum-l">Total Earned</div><div class="ndash-sum-r">${totalEarned>0?'$'+totalEarned.toFixed(2):'—'}</div></div>
              </div>
            </div>

          </div><!-- /ndash-rail -->
        </div><!-- /ndash-grid -->

        <!-- Reset layout — bottom right -->
        <div style="display:flex;justify-content:flex-end;margin-top:16px;padding-bottom:8px">
          <button class="ndash-reset-btn" onclick="resetDashOrder()">↺ RESET LAYOUT</button>
        </div>

      </div><!-- /ndash-wrap -->`;
      // Restore saved layout order, then wire drag-and-drop + resize
      loadDashOrder();
      initDashDrag();
      initDashResize();
      // Draw YTD SVG line chart after DOM is settled
      drawYtdChart(snapshots, totalValue);
      // Append the Discord-connect panel below everything else so it
      // doesn't disturb the draggable dashboard layout. Self-contained
      // small panel — handles its own state via _renderDiscordConnect.
      _renderDiscordConnect();
    }

    // ── Discord link card on the Account dashboard ──────────────────
    // Renders one of three states:
    //   • Unlinked → full panel with code input (the second half of the
    //     /link DM flow).
    //   • Linked + not dismissed → compact one-line "✓ Linked as @user"
    //     strip with × hide button.
    //   • Linked + dismissed (localStorage flag set) → nothing renders.
    //     User can bring it back by clearing pb_hide_discord_panel in
    //     devtools (no Settings page yet to surface the toggle).
    //
    // Concurrency: the original implementation had a race window between
    // "check prior" and "insertAdjacentHTML" — if /link confirmed twice
    // in quick succession, two panels appended. We now (a) drop concurrent
    // calls with a reentrancy flag and (b) belt-and-suspenders sweep ALL
    // existing #discordConnectPanel nodes before appending.
    let _discordPanelRendering = false;
    async function _renderDiscordConnect() {
      if (_discordPanelRendering) return;
      _discordPanelRendering = true;
      try {
        const host = document.getElementById('dashboardContent');
        if (!host || !currentUser) return;
        // Wipe ALL prior panels — querySelectorAll catches duplicates
        // even if a previous race let two slip in.
        document.querySelectorAll('#discordConnectPanel').forEach(n => n.remove());

        let linked = null;
        try {
          const r = await sb.from('discord_links')
            .select('discord_user_id, discord_username, linked_at')
            .eq('user_id', currentUser.id)
            .maybeSingle();
          linked = (r && r.data) || null;
        } catch (_) { /* table may not exist yet pre-migration */ return; }

        // Re-check after the async query — the dashboard may have been
        // torn down while we were waiting (user navigated away).
        const host2 = document.getElementById('dashboardContent');
        if (!host2) return;
        // And re-sweep in case a parallel render slipped through.
        document.querySelectorAll('#discordConnectPanel').forEach(n => n.remove());

        // Linked + dismissed → render nothing.
        const dismissed = (() => {
          try { return localStorage.getItem('pb_hide_discord_panel') === '1'; }
          catch (_) { return false; }
        })();
        if (linked && dismissed) return;

        const inner = linked
          // Linked → compact one-line strip. Less visual weight, dismissable.
          ? `<div style="display:flex;align-items:center;gap:10px;padding:8px 14px;font-size:.7rem">
              <span style="color:#5865F2">◇</span>
              <span style="color:var(--muted)">Discord linked as</span>
              <strong style="color:var(--accent)">@${_escHtml(linked.discord_username || linked.discord_user_id)}</strong>
              <button onclick="_disconnectDiscord()" title="Disconnect"
                style="margin-left:auto;padding:3px 9px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.6rem;letter-spacing:.04em;cursor:pointer;border-radius:var(--r-sm,6px)">Disconnect</button>
              <button onclick="_hideDiscordPanel()" title="Hide this card"
                style="padding:3px 7px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.7rem;line-height:1;cursor:pointer;border-radius:var(--r-sm,6px)">×</button>
            </div>`
          // Unlinked → full panel with code input.
          : `<div class="pb-panel-h" style="padding:10px 14px"><div class="pb-panel-title">`
            + `<span class="pb-panel-title-ico" style="color:#5865F2">◇</span>Discord`
            + `</div></div>`
            + `<div class="pb-panel-body" style="padding:12px 14px">`
            + `<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">`
            +   `<div style="flex:1;min-width:220px;font-size:.7rem;color:var(--muted);line-height:1.5">`
            +     `Run <code style="color:var(--accent)">/link</code> in the PathBinder Discord, then paste the code I DM you here.`
            +   `</div>`
            +   `<input type="text" id="discordLinkCodeInput" placeholder="ABC-XYZ" maxlength="10"`
            +     ` style="padding:7px 10px;background:var(--surface2);border:1px solid var(--border);color:var(--text);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.8rem;letter-spacing:.1em;text-transform:uppercase;width:120px;outline:none;border-radius:var(--r-sm,6px)"`
            +     ` onkeydown="if(event.key==='Enter')_confirmDiscordLink()">`
            +   `<button onclick="_confirmDiscordLink()" style="padding:7px 16px;border:1px solid var(--accent);background:var(--accent);color:var(--text-on-accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;font-weight:700;letter-spacing:.06em;cursor:pointer;border-radius:var(--r-sm,6px)">Connect</button>`
            + `</div>`
            + `<div id="discordLinkStatus" style="margin-top:6px;font-size:.62rem;color:var(--muted);min-height:1em"></div>`
            + `</div>`;

        // Compact strip uses no panel chrome; full panel uses pb-panel.
        const wrapClass = linked ? 'pb-panel' : 'pb-panel';
        host2.insertAdjacentHTML('beforeend',
          `<div id="discordConnectPanel" class="${wrapClass}" style="margin-top:14px;border-left:3px solid #5865F2">`
          + inner
          + '</div>'
        );
      } finally {
        _discordPanelRendering = false;
      }
    }

    // Hide the linked-state panel for this browser. Stored client-side
    // (localStorage) so other devices keep showing it. To re-show: run
    // `localStorage.removeItem('pb_hide_discord_panel')` in devtools.
    // (Pending a real Account Settings page where this becomes a toggle.)
    function _hideDiscordPanel() {
      try { localStorage.setItem('pb_hide_discord_panel', '1'); } catch (_) {}
      document.querySelectorAll('#discordConnectPanel').forEach(n => n.remove());
      try { showToast('Hidden. To show again, clear pb_hide_discord_panel in browser storage.'); } catch (_) {}
    }

    async function _confirmDiscordLink() {
      const input  = document.getElementById('discordLinkCodeInput');
      const status = document.getElementById('discordLinkStatus');
      if (!input || !currentUser) return;
      const code = (input.value || '').trim().toUpperCase().replace(/\s+/g, '');
      if (code.length < 6) {
        if (status) { status.style.color = 'var(--gold)'; status.textContent = 'Enter the code from /link.'; }
        return;
      }
      if (status) { status.style.color = 'var(--muted)'; status.textContent = 'Confirming…'; }
      try {
        const r = await sb.rpc('confirm_discord_link', { p_code: code });
        if (r.error) throw new Error(r.error.message);
        const ok = r.data && r.data.length > 0;
        if (!ok) {
          if (status) { status.style.color = 'var(--red)'; status.textContent = 'Code not found or expired. Run /link in Discord again.'; }
          return;
        }
        if (status) { status.style.color = 'var(--green)'; status.textContent = '✓ Linked. Run /tier in Discord to grant your role.'; }
        setTimeout(_renderDiscordConnect, 800);
      } catch (e) {
        if (status) { status.style.color = 'var(--red)'; status.textContent = 'Failed: ' + (e.message || 'unknown'); }
      }
    }

    async function _disconnectDiscord() {
      if (!currentUser) return;
      if (!confirm('Disconnect your Discord account from PathBinder? Your Discord role will stop syncing.')) return;
      try {
        await sb.from('discord_links').delete().eq('user_id', currentUser.id);
        // Clear the dismissal flag too — once disconnected the user
        // probably wants the panel back so they can re-link.
        try { localStorage.removeItem('pb_hide_discord_panel'); } catch (_) {}
        _renderDiscordConnect();
      } catch (e) { showToast('Disconnect failed: ' + (e.message || 'unknown')); }
    }

    // ── Dashboard drag-and-drop ──────────────────────────────────────────────
    var _dashDragSrc = null;

    function initDashDrag() {
      var panels = document.querySelectorAll('[data-panel-id]');
      panels.forEach(function(panel) {
        panel.setAttribute('draggable', 'false'); // only activated via handle
        var handle = panel.querySelector('.ndash-drag-handle');
        if (handle) {
          handle.addEventListener('mousedown', function() {
            panel.setAttribute('draggable', 'true');
          });
        }
        panel.addEventListener('dragstart', function(e) {
          _dashDragSrc = panel;
          e.dataTransfer.effectAllowed = 'move';
          e.dataTransfer.setData('text/plain', panel.dataset.panelId);
          setTimeout(function() { panel.classList.add('ndash-dragging'); }, 0);
        });
        panel.addEventListener('dragend', function() {
          panel.classList.remove('ndash-dragging');
          panel.setAttribute('draggable', 'false');
          document.querySelectorAll('[data-panel-id]').forEach(function(p) { p.classList.remove('ndash-drag-over'); });
          document.querySelectorAll('.ndash-main,.ndash-rail').forEach(function(c) { c.classList.remove('ndash-col-over'); });
          _dashDragSrc = null;
          saveDashOrder();
        });
        panel.addEventListener('dragover', function(e) {
          e.preventDefault();
          if (!_dashDragSrc || _dashDragSrc === panel) return;
          document.querySelectorAll('[data-panel-id]').forEach(function(p) { p.classList.remove('ndash-drag-over'); });
          panel.classList.add('ndash-drag-over');
        });
        panel.addEventListener('dragleave', function(e) {
          if (!panel.contains(e.relatedTarget)) panel.classList.remove('ndash-drag-over');
        });
        panel.addEventListener('drop', function(e) {
          e.preventDefault();
          e.stopPropagation();
          panel.classList.remove('ndash-drag-over');
          if (!_dashDragSrc || _dashDragSrc === panel) return;
          var dstParent = panel.parentElement;
          var rect = panel.getBoundingClientRect();
          var midY = rect.top + rect.height / 2;
          if (e.clientY < midY) {
            dstParent.insertBefore(_dashDragSrc, panel);
          } else {
            dstParent.insertBefore(_dashDragSrc, panel.nextSibling);
          }
        });
      });

      // Allow dropping onto the column containers (append to end of column)
      document.querySelectorAll('.ndash-main, .ndash-rail').forEach(function(col) {
        col.addEventListener('dragover', function(e) {
          e.preventDefault();
          col.classList.add('ndash-col-over');
        });
        col.addEventListener('dragleave', function(e) {
          if (!col.contains(e.relatedTarget)) col.classList.remove('ndash-col-over');
        });
        col.addEventListener('drop', function(e) {
          e.preventDefault();
          col.classList.remove('ndash-col-over');
          if (!_dashDragSrc) return;
          // Only act if dropped directly on column, not a child panel (child panels call stopPropagation)
          col.appendChild(_dashDragSrc);
        });
      });

      // ── Touch drag for mobile (HTML5 drag API doesn't fire on mobile) ────────
      (function() {
        var tSrc = null, tClone = null, tTimer = null, tActive = false;
        var tOffX = 0, tOffY = 0, tStartX = 0, tStartY = 0;

        function tCleanup() {
          clearTimeout(tTimer); tTimer = null; tActive = false;
          if (tClone && tClone.parentNode) tClone.parentNode.removeChild(tClone);
          tClone = null;
          if (tSrc) { tSrc.style.opacity = ''; tSrc.classList.remove('ndash-dragging'); }
          tSrc = null;
          document.querySelectorAll('[data-panel-id]').forEach(function(p) { p.classList.remove('ndash-drag-over'); });
        }

        document.addEventListener('touchstart', function(e) {
          var handle = e.target.closest('.ndash-drag-handle');
          if (!handle) return;
          var panel = handle.closest('[data-panel-id]');
          if (!panel) return;
          tSrc = panel;
          var t = e.touches[0];
          var rect = panel.getBoundingClientRect();
          tOffX = t.clientX - rect.left;
          tOffY = t.clientY - rect.top;
          tStartX = t.clientX; tStartY = t.clientY;

          tTimer = setTimeout(function() {
            tActive = true;
            tClone = panel.cloneNode(true);
            Object.assign(tClone.style, {
              position: 'fixed', zIndex: '9999', pointerEvents: 'none',
              width: rect.width + 'px', opacity: '0.85',
              top: rect.top + 'px', left: rect.left + 'px',
              transform: 'scale(1.03) rotate(0.5deg)',
              boxShadow: '0 8px 32px rgba(0,0,0,0.55)',
              transition: 'none'
            });
            document.body.appendChild(tClone);
            panel.style.opacity = '0.25';
            panel.classList.add('ndash-dragging');
            if (navigator.vibrate) navigator.vibrate(30);
          }, 200);
        }, { passive: true });

        document.addEventListener('touchmove', function(e) {
          if (!tActive) {
            if (!tTimer) return;
            var t0 = e.touches[0];
            var dx = Math.abs(t0.clientX - tStartX), dy = Math.abs(t0.clientY - tStartY);
            if (dx > 8 || dy > 8) { clearTimeout(tTimer); tTimer = null; tSrc = null; return; }
            e.preventDefault();
            return;
          }
          e.preventDefault();
          var t = e.touches[0];
          tClone.style.left = (t.clientX - tOffX) + 'px';
          tClone.style.top  = (t.clientY - tOffY) + 'px';

          // Highlight panel under finger
          tClone.style.visibility = 'hidden';
          var el = document.elementFromPoint(t.clientX, t.clientY);
          tClone.style.visibility = '';
          document.querySelectorAll('[data-panel-id]').forEach(function(p) { p.classList.remove('ndash-drag-over'); });
          var over = el && el.closest('[data-panel-id]');
          if (over && over !== tSrc) over.classList.add('ndash-drag-over');
        }, { passive: false });

        document.addEventListener('touchend', function(e) {
          if (!tActive) { clearTimeout(tTimer); tTimer = null; tSrc = null; return; }
          var t = e.changedTouches[0];
          tClone.style.visibility = 'hidden';
          var el = document.elementFromPoint(t.clientX, t.clientY);
          tClone.style.visibility = '';
          var over = el && el.closest('[data-panel-id]');
          if (over && over !== tSrc) {
            var rect = over.getBoundingClientRect();
            var midY = rect.top + rect.height / 2;
            var dstParent = over.parentElement;
            if (t.clientY < midY) dstParent.insertBefore(tSrc, over);
            else dstParent.insertBefore(tSrc, over.nextSibling);
            saveDashOrder();
          }
          tCleanup();
        }, { passive: true });

        document.addEventListener('touchcancel', tCleanup, { passive: true });
      })();
    }

    function saveDashOrder() {
      try {
        var main = [...document.querySelectorAll('.ndash-main [data-panel-id]')].map(function(p) { return p.dataset.panelId; });
        var rail = [...document.querySelectorAll('.ndash-rail [data-panel-id]')].map(function(p) { return p.dataset.panelId; });
        localStorage.setItem('pb_dash_order_v1', JSON.stringify({ main: main, rail: rail }));
      } catch(_) {}
    }

    function loadDashOrder() {
      try {
        var raw = localStorage.getItem('pb_dash_order_v1');
        if (!raw) return;
        var saved = JSON.parse(raw);
        var mainCol = document.getElementById('dashMain');
        var railCol = document.getElementById('dashRail');
        if (!mainCol || !railCol) return;
        var allIds = (saved.main || []).concat(saved.rail || []);
        allIds.forEach(function(id) {
          var panel = document.querySelector('[data-panel-id="' + id + '"]');
          if (!panel) return;
          var col = (saved.rail || []).includes(id) ? railCol : mainCol;
          col.appendChild(panel);
        });
      } catch(_) {}
    }

    function resetDashOrder() {
      try { localStorage.removeItem('pb_dash_order_v1'); } catch(_) {}
      renderDashboard();
    }

    // ── Dashboard Panel Resize ───────────────────────────────────────────────
    // Adds a drag handle at the bottom of each panel. Heights are stored in
    // localStorage and restored on next load. The binder panel dynamically
    // injects more cards as it grows.

    var DASH_HEIGHTS_KEY = 'pb_dash_heights_v1';
    var _dashResizeObs = null;

    function saveDashHeights() {
      try {
        var out = {};
        document.querySelectorAll('[data-panel-id]').forEach(function(p) {
          if (p.style.height) out[p.dataset.panelId] = p.style.height;
        });
        localStorage.setItem(DASH_HEIGHTS_KEY, JSON.stringify(out));
      } catch(_) {}
    }

    function loadDashHeights() {
      try {
        var raw = localStorage.getItem(DASH_HEIGHTS_KEY);
        if (!raw) return;
        var saved = JSON.parse(raw);
        Object.keys(saved).forEach(function(id) {
          var p = document.querySelector('[data-panel-id="' + id + '"]');
          if (p) p.style.height = saved[id];
        });
      } catch(_) {}
    }

    // ── Panel collapse ───────────────────────────────────────────────────────
    var DASH_COLLAPSE_KEY = 'pb_dash_collapse_v1';

    function dashToggleCollapse(btn) {
      var panel = btn.closest('[data-panel-id]');
      if (!panel) return;
      var body = panel.querySelector('.ndash-panel-body');
      var isCollapsed = panel.classList.contains('ndash-collapsed');

      if (!isCollapsed) {
        // ── Collapsing ──
        if (body) {
          body.style.maxHeight = body.scrollHeight + 'px';
          body.style.opacity   = '1';
          void body.offsetHeight; // force reflow so transition fires
          body.style.maxHeight = '0';
          body.style.opacity   = '0';
        }
        panel.classList.add('ndash-collapsed');
        btn.textContent = '▸';
      } else {
        // ── Expanding ──
        panel.classList.remove('ndash-collapsed');
        btn.textContent = '▾';
        if (body) {
          body.style.maxHeight = '0';
          body.style.opacity   = '0';
          void body.offsetHeight; // force reflow
          var targetH = body.scrollHeight;
          body.style.maxHeight = targetH + 'px';
          body.style.opacity   = '1';
          body.addEventListener('transitionend', function onDone(e) {
            if (e.propertyName !== 'max-height') return;
            body.style.maxHeight = '';
            body.removeEventListener('transitionend', onDone);
          });
        }
      }
      saveDashCollapse();
    }

    function saveDashCollapse() {
      try {
        var ids = [];
        document.querySelectorAll('[data-panel-id].ndash-collapsed').forEach(function(p) { ids.push(p.dataset.panelId); });
        localStorage.setItem(DASH_COLLAPSE_KEY, JSON.stringify(ids));
      } catch(_) {}
    }

    function loadDashCollapse() {
      try {
        var raw = localStorage.getItem(DASH_COLLAPSE_KEY);
        if (!raw) return;
        JSON.parse(raw).forEach(function(id) {
          if (id === 'scan-cta') return; // SCAN CARD is never collapsible — skip stored state
          var p = document.querySelector('[data-panel-id="' + id + '"]');
          if (!p) return;
          p.classList.add('ndash-collapsed');
          var btn = p.querySelector('.ndash-collapse-btn');
          if (btn) btn.textContent = '▸';
          // Apply collapsed state instantly (no transition on page load)
          var body = p.querySelector('.ndash-panel-body');
          if (body) {
            body.style.transition = 'none';
            body.style.maxHeight  = '0';
            body.style.opacity    = '0';
            requestAnimationFrame(function() { body.style.transition = ''; });
          }
        });
      } catch(_) {}
    }

    function initDashResize() {
      // Remove old handles first (in case of re-render)
      document.querySelectorAll('.ndash-resize-handle').forEach(function(h) { h.remove(); });
      if (_dashResizeObs) { _dashResizeObs.disconnect(); _dashResizeObs = null; }

      document.querySelectorAll('[data-panel-id]').forEach(function(panel) {
        // Scan CTA is a fixed-size button — resizing it does nothing useful
        if (panel.dataset.panelId === 'scan-cta') return;

        var handle = document.createElement('div');
        handle.className = 'ndash-resize-handle';
        handle.title = 'Drag to resize';
        panel.appendChild(handle);

        var startY, startH;
        function onMove(clientY) {
          var newH = Math.max(80, startH + (clientY - startY));
          panel.style.height = newH + 'px';
        }
        function onUp() {
          saveDashHeights();
          document.removeEventListener('mousemove', mouseMove);
          document.removeEventListener('mouseup',   mouseUp);
          document.removeEventListener('touchmove', touchMove);
          document.removeEventListener('touchend',  touchEnd);
        }
        function mouseMove(e) { onMove(e.clientY); }
        function mouseUp()    { onUp(); }
        function touchMove(e) { if (e.touches[0]) onMove(e.touches[0].clientY); }
        function touchEnd()   { onUp(); }

        handle.addEventListener('mousedown', function(e) {
          e.preventDefault();
          startY = e.clientY;
          startH = panel.offsetHeight;
          document.addEventListener('mousemove', mouseMove);
          document.addEventListener('mouseup',   mouseUp);
        });
        handle.addEventListener('touchstart', function(e) {
          if (!e.touches[0]) return;
          startY = e.touches[0].clientY;
          startH = panel.offsetHeight;
          document.addEventListener('touchmove', touchMove, { passive: true });
          document.addEventListener('touchend',  touchEnd,  { passive: true });
        }, { passive: true });
      });

      // Resize-aware panels: load more content as the panel grows.
      // Binder grid loads more cards; Ghost Fund loads more wishlist
      // rows. One ResizeObserver, dispatches per-panel.
      var binderPanel = document.querySelector('[data-panel-id="binder"]');
      var ghostPanel  = document.querySelector('[data-panel-id="ghost-fund"]');
      if (window.ResizeObserver && (binderPanel || ghostPanel)) {
        _dashResizeObs = new ResizeObserver(function(entries) {
          entries.forEach(function(e) {
            if (binderPanel && e.target === binderPanel) _refreshBinderGrid(binderPanel);
            if (ghostPanel  && e.target === ghostPanel)  _refreshGhostFundList(ghostPanel);
          });
        });
        if (binderPanel) _dashResizeObs.observe(binderPanel);
        if (ghostPanel)  _dashResizeObs.observe(ghostPanel);
      }

      // Initial render of the ghost fund list (the ResizeObserver may
      // not fire immediately on first load if the panel size hasn't
      // changed since registration).
      if (ghostPanel) _refreshGhostFundList(ghostPanel);

      loadDashHeights();
      loadDashCollapse();
    }

    // How many cards fit in the current binder panel height
    function _refreshBinderGrid(panel) {
      var grid = panel.querySelector('.ndash-card-grid');
      if (!grid) return;
      var body = panel.querySelector('.ndash-panel-body');
      if (!body) return;
      var bodyH  = body.clientHeight;
      var cardH  = grid.firstElementChild ? grid.firstElementChild.offsetHeight + 8 : 120;
      var cols   = 4; // default grid columns
      if (window.innerWidth <= 480) cols = 2;
      else if (window.innerWidth <= 860) cols = 3;
      var rows = Math.max(2, Math.floor(bodyH / (cardH || 120)));
      var target = rows * cols;

      var ownedCards = typeof collectionItems !== 'undefined'
        ? collectionItems.filter(function(c) { return !c.is_ghost && !c.sold_offline; })
        : [];
      var sorted = [...ownedCards].sort(function(a,b) {
        return ((b.current_value||b.purchase_price||0)*(b.quantity||1)) -
               ((a.current_value||a.purchase_price||0)*(a.quantity||1));
      });
      var show = sorted.slice(0, Math.min(target, sorted.length, 40));
      if (show.length === grid.children.length) return; // nothing changed

      grid.innerHTML = show.map(function(item, i) {
        var v = (item.current_value||item.purchase_price||0)*(item.quantity||1);
        return '<div class="ndash-tcard" onclick="openBinderCardDetail(\'' + item.id + '\')">' +
          '<div class="ndash-tcard-art">' +
            (item.card_image_url
              ? '<img src="' + _pickThumbVariant(item.card_image_url, 200) + '" data-fallback="' + item.card_image_url + '" alt="' + _escHtml(item.card_name) + '" loading="lazy" decoding="async" onerror="if(this.dataset.fallback&&this.src!==this.dataset.fallback){this.src=this.dataset.fallback}else{_binderImgFail(this,\'' + item.id + '\')}">'
              : '<div class="ndash-tcard-art-ph">' + _escHtml(item.card_name.slice(0,12)) + '</div>') +
          '</div>' +
          '<div class="ndash-tcard-foot">' +
            '<div class="ndash-tcard-name">' + _escHtml(item.card_name.slice(0,16)) + '</div>' +
            (v>0 ? '<div class="ndash-tcard-val">$' + v.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}) + '</div>' : '') +
          '</div>' +
        '</div>';
      }).join('');
    }

    // JIT-enrich ghost cards (wishlist items) with live catalog prices.
    // The daily price refresh updates catalog.current_value but never writes
    // to collection_items.current_value for ghost rows (refreshBinderCardPrice
    // only fires on explicit user action). Without this enrichment, a card
    // added to the wishlist months ago would still show the snapshot value
    // captured at add-time, ignoring every subsequent daily refresh.
    //
    // Strategy: batch-fetch catalog.current_value for every ghost row that
    // has an api_card_id, then overwrite the in-memory current_value. No DB
    // writes — purely in-memory, so it's cheap to run on every collection
    // load. Catalog is the source of truth for ghost cards; user-owned cards
    // are left alone (their current_value reflects their condition/grade).
    async function _enrichGhostsFromCatalog(items) {
      try {
        if (!items || !items.length) return;
        var ids = [];
        var seen = new Set();
        for (var i = 0; i < items.length; i++) {
          var c = items[i];
          if (c.is_ghost && c.api_card_id && !seen.has(c.api_card_id)) {
            ids.push(c.api_card_id);
            seen.add(c.api_card_id);
          }
        }
        if (!ids.length) return;
        var priceMap = {};
        var CHUNK = 200;
        for (var j = 0; j < ids.length; j += CHUNK) {
          var slice = ids.slice(j, j + CHUNK);
          var res = await sb.from('catalog')
            .select('id, current_value')
            .in('id', slice);
          if (res && res.data) {
            for (var k = 0; k < res.data.length; k++) {
              var row = res.data[k];
              var v = Number(row.current_value) || 0;
              if (v > 0) priceMap[row.id] = v;
            }
          }
        }
        for (var n = 0; n < items.length; n++) {
          var item = items[n];
          if (item.is_ghost && item.api_card_id && priceMap[item.api_card_id]) {
            item.current_value = priceMap[item.api_card_id];
          }
        }
      } catch (_) { /* network blip — fall back to whatever was stored */ }
    }

    // JIT-enrich OWNED rows that have no current_value with an averaged
    // estimate from the comp tables (catalog.current_value = PriceCharting,
    // card_prices.source='tcgplayer'). Mirrors _enrichGhostsFromCatalog
    // but populates item._compEstimate rather than overwriting current_value
    // — graded rows store condition-adjusted prices in current_value, so
    // overwriting them with a raw-market average would mislead. The list
    // row + card-detail modal read _compEstimate as the next fallback
    // after current_value/purchase_price. Items where current_value is
    // already set are skipped (no need — the displayed value is correct).
    async function _enrichOwnedFromComps(items) {
      try {
        if (!items || !items.length) return;
        var ids = [];
        var seen = new Set();
        for (var i = 0; i < items.length; i++) {
          var c = items[i];
          if (c.is_ghost) continue;
          if (!c.api_card_id) continue;
          // Already has a current_value or a meaningful purchase_price — skip.
          if (Number(c.current_value) > 0) continue;
          if (seen.has(c.api_card_id)) continue;
          ids.push(c.api_card_id);
          seen.add(c.api_card_id);
        }
        if (!ids.length) return;
        var estMap = {};  // catalog_id → averaged number
        var CHUNK  = 200;
        for (var j = 0; j < ids.length; j += CHUNK) {
          var slice = ids.slice(j, j + CHUNK);
          // Pull PC from catalog and TCGplayer from card_prices in one
          // round-trip each. Average per id when both exist.
          var catRes = await sb.from('catalog')
            .select('id, current_value')
            .in('id', slice);
          var cpRes = await sb.from('card_prices')
            .select('catalog_id, source, value')
            .in('catalog_id', slice);
          var perId = {};  // id → { pc: n, tcg: n }
          if (catRes && catRes.data) {
            for (var k = 0; k < catRes.data.length; k++) {
              var r = catRes.data[k];
              var v = Number(r.current_value) || 0;
              if (v > 0) { perId[r.id] = perId[r.id] || {}; perId[r.id].pc = v; }
            }
          }
          if (cpRes && cpRes.data) {
            for (var m = 0; m < cpRes.data.length; m++) {
              var rr = cpRes.data[m];
              var vv = Number(rr.value) || 0;
              if (vv <= 0) continue;
              perId[rr.catalog_id] = perId[rr.catalog_id] || {};
              // Source-key collision avoidance: only take the highest
              // value per source if multiple rows exist (e.g. variants).
              if (rr.source === 'tcgplayer') {
                if (!perId[rr.catalog_id].tcg || vv > perId[rr.catalog_id].tcg) perId[rr.catalog_id].tcg = vv;
              } else if (rr.source === 'pricecharting' && !perId[rr.catalog_id].pc) {
                perId[rr.catalog_id].pc = vv;
              }
            }
          }
          for (var id in perId) {
            var srcs = [];
            if (perId[id].pc)  srcs.push(perId[id].pc);
            if (perId[id].tcg) srcs.push(perId[id].tcg);
            if (srcs.length) {
              estMap[id] = srcs.reduce(function(a, b) { return a + b; }, 0) / srcs.length;
            }
          }
        }
        for (var n = 0; n < items.length; n++) {
          var it = items[n];
          if (it.is_ghost) continue;
          if (Number(it.current_value) > 0) continue;
          if (it.api_card_id && estMap[it.api_card_id]) {
            it._compEstimate = estMap[it.api_card_id];
          }
        }
      } catch (_) { /* network blip — list rows fall back to em-dash */ }
    }

    // ── Ghost Card Fund — render one row + dynamic list refresh ─────────────
    // Renders a single fund row (mini-card thumb + name + progress bar
    // + saved/goal text). Number() coercion guards against Supabase
    // returning numeric columns as strings, which would silently break
    // the percentage math (e.g., '50' / 250 still works, but '50' >
    // 0 also is "true" for non-empty strings — we want real numbers).
    function _renderGhostFundRow(c) {
      var saved = Number(c.amount_saved) || 0;
      // Target = the card's CURRENT market price (refreshed daily), not the
      // savings_goal the user typed when first adding the card. The
      // savings_goal is kept as a fallback for cards we don't have a price
      // for (e.g. no price_source_url set). This way wishlist progress
      // updates automatically as prices move.
      var marketPrice = Number(c.current_value) || 0;
      var goalEntered = Number(c.savings_goal)  || 0;
      var target      = marketPrice > 0 ? marketPrice : goalEntered;
      var targetLabel = marketPrice > 0 ? 'market' : 'goal';
      var pct   = target > 0 ? Math.min(100, (saved / target) * 100) : 0;
      var pctStr = pct.toFixed(0);
      // Raw image (no _thumbUrl) — see _thumbUrl comment: avoids the
      // Supabase /storage/v1/render endpoint that counts against the
      // Pro tier image-transformation quota. Browser scales the source
      // down to the slot size; the bandwidth delta is small here.
      var img = c.card_image_url
        ? '<img src="' + c.card_image_url + '" alt="" loading="lazy" decoding="async">'
        : '<div class="ndash-fund-mini-ph">♡</div>';
      var progress = target > 0
        ? '<div class="ndash-fund-bar"><div class="ndash-fund-bar-fill" style="width:' + pctStr + '%"></div></div>' +
          '<div class="ndash-fund-progress">$' + saved.toFixed(2) + ' / $' + target.toFixed(2) +
          ' <span style="color:var(--muted);font-size:.62rem">(' + targetLabel + ')</span> ' +
          '(' + pctStr + '%)</div>'
        : '<div class="ndash-fund-progress" style="font-style:italic">No market price or goal set</div>';
      return '<div class="ndash-fund-row" onclick="openBinderCardDetail(\'' + c.id + '\')">' +
        '<div class="ndash-fund-mini">' + img + '</div>' +
        '<div class="ndash-fund-info">' +
          '<div class="ndash-fund-name">' + _escHtml((c.card_name || '').slice(0, 28)) + '</div>' +
          progress +
        '</div>' +
      '</div>';
    }

    // Calculate how many ghost-fund rows fit in the current panel
    // height and render exactly that many. Sorted by largest savings
    // goal so the "main" wishlist target stays visible at the top.
    function _refreshGhostFundList(panel) {
      var list = panel.querySelector('.ndash-fund-list');
      if (!list) return;
      var body = panel.querySelector('.ndash-panel-body');
      if (!body) return;
      var bodyH = body.clientHeight;
      var rowH  = 64; // approx height of one fund row + gap
      var rows  = Math.max(1, Math.floor(bodyH / rowH));

      var ghostCards = typeof collectionItems !== 'undefined'
        ? collectionItems.filter(function(c) { return c.is_ghost && !c.sold_offline; })
        : [];
      var sorted = [...ghostCards].sort(function(a,b) {
        return (Number(b.savings_goal)||0) - (Number(a.savings_goal)||0);
      });
      var show = sorted.slice(0, Math.min(rows, sorted.length));
      if (show.length === list.children.length && show.length > 0) return; // no change
      list.innerHTML = show.map(_renderGhostFundRow).join('');
    }

    // ── YTD Portfolio Chart ──────────────────────────────────────────────────
    function buildYtdChart(snapshots, currentValue) {
      // Free tier: show locked preview with upgrade CTA
      if (!hasPriceTracking()) {
        return `<div class="dash-chart-section" style="margin-bottom:16px;position:relative;overflow:hidden">
          <div style="font-size:.75rem;color:var(--accent);margin-bottom:10px;letter-spacing:.08em">YTD Portfolio Value</div>
          <!-- Fake blurred chart -->
          <div style="filter:blur(6px);pointer-events:none;opacity:.5">
            <div style="font-size:1.6rem;color:var(--text);font-weight:700">$2,341.50</div>
            <svg width="100%" height="90" style="display:block;margin-top:8px"><polyline points="0,70 60,55 120,62 180,40 240,35 300,20 360,28 420,15 480,10" fill="none" stroke="var(--accent)" stroke-width="2"/></svg>
          </div>
          <!-- Upgrade overlay -->
          <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:rgba(8,5,0,.7);gap:10px">
            <div style="font-size:.78rem;color:var(--text);text-align:center">Live price tracking is a<br><strong style="color:#1D9E75">Collector</strong> feature</div>
            <button onclick="openPricingModal('collector')" style="padding:8px 20px;background:#1D9E75;color:#fff;border:none;font-family:'Space Mono','Share Tech Mono',monospace;font-size:.78rem;font-weight:700;cursor:pointer">Upgrade →</button>
          </div>
        </div>`;
      }
      const pts = [...snapshots];
      // Append today's live value as the rightmost point
      const todayStr = new Date().toISOString().slice(0, 10);
      if (!pts.length || pts[pts.length-1].snapshot_date !== todayStr) {
        pts.push({ snapshot_date: todayStr, total_value: currentValue });
      }
      if (pts.length < 2) {
        return `<div class="dash-chart-section" style="margin-bottom:16px">
          <div style="font-size:.75rem;color:var(--accent);margin-bottom:8px;letter-spacing:.08em">YTD Portfolio Value</div>
          <div style="display:flex;align-items:baseline;gap:12px;flex-wrap:wrap">
            <div style="font-size:1.6rem;color:var(--text);font-weight:700">${currentValue > 0 ? '$' + currentValue.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}) : '—'}</div>
            <div style="font-size:.72rem;color:var(--muted)">Chart builds automatically — prices refresh in the background each day you open the app. Check back tomorrow.</div>
          </div>
        </div>`;
      }
      return `<div class="dash-chart-section" style="margin-bottom:0">
        <svg id="ytdChartSvg" width="100%" height="82" style="display:block;overflow:visible"></svg>
      </div>`;
    }

    function drawYtdChart(snapshots, currentValue) {
      const svg = document.getElementById('ytdChartSvg');
      if (!svg) return;
      const pts = [...snapshots];
      const todayStr = new Date().toISOString().slice(0, 10);
      if (!pts.length || pts[pts.length-1].snapshot_date !== todayStr) {
        pts.push({ snapshot_date: todayStr, total_value: currentValue });
      }
      if (pts.length < 2) return;

      const W = svg.getBoundingClientRect().width || 500;
      const H = parseInt(svg.getAttribute('height') || '82', 10);
      const PAD_L = 38, PAD_R = 8, PAD_T = 6, PAD_B = 18;
      const vals = pts.map(p => Number(p.total_value) || 0);
      const minV = Math.min(...vals);
      const maxV = Math.max(...vals);
      const range = maxV - minV || 1;

      const xScale = i => PAD_L + (i / (pts.length - 1)) * (W - PAD_L - PAD_R);
      const yScale = v => PAD_T + (1 - (v - minV) / range) * (H - PAD_T - PAD_B);

      const polyPoints = pts.map((p, i) => `${xScale(i).toFixed(1)},${yScale(Number(p.total_value)).toFixed(1)}`).join(' ');
      const areaPoints = `${xScale(0).toFixed(1)},${H - PAD_B} ` + polyPoints + ` ${xScale(pts.length-1).toFixed(1)},${H - PAD_B}`;

      const isUp = vals[vals.length-1] >= vals[0];
      const lineColor = isUp ? 'var(--green)' : 'var(--red)';
      const fillColor = isUp ? 'rgba(210,120,40,.08)' : 'rgba(255,68,85,.08)';

      // Y axis labels
      const yLabels = [minV, (minV + maxV) / 2, maxV].map((v, i) => {
        const y = yScale(v);
        return `<text x="${PAD_L - 4}" y="${y.toFixed(1)}" text-anchor="end" font-size="9" fill="var(--muted)" font-family="Share Tech Mono,monospace" dominant-baseline="middle">$${Math.round(v).toLocaleString()}</text>`;
      }).join('');

      // X axis: show first, middle, last date labels
      const xIdxs = [0, Math.floor((pts.length-1)/2), pts.length-1];
      const xLabels = xIdxs.map(i => {
        const d = pts[i].snapshot_date.slice(5); // MM-DD
        return `<text x="${xScale(i).toFixed(1)}" y="${H - PAD_B + 14}" text-anchor="middle" font-size="9" fill="var(--muted)" font-family="Share Tech Mono,monospace">${d}</text>`;
      }).join('');

      svg.innerHTML = `
        <polygon points="${areaPoints}" fill="${fillColor}" />
        <polyline points="${polyPoints}" fill="none" stroke="${lineColor}" stroke-width="2" stroke-linejoin="round" />
        <circle cx="${xScale(pts.length-1).toFixed(1)}" cy="${yScale(vals[vals.length-1]).toFixed(1)}" r="3" fill="${lineColor}" />
        ${yLabels}
        ${xLabels}
        <line x1="${PAD_L}" y1="${PAD_T}" x2="${PAD_L}" y2="${H - PAD_B}" stroke="var(--border)" stroke-width="1"/>
        <line x1="${PAD_L}" y1="${H - PAD_B}" x2="${W - PAD_R}" y2="${H - PAD_B}" stroke="var(--border)" stroke-width="1"/>
      `;
    }

    // ── Biggest Movers (7-day) ───────────────────────────────────────────────
    // Snapshot of the OLDEST recorded_value per collection_item_id within
    // the trailing 7-day window. Loaded once per session via
    // _loadPriceHistorySnapshot(); buildMovers reads from here. Earlier
    // versions tried to read c.price_history_log on collection_items but
    // that array never got populated — dailyPriceRefresh actually writes
    // history to the separate `price_history` Supabase table.
    // Keyed by period (1 or 7) so the panel can switch between 24h /
    // 7d snapshots without re-fetching. Each entry is a
    // Map<item_id, {value, date}> with the OLDEST entry within the
    // window — that's the value we diff against current_value to get
    // the movement.
    let _priceHistorySnapshots = {};       // { 1: Map, 7: Map }
    let _priceHistoryLoading   = {};       // { 1: bool, 7: bool }

    // GLOBAL movers — sourced from catalog_price_history (written by
    // refresh_catalog_prices.py at ~3am). Lets the dashboard surface
    // market-wide moves across each TCG, not just the user's collection.
    // Cached per (period, sort) key so toggling 1d ↔ 7d ↔ % ↔ $ doesn't
    // re-hit the RPC every time. _globalMovers always points at the
    // currently-active cache entry for the convenience of legacy code.
    let _globalMovers = null;        // { up: [...], down: [...] }
    let _globalMoversLoading = false;
    let _globalMoversCache = {};     // { 'p1-pct': {...}, 'p7-dollar': {...} }

    // Price Movers panel state. Four independent toggles, all binary.
    // Direction is now its own toggle so the panel shows just ONE list
    // (up OR down) per render — easier to scan than two stacked.
    // TODO (multi-TCG): when other TCGs get their own daily price
    // refresh, expose game_type as a 5th selector (currently hardcoded
    // to 'pokemon' since that's the only TCG with active history).
    let _moversScope     = 'global';   // 'global' (market) | 'personal' (your collection)
    let _moversDirection = 'up';       // 'up' | 'down'
    let _moversPeriod    = 1;          // 1 day | 7 days
    // The %/$ toggle was removed — the dollar amount and % are shown
    // together on every row, so toggling the sort axis was redundant.
    // Sorting always by absolute $ change keeps cheap-card-big-% rows
    // (e.g. $0.08 → $0.16 = "+100%") from dominating the list.
    // The setter `setMoversSort` is kept for backwards-compat in case a
    // future toggle wants to flip it again.
    let _moversSort      = 'dollar';   // 'pct' | 'dollar'
    // 'single' = TCG singles; 'sealed' = booster_box/etb/utb/tin/deck/
    // any non-single catalog row. Plumbed to the RPC via p_product_type.
    let _moversProductType = 'single'; // 'single' | 'sealed'

    // Setters used by the toggle pills in the Price Movers panel.
    window.setMoversScope = function(scope) {
      _moversScope = scope;
      try { renderDashboard(); } catch(_) {}
    };
    window.setMoversDirection = function(dir) {
      _moversDirection = dir;
      try { renderDashboard(); } catch(_) {}
    };
    window.setMoversPeriod = function(days) {
      _moversPeriod = days;
      try { renderDashboard(); } catch(_) {}
    };
    window.setMoversSort = function(sort) {
      _moversSort = sort;
      try { renderDashboard(); } catch(_) {}
    };
    window.setMoversProductType = function(pt) {
      _moversProductType = pt;
      try { renderDashboard(); } catch(_) {}
    };

    async function _loadGlobalMovers(game_type = 'pokemon', period = null, sort = null, productType = null) {
      var days = period || _moversPeriod;
      var srt  = sort   || _moversSort;
      var pt   = productType || _moversProductType;
      var cacheKey = 'p' + days + '-' + srt + '-' + pt + '-' + game_type;
      if (_globalMoversCache[cacheKey]) {
        _globalMovers = _globalMoversCache[cacheKey];
        return _globalMovers;
      }
      if (_globalMoversLoading) return null;
      _globalMoversLoading = true;
      window._globalMoversLoading = true;
      console.log('[movers] loading start: game_type=' + game_type + ' period=' + days + 'd sort=' + srt + ' product=' + pt);
      try {
        // Server-side computation via SQL RPC. The RPC does the
        // DISTINCT-ON-oldest + delta math + sort + top-N in one query.
        // Migration: migration_global_price_movers_rpc.sql (v3 — adds
        // p_product_type for the Singles/Sealed dashboard toggle).
        const { data, error } = await sb.rpc('get_global_price_movers', {
          p_game_type:    game_type,
          p_days_back:    days,
          p_top_n:        10,
          p_min_pct:      0.5,
          p_sort:         srt,
          p_product_type: pt,
        });

        if (error) {
          // PGRST202 = RPC function not found (migration not applied yet)
          if (error.code === 'PGRST202' || (error.message || '').includes('function')) {
            console.warn('[movers] RPC not installed yet — apply migration_global_price_movers_rpc.sql. Falling back to client-side.');
            return await _loadGlobalMoversClientFallback(game_type);
          }
          console.error('[movers] RPC error:', error);
          _globalMoversLoading = false;
          window._globalMoversLoading = false;
          return null;
        }

        const rows = data || [];
        const up   = rows.filter(r => r.direction === 'up').map(r => ({
          id: r.catalog_id, name: r.name, set_name: r.set_name,
          image_url: r.image_url,
          currentVal: Number(r.current_value), oldVal: Number(r.old_value),
          delta: Number(r.delta), deltaPct: Number(r.delta_pct),
        }));
        const down = rows.filter(r => r.direction === 'down').map(r => ({
          id: r.catalog_id, name: r.name, set_name: r.set_name,
          image_url: r.image_url,
          currentVal: Number(r.current_value), oldVal: Number(r.old_value),
          delta: Number(r.delta), deltaPct: Number(r.delta_pct),
        }));

        // PostgREST returns UNION ALL rows in arbitrary order — the
        // RPC's inner ORDER BY clauses don't survive the HTTP wire.
        // Re-sort here so the panel is strictly ranked by the active
        // metric (biggest gain first for ↑, biggest loss first for ↓).
        var _sortKeyFn = srt === 'dollar'
          ? (m => Math.abs(m.delta))
          : (m => Math.abs(m.deltaPct));
        up.sort((a, b)   => _sortKeyFn(b) - _sortKeyFn(a));
        down.sort((a, b) => _sortKeyFn(b) - _sortKeyFn(a));

        _globalMovers = { up, down, game_type, period: days, sort: srt, productType: pt };
        _globalMoversCache[cacheKey] = _globalMovers;
        _globalMoversLoading = false;
        console.log('[movers] loaded via RPC: ' + up.length + ' up, ' + down.length + ' down (key=' + cacheKey + ')');
        window._globalMovers = _globalMovers;
        window._globalMoversLoading = false;
        return _globalMovers;
      } catch (e) {
        _globalMoversLoading = false;
        console.error('[movers] load failed:', e);
        window._globalMoversLoading = false;
        return null;
      }
    }

    // Fallback for users where the RPC migration hasn't been applied —
    // does the same logic client-side. Slower (paginates all history +
    // catalog) but works without the function installed. Once the
    // migration runs in Supabase this path is never hit.
    // Honors _moversPeriod + _moversSort so the fallback returns
    // results consistent with the user's toggle selection.
    async function _loadGlobalMoversClientFallback(game_type = 'pokemon') {
      try {
        var days = _moversPeriod;
        var srt  = _moversSort;
        var pt   = _moversProductType;
        var cacheKey = 'p' + days + '-' + srt + '-' + pt + '-' + game_type;
        const cutoff = new Date(Date.now() - days * 24 * 60 * 60 * 1000)
          .toISOString().slice(0, 10);
        const PAGE = 1000;
        let offset = 0;
        const hist = [];
        while (true) {
          const { data: chunk, error: histErr } = await sb
            .from('catalog_price_history')
            .select('catalog_id, recorded_value, recorded_at')
            .eq('game_type', game_type)
            .gte('recorded_at', cutoff)
            .order('recorded_at', { ascending: true })
            .range(offset, offset + PAGE - 1);
          if (histErr || !chunk) { _globalMoversLoading = false; return null; }
          hist.push(...chunk);
          if (chunk.length < PAGE) break;
          offset += PAGE;
          if (offset > 500000) break;
        }
        const oldByCatalog = new Map();
        for (const row of hist) {
          if (!oldByCatalog.has(row.catalog_id)) {
            oldByCatalog.set(row.catalog_id, Number(row.recorded_value));
          }
        }
        if (!oldByCatalog.size) {
          // Cache empty result too, so we don't spam the network.
          var emptyResult = { up: [], down: [], game_type, period: days, sort: srt, productType: pt };
          _globalMovers = emptyResult;
          _globalMoversCache[cacheKey] = emptyResult;
          _globalMoversLoading = false;
          return emptyResult;
        }
        const ids = [...oldByCatalog.keys()];
        const cards = [];
        const CHUNK = 200;
        for (let i = 0; i < ids.length; i += CHUNK) {
          const slice = ids.slice(i, i + CHUNK);
          const { data } = await sb.from('catalog')
            .select('id, name, set_name, image_url, current_value, game_type, product_type')
            .in('id', slice);
          if (data) cards.push(...data);
        }
        const movers = [];
        for (const c of cards) {
          // Product-type filter applied client-side here (the SQL fallback
          // pulls the column so we can scope to singles vs sealed before
          // the top-N cut).
          var cpt = (c.product_type || 'single');
          if (pt === 'single' && cpt !== 'single') continue;
          if (pt === 'sealed' && cpt === 'single') continue;
          const cur = Number(c.current_value || 0);
          const old = oldByCatalog.get(c.id) || 0;
          if (!cur || !old || Math.abs(cur - old) < 0.01) continue;
          const delta    = cur - old;
          const deltaPct = (delta / old) * 100;
          if (Math.abs(deltaPct) < 0.5) continue;
          movers.push({
            id: c.id, name: c.name, set_name: c.set_name,
            image_url: c.image_url,
            currentVal: cur, oldVal: old, delta, deltaPct,
          });
        }
        // Honor the user's sort choice (% or $) in the fallback too.
        var sortKeyFn = srt === 'dollar'
          ? (m => Math.abs(m.delta))
          : (m => Math.abs(m.deltaPct));
        const up   = movers.filter(m => m.delta >= 0)
                           .sort((a, b) => sortKeyFn(b) - sortKeyFn(a)).slice(0, 10);
        const down = movers.filter(m => m.delta < 0)
                           .sort((a, b) => sortKeyFn(b) - sortKeyFn(a)).slice(0, 10);
        var result = { up, down, game_type, period: days, sort: srt, productType: pt };
        _globalMovers = result;
        _globalMoversCache[cacheKey] = result;  // ← critical: prevents re-fire loop
        _globalMoversLoading = false;
        console.log('[movers] fallback loaded: ' + up.length + ' up, ' + down.length + ' down (key=' + cacheKey + ')');
        window._globalMovers = _globalMovers;
        window._globalMoversLoading = false;
        return _globalMovers;
      } catch (e) {
        _globalMoversLoading = false;
        console.error('[movers] fallback failed:', e);
        return null;
      }
    }

    // Smart click-handler for Price Movers rows. Behavior:
    // Click-by-name lookup for trade-history cards. The trade_history
    // table stores card snapshots as {name, qty, avg} JSONB without any
    // catalog reference, so we have to fuzzy-search the catalog by name
    // to find a likely match. Strategy:
    //   - Scope to game_type=pokemon (trade analyzer is pokemon-focused)
    //   - ILIKE on name with a wildcard so common name variations match
    //   - Take the first result (good enough for the common case; if the
    //     user complains about wrong matches we can add a disambiguation
    //     picker later)
    //   - Route to openMoversCardDetail with the matched id — that modal
    //     already shows current_value + image + set + add-to-wishlist
    window.openTradeCardDetail = async function(rawName) {
      var name = String(rawName || '').trim();
      if (!name) return;
      try {
        var res = await sb.from('catalog')
          .select('id, name, set_name')
          .ilike('name', '%' + name.replace(/[%_]/g, '') + '%')
          .eq('game_type', 'pokemon')
          .order('current_value', { ascending: false, nullsFirst: false })
          .limit(1);
        if (res.error || !res.data || !res.data.length) {
          showToast('No catalog match for "' + name + '"');
          return;
        }
        var hit = res.data[0];
        if (typeof openMoversCardDetail === 'function') {
          openMoversCardDetail(hit.id);
        } else {
          showToast('Card detail unavailable');
        }
      } catch (e) {
        showToast('Lookup failed: ' + (e.message || 'unknown'));
      }
    };

    //   - If the user owns the card (matching api_card_id in their
    //     collection_items), open the regular binder card detail.
    //   - If not, fetch the catalog row and pop a lightweight preview
    //     sheet showing image / name / set / current price plus an
    //     "add to wishlist" CTA. Mirrors the previewScanMatch sheet
    //     styling so the UX feels consistent with the scanner picker.
    // Shown in the movers card detail modal when the catalog row has
    // no image_url. Same eligibility check as the scanner integration;
    // routes to the existing window._submitCatalogImageContribution
    // upload flow which already handles bucket + RPC + UI feedback.
    // Unlike the scanner version, we don't have a scan capture handy
    // here — we open a file picker so the user can upload from their
    // device's gallery.
    window._maybeShowMoversContribute = async function(catalogId, name) {
      try {
        const slot = document.getElementById('moversContribSlot_' + catalogId);
        if (!slot || !currentUser) return;
        const r = await sb.rpc('user_can_contribute_image', { p_user_id: currentUser.id });
        if (!r || r.data !== true) return;
        slot.style.display = '';
        slot.innerHTML =
            '<div style="background:rgba(26,199,160,.08);border:1px solid var(--accent);border-radius:6px;padding:10px 12px">'
          +   '<div style="font-size:.6rem;letter-spacing:.1em;color:var(--accent);margin-bottom:4px">◈ HELP FILL THIS IN?</div>'
          +   '<div style="font-size:.66rem;color:var(--text);margin-bottom:8px;line-height:1.5">'
          +     'Got this card in hand? Upload a clean photo and credit goes to you.'
          +   '</div>'
          +   '<input type="file" accept="image/*" capture="environment" id="moversContribFile_' + _escJsAttr(catalogId) + '" '
          +     'onchange="_moversContributeFromFile(this,' + JSON.stringify(catalogId) + ',' + JSON.stringify(name || '') + ')" style="display:none">'
          +   '<button onclick="document.getElementById(\'moversContribFile_' + _escJsAttr(catalogId) + '\').click()" '
          +     'style="width:100%;padding:8px;border:1px solid var(--accent);background:var(--accent);color:var(--text-on-accent);font-family:\'Space Mono\',monospace;font-size:.68rem;font-weight:700;cursor:pointer;letter-spacing:.06em">'
          +     'CONTRIBUTE PHOTO'
          +   '</button>'
          + '</div>';
      } catch (e) {
        console.warn('[movers contrib] eligibility check failed:', e);
      }
    };

    // File-picker variant of the submission flow used by the scanner.
    // Reads the file into a dataURL, stashes it on _scanCapturedDataUrl
    // (the existing scanner upload pipeline reads from there), then
    // delegates to _submitCatalogImageContribution which already
    // handles upload + insert + auto-approval.
    window._moversContributeFromFile = function(fileInput, catalogId, name) {
      const f = fileInput.files && fileInput.files[0];
      if (!f) return;
      const reader = new FileReader();
      reader.onload = function(e) {
        window._scanCapturedDataUrl = e.target.result;
        // Rename the slot id so the scanner submitter's "find the slot
        // and update" path lands on our movers slot, not a scan slot.
        const moversSlot = document.getElementById('moversContribSlot_' + catalogId);
        if (moversSlot) moversSlot.id = 'contribImageSlot_' + catalogId;
        if (typeof window._submitCatalogImageContribution === 'function') {
          window._submitCatalogImageContribution(catalogId, name);
        }
      };
      reader.readAsDataURL(f);
    };

    window.openMoversCardDetail = async function(catalogId) {
      if (!catalogId) return;

      // Owned? Open the existing binder detail modal directly.
      var owned = (typeof collectionItems !== 'undefined' && collectionItems)
        ? collectionItems.find(function(c) { return c.api_card_id === catalogId; })
        : null;
      if (owned) {
        try { openBinderCardDetail(owned.id); } catch(_) {}
        return;
      }

      // Not owned — fetch catalog row, show a quick preview sheet.
      var card;
      try {
        var res = await sb.from('catalog').select('*').eq('id', catalogId).maybeSingle();
        card = res && res.data;
      } catch (_) {}
      if (!card) {
        try { showToast('Card not found in catalog'); } catch(_) {}
        return;
      }

      document.getElementById('moversCardSheet')?.remove();
      var setInfo = [card.set_name, card.card_number ? '#' + card.card_number : '', card.rarity].filter(Boolean).join(' · ');
      var curVal  = Number(card.current_value || 0);
      var priceLine = curVal > 0
        ? '<div style="font-size:1.1rem;font-weight:700;color:var(--green);margin-top:6px">$' + curVal.toFixed(2) + '</div>'
        : '';
      var safeName = (card.name || '').replace(/'/g, "\\'");
      var safeSet  = (card.set_name || '').replace(/'/g, "\\'");
      var safeNum  = card.card_number || '';
      var safeImg  = (card.image_url || '').replace(/'/g, "\\'");
      var safeRar  = (card.rarity || '').replace(/'/g, "\\'");

      var sheet = document.createElement('div');
      sheet.id = 'moversCardSheet';
      // Centered modal (vertically + horizontally) — not a bottom sheet.
      // Padding gives breathing room from viewport edges on small screens.
      // z-index sits below the image lightbox (z-index 30000) so when the
      // user taps the card image to enlarge it, the lightbox cleanly covers
      // this modal instead of being trapped beneath it.
      sheet.style.cssText = 'position:fixed;inset:0;z-index:20000;display:flex;align-items:center;justify-content:center;padding:16px';
      sheet.innerHTML = '' +
        '<div onclick="document.getElementById(\'moversCardSheet\').remove()" style="position:absolute;inset:0;background:rgba(0,0,0,.55)"></div>' +
        '<div style="position:relative;width:100%;max-width:480px;background:var(--surface);border:2px solid var(--copper-dim);border-radius:6px;padding:20px 18px 24px;max-height:90svh;overflow-y:auto;box-shadow:0 0 30px var(--copper-glow)">' +
          '<button onclick="document.getElementById(\'moversCardSheet\').remove()" style="position:absolute;top:12px;right:14px;background:none;border:none;font-size:1.4rem;cursor:pointer;color:var(--muted)">×</button>' +
          '<div style="font-size:.52rem;letter-spacing:.14em;color:var(--copper);margin-bottom:14px">◈ CARD DETAIL</div>' +
          (card.image_url
            ? '<div style="display:flex;justify-content:center;margin-bottom:14px">' +
                '<img src="' + card.image_url + '" alt="' + _escHtml(card.name || '') + '" onclick="openImageLightbox(\'' + safeImg + '\')" style="max-width:180px;width:100%;height:auto;border:1px solid var(--copper-dim);border-radius:4px;cursor:zoom-in;box-shadow:0 0 20px var(--copper-glow)" loading="lazy" decoding="async">' +
              '</div>'
            // Catalog row has no image (common for newly-synced rows
            // from recent sets — the image-mirror job hasn't run yet).
            // Show a placeholder so the modal isn't a confusing
            // text-only block, and seed a slot for the contribute
            // prompt that gets filled async if the user is eligible.
            : '<div style="display:flex;justify-content:center;margin-bottom:6px">' +
                '<div style="width:180px;height:252px;background:rgba(184,115,51,.06);border:1px dashed var(--copper-dim);border-radius:4px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:6px">' +
                  '<span style="font-size:2rem;opacity:.25">⬡</span>' +
                  '<span style="font-size:.5rem;letter-spacing:.1em;color:var(--copper-dim)">NO IMAGE YET</span>' +
                '</div>' +
              '</div>' +
              '<div id="moversContribSlot_' + _escJsAttr(catalogId) + '" style="display:none;margin-bottom:12px"></div>' +
              '<script>(function(){ if(typeof _maybeShowMoversContribute===\'function\') _maybeShowMoversContribute(' + JSON.stringify(catalogId) + ',' + JSON.stringify(card.name || '') + '); })();<\/script>') +
          '<div style="text-align:center;margin-bottom:14px">' +
            '<div style="font-size:1rem;font-weight:700;color:var(--text);margin-bottom:4px">' + _escHtml(card.name || 'Unknown Card') + '</div>' +
            (setInfo ? '<div style="font-size:.65rem;color:var(--muted)">' + _escHtml(setInfo) + '</div>' : '') +
            priceLine +
          '</div>' +
          '<div style="display:flex;flex-direction:column;gap:8px">' +
            '<button onclick="document.getElementById(\'moversCardSheet\').remove();openAddToWishlistModal({cardName:\'' + safeName + '\',setName:\'' + safeSet + '\',cardNumber:\'' + safeNum + '\',cardImageUrl:\'' + safeImg + '\',rarity:\'' + safeRar + '\',apiCardId:\'' + catalogId + '\'})" style="width:100%;padding:11px;border:1px solid var(--teal);background:rgba(26,199,160,.1);color:var(--teal);font-family:\'Space Mono\',\'Share Tech Mono\',monospace;font-size:.78rem;font-weight:700;cursor:pointer;letter-spacing:.06em">♡ ADD TO WISHLIST</button>' +
            (card.price_source_url
              ? '<a href="' + card.price_source_url + '" target="_blank" rel="noopener" style="display:block;text-align:center;width:100%;padding:9px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:\'Space Mono\',monospace;font-size:.7rem;cursor:pointer;text-decoration:none;letter-spacing:.04em">↗ View on PriceCharting</a>'
              : '') +
            '<button onclick="document.getElementById(\'moversCardSheet\').remove()" style="width:100%;padding:8px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:\'Space Mono\',monospace;font-size:.66rem;cursor:pointer">CLOSE</button>' +
          '</div>' +
        '</div>';
      document.body.appendChild(sheet);
    };

    function _renderGlobalMovers(g) {
      if (!g || (!g.up.length && !g.down.length)) return '';
      // Headline metric depends on the sort: when sorted by $, show
      // the dollar amount prominently and put % in parens (the
      // opposite of the pct sort, which leads with %).
      var sortByDollar = g.sort === 'dollar';
      function row(c) {
        const sign  = c.delta >= 0 ? '+' : '';
        const color = c.delta >= 0 ? 'var(--green)' : 'var(--red)';
        const name  = (c.name || '').length > 24 ? c.name.slice(0, 23) + '…' : (c.name || '');
        const setBit = c.set_name ? `<span style="font-size:.6rem;color:var(--muted);margin-left:5px">${c.set_name}</span>` : '';
        const primary   = sortByDollar
          ? sign + '$' + Math.abs(c.delta).toFixed(2)
          : sign + c.deltaPct.toFixed(1) + '%';
        const secondary = sortByDollar
          ? '(' + sign + c.deltaPct.toFixed(1) + '%)'
          : '(' + sign + '$' + Math.abs(c.delta).toFixed(2) + ')';
        // Escape the catalog_id for safe inline onclick attribute use.
        const safeId = String(c.id || '').replace(/'/g, "\\'");
        return `<div onclick="openMoversCardDetail('${safeId}')" style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid var(--border);cursor:pointer;transition:background-color .12s" onmouseover="this.style.background='var(--surface2)'" onmouseout="this.style.background=''">
          <div style="overflow:hidden;text-overflow:ellipsis;flex:1;min-width:0">
            <span style="font-size:.75rem;color:var(--text)">${name}</span>
            ${setBit}
          </div>
          <span style="font-size:.78rem;color:${color};font-weight:700;white-space:nowrap;margin-left:8px">${primary} ${secondary}</span>
        </div>`;
      }
      const tcgLabel    = (g.game_type || 'pokemon').replace(/^./, c => c.toUpperCase());
      const periodLabel = (g.period === 1) ? '24h' : (g.period + 'd');
      // Sort label dropped from the header — the %/$ toggle is gone and
      // every row shows both metrics, so an explicit "by $" label is noise.
      // Show only the direction the user picked (up OR down). The
      // direction toggle in the panel header swaps between them.
      var list = (_moversDirection === 'down') ? g.down : g.up;
      var arrow = (_moversDirection === 'down') ? '↓' : '↑';
      var arrowColor = (_moversDirection === 'down') ? 'var(--red)' : 'var(--green)';
      return `<div class="dash-chart-section" style="margin-bottom:16px">
        <div style="font-size:.66rem;color:var(--muted);margin-bottom:8px;letter-spacing:.08em">MARKET · ${tcgLabel} · ${periodLabel}</div>
        <div style="font-size:.75rem;color:${arrowColor};margin-bottom:6px;letter-spacing:.08em">${arrow} Top Movers</div>
        ${list.length ? list.map(row).join('') : `<div style="font-size:.7rem;color:var(--muted);padding:6px 0">No ${_moversDirection === 'down' ? 'declines' : 'gains'} at this threshold.</div>`}
      </div>`;
    }

    async function _loadPriceHistorySnapshot(period) {
      period = period || _moversPeriod || 7;
      if (!currentUser) return null;
      if (_priceHistorySnapshots[period])        return _priceHistorySnapshots[period];
      if (_priceHistoryLoading[period])          return null;
      _priceHistoryLoading[period] = true;
      try {
        // Window is the user-selected period plus 1 day of buffer so
        // edge-of-day timestamps don't drop the oldest entry. For 24h
        // mode we look back 2 days; for 7d mode we look back 8 days.
        const windowDays = period + 1;
        const cutoff = new Date(Date.now() - windowDays * 24 * 60 * 60 * 1000)
          .toISOString().slice(0, 10);
        const { data, error } = await sb.from('price_history')
          .select('collection_item_id, recorded_value, recorded_at')
          .eq('user_id', currentUser.id)
          .gte('recorded_at', cutoff)
          .order('recorded_at', { ascending: true });
        if (error || !data) { _priceHistoryLoading[period] = false; return null; }
        const map = new Map();
        // First entry per item_id wins (ascending order = oldest first).
        for (const row of data) {
          if (!map.has(row.collection_item_id)) {
            map.set(row.collection_item_id, {
              value: Number(row.recorded_value),
              date:  row.recorded_at,
            });
          }
        }
        _priceHistorySnapshots[period] = map;
        _priceHistoryLoading[period]   = false;
        return map;
      } catch(_) {
        _priceHistoryLoading[period] = false;
        return null;
      }
    }

    function buildMovers(cards) {
      // Lazy-trigger BOTH snapshot loads on first render. When either
      // resolves it kicks off a re-render so the panel populates without
      // blocking. Global movers come from catalog_price_history (written
      // by refresh_catalog_prices.py at 3am); user movers come from the
      // per-user price_history table. Cache keyed by period so the
      // 24h/7d toggle switches without re-fetching.
      const _activePeriod = _moversPeriod || 7;
      if (!_priceHistorySnapshots[_activePeriod] && !_priceHistoryLoading[_activePeriod] && currentUser) {
        _loadPriceHistorySnapshot(_activePeriod).then(snap => {
          if (snap && snap.size) renderDashboard();
        });
      }
      // Re-load the global movers for the currently-selected period+sort+
      // product_type if we don't already have that combo cached.
      var _cacheKey = 'p' + _moversPeriod + '-' + _moversSort + '-' + _moversProductType + '-pokemon';
      if (!_globalMoversCache[_cacheKey] && !_globalMoversLoading) {
        _loadGlobalMovers('pokemon', _moversPeriod, _moversSort, _moversProductType).then(g => {
          if (g) renderDashboard();
        });
      }
      var _activeGlobal = _globalMoversCache[_cacheKey] || null;
      // Honor scope toggle: when user selected "Personal", suppress the
      // global market section so the panel only shows their collection.
      const globalHtml = (_moversScope === 'global' && _activeGlobal)
        ? _renderGlobalMovers(_activeGlobal) : '';
      const snap = _priceHistorySnapshots[_activePeriod] || null;
      const _periodLabel = (_activePeriod === 1) ? '24h' : (_activePeriod + 'd');
      const movers = [];

      for (const c of cards) {
        // Honor the Singles/Sealed toggle for personal scope too — read
        // product_type off the collection_items row (synced from catalog
        // at add time). Default missing/legacy rows to 'single'.
        var _cpt = (c.product_type || 'single');
        if (_moversProductType === 'single' && _cpt !== 'single') continue;
        if (_moversProductType === 'sealed' && _cpt === 'single') continue;
        const currentVal = c.current_value || 0;
        if (!currentVal) continue;

        let oldVal = null;
        let periodLabel = _periodLabel;

        // 1. Authoritative source: Supabase price_history table.
        if (snap && snap.has(c.id)) {
          const h = snap.get(c.id);
          if (h.value && Math.abs(h.value - currentVal) > 0.005) {
            oldVal = h.value;
          }
        }
        // 2. Legacy in-memory log (kept for backwards-compat).
        if (!oldVal) {
          const history = c.price_history_log || [];
          if (history.length) {
            const cutoffMs = Date.now() - _activePeriod * 24 * 60 * 60 * 1000;
            const cutoffStr = new Date(cutoffMs).toISOString().slice(0, 10);
            const oldEntry = [...history].filter(h => h.date >= cutoffStr).shift();
            if (oldEntry && oldEntry.value && oldEntry.value !== currentVal) {
              oldVal = oldEntry.value;
            }
          }
        }
        // 3. Last resort — vs cost basis.
        if (!oldVal && c.purchase_price && c.purchase_price !== currentVal) {
          oldVal = c.purchase_price;
          periodLabel = 'vs cost';
        }

        if (!oldVal) continue;
        const delta    = currentVal - oldVal;
        const deltaPct = (delta / oldVal) * 100;
        if (Math.abs(deltaPct) < 0.1) continue; // skip <0.1% noise
        movers.push({ ...c, delta, deltaPct, oldVal, currentVal, periodLabel });
      }

      // Loader-state messaging. When scope = 'global', we ONLY render
      // the global market section (no personal collection section).
      // When scope = 'personal', we render only the user collection.
      if (_moversScope === 'global') {
        // Global-only view. If we have global data, show it. Otherwise
        // show a "loading" or "no data" placeholder.
        if (globalHtml) return globalHtml;
        return `<div class="dash-chart-section" style="margin-bottom:16px">
          <div style="font-size:.66rem;color:var(--muted);margin-bottom:8px;letter-spacing:.08em">MARKET · last ${_periodLabel}</div>
          <div style="font-size:.72rem;color:var(--muted);padding:8px 0">${_globalMoversLoading ? 'Loading market data…' : 'No market movement at this threshold — try a wider period.'}</div>
        </div>`;
      }
      // Personal scope: omit globalHtml entirely.
      if (!movers.length) {
        const yourHeader = `<div style="font-size:.66rem;color:var(--muted);margin-bottom:8px;letter-spacing:.08em">YOUR COLLECTION · last ${_periodLabel}</div>`;
        if (_priceHistoryLoading[_activePeriod]) {
          return `<div class="dash-chart-section" style="margin-bottom:16px">
            ${yourHeader}
            <div style="font-size:.72rem;color:var(--muted);padding:8px 0">Loading price history…</div>
          </div>`;
        }
        return `<div class="dash-chart-section" style="margin-bottom:16px">
          ${yourHeader}
          <div style="font-size:.72rem;color:var(--muted);padding:8px 0">No price movement yet — refreshing daily.</div>
        </div>`;
      }

      // Split into up-movers + down-movers, top 10 each. Sort metric
      // follows the user's $/% toggle so the personal list ranks by the
      // same axis as the global Market list.
      var _personalSortKeyFn = _moversSort === 'dollar'
        ? (m => Math.abs(m.delta))
        : (m => Math.abs(m.deltaPct));
      const upMovers   = movers.filter(m => m.delta >= 0)
                               .sort((a, b) => _personalSortKeyFn(b) - _personalSortKeyFn(a))
                               .slice(0, 10);
      const downMovers = movers.filter(m => m.delta < 0)
                               .sort((a, b) => _personalSortKeyFn(b) - _personalSortKeyFn(a))
                               .slice(0, 10);

      function _moverRow(c) {
        const sign  = c.delta >= 0 ? '+' : '';
        const color = c.delta >= 0 ? 'var(--green)' : 'var(--red)';
        const name  = c.card_name.length > 22 ? c.card_name.slice(0, 21) + '…' : c.card_name;
        const ghostMark = c.is_ghost ? ' <span style="color:var(--teal);font-size:.6rem">♡</span>' : '';
        return `<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid var(--border);cursor:pointer"
          onclick="openBinderCardDetail('${c.id}')">
          <div>
            <span style="font-size:.75rem;color:var(--text)">${name}${ghostMark}</span>
            <span style="font-size:.6rem;color:var(--muted);margin-left:5px">${c.periodLabel}</span>
          </div>
          <span style="font-size:.78rem;color:${color};font-weight:700">${sign}${c.deltaPct.toFixed(1)}% (${sign}$${Math.abs(c.delta).toFixed(2)})</span>
        </div>`;
      }

      // Personal section — show only the direction the user picked.
      var personalList  = (_moversDirection === 'down') ? downMovers : upMovers;
      var personalArrow = (_moversDirection === 'down') ? '↓' : '↑';
      var personalColor = (_moversDirection === 'down') ? 'var(--red)' : 'var(--green)';
      return `<div class="dash-chart-section" style="margin-bottom:16px">
        <div style="font-size:.66rem;color:var(--muted);margin-bottom:8px;letter-spacing:.08em">YOUR COLLECTION · last ${_periodLabel}</div>
        <div style="font-size:.75rem;color:${personalColor};margin-bottom:8px;letter-spacing:.08em">${personalArrow} Movers</div>
        ${personalList.length ? personalList.map(_moverRow).join('') : `<div style="font-size:.7rem;color:var(--muted);padding:6px 0">No ${_moversDirection === 'down' ? 'declines' : 'gains'} in your collection at this threshold.</div>`}
      </div>`;
    }

    // ── Price Alerts for Ghost Cards ─────────────────────────────────────────
    // Triggers two alert types per wishlist row:
    //   - price_hit:   the live market price is at or below the user's target
    //   - listing_hit: a marketplace listing exists within 5% above target
    //
    // The 5% buffer on listing_hit is the spirit of "if it's listed for
    // ~roughly~ what you wanted to pay, ping me" — a strict <= would silently
    // skip a listing that's $1 over target on a $50 card.
    function buildPriceAlerts(ghostCards) {
      const alerts = [];
      const LISTING_WITHIN_PCT = 0.05; // 5%

      for (const c of ghostCards) {
        const goal = c.savings_goal || 0;
        if (!goal) continue;
        const marketVal = c.current_value || 0;

        // Alert: current tracked price is at or below target
        if (marketVal > 0 && marketVal <= goal) {
          alerts.push({ type: 'price_hit', card: c, marketVal, goal });
        }

        // Alert: a marketplace listing exists within 5% of target
        const ceiling = goal * (1 + LISTING_WITHIN_PCT);
        const matchingListing = listings.find(l =>
          l.name.toLowerCase().includes(c.card_name.toLowerCase().slice(0, 8)) &&
          (l.status === 'active' || l.status === 'available') &&
          (l.value || 0) > 0 &&
          (l.value || 0) <= ceiling
        );
        if (matchingListing) {
          alerts.push({ type: 'listing_hit', card: c, listing: matchingListing, goal });
        }
      }

      if (!alerts.length) return '';

      return `<div style="margin-bottom:20px">
        ${alerts.map(a => {
          if (a.type === 'price_hit') {
            return `<div style="background:rgba(210,120,40,.07);border:1px solid rgba(210,120,40,.35);padding:10px 14px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;cursor:pointer"
              onclick="openBinderCardDetail('${a.card.id}')">
              <div>
                <div style="font-size:.75rem;color:var(--green);font-weight:700">PRICE TARGET HIT — ${a.card.card_name}</div>
                <div style="font-size:.68rem;color:var(--muted);margin-top:2px">Market price $${a.marketVal.toFixed(0)} is at or below your $${a.goal.toFixed(0)} target</div>
              </div>
              <span style="font-size:.7rem;color:var(--green)">→</span>
            </div>`;
          } else {
            // ±5% window — copy reflects "near target" not "at target"
            // since the listing might be slightly over the user's number.
            var _lv = a.listing.value || 0;
            var _diffPct = a.goal > 0 ? ((_lv - a.goal) / a.goal * 100) : 0;
            var _diffNote = _lv <= a.goal
              ? 'at or below your target'
              : '+' + _diffPct.toFixed(1) + '% over your target (within 5%)';
            return `<div style="background:rgba(210,120,40,.07);border:1px solid rgba(210,120,40,.35);padding:10px 14px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;cursor:pointer"
              onclick="showPage('browse');setMobileNav('browse')">
              <div>
                <div style="font-size:.75rem;color:var(--green);font-weight:700">LISTED NEAR TARGET — ${a.card.card_name}</div>
                <div style="font-size:.68rem;color:var(--muted);margin-top:2px">${a.listing.name} is on the marketplace for $${_lv.toFixed(0)} — ${_diffNote} (target $${a.goal.toFixed(0)})</div>
              </div>
              <span style="font-size:.7rem;color:var(--green)">→ Marketplace</span>
            </div>`;
          }
        }).join('')}
      </div>`;
    }

    function renderMyListings() {
      const content = document.getElementById('myListingsContent');
      if (!content || !currentUser) return;
      const mine = listings.filter(l => l.seller_id === currentUser.id || l.sellerId === currentUser.id);

      // Stripe Connect status banner — only for tiers that can sell. Lives
      // above the listing-cap header so the seller sees payout state first.
      // Renders synchronously from cached connectStatus; an async refresh
      // is kicked off in parallel and re-runs this view when it returns.
      var _connectHtml = (typeof renderConnectStatusBanner === 'function')
        ? renderConnectStatusBanner()
        : '';
      if (typeof refreshConnectStatus === 'function' && tierAtLeast('enthusiast')) {
        // Fire-and-forget. The callback re-paints my listings if anything
        // changed. Guarded against being called more than once per page
        // load by the helper itself.
        refreshConnectStatus(function() { renderMyListings(); });
      }

      // Listing-cap status header (skip if free/collector since cap=0 means
      // they shouldn't be here at all, or shop since cap=Infinity).
      var _cap = listingCap();
      var _used = activeListingCount();
      var _capHtml = '';
      if (_cap !== Infinity && _cap > 0) {
        var _pct = _cap > 0 ? Math.round((_used / _cap) * 100) : 0;
        var _color = _used >= _cap ? 'var(--red)' : (_used >= _cap * 0.8 ? 'var(--yellow,#FFD93D)' : 'var(--accent)');
        _capHtml = '<div style="padding:10px 14px;background:var(--surface2);border:1px solid var(--border);border-left:3px solid ' + _color + ';margin-bottom:12px;display:flex;justify-content:space-between;align-items:center;font-family:\'Space Mono\',monospace;font-size:.72rem;color:var(--muted)">' +
          '<span><b style="color:' + _color + '">' + _used + ' / ' + _cap + '</b> active listings (' + TIER_COLORS[userTier()].label + ' tier)</span>' +
          (_used >= _cap
            ? '<button onclick="openPricingModalWithPromo(\'' + (tierAtLeast('vendor') ? 'shop' : (tierAtLeast('enthusiast') ? 'vendor' : 'enthusiast')) + '\')" class="pb-panel-link" style="border-color:var(--accent);color:var(--accent);font-size:.65rem">Upgrade for more →</button>'
            : '<span>' + Math.max(0, _cap - _used) + ' slots remaining</span>') +
          '</div>';
      }
      if (mine.length === 0) {
        content.innerHTML = _connectHtml + _capHtml + '<div class="coll-empty">You have no active listings.<br>Click "List A Card" to get started.</div>';
        return;
      }
      content.innerHTML = _connectHtml + _capHtml + `<div class="coll-table-wrap"><table class="coll-table">
        <thead><tr><th>Card</th><th>Grade</th><th>Price</th><th>Status</th><th></th></tr></thead>
        <tbody>${mine.map(l => {
          const price = l.list_price || l.value || 0;
          // Whole row click → viewDetail. The Remove button calls
          // event.stopPropagation() so it doesn't double-fire.
          return `<tr onclick="viewDetail('${l.id}')" style="cursor:pointer">
            <td>
              <div style="display:flex;align-items:center;gap:8px">
                ${l.photos && l.photos[0] ? `<img src="${_pickThumbVariant(l.photos[0], 200)}" data-fallback="${l.photos[0]}" style="height:40px;width:auto;border:1px solid var(--border)" onerror="if(this.dataset.fallback&&this.src!==this.dataset.fallback){this.src=this.dataset.fallback}else{this.style.display='none';this.onerror=null}" loading="lazy" decoding="async">` : ''}
                <span style="color:var(--text)">${l.name}</span>
              </div>
            </td>
            <td><span class="${l.grade && l.grade !== 'Raw' ? 'grade-badge' : 'raw-badge'}">${l.grade || 'Raw'}</span></td>
            <td style="color:var(--accent)">$${Number(price).toLocaleString()}</td>
            <td><span class="badge ${l.status === 'sold' ? 'badge-full' : 'badge-open'}">${l.status || 'Active'}</span></td>
            <td>
              ${l.status !== 'sold' ? `
                <div style="display:flex;gap:6px;justify-content:flex-end">
                  <button onclick="event.stopPropagation();openEditMarketplaceListing('${l.id}')" style="background:transparent;border:1px solid var(--accent);color:var(--accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.68rem;padding:4px 8px;cursor:pointer">Edit</button>
                  <button onclick="event.stopPropagation();deactivateListing('${l.id}')" style="background:transparent;border:1px solid var(--border);color:var(--red);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.68rem;padding:4px 8px;cursor:pointer">Remove</button>
                </div>` : ''}
            </td>
          </tr>`;
        }).join('')}</tbody>
      </table></div>`;
    }

    function renderOrders() {
      const content = document.getElementById('ordersContent');
      if (!content || !currentUser) return;

      const mine = orders.filter(o =>
        activeOrdersTab === 'buying' ? o.buyer_id === currentUser.id : o.seller_id === currentUser.id
      );

      if (mine.length === 0) {
        content.innerHTML = `<div class="coll-empty">${activeOrdersTab === 'buying' ? 'No purchases yet.' : 'No sales yet.'}</div>`;
        return;
      }

      const statusLabel = { pending_payment:'Pending Payment', paid:'Paid — Awaiting Shipment', shipped:'Shipped — In Transit', delivered:'Delivered', completed:'Completed', cancelled:'Cancelled', disputed:'Disputed', return_requested:'Return Requested — Ship Card Back', refunded:'Refunded' };
      const statusColor = { pending_payment:'var(--muted)', paid:'var(--yellow)', shipped:'var(--teal)', delivered:'var(--green)', completed:'var(--green)', cancelled:'var(--red)', disputed:'var(--red)', return_requested:'var(--yellow)', refunded:'var(--muted)' };

      content.innerHTML = mine.map(order => {
        const listing = listings.find(l => String(l.id) === String(order.listing_id));
        const cardName = listing ? listing.name : (order.card_name || 'Unknown Card');
        const photoSrc = listing && listing.photos && listing.photos[0] ? listing.photos[0] : '';
        const status = order.status || 'pending_payment';
        const isBuying = activeOrdersTab === 'buying';

        let actionHtml = '';
        // Block of read-only context shown above the action buttons when
        // there's a return in flight — gives both sides the reason text
        // and decision state at a glance.
        let returnContext = '';
        if (order.return_reason && (status === 'return_requested' || status === 'disputed' || status === 'refunded')) {
          const reasonLabels = {
            not_as_described: 'Not as described',
            damaged:          'Arrived damaged',
            never_arrived:    'Never arrived',
            wrong_item:       'Wrong item',
            other:            'Other',
          };
          const reasonLbl = reasonLabels[order.return_reason] || order.return_reason;
          const detailEsc = String(order.return_reason_detail || '')
            .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
          returnContext = ''
            + '<div style="margin-top:8px;padding:8px 10px;border-left:3px solid var(--yellow);background:rgba(255,217,61,.06);font-size:.72rem;color:var(--muted);line-height:1.5">'
            +   '<div style="color:var(--yellow);font-weight:700;letter-spacing:.04em;margin-bottom:2px">RETURN REASON &middot; ' + reasonLbl + '</div>'
            +   (detailEsc ? '<div style="color:var(--text)">"' + detailEsc + '"</div>' : '')
            + '</div>';
        }

        if (isBuying && status === 'shipped') {
          // Buyer can mark received (which opens a rate-seller prompt) OR
          // file a dispute if there's an issue. No more "Confirm Delivery"
          // gating a payout — sellers are paid via Stripe's normal schedule.
          // stopPropagation prevents these from also firing the row's
          // viewDetail click handler.
          actionHtml = `<div style="display:flex;gap:8px;flex-wrap:wrap">
            <button onclick="event.stopPropagation();markOrderReceived('${order.id}')" style="padding:8px 16px;background:var(--accent);color:var(--text-on-accent);border:none;font-family:'Space Mono','Share Tech Mono',monospace;font-size:.78rem;font-weight:700;cursor:pointer">✓ Mark Received</button>
            <button onclick="event.stopPropagation();requestReturn('${order.id}')" style="padding:8px 16px;border:1px solid var(--red);background:transparent;color:var(--red);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">⚠ Report Issue</button>
          </div>`;
        } else if (isBuying && status === 'completed') {
          actionHtml = `<button onclick="event.stopPropagation();requestReturn('${order.id}')" style="padding:8px 16px;border:1px solid var(--red);background:transparent;color:var(--red);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">↩ Return / Refund Request</button>`;
        } else if (isBuying && status === 'return_requested') {
          // Buyer is waiting on the seller's decision. No actions.
          actionHtml = '<div style="font-size:.72rem;color:var(--yellow)">Waiting on seller to respond</div>';
        } else if (isBuying && status === 'disputed') {
          actionHtml = '<div style="font-size:.72rem;color:var(--red)">Disputed &mdash; admin reviewing</div>';
        } else if (!isBuying && status === 'paid') {
          actionHtml = `<button onclick="event.stopPropagation();openAddTrackingModal('${order.id}')" style="padding:8px 16px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.78rem;cursor:pointer">Add Tracking #</button>`;
        } else if (!isBuying && status === 'return_requested') {
          // Seller-side response to a return request. Approve issues the
          // refund via /api/seller-refund; Decline escalates to disputed.
          actionHtml = `<div style="display:flex;gap:8px;flex-wrap:wrap">
            <button onclick="event.stopPropagation();openSellerRefundConfirm('${order.id}')" style="padding:8px 16px;background:var(--red);color:var(--surface);border:none;font-family:'Space Mono','Share Tech Mono',monospace;font-size:.78rem;font-weight:700;cursor:pointer">Approve Refund</button>
            <button onclick="event.stopPropagation();declineReturnRequest('${order.id}')" style="padding:8px 16px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">Decline &amp; Dispute</button>
          </div>`;
        } else if (!isBuying && (status === 'shipped' || status === 'delivered' || status === 'completed')) {
          // Seller can issue a goodwill refund any time before the buyer
          // confirms. Less prominent (border-only) since most don't need it.
          actionHtml = `<button onclick="event.stopPropagation();openSellerRefundConfirm('${order.id}')" style="padding:8px 16px;border:1px solid var(--red);background:transparent;color:var(--red);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;cursor:pointer">Refund Buyer</button>`;
        } else if (!isBuying && status === 'disputed') {
          actionHtml = '<div style="font-size:.72rem;color:var(--red)">Disputed &mdash; admin reviewing</div>';
        }

        // Whole card click → viewDetail. Action buttons inside use
        // event.stopPropagation() so they don't double-fire. Only
        // clickable when the underlying listing still exists in cache;
        // otherwise the click would silently no-op.
        var _clickAttr = listing
          ? ' onclick="viewDetail(\'' + listing.id + '\')" style="cursor:pointer;background:var(--surface);border:1px solid var(--border);padding:16px;margin-bottom:12px"'
          : ' style="background:var(--surface);border:1px solid var(--border);padding:16px;margin-bottom:12px"';
        return '<div' + _clickAttr + '>' + `
          <div style="display:flex;gap:12px;align-items:start;flex-wrap:wrap">
            ${photoSrc ? `<img src="${photoSrc}" style="height:60px;width:auto;border:1px solid var(--border);flex-shrink:0" loading="lazy" decoding="async">` : ''}
            <div style="flex:1;min-width:200px">
              <div style="color:var(--text);font-size:.9rem;margin-bottom:4px">${cardName}</div>
              <div style="font-size:.75rem;color:var(--muted);margin-bottom:6px">Order #${order.id.slice(0,8).toUpperCase()} · ${_fmtDate(order.created_at)}</div>
              <div style="font-size:.78rem;margin-bottom:6px">
                <span style="color:${statusColor[status] || 'var(--muted)'}">● ${statusLabel[status] || status}</span>
              </div>
              ${order.tracking_number ? `<div style="font-size:.72rem;color:var(--muted)">Tracking: ${order.tracking_carrier || ''} ${order.tracking_number}</div>` : ''}
              <div style="font-size:.78rem;color:var(--muted);margin-top:4px">
                ${isBuying ? `Paid: $${(order.amount||0).toFixed(2)}` : `Your payout: $${(order.seller_payout||0).toFixed(2)} · paid via Stripe`}
              </div>
              ${returnContext}
              <div style="margin-top:8px">
                <button onclick="event.stopPropagation();openOrderMessagesModal('${order.id}')"
                  style="padding:5px 12px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.68rem;cursor:pointer;letter-spacing:.04em">
                  ⬡ Message ${isBuying ? 'seller' : 'buyer'}
                </button>
              </div>
            </div>
            ${actionHtml ? `<div>${actionHtml}</div>` : ''}
          </div>
        </div>`;
      }).join('');
    }

    function renderWatchlist() {
      const content = document.getElementById('watchlistContent');
      if (!content) return;
      if (!currentUser || !currentUser.watchlist || currentUser.watchlist.length === 0) {
        content.innerHTML = '<div class="coll-empty">No items in your watchlist yet.<br>Click the bell on any listing to watch it.</div>';
        return;
      }
      const watched = listings.filter(l => currentUser.watchlist.includes(String(l.id)));
      if (watched.length === 0) {
        content.innerHTML = '<div class="coll-empty">Your watched listings are no longer available.</div>';
        return;
      }
      content.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:16px">
        ${watched.map(l => {
          const price = l.list_price || l.value || 0;
          const photo = l.photos && l.photos[0];
          return `<div class="listing-card" style="cursor:pointer" onclick="viewDetail('${l.id}')">
            ${photo ? `<img src="${photo}" style="width:100%;height:140px;object-fit:contain;border-bottom:1px solid var(--border)" loading="lazy" decoding="async">` : ''}
            <div style="padding:10px">
              <div style="color:var(--text);font-size:.85rem;margin-bottom:4px">${l.name}</div>
              <div style="color:var(--accent);font-size:.9rem">$${Number(price).toLocaleString()}</div>
            </div>
          </div>`;
        }).join('')}
      </div>`;
    }

    // ===== SHAREABLE COLLECTION LINKS =====

    function getShareUsername() {
      // Prefer username slug, fall back to user UUID
      return currentUser?.username || currentUser?.id || null;
    }

    function getShareUrl(username, binderId) {
      let url = `${window.location.origin}${window.location.pathname}?binder=${encodeURIComponent(username)}`;
      if (binderId) url += `&b=${encodeURIComponent(binderId)}`;
      return url;
    }

    function copyShareLink() {
      const slug = getShareUsername();
      if (!slug) { showToast('Sign in to share your binder'); return; }
      console.log('[Share] currentBinderId:', currentBinderId, '| slug:', slug);
      const url = getShareUrl(slug, currentBinderId);
      navigator.clipboard.writeText(url).then(() => {
        showToast('Share link copied! Send it to anyone.');
      }).catch(() => {
        // Fallback for older browsers
        const ta = document.createElement('textarea');
        ta.value = url;
        ta.style.position = 'fixed'; ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select(); document.execCommand('copy');
        document.body.removeChild(ta);
        showToast('Share link copied!');
      });
    }

    // ── Public binder renderer (read-only view for visitors) ──────────────────
    async function loadPublicBinder(usernameOrId, binderId) {
      const el = document.getElementById('publicBinderContent');
      if (!el) return;
      isPublicView = true; // prevent onAuthStateChange from redirecting to browse
      el.innerHTML = `<div style="text-align:center;padding:60px;color:var(--muted)">Loading binder…</div>`;
      showPage('publicBinder');

      try {
        // Look up profile by username first, then by UUID
        let profile = null;
        console.log('[PublicBinder] looking up:', usernameOrId);
        const { data: byUsername, error: e1 } = await sb.from('profiles')
          .select('*')
          .eq('username', usernameOrId)
          .maybeSingle();
        console.log('[PublicBinder] byUsername result:', byUsername, 'error:', e1);
        if (byUsername) {
          profile = byUsername;
        } else {
          const { data: byId, error: e2 } = await sb.from('profiles')
            .select('*')
            .eq('id', usernameOrId)
            .maybeSingle();
          console.log('[PublicBinder] byId result:', byId, 'error:', e2);
          profile = byId;
        }

        if (!profile) {
          el.innerHTML = `<div style="text-align:center;padding:60px;color:var(--muted)">Binder not found.<br><span style="font-size:.7rem;color:var(--muted)">Looking for: "${usernameOrId}"</span></div>`;
          return;
        }

        // Load their collection (public cards only — no ghost/wishlist items)
        // If a specific binder ID was shared, filter to just that binder
        let itemsQuery = sb.from('collection_items')
          .select('id, card_name, set_name, card_number, condition, grade_value, quantity, card_image_url, current_value, purchase_price, rarity, api_card_id, binder_id')
          .eq('user_id', profile.id)
          .eq('is_ghost', false);
        if (binderId) itemsQuery = itemsQuery.eq('binder_id', binderId);
        const { data: items, error } = await itemsQuery.order('created_at', { ascending: true });
        window._publicBinderItems = items || [];
        console.log('[PublicBinder] items query error:', error, '| count:', items?.length, '| sample url:', items?.[0]?.card_image_url);

        // Resolve binder metadata (name, cover, color)
        let binderName = null, binderCoverUrl = null, binderColor = '#444';
        if (binderId) {
          const { data: binderRow } = await sb.from('binders').select('name, cover_image_url, color').eq('id', binderId).maybeSingle();
          binderName     = binderRow?.name || null;
          binderCoverUrl = binderRow?.cover_image_url || null;
          binderColor    = binderRow?.color || '#444';
        } else {
          // All Cards — use the default cover
          binderCoverUrl = 'https://xjamytrhxeaynywcwfun.supabase.co/storage/v1/object/public/binder-covers/default-cover.webp';
        }

        if (error) throw error;

        const displayName = profile.shop_name || profile.name || profile.username || 'Collector';
        const binderTitle = binderName ? `${displayName}'s ${binderName} Binder` : `${displayName}'s Binder`;
        const memberSince = profile.created_at ? new Date(profile.created_at).getFullYear() : '';
        const cardCount   = items?.length || 0;
        const totalValue  = (items||[]).reduce((s,c) => s + ((c.current_value||c.purchase_price||0) * (c.quantity||1)), 0);

        // Tier badge
        const tierColors = { free:'var(--muted)', collector:'var(--teal)', vendor:'var(--gold)', shop:'var(--accent)' };
        const tier = profile.subscription_tier || (profile.is_admin ? 'shop' : profile.is_vendor ? 'vendor' : profile.is_premium ? 'collector' : 'free');
        const tierBadge = tier !== 'free'
          ? `<span style="font-size:.62rem;padding:2px 7px;border:1px solid ${tierColors[tier]||'var(--muted)'};color:${tierColors[tier]||'var(--muted)'};letter-spacing:.08em;margin-left:8px">${tier.toUpperCase()}</span>`
          : '';

        // Build card grid (hidden initially)
        const gridCards = (items||[]).map((c, idx) => {
          const condLabel = c.condition === 'graded' && c.grade_value
            ? `PSA ${c.grade_value}`
            : (c.condition||'').toUpperCase();
          // Use 'data:,' to trigger onerror catalog fallback when url is missing but api_card_id exists
          const _pbSrc = c.card_image_url || (c.api_card_id ? 'data:,' : '');
          const img = _pbSrc
            ? `<img src="${_pbSrc}" alt="${_escHtml(c.card_name)}" loading="lazy" decoding="async" style="width:100%;height:160px;object-fit:contain;border-radius:4px 4px 0 0;display:block" onerror="_publicImgFail(this,'${c.api_card_id||''}')">`+
              `<div class="pub-no-img" style="display:none;width:100%;height:160px;background:var(--surface2);border-radius:4px 4px 0 0;align-items:center;justify-content:center;color:var(--muted);font-size:.7rem">NO IMAGE</div>`
            : `<div style="width:100%;height:160px;background:var(--surface2);border-radius:4px 4px 0 0;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:.7rem">NO IMAGE</div>`;
          const qtyBadge = c.quantity > 1
            ? `<span style="position:absolute;top:6px;right:6px;background:rgba(0,0,0,.7);color:var(--text);font-size:.6rem;padding:1px 5px;border-radius:2px">×${c.quantity}</span>`
            : '';
          return `<div onclick="openPublicCardDetail(${idx})" style="background:var(--surface);border:1px solid var(--border);border-radius:6px;overflow:hidden;position:relative;transition:transform .15s,box-shadow .15s;cursor:pointer" onmouseenter="this.style.transform='translateY(-3px)';this.style.boxShadow='0 6px 24px rgba(0,0,0,.5)'" onmouseleave="this.style.transform='';this.style.boxShadow=''">
            ${img}
            ${qtyBadge}
            <div style="padding:8px 10px">
              <div style="font-size:.75rem;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-weight:600">${c.card_name}</div>
              ${c.set_name ? `<div style="font-size:.65rem;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${c.set_name}${c.card_number?` #${c.card_number}`:''}</div>` : ''}
              ${condLabel ? `<div style="font-size:.62rem;color:var(--teal);margin-top:2px">${condLabel}</div>` : ''}
            </div>
          </div>`;
        }).join('');

        // CTA for visitors who aren't signed in
        const ctaHtml = !currentUser ? `
          <div style="margin-top:32px;padding:20px;background:var(--surface);border:1px solid var(--border);text-align:center">
            <div style="color:var(--accent);font-size:.9rem;margin-bottom:8px;letter-spacing:.08em">// BUILD YOUR OWN BINDER</div>
            <div style="color:var(--muted);font-size:.8rem;margin-bottom:16px">PathBinder is the card collector's portfolio tracker. Free to start.</div>
            <button onclick="openModal('registerModal')"
              style="padding:10px 28px;border:none;background:var(--accent);color:var(--text-on-accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.85rem;font-weight:700;cursor:pointer;letter-spacing:.04em">
              Create Free Account →
            </button>
          </div>` : '';

        // Binder cover art
        const coverArt = binderCoverUrl
          ? `<img src="${binderCoverUrl}" alt="${binderName||'Binder'}" style="width:100%;height:100%;object-fit:cover;display:block;pointer-events:none" loading="lazy" decoding="async">`
          : `<div style="width:100%;height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;background:${binderColor}22;padding:16px">
               <div style="font-size:2rem;color:${binderColor};opacity:.8">⬡</div>
               <div style="font-size:.8rem;font-family:'Space Mono','Share Tech Mono',monospace;color:rgba(255,255,255,.72);text-align:center;word-break:break-word">${binderName||displayName}</div>
             </div>`;

        el.innerHTML = `
          <!-- Top nav row -->
          <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:32px">
            <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
              <span style="font-size:.8rem;color:var(--muted)">@${profile.username||displayName}</span>
              ${tierBadge}
              ${memberSince ? `<span style="font-size:.72rem;color:var(--muted)">· since ${memberSince}</span>` : ''}
            </div>
            <div style="display:flex;gap:10px">
              <button onclick="window.history.back()" style="padding:7px 14px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">← Back</button>
              ${currentUser ? `<button onclick="showPage('collection');setMobileNav('collection')" style="padding:7px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">My Binder</button>` : `<button onclick="openModal('loginModal')" style="padding:7px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">Sign In</button>`}
            </div>
          </div>

          <!-- ══ COVER STATE ══ -->
          <div id="pbCoverState" style="display:flex;flex-direction:column;align-items:center;gap:28px;padding:20px 0 40px">
            <div style="text-align:center">
              <h2 style="font-size:1.4rem;margin:0 0 4px">${binderTitle}</h2>
              <div style="font-size:.78rem;color:var(--muted)">${cardCount} card${cardCount!==1?'s':''}</div>
            </div>

            <!-- Big binder book -->
            <div id="pbBinderBook" style="
              position:relative;width:180px;height:236px;
              transform:perspective(900px) rotateY(-18deg);
              filter:drop-shadow(8px 16px 32px rgba(0,0,0,.85));
              transition:transform .5s cubic-bezier(.22,1,.36,1),filter .5s ease;
              cursor:pointer" onclick="openPublicBinder()" title="Open Binder">
              <!-- Spine -->
              <div style="position:absolute;left:0;top:0;bottom:0;width:28px;border-radius:5px 0 0 5px;background:${binderColor};display:flex;align-items:center;justify-content:center;overflow:hidden">
                <span style="writing-mode:vertical-rl;transform:rotate(180deg);font-size:.7rem;font-family:'Space Mono','Share Tech Mono',monospace;color:rgba(255,255,255,.88);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-height:190px;letter-spacing:.05em">${binderName||displayName}</span>
              </div>
              <!-- Cover -->
              <div style="position:absolute;left:28px;top:0;right:0;bottom:0;border-radius:0 6px 6px 0;overflow:hidden;border-left:2px solid rgba(0,0,0,.3)">
                ${coverArt}
              </div>
            </div>

            <button onclick="openPublicBinder()" style="
              padding:12px 36px;border:none;background:var(--accent);
              color:var(--surface);font-family:'Space Mono','Share Tech Mono',monospace;
              font-size:.88rem;font-weight:700;cursor:pointer;letter-spacing:.06em;
              transition:transform .1s,box-shadow .1s">
              Open Binder →
            </button>
          </div>

          <!-- ══ CARDS STATE (hidden until opened) ══ -->
          <div id="pbCardsState" style="display:none;opacity:0;transition:opacity .4s ease">
            <!-- Stats bar -->
            <div style="display:flex;gap:16px;flex-wrap:wrap;margin-bottom:24px;padding:12px 16px;background:var(--surface);border:1px solid var(--border)">
              <span style="font-size:.78rem;color:var(--muted)">Cards: <span style="color:var(--text)">${cardCount}</span></span>
              ${totalValue > 0 ? `<span style="font-size:.78rem;color:var(--muted)">Est. Value: <span style="color:var(--green)">$${totalValue.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}</span></span>` : ''}
              <button onclick="showPublicBinderCover()" style="margin-left:auto;background:transparent;border:none;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.7rem;cursor:pointer;padding:0">← Close</button>
            </div>
            <!-- Card grid -->
            ${cardCount === 0
              ? `<div style="text-align:center;padding:60px;color:var(--muted)">This binder is empty.</div>`
              : `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:14px">${gridCards}</div>`}
            ${ctaHtml}
          </div>`;



      } catch (err) {
        console.error('loadPublicBinder error:', err);
        el.innerHTML = `<div style="text-align:center;padding:60px;color:var(--red)">Failed to load binder.</div>`;
      }
    }

    // ── Public binder card detail popup ─────────────────────────────────────
    function openPublicCardDetail(idx) {
      const c = (window._publicBinderItems || [])[idx];
      if (!c) return;

      document.getElementById('pubCardDetail')?.remove();

      const img = c.card_image_url || '';
      const condLabel = c.condition === 'graded' && c.grade_value
        ? `PSA ${c.grade_value}`
        : (c.condition || 'Raw').toUpperCase();
      const value = c.current_value || c.purchase_price || null;

      const wishlistAction = currentUser
        ? `<button onclick="addPublicCardToWishlist(${idx})"
            style="padding:9px;width:100%;border:1px solid rgba(26,199,160,.22);background:transparent;color:rgba(26,199,160,.5);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.7rem;cursor:pointer;letter-spacing:.08em;transition:all .15s"
            onmouseover="this.style.borderColor='rgba(26,199,160,.55)';this.style.color='rgba(26,199,160,.88)'"
            onmouseout="this.style.borderColor='rgba(26,199,160,.22)';this.style.color='rgba(26,199,160,.5)'">&#9825; ADD TO WISHLIST</button>`
        : `<div style="text-align:center;padding:12px;font-size:.65rem;color:rgba(26,199,160,.35);letter-spacing:.08em">
             SIGN IN TO ADD TO WISHLIST
           </div>`;

      const overlay = document.createElement('div');
      overlay.id = 'pubCardDetail';
      overlay.className = 'modal-overlay';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:10010;display:flex;align-items:center;justify-content:center;padding:16px';

      overlay.innerHTML = `
        <div class="modal" style="width:100%;max-width:340px;padding:22px 20px;max-height:92vh;overflow-y:auto;overflow-x:hidden">
          <!-- Header -->
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:18px">
            <h3 style="font-size:.6rem;letter-spacing:.14em;margin:0">CARD DETAIL</h3>
            <button class="modal-close" onclick="document.getElementById('pubCardDetail').remove()"
              style="background:none;border:none;font-size:1.4rem;cursor:pointer;line-height:1;padding:0 2px">×</button>
          </div>

          <!-- Card image — centered, clickable -->
          ${img ? `<div style="display:flex;justify-content:center;margin-bottom:16px">
            <img src="${img}" alt="${_escHtml(c.card_name)}"
              title="Click to enlarge" style="max-width:200px;width:100%;height:auto;border:1px solid rgba(26,199,160,.35);border-radius:4px;box-shadow:0 0 24px rgba(26,199,160,.22),0 0 60px rgba(26,199,160,.08);cursor:zoom-in;transition:transform .15s"
              onmouseover="this.style.transform='scale(1.03)'" onmouseout="this.style.transform=''"
              onclick="openImageLightbox('${img}')"
              onerror="this.parentElement.innerHTML='<div style=\\'width:200px;height:280px;background:rgba(26,199,160,.04);border:1px solid rgba(26,199,160,.15);border-radius:4px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px\\' loading="lazy" decoding="async"><span style=\\'font-size:2rem;opacity:.2\\'>⬡</span><span style=\\'font-size:.55rem;letter-spacing:.1em;color:rgba(26,199,160,.25)\\'>NO IMAGE</span></div>'">
          </div>` : ''}

          <!-- Card info — centered -->
          <div style="text-align:center;margin-bottom:14px">
            <div style="font-size:.9rem;font-weight:700;color:rgba(210,240,255,.95);margin-bottom:5px">${_escHtml(c.card_name)}</div>
            ${c.set_name ? `<div style="font-size:.63rem;color:rgba(26,199,160,.5);margin-bottom:6px">${_escHtml(c.set_name)}${c.card_number ? ` &middot; #${c.card_number}` : ''}</div>` : ''}
            ${c.rarity ? `<div style="margin-bottom:6px"><span style="padding:2px 10px;border:1px solid rgba(26,199,160,.28);font-size:.57rem;color:rgba(26,199,160,.55);letter-spacing:.08em">${_escHtml(c.rarity)}</span></div>` : ''}
            <div style="margin-top:6px"><span style="padding:2px 8px;border:1px solid rgba(26,199,160,.18);font-size:.57rem;color:rgba(26,199,160,.42);letter-spacing:.06em">${condLabel}</span></div>
            ${c.quantity > 1 ? `<div style="font-size:.58rem;color:rgba(26,199,160,.35);margin-top:4px;letter-spacing:.06em">×${c.quantity} in collection</div>` : ''}
            ${value ? `<div style="font-size:1.05rem;font-weight:700;color:#1AC7A0;margin-top:12px;text-shadow:0 0 12px rgba(26,199,160,.5)">~$${Number(value).toFixed(2)}</div>
              <div style="font-size:.56rem;color:rgba(26,199,160,.38);letter-spacing:.06em">estimated value</div>` : ''}
          </div>

          <!-- Divider -->
          <div style="height:1px;background:rgba(26,199,160,.1);margin-bottom:14px"></div>

          <!-- Wishlist only -->
          ${wishlistAction}
        </div>
      `;

      overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
      document.body.appendChild(overlay);
    }

    async function addPublicCardToWishlist(idx) {
      if (!currentUser) { showToast('Sign in to add to wishlist'); return; }
      const c = (window._publicBinderItems || [])[idx];
      if (!c) return;
      const btn = document.querySelector('#pubCardDetail button[onclick*="addPublicCardToWishlist"]');
      if (btn) { btn.textContent = 'Adding…'; btn.disabled = true; }
      const { error } = await sb.from('collection_items').insert({
        user_id:       currentUser.id,
        card_name:     c.card_name,
        set_name:      c.set_name     || null,
        card_number:   c.card_number  || null,
        card_image_url:c.card_image_url||null,
        api_card_id:   c.api_card_id  || null,
        rarity:        c.rarity       || null,
        game_type:     'pokemon',
        condition:     'raw',
        quantity:      1,
        is_ghost:      true,
        current_value: c.current_value || null,
      });
      if (error) {
        showToast('Error: ' + error.message);
        if (btn) { btn.textContent = '♡ ADD TO WISHLIST'; btn.disabled = false; }
      } else {
        showToast('♡ Added to wishlist!');
        document.getElementById('pubCardDetail')?.remove();
        await loadCollection();
      }
    }

    // ── Public binder open/close animation ──────────────────────────────────
    function openPublicBinder() {
      const book   = document.getElementById('pbBinderBook');
      const cover  = document.getElementById('pbCoverState');
      const cards  = document.getElementById('pbCardsState');
      if (!book || !cover || !cards) return;

      // Flip the binder open
      book.style.transform = 'perspective(900px) rotateY(-52deg) translateY(-12px)';
      book.style.filter    = 'drop-shadow(12px 20px 40px rgba(0,0,0,.95))';

      // After the flip, swap to card grid
      setTimeout(() => {
        cover.style.opacity = '0';
        cover.style.transition = 'opacity .25s ease';
        setTimeout(() => {
          cover.style.display = 'none';
          cards.style.display = 'block';
          requestAnimationFrame(() => {
            cards.style.opacity = '1';
          });
        }, 250);
      }, 380);
    }

    function showPublicBinderCover() {
      const cover = document.getElementById('pbCoverState');
      const cards = document.getElementById('pbCardsState');
      const book  = document.getElementById('pbBinderBook');
      if (!cover || !cards || !book) return;

      cards.style.opacity = '0';
      setTimeout(() => {
        cards.style.display = 'none';
        cover.style.display = 'flex';
        cover.style.opacity = '0';
        book.style.transform = 'perspective(900px) rotateY(-18deg)';
        book.style.filter    = 'drop-shadow(8px 16px 32px rgba(0,0,0,.85))';
        requestAnimationFrame(() => {
          cover.style.transition = 'opacity .3s ease';
          cover.style.opacity = '1';
        });
      }, 250);
    }

    // ── Storefront helper functions ──────────────────────────────────────────
    function copyStoreLink() {
      const slug = getShareUsername();
      if (!slug) { showToast('Sign in to access your store link'); return; }
      const url = `${window.location.origin}${window.location.pathname}?store=${encodeURIComponent(slug)}`;
      navigator.clipboard.writeText(url).then(() => {
        showToast('Store link copied! Share it with customers.');
      }).catch(() => {
        const ta = document.createElement('textarea');
        ta.value = url;
        ta.style.position = 'fixed'; ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select(); document.execCommand('copy');
        document.body.removeChild(ta);
        showToast('Store link copied!');
      });
    }

    function previewStorefront() {
      const slug = getShareUsername();
      if (!slug) { showToast('Sign in to preview your storefront'); return; }
      loadStorefront(slug);
    }

    async function saveShopSettings() {
      if (!currentUser) return;
      const name    = document.getElementById('shopSettingName')?.value.trim()     || '';
      const tagline = document.getElementById('shopSettingTagline')?.value.trim()  || '';
      const insta   = document.getElementById('shopSettingInstagram')?.value.trim()|| '';
      const website = document.getElementById('shopSettingWebsite')?.value.trim()  || '';
      const desc    = document.getElementById('shopSettingDesc')?.value.trim()     || '';
      const active  = document.querySelector('#shopBannerPicker [data-bc]');
      // find which swatch has the accent outline
      let banner = currentUser.shop_banner_color || '#080500';
      document.querySelectorAll('#shopBannerPicker [data-bc]').forEach(el => {
        if (el.style.outline && el.style.outline.includes('2px')) banner = el.getAttribute('data-bc');
      });

      const { error } = await sb.from('profiles').update({
        shop_name:         name     || null,
        shop_tagline:      tagline  || null,
        shop_instagram:    insta    || null,
        shop_website:      website  || null,
        shop_description:  desc     || null,
        shop_banner_color: banner,
      }).eq('id', currentUser.id);

      if (error) { showToast('Error: ' + error.message); return; }

      currentUser.shop_name         = name     || null;
      currentUser.shop_tagline      = tagline  || null;
      currentUser.shop_instagram    = insta    || null;
      currentUser.shop_website      = website  || null;
      currentUser.shop_description  = desc     || null;
      currentUser.shop_banner_color = banner;

      const saved = document.getElementById('shopSettingSaved');
      if (saved) { saved.style.display = 'inline'; setTimeout(() => { saved.style.display = 'none'; }, 2500); }
      showToast('✓ Shop settings saved');
    }

    // ── Public storefront page ───────────────────────────────────────────────
    async function loadStorefront(usernameOrId) {
      const el = document.getElementById('storefrontContent');
      if (!el) return;
      el.innerHTML = `<div style="text-align:center;padding:80px;color:var(--muted)">Loading storefront…</div>`;
      showPage('storefront');

      try {
        // Resolve profile
        let profile = null;
        const { data: byUsername } = await sb.from('profiles')
          .select('id, name, username, shop_name, shop_tagline, shop_description, shop_instagram, shop_website, shop_banner_color, subscription_tier, is_premium, is_vendor, is_admin, avatar_url, created_at')
          .eq('username', usernameOrId).maybeSingle();
        if (byUsername) {
          profile = byUsername;
        } else {
          const { data: byId } = await sb.from('profiles')
            .select('id, name, username, shop_name, shop_tagline, shop_description, shop_instagram, shop_website, shop_banner_color, subscription_tier, is_premium, is_vendor, is_admin, avatar_url, created_at')
            .eq('id', usernameOrId).maybeSingle();
          profile = byId;
        }

        if (!profile) {
          el.innerHTML = `<div style="text-align:center;padding:80px;color:var(--muted)">Storefront not found.</div>`;
          return;
        }

        // Must be at least vendor to have a public storefront
        const tier = profile.subscription_tier ||
          (profile.is_admin ? 'shop' : profile.is_vendor ? 'vendor' : profile.is_premium ? 'collector' : 'free');
        const tierOrder = ['free','collector','vendor','shop'];
        const tierIdx   = tierOrder.indexOf(tier);
        if (tierIdx < tierOrder.indexOf('vendor')) {
          el.innerHTML = `<div style="text-align:center;padding:80px;color:var(--muted)">This user doesn't have a public storefront.</div>`;
          return;
        }

        // Fetch their active (non-ghost, non-sold) cards
        const { data: items } = await sb.from('collection_items')
          .select('*')
          .eq('user_id', profile.id)
          .eq('is_ghost', false)
          .order('created_at', { ascending: true });

        const cards      = items || [];
        const cardCount  = cards.length;
        const totalValue = cards.reduce((s, c) => s + ((c.current_value || c.purchase_price || 0) * (c.quantity || 1)), 0);

        // Display values
        const shopName   = profile.shop_name    || profile.name || profile.username || 'Shop';
        const tagline    = profile.shop_tagline  || '';
        const desc       = profile.shop_description || '';
        const banner     = profile.shop_banner_color || '#0a0a14';
        const insta      = profile.shop_instagram ? profile.shop_instagram.replace(/^@/, '') : '';
        const website    = profile.shop_website || '';

        // Tier badge
        const tierColors = { free:'var(--muted)', collector:'var(--teal)', vendor:'var(--gold)', shop:'var(--accent)' };
        const tierBadge = tier !== 'free'
          ? `<span style="font-size:.6rem;padding:2px 8px;border:1px solid ${tierColors[tier]||'var(--muted)'};color:${tierColors[tier]||'var(--muted)'};letter-spacing:.1em;vertical-align:middle">${tier.toUpperCase()}</span>`
          : '';

        // Social links
        const socialHtml = [
          insta   ? `<a href="https://instagram.com/${insta}" target="_blank" rel="noopener"
                       style="color:var(--teal);font-size:.78rem;text-decoration:none;border:1px solid var(--border);padding:5px 12px;display:inline-block">
                       ↗ @${insta}
                     </a>` : '',
          website ? `<a href="${website.startsWith('http') ? website : 'https://'+website}" target="_blank" rel="noopener"
                       style="color:var(--muted);font-size:.78rem;text-decoration:none;border:1px solid var(--border);padding:5px 12px;display:inline-block">
                       ↗ Website
                     </a>` : '',
        ].filter(Boolean).join('');

        // Card grid
        const gridCards = cards.map(c => {
          const condLabel = c.condition === 'graded' && c.grade_value
            ? `${c.grade_label || 'PSA'} ${c.grade_value}`
            : (c.condition || '').toUpperCase();
          // Use 'data:,' as a deliberate invalid-image src so onerror fires and
          // _binderImgFail can look the image up from the catalog (self-heal).
          const _imgSrc = c.card_image_url || (c.api_card_id ? 'data:,' : '');
          const img = _imgSrc
            ? `<img src="${_imgSrc}" alt="${c.card_name}" loading="lazy" decoding="async"
                 style="width:100%;height:160px;object-fit:contain;background:var(--surface2);border-radius:4px 4px 0 0;display:block"
                 onerror="_binderImgFail(this,'${c.id}')">`
            : `<div style="width:100%;height:160px;background:var(--surface2);border-radius:4px 4px 0 0;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:.68rem">NO IMAGE</div>`;
          const qtyBadge = (c.quantity || 1) > 1
            ? `<span style="position:absolute;top:6px;right:6px;background:rgba(0,0,0,.75);color:var(--text);font-size:.6rem;padding:1px 5px;border-radius:2px">×${c.quantity}</span>`
            : '';
          const valBadge = c.current_value
            ? `<span style="font-size:.7rem;color:var(--green);font-weight:700">$${c.current_value.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}</span>`
            : '';
          return `<div style="background:var(--surface);border:1px solid var(--border);border-radius:6px;overflow:hidden;position:relative;transition:transform .15s,box-shadow .15s"
                       onmouseenter="this.style.transform='translateY(-3px)';this.style.boxShadow='0 8px 28px rgba(0,0,0,.55)'"
                       onmouseleave="this.style.transform='';this.style.boxShadow=''">
            ${img}
            ${qtyBadge}
            <div style="padding:8px 10px">
              <div style="font-size:.75rem;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-weight:600">${c.card_name}</div>
              ${c.set_name ? `<div style="font-size:.63rem;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${c.set_name}${c.card_number ? ` #${c.card_number}` : ''}</div>` : ''}
              <div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px">
                ${condLabel ? `<span style="font-size:.6rem;color:var(--teal)">${condLabel}</span>` : '<span></span>'}
                ${valBadge}
              </div>
            </div>
          </div>`;
        }).join('');

        // Shop stats bar
        const statsHtml = `
          <div style="display:flex;gap:24px;flex-wrap:wrap;padding:14px 20px;background:var(--surface);border-bottom:1px solid var(--border);font-size:.78rem">
            <span style="color:var(--muted)">Inventory: <span style="color:var(--text);font-weight:700">${cardCount.toLocaleString()}</span> cards</span>
            ${totalValue > 0 ? `<span style="color:var(--muted)">Est. Value: <span style="color:var(--green);font-weight:700">$${totalValue.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}</span></span>` : ''}
            ${profile.username ? `<span style="color:var(--muted)">Handle: <span style="color:var(--text)">@${profile.username}</span></span>` : ''}
          </div>`;

        // CTA for anonymous visitors
        const ctaHtml = !currentUser ? `
          <div style="margin:32px 20px;padding:22px;background:var(--surface);border:1px solid var(--border);text-align:center;max-width:480px;margin-left:auto;margin-right:auto">
            <div style="color:var(--accent);font-size:.88rem;margin-bottom:8px;letter-spacing:.08em">// BUILD YOUR OWN COLLECTION</div>
            <div style="color:var(--muted);font-size:.8rem;margin-bottom:16px">Track your cards, monitor prices, and launch your own storefront with PathBinder.</div>
            <button onclick="openModal('registerModal')"
              style="padding:10px 28px;border:none;background:var(--accent);color:var(--text-on-accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.85rem;font-weight:700;cursor:pointer;letter-spacing:.04em">
              Start Free →
            </button>
          </div>` : '';

        // Back button logic
        const backBtn = `<button onclick="window.history.back()" style="padding:7px 14px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">← Back</button>`;
        const myBtn   = currentUser
          ? `<button onclick="showPage('collection');setMobileNav('collection')" style="padding:7px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">My Binder</button>`
          : `<button onclick="openModal('loginModal')" style="padding:7px 14px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.75rem;cursor:pointer">Sign In</button>`;

        el.innerHTML = `
          <!-- Banner -->
          <div style="background:${banner};border-bottom:1px solid var(--border);padding:32px 24px 24px">
            <div style="max-width:900px;margin:0 auto;display:flex;align-items:flex-start;justify-content:space-between;gap:16px;flex-wrap:wrap">
              <div>
                <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:6px">
                  <h1 style="font-size:1.6rem;margin:0;letter-spacing:.04em">${shopName}</h1>
                  ${tierBadge}
                </div>
                ${tagline ? `<div style="color:var(--muted);font-size:.88rem;margin-bottom:12px">${tagline}</div>` : ''}
                ${socialHtml ? `<div style="display:flex;gap:8px;flex-wrap:wrap">${socialHtml}</div>` : ''}
              </div>
              <div style="display:flex;gap:8px;align-items:center">
                ${backBtn}
                ${myBtn}
              </div>
            </div>
          </div>

          ${statsHtml}

          <!-- Body -->
          <div style="max-width:900px;margin:0 auto;padding:24px 20px">

            ${desc ? `
            <div style="margin-bottom:28px;padding:16px 20px;background:var(--surface);border:1px solid var(--border)">
              <div style="font-size:.65rem;color:var(--accent);letter-spacing:.1em;margin-bottom:8px">// ABOUT</div>
              <p style="margin:0;font-size:.85rem;color:var(--muted);line-height:1.65">${desc.replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>')}</p>
            </div>` : ''}

            <!-- Card Grid -->
            <div style="margin-bottom:12px;display:flex;align-items:baseline;justify-content:space-between;flex-wrap:wrap;gap:8px">
              <div style="font-size:.65rem;color:var(--accent);letter-spacing:.1em">// COLLECTION · ${cardCount} CARDS</div>
            </div>
            ${cardCount === 0
              ? `<div style="text-align:center;padding:60px;color:var(--muted)">No cards in collection yet.</div>`
              : `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:14px">${gridCards}</div>`}

            ${ctaHtml}
          </div>`;

      } catch (err) {
        console.error('loadStorefront error:', err);
        el.innerHTML = `<div style="text-align:center;padding:80px;color:var(--red)">Failed to load storefront.</div>`;
      }
    }

    // ── Sales period filter state ─────────────────────────────────────────────
    let _salesPeriod = 'all'; // 'today'|'week'|'month'|'year'|'all'

    function setSalesPeriod(p) {
      _salesPeriod = p;
      renderSalesArchive();
    }

    function _salesPeriodRange() {
      const now = new Date();
      switch (_salesPeriod) {
        case 'today': {
          const d = new Date(now); d.setHours(0,0,0,0);
          return { from: d, label: 'Today' };
        }
        case 'week': {
          const d = new Date(now); d.setDate(d.getDate() - 6); d.setHours(0,0,0,0);
          return { from: d, label: 'Last 7 Days' };
        }
        case 'month': {
          const d = new Date(now.getFullYear(), now.getMonth(), 1);
          return { from: d, label: now.toLocaleString('default',{month:'long',year:'numeric'}) };
        }
        case 'year': {
          const d = new Date(now.getFullYear(), 0, 1);
          return { from: d, label: String(now.getFullYear()) };
        }
        default:
          return { from: null, label: 'All Time' };
      }
    }

    function _inSalesPeriod(dateStr) {
      const { from } = _salesPeriodRange();
      if (!from) return true;
      return new Date(dateStr) >= from;
    }

    // ─── Payments tab ──────────────────────────────────────────────────
    // Seller-side payments dashboard:
    //   1. Stripe Connect status banner (reuses the My Listings one)
    //   2. Lifetime totals — total earned, total fees paid, pending payout
    //   3. Commission rate explainer for the user's current tier
    //   4. Recent payouts list — last 20 sales ordered by date
    //
    // No new server endpoints — reads from the existing in-memory
    // `orders` array. Re-renders on every tab switch via switchAccountTab.
    function renderPayments() {
      const content = document.getElementById('paymentsContent');
      if (!content || !currentUser) return;

      // ── Empty state for free/collector (can't sell) ─────────────────
      if (!tierAtLeast('enthusiast')) {
        content.innerHTML = ''
          + '<div style="text-align:center;padding:48px 24px">'
          +   '<div style="font-family:\'Orbitron\',monospace;font-size:.7rem;color:var(--copper);letter-spacing:.14em;margin-bottom:8px">◈ SELLER DASHBOARD</div>'
          +   '<h2 style="font-family:\'Orbitron\',monospace;font-size:1.15rem;color:var(--text);margin:0 0 10px">Marketplace selling is on Enthusiast+ tiers</h2>'
          +   '<p style="color:var(--muted);font-size:.85rem;line-height:1.65;max-width:480px;margin:0 auto 20px">Once you upgrade you\'ll see Stripe Connect status, your lifetime payout history, and a per-tier commission breakdown here.</p>'
          +   '<button onclick="openPricingModalWithPromo(\'enthusiast\')" style="padding:11px 22px;background:var(--accent);color:var(--text-on-accent);border:none;font-family:\'Space Mono\',monospace;font-size:.78rem;font-weight:700;cursor:pointer;letter-spacing:.04em">See plans</button>'
          + '</div>';
        return;
      }

      // ── Gather seller-side orders ───────────────────────────────────
      const mySales = (orders || []).filter(o =>
        o.seller_id === currentUser.id || o.sellerId === currentUser.id
      );
      const completed = mySales.filter(o => o.status === 'completed' || o.status === 'delivered');
      const inFlight  = mySales.filter(o => o.status === 'paid' || o.status === 'shipped');
      const refunded  = mySales.filter(o => o.status === 'refunded');

      const lifetimePayouts  = completed.reduce((s, o) => s + (o.seller_payout || 0), 0);
      const lifetimeFees     = completed.reduce((s, o) => s + (o.platform_fee  || 0), 0);
      const pendingPayout    = inFlight.reduce((s, o) => s + (o.seller_payout || 0), 0);
      const lifetimeRefunded = refunded.reduce((s, o) => s + (o.amount        || 0), 0);

      const myRate    = myCommissionRate();
      const myRatePct = (myRate * 100).toFixed(0) + '%';
      const tierName  = userTier();
      const tierLabel = tierName.charAt(0).toUpperCase() + tierName.slice(1);

      // Trigger an async Connect status refresh so the banner reflects
      // current state. Repaint when the cache changes.
      if (typeof refreshConnectStatus === 'function') {
        refreshConnectStatus(function() { renderPayments(); });
      }
      const connectHtml = (typeof renderConnectStatusBanner === 'function')
        ? renderConnectStatusBanner() : '';

      // ── First-run / zero-sales empty state ─────────────────────────
      // No sales yet → skip the wall of $0 stat cards and show a
      // friendlier "here's what you'll see once it kicks off" panel.
      // Connect banner stays at top so the user can finish onboarding
      // before their first sale lands.
      if (mySales.length === 0) {
        content.innerHTML = ''
          + connectHtml
          + '<div style="background:var(--surface);border:1px solid var(--border);border-left:3px solid var(--copper);border-radius:10px;padding:32px 28px;text-align:center;margin-top:12px">'
          +   '<div style="font-family:\'Orbitron\',monospace;font-size:.7rem;color:var(--copper);letter-spacing:.14em;margin-bottom:8px">◈ NO SALES YET</div>'
          +   '<h2 style="font-family:\'Orbitron\',monospace;font-size:1.2rem;color:var(--text);margin:0 0 12px;letter-spacing:.04em">Once your first sale lands, this is where you\'ll track it.</h2>'
          +   '<p style="color:var(--muted);font-size:.85rem;line-height:1.65;max-width:520px;margin:0 auto 22px">'
          +     'Every sale shows up here with the gross amount, the ' + myRatePct + ' platform fee deducted, and your net payout. '
          +     'Lifetime totals and pending balance update in real time as orders move through paid → shipped → completed.'
          +   '</p>'
          +   '<div style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap">'
          +     '<button onclick="openListCardModal()" style="padding:11px 22px;background:var(--accent);color:var(--text-on-accent);border:none;font-family:\'Space Mono\',monospace;font-size:.78rem;font-weight:700;cursor:pointer;letter-spacing:.04em;border-radius:8px">List your first item &rarr;</button>'
          +     '<button onclick="switchAccountTab(\'myListings\')" style="padding:11px 22px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:\'Space Mono\',monospace;font-size:.78rem;cursor:pointer;letter-spacing:.04em;border-radius:8px">Manage listings</button>'
          +   '</div>'
          + '</div>'
          // Still show the commission table — useful at-a-glance reference
          // for new sellers planning what to price things at.
          + '<div style="margin-top:18px">'
          +   _paymentsCommissionPanel(tierName)
          + '</div>';
        return;
      }

      // ── Stats grid ──────────────────────────────────────────────────
      const statsHtml = ''
        + '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px;margin-bottom:16px">'
        +   _paymentsStatCard('Lifetime payouts',  '$' + lifetimePayouts.toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2}), 'completed sales',  'var(--green)')
        +   _paymentsStatCard('Pending payout',    '$' + pendingPayout.toLocaleString(undefined,   {minimumFractionDigits:2, maximumFractionDigits:2}),  inFlight.length + ' order' + (inFlight.length === 1 ? '' : 's'), 'var(--yellow)')
        +   _paymentsStatCard('Platform fees paid','$' + lifetimeFees.toLocaleString(undefined,    {minimumFractionDigits:2, maximumFractionDigits:2}),  myRatePct + ' on ' + tierLabel + ' tier', 'var(--copper)')
        +   _paymentsStatCard('Refunded',          '$' + lifetimeRefunded.toLocaleString(undefined,{minimumFractionDigits:2, maximumFractionDigits:2}), refunded.length + ' order' + (refunded.length === 1 ? '' : 's'), 'var(--red)')
        + '</div>';

      // ── Commission rate explainer ───────────────────────────────────
      const commissionHtml = _paymentsCommissionPanel(tierName);

      // ── Recent payouts list ─────────────────────────────────────────
      const recent = [...mySales]
        .sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0))
        .slice(0, 20);

      let payoutsListHtml;
      if (!recent.length) {
        payoutsListHtml = ''
          + '<div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:32px 20px;text-align:center;color:var(--muted);font-size:.85rem">'
          +   'No sales yet. Once a buyer purchases one of your listings, it shows up here.'
          + '</div>';
      } else {
        const statusLabel = {
          pending_payment: 'Pending payment',
          paid:            'Paid · awaiting ship',
          shipped:         'In transit',
          delivered:       'Delivered',
          completed:       'Completed',
          cancelled:       'Cancelled',
          disputed:        'Disputed',
          return_requested:'Return requested',
          refunded:        'Refunded',
        };
        const statusColor = {
          pending_payment:'var(--muted)', paid:'var(--yellow)', shipped:'var(--teal)',
          delivered:'var(--green)',       completed:'var(--green)', cancelled:'var(--red)',
          disputed:'var(--red)',          return_requested:'var(--yellow)', refunded:'var(--muted)',
        };
        payoutsListHtml = '<div class="coll-table-wrap"><table class="coll-table">'
          + '<thead><tr>'
          +   '<th>Date</th><th>Item</th><th>Status</th><th style="text-align:right">Sale</th><th style="text-align:right">Fee</th><th style="text-align:right">Payout</th>'
          + '</tr></thead><tbody>'
          + recent.map(o => {
              const listing = (listings || []).find(l => String(l.id) === String(o.listing_id));
              const itemName = listing ? listing.name : (o.card_name || '(item removed)');
              const date  = _fmtDate(o.created_at);
              const st    = o.status || 'pending_payment';
              const lbl   = statusLabel[st] || st;
              const col   = statusColor[st] || 'var(--muted)';
              const amt   = (o.amount        || 0).toFixed(2);
              const fee   = (o.platform_fee  || 0).toFixed(2);
              const pay   = (o.seller_payout || 0).toFixed(2);
              return '<tr>'
                + '<td style="color:var(--muted);font-size:.72rem">' + date + '</td>'
                + '<td style="color:var(--text)">' + itemName + '</td>'
                + '<td><span style="color:' + col + ';font-size:.72rem">● ' + lbl + '</span></td>'
                + '<td style="text-align:right;color:var(--muted)">$' + amt + '</td>'
                + '<td style="text-align:right;color:var(--copper);font-size:.78rem">−$' + fee + '</td>'
                + '<td style="text-align:right;color:var(--green);font-weight:700">$' + pay + '</td>'
              + '</tr>';
            }).join('')
          + '</tbody></table></div>';
      }

      content.innerHTML = ''
        + connectHtml
        + statsHtml
        + commissionHtml
        + '<div style="font-family:\'Orbitron\',monospace;font-size:.7rem;font-weight:800;letter-spacing:.14em;color:var(--accent);text-transform:uppercase;margin:18px 0 10px">'
        +   '◈ Recent payouts'
        + '</div>'
        + payoutsListHtml;
    }

    // Reusable commission-rate panel — shared between the populated
    // Payments view AND the zero-sales empty state. Highlights the
    // user's current tier in teal so they see their own rate at a glance.
    function _paymentsCommissionPanel(currentTier) {
      const rows = [
        { tier: 'Enthusiast', rate: '8%', isMe: currentTier === 'enthusiast' },
        { tier: 'Vendor',     rate: '7%', isMe: currentTier === 'vendor'     },
        { tier: 'Shop',       rate: '6%', isMe: currentTier === 'shop'       },
      ].map(r => '<tr' + (r.isMe ? ' style="background:rgba(26,199,160,0.08)"' : '') + '>'
        + '<td style="padding:8px 12px;color:' + (r.isMe ? 'var(--accent)' : 'var(--text)') + ';font-weight:' + (r.isMe ? '700' : '400') + '">' + r.tier + (r.isMe ? ' (you)' : '') + '</td>'
        + '<td style="padding:8px 12px;color:' + (r.isMe ? 'var(--accent)' : 'var(--muted)') + ';text-align:right;font-family:\'Space Mono\',monospace">' + r.rate + '</td>'
        + '</tr>'
      ).join('');
      return ''
        + '<div style="background:var(--surface2);border:1px solid var(--border);border-left:3px solid var(--copper);padding:14px 18px;margin-bottom:16px;border-radius:10px">'
        +   '<div style="font-family:\'Orbitron\',monospace;font-size:.7rem;font-weight:800;letter-spacing:.14em;color:var(--copper);text-transform:uppercase;margin-bottom:10px">'
        +     '◈ Commission rates by tier'
        +   '</div>'
        +   '<div style="font-size:.74rem;color:var(--muted);line-height:1.6;margin-bottom:12px">'
        +     'Lower commission as you move up tiers. The $0.30/transaction Stripe processing floor is included so cheap-item sales never put us underwater. Shipping passes through to you 100% — commission applies to the item price only.'
        +   '</div>'
        +   '<table style="width:100%;border-collapse:collapse;font-size:.78rem">'
        +     rows
        +   '</table>'
        + '</div>';
    }

    function _paymentsStatCard(label, value, sub, color) {
      return ''
        + '<div style="background:var(--surface);border:1px solid var(--border);border-left:3px solid ' + color + ';padding:14px 16px;border-radius:10px;min-height:90px;display:flex;flex-direction:column;justify-content:space-between">'
        +   '<div style="font-size:.65rem;color:var(--muted);letter-spacing:.08em;text-transform:uppercase">' + label + '</div>'
        +   '<div>'
        +     '<div style="font-family:\'Orbitron\',monospace;font-size:1.4rem;font-weight:800;color:' + color + ';line-height:1.1;margin:6px 0 4px">' + value + '</div>'
        +     '<div style="font-size:.65rem;color:var(--muted)">' + sub + '</div>'
        +   '</div>'
        + '</div>';
    }

    function renderSalesArchive() {
      const el = document.getElementById('salesArchiveContent');
      if (!el || !currentUser) return;

      // Sales-archive analytics moved to enthusiast tier (it was the old
      // 'vendor' tier's headline feature; that tier got renamed). The
      // variable name stays for code-history reasons but means "this user
      // can see vendor-class analytics" — true for enthusiast / vendor / shop.
      const isVendorPlus = tierAtLeast('enthusiast');
      const isShop       = tierAtLeast('shop');
      const { label: periodLabel } = _salesPeriodRange();

      // ── Collect all sales data ─────────────────────────────────────────────
      const allOffline = [...collectionItems.filter(c => c.sold_offline)]
        .sort((a,b) => (b.offline_sale_date||'').localeCompare(a.offline_sale_date||''));
      const allOnline = isVendorPlus
        ? [...orders.filter(o => o.seller_id === currentUser.id && o.status === 'completed')]
            .sort((a,b) => new Date(b.created_at) - new Date(a.created_at))
        : [];

      // Period-filtered views
      const offline = isVendorPlus
        ? allOffline.filter(c => _inSalesPeriod(c.offline_sale_date || '1900-01-01'))
        : allOffline;
      const online  = allOnline.filter(o => _inSalesPeriod(o.created_at));

      // ── Summary numbers ────────────────────────────────────────────────────
      const offRev    = offline.reduce((s,c) => s + (c.offline_sale_price||0), 0);
      const offCost   = offline.reduce((s,c) => s + (c.purchase_price||0), 0);
      const offProfit = offRev - offCost;
      const onRev     = online.reduce((s,o) => s + (o.seller_payout||0), 0);
      const onFees    = online.reduce((s,o) => s + (o.platform_fee||0), 0);
      const totalRev  = offRev + onRev;
      const totalProfit = offProfit + onRev; // online: payout already net of fees
      const margin    = totalRev > 0 ? (totalProfit / totalRev * 100) : 0;
      const totalCount = offline.length + online.length;

      // ── Period tab bar (Vendor+) ───────────────────────────────────────────
      const periods = [
        { k:'today', l:'Today' }, { k:'week', l:'This Week' },
        { k:'month', l:'This Month' }, { k:'year', l:'This Year' },
        { k:'all', l:'All Time' },
      ];
      const periodTabs = isVendorPlus ? `
        <div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:20px">
          ${periods.map(p => `
            <button onclick="setSalesPeriod('${p.k}')" style="
              padding:5px 12px;font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;cursor:pointer;
              border:1px solid ${_salesPeriod===p.k ? 'var(--accent)' : 'var(--border)'};
              background:${_salesPeriod===p.k ? 'var(--accent)' : 'transparent'};
              color:${_salesPeriod===p.k ? 'var(--accent)' : 'var(--muted)'};
            ">${p.l}</button>
          `).join('')}
        </div>` : '';

      // ── Summary stat tiles (Vendor+) ───────────────────────────────────────
      const statTiles = isVendorPlus ? `
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:10px;margin-bottom:20px">
          <div class="coll-stat-box">
            <div class="coll-stat-label">Total Sales</div>
            <div class="coll-stat-value">${totalCount}</div>
          </div>
          <div class="coll-stat-box">
            <div class="coll-stat-label">Revenue</div>
            <div class="coll-stat-value" style="color:var(--green)">$${totalRev.toFixed(2)}</div>
          </div>
          <div class="coll-stat-box">
            <div class="coll-stat-label">Profit</div>
            <div class="coll-stat-value" style="color:${totalProfit>=0?'var(--green)':'var(--red)'}">${totalProfit>=0?'+':''}$${Math.abs(totalProfit).toFixed(2)}</div>
          </div>
          <div class="coll-stat-box">
            <div class="coll-stat-label">Margin</div>
            <div class="coll-stat-value" style="color:${margin>=0?'var(--teal)':'var(--red)'}">${margin.toFixed(1)}%</div>
          </div>
          ${isVendorPlus && onFees > 0 ? `
          <div class="coll-stat-box">
            <div class="coll-stat-label">Fees Paid</div>
            <div class="coll-stat-value" style="color:var(--muted)">$${onFees.toFixed(2)}</div>
          </div>` : ''}
        </div>` : '';

      // ── Export buttons (Vendor+) ───────────────────────────────────────────
      const exportBtns = isVendorPlus ? `
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px">
          <button onclick="exportSalesCSV()" style="padding:6px 14px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;cursor:pointer;transition:all .15s"
            onmouseover="this.style.borderColor='var(--teal)';this.style.color='var(--teal)'"
            onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--muted)'">⬇ Export CSV</button>
          <button onclick="${isShop ? 'exportSalesReportPDF()' : 'exportSalesPDF()'}" style="padding:6px 14px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;cursor:pointer;transition:all .15s"
            onmouseover="this.style.borderColor='var(--accent)';this.style.color='var(--accent)'"
            onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--muted)'">⬇ Export PDF${isShop ? ' (Full Report)' : ''}</button>
        </div>` : '';

      // ── Combined transaction table ─────────────────────────────────────────
      // Merge offline + online into one sorted list
      const combined = [
        ...offline.map(c => ({
          date:    c.offline_sale_date || '',
          name:    c.card_name,
          set:     c.set_name || '',
          cond:    c.condition === 'graded' ? `${c.grade_label||'PSA'} ${c.grade_value||''}`.trim() : 'Raw',
          buyer:   c.offline_buyer || '',
          revenue: c.offline_sale_price || 0,
          cost:    c.purchase_price || 0,
          profit:  (c.offline_sale_price||0) - (c.purchase_price||0),
          fee:     0,
          channel: 'Offline',
          id:      c.id,
          isOffline: true,
        })),
        ...online.map(o => {
          const listing = listings.find(l => String(l.id) === String(o.listing_id));
          return {
            date:    new Date(o.created_at).toISOString().slice(0,10),
            name:    listing?.name || 'Marketplace Sale',
            set:     '',
            cond:    listing?.condition || '',
            buyer:   '',
            revenue: (o.seller_payout||0) + (o.platform_fee||0),
            cost:    0,
            profit:  o.seller_payout || 0,
            fee:     o.platform_fee || 0,
            channel: 'Online',
            id:      o.id,
            isOffline: false,
          };
        }),
      ].sort((a,b) => b.date.localeCompare(a.date));

      const tableRows = combined.length
        ? combined.map(r => {
            const sign = r.profit >= 0 ? '+' : '';
            return `<tr>
              <td style="color:var(--muted);font-size:.72rem;white-space:nowrap">${r.date||'—'}</td>
              <td style="color:var(--text);font-size:.78rem">
                <div>${r.name}</div>
                ${r.set ? `<div style="font-size:.65rem;color:var(--muted)">${r.set}</div>` : ''}
                ${r.buyer ? `<div style="font-size:.62rem;color:var(--teal)">→ ${r.buyer}</div>` : ''}
              </td>
              <td style="font-size:.72rem;color:var(--muted)">${r.cond}</td>
              <td style="color:var(--green);font-size:.78rem">$${r.revenue.toFixed(2)}</td>
              <td style="font-size:.72rem;color:var(--muted)">$${r.cost.toFixed(2)}</td>
              <td style="color:${r.profit>=0?'var(--green)':'var(--red)'};font-size:.78rem">${sign}$${Math.abs(r.profit).toFixed(2)}</td>
              <td>
                <span style="font-size:.6rem;padding:1px 5px;border:1px solid ${r.channel==='Online'?'var(--teal)':'var(--border)'};color:${r.channel==='Online'?'var(--teal)':'var(--muted)'}">${r.channel}</span>
              </td>
              ${r.isOffline ? `<td><button onclick="restoreArchivedCard('${r.id}')" style="padding:2px 6px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.6rem;cursor:pointer">↩</button></td>` : '<td></td>'}
            </tr>`;
          }).join('')
        : `<tr><td colspan="8" style="text-align:center;padding:30px;color:var(--muted);font-size:.82rem">
            No sales in this period.<br>
            <span style="font-size:.72rem">Mark a card as "Sold Offline" in the binder to record it here.</span>
          </td></tr>`;

      const tableHeaders = isVendorPlus
        ? '<tr><th>Date</th><th>Card</th><th>Condition</th><th>Revenue</th><th>Cost</th><th>Profit</th><th>Channel</th><th></th></tr>'
        : '<tr><th>Date</th><th>Card</th><th>Condition</th><th>Sale Price</th><th>Cost</th><th>Profit</th><th>Type</th><th></th></tr>';

      // ── Shop-only: monthly revenue chart ──────────────────────────────────
      let shopAnalytics = '';
      if (isShop) {
        // Build monthly buckets from ALL sales (not period-filtered) for the chart
        const monthMap = {};
        [...allOffline, ...allOnline.map(o => ({
          offline_sale_date: new Date(o.created_at).toISOString().slice(0,10),
          offline_sale_price: (o.seller_payout||0) + (o.platform_fee||0),
          _isOnline: true, _payout: o.seller_payout||0,
        }))].forEach(s => {
          const d = s.offline_sale_date || '';
          if (!d) return;
          const mo = d.slice(0,7); // YYYY-MM
          if (!monthMap[mo]) monthMap[mo] = { rev: 0, profit: 0, count: 0 };
          const rev  = s.offline_sale_price || 0;
          const prof = s._isOnline ? s._payout : (rev - (s.purchase_price||0));
          monthMap[mo].rev    += rev;
          monthMap[mo].profit += prof;
          monthMap[mo].count  += 1;
        });
        const months = Object.keys(monthMap).sort().slice(-12); // last 12 months

        // Top 5 cards by revenue
        const cardRevMap = {};
        allOffline.forEach(c => {
          if (!cardRevMap[c.card_name]) cardRevMap[c.card_name] = { rev:0, count:0 };
          cardRevMap[c.card_name].rev   += c.offline_sale_price||0;
          cardRevMap[c.card_name].count += 1;
        });
        allOnline.forEach(o => {
          const l = listings.find(x => String(x.id) === String(o.listing_id));
          const n = l?.name || 'Marketplace Sale';
          if (!cardRevMap[n]) cardRevMap[n] = { rev:0, count:0 };
          cardRevMap[n].rev   += (o.seller_payout||0) + (o.platform_fee||0);
          cardRevMap[n].count += 1;
        });
        const top5 = Object.entries(cardRevMap)
          .sort((a,b) => b[1].rev - a[1].rev).slice(0,5);

        // Channel breakdown
        const chanOffRev = allOffline.reduce((s,c) => s+(c.offline_sale_price||0),0);
        const chanOnRev  = allOnline.reduce((s,o) => s+(o.seller_payout||0)+(o.platform_fee||0),0);
        const chanTotal  = chanOffRev + chanOnRev || 1;

        // Draw monthly bar chart as SVG
        let barChartSvg = '';
        if (months.length > 0) {
          const maxRev = Math.max(...months.map(m => monthMap[m].rev), 1);
          const barW   = Math.min(36, Math.floor(420 / months.length) - 4);
          const chartW = Math.max(300, months.length * (barW + 6));
          const chartH = 100;
          const padB   = 22, padT = 8;

          const bars = months.map((m, i) => {
            const rev  = monthMap[m].rev;
            const prof = monthMap[m].profit;
            const bH   = Math.max(2, (rev / maxRev) * (chartH - padT - padB));
            const x    = i * (barW + 6) + 2;
            const y    = chartH - padB - bH;
            const mo   = new Date(m + '-01').toLocaleString('default',{month:'short'});
            const isProfit = prof >= 0;
            return `
              <rect x="${x}" y="${y}" width="${barW}" height="${bH}" fill="var(--accent)" rx="1"/>
              <text x="${x + barW/2}" y="${chartH - padB + 12}" text-anchor="middle" font-size="7" fill="var(--muted)" font-family="Share Tech Mono,monospace">${mo}</text>
              <text x="${x + barW/2}" y="${y - 3}" text-anchor="middle" font-size="7" fill="var(--accent)" font-family="Share Tech Mono,monospace">${rev >= 1000 ? '$'+(rev/1000).toFixed(1)+'k' : '$'+rev.toFixed(0)}</text>
            `;
          }).join('');

          barChartSvg = `
            <div style="font-size:.72rem;color:var(--accent);letter-spacing:.08em;margin-bottom:8px">Monthly Revenue (Last 12 Months)</div>
            <div style="overflow-x:auto;margin-bottom:20px">
              <svg width="${chartW}" height="${chartH}" style="display:block;min-width:${chartW}px">
                <line x1="0" y1="${chartH-padB}" x2="${chartW}" y2="${chartH-padB}" stroke="var(--border)" stroke-width="1"/>
                ${bars}
              </svg>
            </div>`;
        }

        // Monthly breakdown table (last 12 months)
        const monthTableRows = months.slice().reverse().map(m => {
          const { rev, profit, count } = monthMap[m];
          const sign = profit >= 0 ? '+' : '';
          const label = new Date(m + '-01').toLocaleString('default',{month:'long', year:'numeric'});
          return `<tr>
            <td style="color:var(--muted);font-size:.75rem">${label}</td>
            <td style="color:var(--text);font-size:.75rem;text-align:right">${count}</td>
            <td style="color:var(--green);font-size:.75rem;text-align:right">$${rev.toFixed(2)}</td>
            <td style="color:${profit>=0?'var(--green)':'var(--red)'};font-size:.75rem;text-align:right">${sign}$${Math.abs(profit).toFixed(2)}</td>
            <td style="color:var(--muted);font-size:.75rem;text-align:right">${rev>0?(profit/rev*100).toFixed(1)+'%':'—'}</td>
          </tr>`;
        }).join('');

        shopAnalytics = `
          <div style="margin-top:28px;padding-top:20px;border-top:1px solid var(--border)">
            <div style="font-size:.72rem;color:var(--accent);letter-spacing:.1em;margin-bottom:16px">Shop Analytics</div>

            ${barChartSvg}

            <div class="tx-shop-analytics-grid" style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:20px">
              <!-- Top 5 cards -->
              <div style="min-width:0">
                <div style="font-size:.68rem;color:var(--muted);letter-spacing:.08em;margin-bottom:8px">Top Cards by Revenue</div>
                ${top5.length ? top5.map(([name, data], i) => `
                  <div style="display:flex;justify-content:space-between;align-items:center;padding:5px 0;border-bottom:1px solid rgba(74,40,0,.3)">
                    <div style="font-size:.72rem;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:65%">${i+1}. ${name}</div>
                    <div style="font-size:.72rem;color:var(--green);flex-shrink:0">$${data.rev.toFixed(2)}</div>
                  </div>`).join('')
                : '<div style="font-size:.72rem;color:var(--muted)">No data yet</div>'}
              </div>
              <!-- Channel breakdown -->
              <div style="min-width:0">
                <div style="font-size:.68rem;color:var(--muted);letter-spacing:.08em;margin-bottom:8px">Channel Breakdown</div>
                <div style="display:flex;flex-direction:column;gap:8px">
                  <div>
                    <div style="display:flex;justify-content:space-between;font-size:.7rem;margin-bottom:3px">
                      <span style="color:var(--muted)">Offline</span>
                      <span style="color:var(--text)">$${chanOffRev.toFixed(2)} (${allOffline.length} sales)</span>
                    </div>
                    <div style="height:6px;background:var(--surface2);border:1px solid var(--border)">
                      <div style="height:100%;width:${(chanOffRev/chanTotal*100).toFixed(1)}%;background:var(--accent)"></div>
                    </div>
                  </div>
                  <div>
                    <div style="display:flex;justify-content:space-between;font-size:.7rem;margin-bottom:3px">
                      <span style="color:var(--muted)">Online</span>
                      <span style="color:var(--text)">$${chanOnRev.toFixed(2)} (${allOnline.length} sales)</span>
                    </div>
                    <div style="height:6px;background:var(--surface2);border:1px solid var(--border)">
                      <div style="height:100%;width:${(chanOnRev/chanTotal*100).toFixed(1)}%;background:var(--teal)"></div>
                    </div>
                  </div>
                </div>

                <div style="margin-top:14px">
                  <div style="font-size:.68rem;color:var(--muted);letter-spacing:.08em;margin-bottom:8px">Monthly Breakdown</div>
                  <div class="tx-table-wrap" style="max-height:200px;overflow-y:auto">
                    <table class="tx-table">
                      <thead><tr><th>Month</th><th style="text-align:right">Sales</th><th style="text-align:right">Revenue</th><th style="text-align:right">Profit</th><th style="text-align:right">Margin</th></tr></thead>
                      <tbody>${monthTableRows || '<tr><td colspan="5" style="text-align:center;padding:10px;color:var(--muted)">No data</td></tr>'}</tbody>
                    </table>
                  </div>
                </div>
              </div>
            </div>
          </div>`;
      }

      el.innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;margin-bottom:16px">
          <div>
            <div style="font-size:.75rem;color:var(--green);letter-spacing:.08em">Sales Archive${isVendorPlus ? ' — ' + periodLabel : ''}</div>
            <div style="font-size:.75rem;color:var(--muted);margin-top:2px">
              ${isVendorPlus ? 'All sales channels combined.' : 'Cards you\'ve sold or archived. Restore any card to your active binder.'}
            </div>
          </div>
        </div>

        ${periodTabs}
        ${statTiles}
        ${exportBtns}

        <div class="tx-table-wrap">
          <table class="tx-table">
            <thead>${tableHeaders}</thead>
            <tbody>${tableRows}</tbody>
          </table>
        </div>

        ${shopAnalytics}`;
    }

    async function restoreArchivedCard(itemId) {
      if (!confirm('Restore this card to your active binder?')) return;
      const { error } = await sb.from('collection_items')
        .update({ sold_offline: false, offline_sale_price: null, offline_sale_date: null, offline_buyer: null })
        .eq('id', itemId);
      if (error) { showToast('Error: ' + error.message); return; }
      const item = collectionItems.find(c => String(c.id) === String(itemId));
      if (item) {
        item.sold_offline = false;
        item.offline_sale_price = null;
        item.offline_sale_date = null;
        item.offline_buyer = null;
      }
      renderSalesArchive();
      renderBinder();
      showToast('✓ Card restored to binder');
    }

    // ── Build the unified sales rows used by both export functions ───────────
    function _buildSalesRows() {
      const { from } = _salesPeriodRange();
      const inPeriod = d => !from || new Date(d) >= from;

      const offline = collectionItems.filter(c => c.sold_offline && inPeriod(c.offline_sale_date||'1900-01-01'));
      // Online sales view is part of the renamed enthusiast tier's
      // analytics suite (was the old vendor tier's feature).
      const online  = tierAtLeast('enthusiast')
        ? orders.filter(o => o.seller_id === currentUser?.id && o.status === 'completed' && inPeriod(o.created_at))
        : [];

      return [
        ...offline.map(c => ({
          date:    c.offline_sale_date || '',
          name:    c.card_name,
          set:     c.set_name || '',
          cond:    c.condition === 'graded' ? `${c.grade_label||'PSA'} ${c.grade_value||''}`.trim() : 'Raw',
          revenue: c.offline_sale_price || 0,
          cost:    c.purchase_price     || 0,
          profit:  (c.offline_sale_price||0) - (c.purchase_price||0),
          fee:     0,
          channel: 'Offline',
        })),
        ...online.map(o => {
          const l = listings.find(x => String(x.id) === String(o.listing_id));
          return {
            date:    new Date(o.created_at).toISOString().slice(0,10),
            name:    l?.name || 'Marketplace Sale',
            set:     '',
            cond:    l?.condition || '',
            revenue: (o.seller_payout||0) + (o.platform_fee||0),
            cost:    0,
            profit:  o.seller_payout || 0,
            fee:     o.platform_fee  || 0,
            channel: 'Online',
          };
        }),
      ].sort((a,b) => b.date.localeCompare(a.date));
    }

    // ── CSV Export (Enthusiast+) ──────────────────────────────────────────────
    // Was originally Vendor+; tier rename moved CSV export to the
    // enthusiast tier (same feature set, lower price + 40-listing cap).
    function exportSalesCSV() {
      if (!tierAtLeast('enthusiast')) { showToast('Enthusiast tier or higher required'); return; }
      const rows = _buildSalesRows();
      const { label } = _salesPeriodRange();
      const headers = ['Date','Card','Set','Condition','Channel','Revenue','Cost','Fee','Profit'];
      const csvRows = [headers, ...rows.map(r => [
        r.date, `"${r.name.replace(/"/g,'""')}"`, `"${r.set.replace(/"/g,'""')}"`,
        r.cond, r.channel,
        r.revenue.toFixed(2), r.cost.toFixed(2), r.fee.toFixed(2), r.profit.toFixed(2),
      ])].map(r => r.join(',')).join('\n');

      const blob = new Blob([csvRows], { type: 'text/csv' });
      const a    = document.createElement('a');
      a.href     = URL.createObjectURL(blob);
      a.download = `pathbinder-sales-${label.replace(/\s+/g,'-').toLowerCase()}-${new Date().toISOString().slice(0,10)}.csv`;
      a.click();
      showToast('✓ CSV downloaded');
    }

    // ── PDF Export — Enthusiast+: itemized transaction list ──────────────────
    function exportSalesPDF() {
      if (!tierAtLeast('enthusiast')) { showToast('Enthusiast tier or higher required'); return; }
      _loadJsPDF(() => {
        const { jsPDF } = window.jspdf;
        const doc  = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' });
        const rows = _buildSalesRows();
        const { label } = _salesPeriodRange();
        const totalRev    = rows.reduce((s,r) => s + r.revenue, 0);
        const totalProfit = rows.reduce((s,r) => s + r.profit,  0);
        const totalFees   = rows.reduce((s,r) => s + r.fee,     0);
        const seller      = currentUser?.shop_name || currentUser?.username || currentUser?.email || 'PathBinder User';
        const today       = new Date().toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });

        // Header
        doc.setFont('helvetica','bold'); doc.setFontSize(18);
        doc.text('PathBinder Sales Report', 20, 22);
        doc.setFont('helvetica','normal'); doc.setFontSize(10);
        doc.setTextColor(120);
        doc.text(`Seller: ${seller}`, 20, 30);
        doc.text(`Period: ${label}`, 20, 36);
        doc.text(`Generated: ${today}`, 20, 42);
        doc.setDrawColor(200); doc.line(20, 46, 192, 46);

        // Summary row
        doc.setTextColor(0); doc.setFontSize(9);
        doc.text(`Total Sales: ${rows.length}`, 20, 53);
        doc.text(`Revenue: $${totalRev.toFixed(2)}`, 70, 53);
        doc.text(`Fees: $${totalFees.toFixed(2)}`, 120, 53);
        doc.text(`Profit: $${totalProfit.toFixed(2)}`, 160, 53);
        doc.line(20, 57, 192, 57);

        // Transaction table
        doc.autoTable({
          startY: 61,
          head: [['Date','Card','Set','Cond.','Channel','Revenue','Cost','Fee','Profit']],
          body: rows.map(r => [
            r.date, r.name, r.set, r.cond, r.channel,
            '$'+r.revenue.toFixed(2), '$'+r.cost.toFixed(2),
            r.fee > 0 ? '$'+r.fee.toFixed(2) : '—',
            (r.profit>=0?'+':'')+'$'+Math.abs(r.profit).toFixed(2),
          ]),
          styles:      { fontSize: 7.5, cellPadding: 2 },
          headStyles:  { fillColor: [30,20,10], textColor: 255, fontStyle: 'bold' },
          alternateRowStyles: { fillColor: [248, 246, 240] },
          columnStyles: {
            0: { cellWidth: 20 }, 1: { cellWidth: 42 }, 2: { cellWidth: 28 },
            3: { cellWidth: 14 }, 4: { cellWidth: 16 }, 5: { cellWidth: 20 },
            6: { cellWidth: 16 }, 7: { cellWidth: 14 }, 8: { cellWidth: 20 },
          },
          margin: { left: 20, right: 8 },
        });

        // Footer
        const pageCount = doc.internal.getNumberOfPages();
        for (let i = 1; i <= pageCount; i++) {
          doc.setPage(i);
          doc.setFontSize(7); doc.setTextColor(160);
          doc.text(`PathBinder — pathbinder.app | Page ${i} of ${pageCount}`, 20, 275);
        }

        doc.save(`pathbinder-sales-${label.replace(/\s+/g,'-').toLowerCase()}-${new Date().toISOString().slice(0,10)}.pdf`);
        showToast('✓ PDF downloaded');
      });
    }

    // ── PDF Export — Shop: full P&L report ────────────────────────────────────
    function exportSalesReportPDF() {
      if (!tierAtLeast('shop')) { showToast('Shop plan required'); return; }
      _loadJsPDF(() => {
        const { jsPDF } = window.jspdf;
        const doc     = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' });
        const allRows = _buildSalesRows();
        const { label } = _salesPeriodRange();
        const seller  = currentUser?.shop_name || currentUser?.username || currentUser?.email || 'PathBinder User';
        const today   = new Date().toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });

        const totalRev    = allRows.reduce((s,r) => s + r.revenue, 0);
        const totalCost   = allRows.reduce((s,r) => s + r.cost,    0);
        const totalFees   = allRows.reduce((s,r) => s + r.fee,     0);
        const totalProfit = allRows.reduce((s,r) => s + r.profit,  0);
        const margin      = totalRev > 0 ? (totalProfit / totalRev * 100) : 0;
        const offRows     = allRows.filter(r => r.channel === 'Offline');
        const onRows      = allRows.filter(r => r.channel === 'Online');

        // ── Cover / P&L header ────────────────────────────────────────────
        doc.setFillColor(20, 12, 2);
        doc.rect(0, 0, 216, 40, 'F');
        doc.setTextColor(255, 140, 20);
        doc.setFont('helvetica','bold'); doc.setFontSize(20);
        doc.text('PATHBINDER', 20, 16);
        doc.setFontSize(10); doc.setFont('helvetica','normal');
        doc.text('Sales & Profit/Loss Report', 20, 24);
        doc.setTextColor(180); doc.setFontSize(8.5);
        doc.text(`${seller}  ·  Period: ${label}  ·  Generated: ${today}`, 20, 32);

        // ── P&L Summary section ───────────────────────────────────────────
        doc.setTextColor(0); doc.setFont('helvetica','bold'); doc.setFontSize(11);
        doc.text('Profit & Loss Summary', 20, 52);
        doc.setDrawColor(220); doc.line(20, 55, 192, 55);

        doc.autoTable({
          startY: 58,
          body: [
            ['Gross Revenue',         '$'+totalRev.toFixed(2)],
            ['Cost of Goods Sold',    '($'+totalCost.toFixed(2)+')'],
            ['Platform Fees',         '($'+totalFees.toFixed(2)+')'],
            ['Net Profit',            (totalProfit>=0?'':'(')+' $'+Math.abs(totalProfit).toFixed(2)+(totalProfit<0?')':'')],
            ['Profit Margin',         margin.toFixed(1)+'%'],
            ['Total Transactions',    String(allRows.length)],
            ['Offline Sales',         `${offRows.length} sales  ·  $${offRows.reduce((s,r)=>s+r.revenue,0).toFixed(2)}`],
            ['Marketplace Sales',     `${onRows.length} sales  ·  $${onRows.reduce((s,r)=>s+r.revenue,0).toFixed(2)}`],
          ],
          styles:     { fontSize: 9, cellPadding: 2.5 },
          headStyles: { fillColor: [20,12,2] },
          columnStyles: { 0: { fontStyle:'bold', cellWidth:80 }, 1: { cellWidth:50 } },
          alternateRowStyles: { fillColor: [248,246,240] },
          margin: { left: 20 },
        });

        // ── Monthly breakdown table ────────────────────────────────────────
        const monthMap = {};
        allRows.forEach(r => {
          const mo = r.date.slice(0,7);
          if (!monthMap[mo]) monthMap[mo] = { rev:0, cost:0, profit:0, count:0 };
          monthMap[mo].rev    += r.revenue;
          monthMap[mo].cost   += r.cost;
          monthMap[mo].profit += r.profit;
          monthMap[mo].count  += 1;
        });
        const months = Object.keys(monthMap).sort().reverse();

        const finalY1 = doc.lastAutoTable.finalY + 12;
        doc.setFont('helvetica','bold'); doc.setFontSize(11); doc.setTextColor(0);
        doc.text('Monthly Breakdown', 20, finalY1);
        doc.setDrawColor(220); doc.line(20, finalY1+3, 192, finalY1+3);

        doc.autoTable({
          startY: finalY1 + 6,
          head: [['Month','Sales','Revenue','Cost','Profit','Margin']],
          body: months.map(m => {
            const { rev, cost, profit, count } = monthMap[m];
            const mo = new Date(m+'-01').toLocaleString('default',{month:'long',year:'numeric'});
            return [mo, count, '$'+rev.toFixed(2), '$'+cost.toFixed(2),
              (profit>=0?'+':'')+'$'+Math.abs(profit).toFixed(2),
              rev > 0 ? (profit/rev*100).toFixed(1)+'%' : '—'];
          }),
          styles:     { fontSize: 8.5, cellPadding: 2 },
          headStyles: { fillColor: [20,12,2], textColor: 255, fontStyle:'bold' },
          alternateRowStyles: { fillColor: [248,246,240] },
          margin: { left: 20, right: 8 },
        });

        // ── Itemized transactions ─────────────────────────────────────────
        doc.addPage();
        doc.setFillColor(20,12,2); doc.rect(0,0,216,16,'F');
        doc.setTextColor(255,140,20); doc.setFont('helvetica','bold'); doc.setFontSize(11);
        doc.text('Itemized Transactions', 20, 11);

        doc.autoTable({
          startY: 22,
          head: [['Date','Card','Set','Condition','Channel','Revenue','Cost','Fee','Profit']],
          body: allRows.map(r => [
            r.date, r.name, r.set, r.cond, r.channel,
            '$'+r.revenue.toFixed(2), r.cost>0?'$'+r.cost.toFixed(2):'—',
            r.fee>0?'$'+r.fee.toFixed(2):'—',
            (r.profit>=0?'+':'')+'$'+Math.abs(r.profit).toFixed(2),
          ]),
          styles:     { fontSize: 7.5, cellPadding: 1.8 },
          headStyles: { fillColor: [30,20,10], textColor:255, fontStyle:'bold' },
          alternateRowStyles: { fillColor:[248,246,240] },
          columnStyles: {
            0:{cellWidth:20}, 1:{cellWidth:40}, 2:{cellWidth:25},
            3:{cellWidth:15}, 4:{cellWidth:16}, 5:{cellWidth:20},
            6:{cellWidth:16}, 7:{cellWidth:14}, 8:{cellWidth:20},
          },
          margin: { left:20, right:8 },
        });

        // Footer on every page
        const pageCount = doc.internal.getNumberOfPages();
        for (let i = 1; i <= pageCount; i++) {
          doc.setPage(i);
          doc.setFontSize(7); doc.setTextColor(160); doc.setFont('helvetica','normal');
          doc.text(`PathBinder — pathbinder.app  ·  CONFIDENTIAL  ·  Page ${i} of ${pageCount}`, 20, 275);
        }

        doc.save(`pathbinder-pl-report-${label.replace(/\s+/g,'-').toLowerCase()}-${new Date().toISOString().slice(0,10)}.pdf`);
        showToast('✓ Full P&L Report downloaded');
      });
    }

    function renderHistory() {
      const el = document.getElementById('historyContent');
      if (!el || !currentUser) return;

      // 'isVendor' here means "can sell on the marketplace" — true for
      // enthusiast / vendor / shop tiers. Legacy variable name kept to
      // minimize churn in this function.
      const isVendor = tierAtLeast('enthusiast');

      // ── Purchase History (all users) ──────────────────────────────────────
      const purchases = orders.filter(o => o.buyer_id === currentUser.id);
      const purchaseRows = purchases.length
        ? purchases.map(o => {
            const listing = listings.find(l => String(l.id) === String(o.listing_id));
            return `<tr>
              <td style="color:var(--text)">${listing ? listing.name : 'Unknown Card'}</td>
              <td style="color:var(--muted);font-size:.8rem">${_fmtDate(o.created_at)}</td>
              <td style="color:var(--teal)">$${(o.amount||0).toFixed(2)}</td>
              <td><span class="badge badge-open" style="font-size:.6rem">${o.status||'—'}</span></td>
            </tr>`;
          }).join('')
        : `<tr><td colspan="4" style="text-align:center;padding:20px;color:var(--muted);font-size:.8rem">No purchases yet</td></tr>`;

      let vendorHtml = '';
      if (isVendor) {
        // ── Online Sales (vendor only) ──────────────────────────────────────
        const onlineSales = orders.filter(o => o.seller_id === currentUser.id);
        const onlineSaleRows = onlineSales.length
          ? onlineSales.map(o => {
              const listing = listings.find(l => String(l.id) === String(o.listing_id));
              const payout = o.seller_payout || 0;
              return `<tr>
                <td style="color:var(--text)">${listing ? listing.name : 'Unknown Card'}</td>
                <td style="color:var(--muted);font-size:.8rem">${_fmtDate(o.created_at)}</td>
                <td style="color:var(--green)">$${payout.toFixed(2)}</td>
                <td><span class="badge" style="background:rgba(210,120,40,.1);color:var(--green);font-size:.6rem">${o.status||'—'}</span></td>
              </tr>`;
            }).join('')
          : `<tr><td colspan="4" style="text-align:center;padding:20px;color:var(--muted);font-size:.8rem">No online sales yet</td></tr>`;

        // ── Offline Sales (vendor only) ─────────────────────────────────────
        const soldOffline = collectionItems.filter(c => c.sold_offline);
        const totalOfflineRevenue = soldOffline.reduce((s,c) => s + (c.offline_sale_price||0), 0);
        const totalOfflineProfit  = soldOffline.reduce((s,c) => s + ((c.offline_sale_price||0)-(c.purchase_price||0)), 0);

        const offlineSaleRows = soldOffline.length
          ? [...soldOffline].sort((a,b)=>(b.offline_sale_date||'').localeCompare(a.offline_sale_date||'')).map(c => {
              const profit = (c.offline_sale_price||0) - (c.purchase_price||0);
              const sign = profit >= 0 ? '+' : '';
              return `<tr>
                <td style="color:var(--text)">${c.card_name}${c.offline_buyer ? `<div style="font-size:.65rem;color:var(--muted)">${c.offline_buyer}</div>` : ''}</td>
                <td style="color:var(--muted);font-size:.8rem">${c.offline_sale_date || '—'}</td>
                <td>
                  <div style="color:var(--green);font-size:.82rem">$${(c.offline_sale_price||0).toFixed(2)}</div>
                  <div style="font-size:.68rem;color:var(--muted)">cost $${(c.purchase_price||0).toFixed(2)}</div>
                </td>
                <td style="color:${profit>=0?'var(--green)':'var(--red)'};font-size:.8rem">${sign}$${Math.abs(profit).toFixed(2)}</td>
              </tr>`;
            }).join('')
          : `<tr><td colspan="4" style="text-align:center;padding:20px;color:var(--muted);font-size:.8rem">No offline sales recorded yet</td></tr>`;

        const offlineTotals = soldOffline.length ? `
          <div style="display:flex;gap:16px;margin-top:10px;padding-top:10px;border-top:1px solid var(--border)">
            <span style="font-size:.72rem;color:var(--muted)">Total Revenue: <span style="color:var(--green)">$${totalOfflineRevenue.toFixed(2)}</span></span>
            <span style="font-size:.72rem;color:var(--muted)">Total Profit: <span style="color:${totalOfflineProfit>=0?'var(--green)':'var(--red)'}">$${totalOfflineProfit>=0?'+':''}${totalOfflineProfit.toFixed(2)}</span></span>
          </div>` : '';

        vendorHtml = `
          <div style="margin-top:28px">
            <div style="font-size:.75rem;color:var(--green);letter-spacing:.08em;margin-bottom:12px">Online Sales</div>
            <div class="tx-table-wrap">
              <table class="tx-table">
                <thead><tr><th>Card</th><th>Date</th><th>Payout</th><th>Status</th></tr></thead>
                <tbody>${onlineSaleRows}</tbody>
              </table>
            </div>
          </div>
          <div style="margin-top:28px">
            <div style="font-size:.75rem;color:var(--green);letter-spacing:.08em;margin-bottom:12px">Offline Sales</div>
            <div class="tx-table-wrap">
              <table class="tx-table">
                <thead><tr><th>Card</th><th>Date</th><th>Sale Price</th><th>Profit</th></tr></thead>
                <tbody>${offlineSaleRows}</tbody>
              </table>
            </div>
            ${offlineTotals}
          </div>`;
      }

      el.innerHTML = `
        <div style="font-size:.75rem;color:var(--teal);letter-spacing:.08em;margin-bottom:12px">Purchase History</div>
        <div class="tx-table-wrap">
          <table class="tx-table">
            <thead><tr><th>Card</th><th>Date</th><th>Amount</th><th>Status</th></tr></thead>
            <tbody>${purchaseRows}</tbody>
          </table>
        </div>
        ${vendorHtml}`;
    }

    // ─── Marketplace actions ───────────────────────────────────────────
    async function deactivateListing(listingId) {
      if (!confirm('Remove this listing from the marketplace?')) return;
      // Snapshot the listing before deactivating so the bookkeeping
      // hook has the api_card_id / variant / quantity it needs to
      // release the units back to on_shelf_qty. Local cache is the
      // fast path; falls back to a one-shot select if it's missing.
      let snap = (listings || []).find(function(l) { return String(l.id) === String(listingId); });
      if (!snap) {
        const sr = await sb.from('listings').select('api_card_id, variant, quantity').eq('id', listingId).maybeSingle();
        snap = sr.data || null;
      }
      const { error } = await sb.from('listings').update({ status: 'inactive' }).eq('id', listingId);
      if (error) { showToast('Error: ' + error.message); return; }
      // Step 4 bookkeeping — release the held units back onto the shelf.
      if (snap && snap.api_card_id && currentUser) {
        try {
          await _invOnListingReleased(currentUser.id, snap.api_card_id, snap.variant || 'normal', snap.quantity || 1);
        } catch (e) {
          console.warn('[inv] release on deactivate failed:', e && e.message);
        }
      }
      // Remove from local state entirely so it disappears from both views
      listings = listings.filter(l => String(l.id) !== String(listingId));
      renderMyListings();
      renderBrowse();
      showToast('Listing removed');
    }

    // Buyer marks the order as received. This is NOT a payment gate (sellers
    // get paid on Stripe's standard schedule regardless). It just closes the
    // order, adds the card to the buyer's binder, and prompts for a rating.
    // If anything is wrong with the card, the buyer should use "Report Issue"
    // (requestReturn) which opens a dispute flow inside the 7-day window.
    async function markOrderReceived(orderId) {
      if (!confirm('Mark this order as received? The card will be added to your binder. If there\'s an issue with the card, use "Report Issue" instead.')) return;
      const now = new Date().toISOString();
      const { error } = await sb.from('orders').update({
        status: 'completed',
        delivered_at: now,
        completed_at: now
      }).eq('id', orderId);
      if (error) { showToast('Error: ' + error.message); return; }
      const o = orders.find(x => x.id === orderId);
      if (o) { o.status = 'completed'; o.delivered_at = now; o.completed_at = now; }

      // Auto-add purchased card to buyer's binder
      if (o && currentUser) {
        const listing = listings.find(l => String(l.id) === String(o.listing_id));
        if (listing) {
          const isGraded = listing.condition && listing.condition !== 'Raw' && listing.condition !== 'raw';
          const insertData = {
            user_id:        currentUser.id,
            card_name:      listing.name,
            game_type:      listing.gameType || listing.game_type || 'Other',
            condition:      isGraded ? 'graded' : 'raw',
            grade_value:    listing.grade_value || listing.gradeValue || null,
            card_image_url: listing.photos?.[0] || null,
            purchase_price: o.amount || listing.list_price || listing.value || 0,
            current_value:  listing.market_price || listing.value || 0,
            quantity:       1,
            purchase_date:  now.slice(0, 10),
            notes:          'auto_purchase:' + orderId
          };
          const { data: newItem, error: collErr } = await sb.from('collection_items').insert(insertData).select().single();
          if (collErr) {
            console.warn('[binder auto-add] failed:', collErr.message);
          } else if (newItem) {
            collectionItems.unshift(newItem);
            showToast('Card added to your binder!');
          }
        }
      }

      showToast('Order marked received. Thanks for the trade!');
      renderOrders();
      updateOrderNotification();
      // Prompt for seller rating
      if (o) setTimeout(() => openRateSellerModal(orderId, o.seller_id, o.seller_name || 'the seller'), 800);
    }
    // Legacy alias — older code paths may still call confirmDelivery
    var confirmDelivery = markOrderReceived;

    // Buyer-side: opens the structured return-request modal. The actual
    // submission happens in submitReturnRequest() once the buyer picks a
    // reason and writes a detail. Replaces the old confirm()-prompt path
    // which captured no context for the seller.
    // ─── Order messaging (buyer ↔ seller chat per order) ──────────────
    // RLS on order_messages restricts read/write to the two parties on
    // the order (plus admins). Thread is fetched fresh on every modal
    // open — no realtime subscription in V1 since orders don't churn
    // fast enough to need live streaming. Unread counts cached on
    // orders.unread_messages for badge rendering; refreshed via
    // refreshUnreadMessageCount() on order list render.
    let _orderMessagesCache = {};   // orderId → array of messages
    let _totalUnreadMessages = 0;   // populated by refreshUnreadMessageCount

    async function openOrderMessagesModal(orderId) {
      if (!currentUser) { openModal('loginModal'); return; }
      const order = (orders || []).find(o => String(o.id) === String(orderId));
      if (!order) { showToast('Order not found'); return; }

      // Figure out who the "counterparty" is so we can label the modal
      // accordingly ("Message buyer" vs "Message seller").
      const isBuyer = order.buyer_id === currentUser.id;
      const counterpartyRole = isBuyer ? 'seller' : 'buyer';

      document.getElementById('orderMessagesOrderId').value = orderId;
      const titleEl = document.getElementById('orderMessagesTitle');
      const subEl   = document.getElementById('orderMessagesSub');
      if (titleEl) titleEl.textContent = 'Message the ' + counterpartyRole;
      if (subEl) {
        const listing = (listings || []).find(l => String(l.id) === String(order.listing_id));
        const cardName = listing ? listing.name : (order.card_name || 'this order');
        subEl.innerHTML = 'About <strong style="color:var(--text)">' + (cardName || 'this order').replace(/</g,'&lt;') + '</strong> &middot; Order #' + String(orderId).slice(0,8).toUpperCase();
      }
      const inp = document.getElementById('orderMessagesInput');
      if (inp) inp.value = '';
      const sts = document.getElementById('orderMessagesStatus');
      if (sts) sts.textContent = '';
      openModal('orderMessagesModal');
      await _loadOrderMessages(orderId);
    }

    async function _loadOrderMessages(orderId) {
      const host = document.getElementById('orderMessagesThread');
      if (!host) return;
      host.innerHTML = '<div style="color:var(--muted);font-size:.78rem;text-align:center;padding:18px 0">Loading…</div>';
      try {
        const { data, error } = await sb
          .from('order_messages')
          .select('id, sender_id, body, created_at, read_at')
          .eq('order_id', orderId)
          .order('created_at', { ascending: true });
        if (error) throw error;
        _orderMessagesCache[orderId] = data || [];
        _renderOrderMessagesThread(orderId);

        // Mark every message we received as read.
        try {
          await sb.rpc('mark_order_messages_read', { p_order_id: orderId });
          // Refresh the badge after marking-as-read.
          refreshUnreadMessageCount();
        } catch (_) { /* best effort */ }
      } catch (e) {
        console.error('[order-messages] load failed:', e);
        host.innerHTML = '<div style="color:var(--red);font-size:.78rem;text-align:center;padding:18px 0">Failed to load thread: ' + (e.message || '') + '</div>';
      }
    }

    function _renderOrderMessagesThread(orderId) {
      const host = document.getElementById('orderMessagesThread');
      if (!host) return;
      const msgs = _orderMessagesCache[orderId] || [];
      if (!msgs.length) {
        host.innerHTML = '<div style="color:var(--muted);font-size:.78rem;text-align:center;padding:24px 0">No messages yet. Start the conversation.</div>';
        return;
      }
      host.innerHTML = msgs.map(m => {
        const mine = m.sender_id === currentUser.id;
        const safe = String(m.body || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g, '<br/>');
        const ts   = (function(){ try { return new Date(m.created_at).toLocaleString(undefined, { dateStyle:'short', timeStyle:'short' }); } catch(_) { return ''; } })();
        // Right-align user's own messages; left-align counterparty's.
        // Cyan bubble for mine, slate bubble for theirs (SMS-style).
        return ''
          + '<div style="display:flex;justify-content:' + (mine ? 'flex-end' : 'flex-start') + '">'
          +   '<div style="max-width:80%">'
          +     '<div style="background:' + (mine ? 'rgba(26,199,160,0.12)' : 'var(--surface)') + ';border:1px solid ' + (mine ? 'var(--accent)' : 'var(--border)') + ';border-radius:10px;padding:9px 12px;font-size:.82rem;color:var(--text);line-height:1.4;white-space:pre-wrap;word-break:break-word">'
          +       safe
          +     '</div>'
          +     '<div style="font-size:.6rem;color:var(--muted);margin-top:3px;text-align:' + (mine ? 'right' : 'left') + ';font-family:\'Space Mono\',monospace">' + ts + '</div>'
          +   '</div>'
          + '</div>';
      }).join('');
      // Auto-scroll to bottom (newest message).
      host.scrollTop = host.scrollHeight;
    }

    async function sendOrderMessage() {
      const orderId = document.getElementById('orderMessagesOrderId').value;
      const inp     = document.getElementById('orderMessagesInput');
      const btn     = document.getElementById('orderMessagesSendBtn');
      const sts     = document.getElementById('orderMessagesStatus');
      const body    = (inp.value || '').trim();
      if (!body) { if (sts) sts.textContent = 'Type a message first.'; return; }
      if (body.length > 4000) { if (sts) sts.textContent = 'Message is too long (4000 char max).'; return; }
      btn.disabled = true; btn.textContent = 'Sending…';
      if (sts) sts.textContent = '';
      try {
        const { error } = await sb.from('order_messages').insert({
          order_id:  orderId,
          sender_id: currentUser.id,
          body:      body,
        });
        if (error) throw error;
        inp.value = '';
        // Refresh the thread so the new message shows up.
        await _loadOrderMessages(orderId);
      } catch (e) {
        console.error('[order-messages] send failed:', e);
        if (sts) { sts.textContent = 'Send failed: ' + (e.message || 'try again'); sts.style.color = 'var(--red)'; }
      } finally {
        btn.disabled = false; btn.textContent = 'Send';
      }
    }

    // Loads the global unread count and stamps it on the Orders nav-tab
    // badge. Quietly fails for signed-out / unsupported state.
    async function refreshUnreadMessageCount() {
      if (!currentUser) return;
      try {
        const { data, error } = await sb.rpc('unread_order_messages_count');
        if (error) throw error;
        _totalUnreadMessages = parseInt(data, 10) || 0;
      } catch (e) {
        _totalUnreadMessages = 0;
      }
      // Surface on the Orders tab badge — merges with order-notification
      // count (paid awaiting-ship orders) by taking the sum so the user
      // sees ANY actionable orders count.
      try { updateOrderNotification(); } catch(_) {}
    }

    function requestReturn(orderId) {
      if (!currentUser) return;
      const o = orders.find(x => x.id === orderId);
      if (!o) { showToast('Order not found'); return; }
      if (o.status === 'refunded' || o.status === 'return_requested' || o.status === 'disputed') {
        showToast('A return is already in progress for this order'); return;
      }
      document.getElementById('returnOrderId').value = orderId;
      document.getElementById('returnReason').value = 'not_as_described';
      document.getElementById('returnReasonDetail').value = '';
      const sts = document.getElementById('returnRequestStatus');
      if (sts) { sts.textContent = ''; sts.style.color = 'var(--muted)'; }
      const btn = document.getElementById('returnSubmitBtn');
      if (btn) { btn.disabled = false; btn.textContent = 'Submit Request'; }
      openModal('returnRequestModal');
    }

    async function submitReturnRequest() {
      const orderId = document.getElementById('returnOrderId').value;
      const reason  = document.getElementById('returnReason').value;
      const detail  = document.getElementById('returnReasonDetail').value.trim();
      const sts = document.getElementById('returnRequestStatus');
      const btn = document.getElementById('returnSubmitBtn');
      if (!detail || detail.length < 10) {
        if (sts) { sts.textContent = 'Add a few words describing what went wrong (at least 10 characters).'; sts.style.color = 'var(--red)'; }
        return;
      }
      if (btn) { btn.disabled = true; btn.textContent = 'Submitting…'; }

      const o = orders.find(x => x.id === orderId);

      // Auto-purchase binder cleanup — same logic the legacy flow had.
      // The card goes back to the seller's listing on this side, gets
      // re-added to the buyer's binder only if the seller declines.
      const autoItem = collectionItems.find(c => c.notes === 'auto_purchase:' + orderId);
      if (autoItem) {
        try {
          await sb.from('collection_items').delete().eq('id', autoItem.id);
          collectionItems = collectionItems.filter(c => c.id !== autoItem.id);
        } catch (_) { /* non-fatal */ }
      }

      const nowIso = new Date().toISOString();
      const { error } = await sb.from('orders').update({
        status:               'return_requested',
        return_reason:        reason,
        return_reason_detail: detail,
        return_requested_at:  nowIso,
      }).eq('id', orderId);

      if (error) {
        if (sts) { sts.textContent = 'Error: ' + error.message; sts.style.color = 'var(--red)'; }
        if (btn) { btn.disabled = false; btn.textContent = 'Submit Request'; }
        return;
      }
      if (o) {
        o.status               = 'return_requested';
        o.return_reason        = reason;
        o.return_reason_detail = detail;
        o.return_requested_at  = nowIso;
      }

      closeModal('returnRequestModal');
      showToast('Return requested. The seller has 48 hours to respond.');
      renderOrders();
      updateOrderNotification();
    }

    // ─── Seller-side response to a return request ──────────────────────
    // The seller sees the return reason + detail in their Orders → Selling
    // view. Two paths from there:
    //   - Approve refund  → /api/seller-refund (Stripe refund + listing back)
    //   - Decline         → status flips to 'disputed' for admin handling
    function openSellerRefundConfirm(orderId) {
      const o = orders.find(x => x.id === orderId);
      if (!o) { showToast('Order not found'); return; }
      if (o.seller_id !== currentUser.id && !(currentUser && currentUser.is_admin)) {
        showToast('Only the seller can refund this order'); return;
      }
      document.getElementById('sellerRefundOrderId').value = orderId;
      const body = document.getElementById('sellerRefundBody');
      if (body) {
        const amt = (o.amount || 0).toFixed(2);
        const route = o.payment_route === 'destination_charge' ? 'Stripe Connect (destination charge)' : 'Stripe (platform balance)';
        body.innerHTML = ''
          + 'You&rsquo;re about to refund <strong style="color:var(--text)">$' + amt + '</strong> '
          + 'to the buyer. Funds + the platform fee are returned via ' + route + '. '
          + 'The listing is put back on the market. This cannot be undone.';
      }
      const sts = document.getElementById('sellerRefundStatus');
      if (sts) { sts.textContent = ''; sts.style.color = 'var(--muted)'; }
      const btn = document.getElementById('sellerRefundBtn');
      if (btn) { btn.disabled = false; btn.textContent = 'Issue Refund'; }
      openModal('sellerRefundConfirmModal');
    }

    async function confirmSellerRefund() {
      const orderId = document.getElementById('sellerRefundOrderId').value;
      const sts = document.getElementById('sellerRefundStatus');
      const btn = document.getElementById('sellerRefundBtn');
      if (!orderId) return;
      if (btn) { btn.disabled = true; btn.textContent = 'Refunding…'; }

      try {
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) throw new Error('Not signed in');
        const r = await fetch('/api/seller-refund', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
          body:    JSON.stringify({ orderId: orderId, reason: 'requested_by_customer' }),
        });
        const data = await r.json();
        if (!r.ok || !data.success) throw new Error(data.error || 'Refund failed');

        // Mirror onto local state so the UI updates without a refetch.
        const o = orders.find(x => x.id === orderId);
        if (o) {
          o.status                   = 'refunded';
          o.refunded_at              = new Date().toISOString();
          o.refund_id                = data.refundId;
          o.return_decision          = 'approved';
          o.return_decided_at        = new Date().toISOString();
          o.refunded_application_fee = true;
          if (o.listing_id) {
            const l = listings.find(x => String(x.id) === String(o.listing_id));
            if (l) l.status = 'available';
          }
        }
        closeModal('sellerRefundConfirmModal');
        showToast('Refunded $' + (data.amount || 0).toFixed(2) + ' to the buyer.');
        renderOrders();
        updateOrderNotification();
      } catch (e) {
        console.error('[seller-refund] error:', e);
        if (sts) { sts.textContent = e.message || 'Refund failed'; sts.style.color = 'var(--red)'; }
        if (btn) { btn.disabled = false; btn.textContent = 'Issue Refund'; }
      }
    }

    // ─── Admin notifications ───────────────────────────────────────────
    // Source of truth: admin_notifications table. Populated by the
    // trg_order_disputed trigger (and future event sources). Per-admin
    // read state lives on the row itself via the read_by[] / dismissed_by[]
    // uuid arrays — simpler than a join table for the volume we'll have.
    let adminNotifications = [];
    let _adminNotificationsLoading = false;

    function userIsAdmin() {
      return !!(currentUser && currentUser.is_admin);
    }

    // Pulls the latest admin notifications into the local cache. Bails
    // quietly for non-admins. RLS lets admins read every row; the cap
    // (50 latest) keeps the bell snappy without paginating the whole
    // history.
    async function loadAdminNotifications() {
      if (!userIsAdmin()) { adminNotifications = []; updateAdminBellBadge(); return; }
      if (_adminNotificationsLoading) return;
      _adminNotificationsLoading = true;
      try {
        const { data, error } = await sb
          .from('admin_notifications')
          .select('*')
          .order('created_at', { ascending: false })
          .limit(50);
        if (error) { console.warn('[admin-notif] load failed:', error.message); return; }
        adminNotifications = (data || []).filter(n => !(n.dismissed_by || []).includes(currentUser.id));
        updateAdminBellBadge();
      } catch (e) {
        console.warn('[admin-notif] load exception:', e && e.message);
      } finally {
        _adminNotificationsLoading = false;
      }
    }

    // Shows the bell row in the avatar dropdown and stamps an unread
    // count pill. No-op (and explicitly hides) for non-admins.
    function updateAdminBellBadge() {
      const btn      = document.getElementById('adminBellBtn');
      const divider  = document.getElementById('adminBellDivider');
      const countEl  = document.getElementById('adminBellCount');
      const navBadge = document.getElementById('adminNavBadge');
      if (!btn || !countEl) return;
      if (!userIsAdmin()) {
        btn.style.display = 'none';
        if (divider)  divider.style.display  = 'none';
        if (navBadge) navBadge.style.display = 'none';
        countEl.textContent = '';
        return;
      }
      btn.style.display = 'block';
      if (divider) divider.style.display = 'block';
      const unread = adminNotifications.filter(n => !(n.read_by || []).includes(currentUser.id)).length;

      // Dropdown chip (inside the avatar menu's "Admin Alerts" item)
      if (unread > 0) {
        countEl.innerHTML = '<span style="display:inline-block;background:var(--red);color:#fff;font-family:\'Space Mono\',monospace;font-size:.62rem;font-weight:700;padding:1px 6px;border-radius:8px;min-width:18px;text-align:center">' + unread + '</span>';
      } else {
        countEl.innerHTML = '';
      }

      // Nav-tab badge — mirrors the unread count so the admin can see
      // there's something needing attention without opening the dropdown.
      // Reuses the existing .badge-count CSS class used by the orders
      // notification badge.
      if (navBadge) {
        if (unread > 0) {
          navBadge.textContent  = unread > 99 ? '99+' : String(unread);
          navBadge.style.display = 'flex';
        } else {
          navBadge.style.display = 'none';
        }
      }
    }

    async function openAdminNotificationsPanel() {
      if (!userIsAdmin()) { showToast('Admins only'); return; }
      openModal('adminNotificationsModal');
      // Refresh in case the cache is stale (other admin marked something
      // read, etc.) then render.
      await loadAdminNotifications();
      renderAdminNotificationsList();
      // Mark everything in this view as read for this admin. Fire and
      // forget — if it fails the next open will retry.
      _markAdminNotificationsReadForViewer().catch(() => {});
    }

    function renderAdminNotificationsList() {
      const host = document.getElementById('adminNotificationsList');
      if (!host) return;
      if (!adminNotifications.length) {
        host.innerHTML = '<div style="color:var(--muted);font-size:.82rem;padding:14px 0;text-align:center">No admin notifications. You\'re caught up.</div>';
        return;
      }
      host.innerHTML = adminNotifications.map(function(n) {
        const isUnread = !(n.read_by || []).includes(currentUser.id);
        const dateStr = (function() {
          try { return new Date(n.created_at).toLocaleString(undefined, { dateStyle: 'medium', timeStyle: 'short' }); }
          catch (_) { return ''; }
        })();
        const linkBtn = n.link_path
          ? '<a href="' + n.link_path + '" style="display:inline-block;margin-top:6px;color:var(--accent);font-size:.74rem;font-family:\'Space Mono\',monospace;text-decoration:none">Review &rarr;</a>'
          : '';
        const dismissBtn = '<button type="button" onclick="dismissAdminNotification(\'' + n.id + '\')" '
          + 'style="background:transparent;border:1px solid var(--border);color:var(--muted);font-family:\'Space Mono\',monospace;font-size:.65rem;padding:3px 8px;cursor:pointer">Dismiss</button>';
        const safeTitle   = String(n.title || '').replace(/</g, '&lt;');
        const safeMessage = String(n.message || '').replace(/</g, '&lt;');
        return ''
          + '<div style="padding:12px 14px;border:1px solid var(--border);background:' + (isUnread ? 'rgba(184,115,51,.05)' : 'var(--surface2)') + ';border-left:3px solid ' + (isUnread ? 'var(--copper)' : 'var(--border)') + '">'
          +   '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px">'
          +     '<div style="flex:1">'
          +       '<div style="font-family:\'Space Mono\',monospace;font-size:.78rem;color:var(--text);font-weight:700;margin-bottom:4px">' + safeTitle + '</div>'
          +       '<div style="font-size:.74rem;color:var(--muted);line-height:1.5">' + safeMessage + '</div>'
          +       linkBtn
          +     '</div>'
          +     '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px">'
          +       '<div style="font-size:.66rem;color:var(--muted);font-family:\'Space Mono\',monospace">' + dateStr + '</div>'
          +       dismissBtn
          +     '</div>'
          +   '</div>'
          + '</div>';
      }).join('');
    }

    // Append the current admin's uid to read_by[] for every notification
    // they haven't already marked read. RLS lets admins update any row;
    // we only ever push our own uid so collisions are impossible.
    async function _markAdminNotificationsReadForViewer() {
      if (!userIsAdmin()) return;
      const myUid = currentUser.id;
      const toMark = adminNotifications.filter(n => !(n.read_by || []).includes(myUid));
      for (const n of toMark) {
        const next = (n.read_by || []).concat([myUid]);
        try {
          await sb.from('admin_notifications').update({ read_by: next }).eq('id', n.id);
          n.read_by = next;
        } catch (_) { /* best effort */ }
      }
      updateAdminBellBadge();
    }

    async function markAllAdminNotificationsRead() {
      await _markAdminNotificationsReadForViewer();
      renderAdminNotificationsList();
    }

    async function dismissAdminNotification(id) {
      if (!userIsAdmin()) return;
      const n = adminNotifications.find(x => x.id === id);
      if (!n) return;
      const next = (n.dismissed_by || []).concat([currentUser.id]);
      try {
        await sb.from('admin_notifications').update({ dismissed_by: next }).eq('id', id);
      } catch (_) { /* best effort */ }
      adminNotifications = adminNotifications.filter(x => x.id !== id);
      renderAdminNotificationsList();
      updateAdminBellBadge();
    }

    async function declineReturnRequest(orderId) {
      if (!currentUser) return;
      const o = orders.find(x => x.id === orderId);
      if (!o) { showToast('Order not found'); return; }
      if (o.seller_id !== currentUser.id && !(currentUser && currentUser.is_admin)) {
        showToast('Only the seller can decline this return'); return;
      }
      // Plain confirm — declining isn't destructive (no money moves), just
      // escalates to admin via the disputed status. Admin tools handle it
      // from there.
      if (!confirm('Decline this return request? It will be escalated to PathBinder admins to mediate. Do this only if you believe the buyer\'s claim is invalid.')) return;

      const nowIso = new Date().toISOString();
      const { error } = await sb.from('orders').update({
        status:            'disputed',
        return_decision:   'declined',
        return_decided_at: nowIso,
        disputed_at:       nowIso,
      }).eq('id', orderId);
      if (error) { showToast('Error: ' + error.message); return; }
      o.status            = 'disputed';
      o.return_decision   = 'declined';
      o.return_decided_at = nowIso;
      o.disputed_at       = nowIso;
      showToast('Return declined. An admin will review the dispute.');
      renderOrders();
      updateOrderNotification();

      // Fire the admin email side. In-app notification is already
      // handled server-side by trg_order_disputed. Best-effort — we
      // don't surface a failure to the seller because the dispute is
      // already in the admin queue regardless.
      try {
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (tok) {
          fetch('/api/admin-notify-dispute', {
            method:  'POST',
            headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
            body:    JSON.stringify({ orderId: orderId }),
          }).catch(function() { /* silent */ });
        }
      } catch (_) { /* silent */ }
    }

    // ─── Seller Ratings ────────────────────────────────────────────────
    function openRateSellerModal(orderId, sellerId, sellerName) {
      const o = orders.find(x => x.id === orderId);
      if (o && o.rating_submitted) return; // already rated
      document.getElementById('rateOrderId').value = orderId;
      document.getElementById('rateSellerId').value = sellerId || '';
      document.getElementById('rateSellerName').textContent = `Rate your experience with ${sellerName}`;
      document.getElementById('ratingComment').value = '';
      selectedRating = 0;
      document.querySelectorAll('.star-btn').forEach(b => b.classList.remove('active'));
      document.getElementById('ratingLabel').textContent = 'Select a rating';
      openModal('rateSellerModal');
    }

    function selectRating(val) {
      selectedRating = val;
      const labels = ['','Terrible','Poor','OK','Good','Excellent'];
      document.getElementById('ratingLabel').textContent = labels[val] || '';
      document.querySelectorAll('.star-btn').forEach(b => {
        b.classList.toggle('active', parseInt(b.dataset.v) <= val);
      });
    }

    async function submitRating() {
      if (!selectedRating) { showToast('Select a rating first'); return; }
      const orderId = document.getElementById('rateOrderId').value;
      const sellerId = document.getElementById('rateSellerId').value;
      const comment = document.getElementById('ratingComment').value.trim();

      const { error } = await sb.from('seller_ratings').insert({
        order_id: orderId,
        seller_id: sellerId || null,
        buyer_id: currentUser.id,
        rating: selectedRating,
        comment: comment || null
      });
      if (error) { showToast('Error submitting rating: ' + error.message); return; }

      // Mark order as rated
      await sb.from('orders').update({ rating_submitted: true }).eq('id', orderId);
      const o = orders.find(x => x.id === orderId);
      if (o) o.rating_submitted = true;

      closeModal('rateSellerModal');
      showToast('Rating submitted — thanks!');
    }

    function openAddTrackingModal(orderId) {
      document.getElementById('trackingOrderId').value = orderId;
      document.getElementById('trackingNumber').value = '';
      document.getElementById('trackingCarrier').value = '';
      openModal('addTrackingModal');
    }

    async function saveTracking() {
      const orderId = document.getElementById('trackingOrderId').value;
      const trackingNumber = document.getElementById('trackingNumber').value.trim();
      const carrier = document.getElementById('trackingCarrier').value;
      if (!trackingNumber) { showToast('Enter a tracking number'); return; }
      const { error } = await sb.from('orders').update({
        tracking_number: trackingNumber,
        tracking_carrier: carrier,
        status: 'shipped',
        shipped_at: new Date().toISOString()
      }).eq('id', orderId);
      if (error) { showToast('Error: ' + error.message); return; }
      const o = orders.find(o => o.id === orderId);
      if (o) { o.tracking_number = trackingNumber; o.tracking_carrier = carrier; o.status = 'shipped'; }

      // Step 4 bookkeeping — the unit has physically left the shop.
      // Drop listed_online_qty AND quantity on the matching collection
      // row. Pulls the listing snapshot to get api_card_id / variant /
      // qty so the right collection row gets decremented.
      try {
        if (o && o.listing_id && currentUser && o.seller_id === currentUser.id) {
          const sr = await sb.from('listings').select('api_card_id, variant, quantity').eq('id', o.listing_id).maybeSingle();
          const snap = sr.data;
          if (snap && snap.api_card_id) {
            const orderQty = (o.quantity || 1);
            await _invOnListingShipped(currentUser.id, snap.api_card_id, snap.variant || 'normal', orderQty);
          }
        }
      } catch (e) {
        console.warn('[inv] ship bookkeeping failed:', e && e.message);
      }

      closeModal('addTrackingModal');
      showToast('Tracking added! Buyer has been notified.');
      renderOrders();
      updateOrderNotification();
    }

    // ─── Collection Panel Toggle ───────────────────────────────────────
    function toggleCollectionPanel() {
      const panel = document.getElementById('collectionPanel');
      const btn = document.getElementById('collPanelBtn');
      if (!panel) return;
      const isOpen = panel.classList.contains('open');
      panel.classList.toggle('open', !isOpen);
      if (btn) btn.textContent = isOpen ? '+ Add to My Binder' : '− Add to My Binder';
    }

    // ─── Market Price Lookup ───────────────────────────────────────────
    async function lookupMarketPrice() {
      const name = (document.getElementById('lcName') || {}).value?.trim();
      const condition = (document.getElementById('lcCondition') || {}).value || 'NM';
      const resultEl = document.getElementById('lcMarketPriceResult');
      if (!name || !resultEl) return;

      resultEl.style.display = 'block';
      resultEl.style.color = 'var(--muted)';
      resultEl.textContent = '// Looking up market price...';

      try {
        // Use our existing price scraper endpoint
        const res = await fetch('/api/lookup-price', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ name, condition })
        });
        if (res.ok) {
          const { price } = await res.json();
          if (price) {
            document.getElementById('lcMarketPriceResult').innerHTML =
              `Market price: <strong style="color:var(--accent)">$${price.toFixed(2)}</strong> <span style="color:var(--muted)">(PriceCharting)</span>`;
            // Store for comparison
            document.getElementById('lcMarketPriceResult').dataset.marketPrice = price;
          } else {
            resultEl.textContent = '// No market price found — you can still list manually';
          }
        } else {
          resultEl.textContent = '// Price lookup unavailable';
        }
      } catch(e) {
        resultEl.textContent = '// Price lookup unavailable';
      }
    }

    // ─── Photo Handling ────────────────────────────────────────────────
    function handleLcPhotoSelect(event) {
      const files = Array.from(event.target.files);
      addLcPhotos(files);
    }

    function handleLcPhotoDrop(event) {
      event.preventDefault();
      document.getElementById('lcPhotoArea').style.borderColor = 'var(--border)';
      const files = Array.from(event.dataTransfer.files).filter(f => f.type.startsWith('image/'));
      addLcPhotos(files);
    }

    function addLcPhotos(files) {
      const errEl = document.getElementById('lcPhotoError');
      errEl.style.display = 'none';
      const remaining = 8 - lcPhotos.length;
      if (remaining <= 0) { errEl.textContent = 'Maximum 8 photos allowed'; errEl.style.display = 'block'; return; }
      const toAdd = files.slice(0, remaining);
      toAdd.forEach(file => {
        if (file.size > 5 * 1024 * 1024) {
          errEl.textContent = `${file.name} is over 5MB`; errEl.style.display = 'block'; return;
        }
        lcPhotos.push(file);
      });
      renderLcPhotoPreview();
    }

    function renderLcPhotoPreview() {
      const preview = document.getElementById('lcPhotoPreview');
      if (!preview) return;
      preview.innerHTML = lcPhotos.map((file, i) => {
        const url = URL.createObjectURL(file);
        const label = i === 0 ? '<div style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,.7);font-size:.55rem;text-align:center;color:#fff;padding:2px">FRONT</div>'
          : i === 1 ? '<div style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,.7);font-size:.55rem;text-align:center;color:#fff;padding:2px">BACK</div>' : '';
        return `<div class="lc-photo-thumb">
          <img src="${url}" alt="Photo ${i+1}" loading="lazy" decoding="async">
          ${label}
          <button class="rm-btn" onclick="removeLcPhoto(${i})">×</button>
        </div>`;
      }).join('');
      document.getElementById('lcPhotoArea').style.display = lcPhotos.length >= 8 ? 'none' : '';
    }

    function removeLcPhoto(idx) {
      lcPhotos.splice(idx, 1);
      renderLcPhotoPreview();
      document.getElementById('lcPhotoArea').style.display = '';
    }

    function toggleLcGrade() {
      const cond = document.getElementById('lcCondition').value;
      const show = cond === 'Graded';
      document.getElementById('lcGradeWrap').style.display = show ? '' : 'none';
      document.getElementById('lcGradeNumWrap').style.display = show ? '' : 'none';
    }

    // ─── List Card Modal ───────────────────────────────────────────────
    // Tracks whether the currently-open list modal is for a single card
    // ('single', default) or a sealed product ('booster_box', 'etb', etc.).
    // Drives photo count requirement, condition options, modal copy.
    let lcProductType = 'single';
    // Catalog-link payload populated by openListCardModal's prefill.
    // Read in the listings.insert() call below so api_card_id +
    // card_number + variant land on the new row. Null for sealed /
    // non-TCG / fully-manual listings — column is nullable.
    let _lcPrefillCatalog = { apiCardId: null, cardNumber: null, variant: null };

    // Re-renders the fee + payout callout inside the listing modal. Pulls
    // the seller's commission rate from their current tier (server-side
    // truth lives in /api/marketplace-checkout.js — mirrored in
    // TIER_COMMISSION_RATES at the top of this script) and projects a
    // live "you receive $X" number from the ask + shipping inputs.
    // Safe to call at any time; bails silently if the box isn't mounted.
    function updateListingFeePreview() {
      const box = document.getElementById('lcFeePreview');
      if (!box) return;
      const rate     = myCommissionRate();          // 0.07 / 0.06 / 0.05
      const ratePct  = (rate * 100).toFixed(0) + '%';
      const tierName = userTier();                  // 'enthusiast' | 'vendor' | 'shop'
      // ucfirst for display — TIER_ORDER keys are lowercase.
      const tierLabel = tierName.charAt(0).toUpperCase() + tierName.slice(1);

      const askEl  = document.getElementById('lcPrice');
      const shipEl = document.getElementById('lcShipping');
      const ask    = parseFloat(askEl && askEl.value)  || 0;
      const ship   = parseFloat(shipEl && shipEl.value) || 0;

      let payoutLine = '';
      if (ask > 0) {
        // Commission applies to the card price only — shipping passes
        // through to the seller. Matches the server-side calc which uses
        // the unit_amount (price, not price+shipping). The $0.30 buyer
        // processing fee is charged to the buyer separately on the
        // checkout page; it does NOT come out of the seller's payout.
        const pctFee  = ask * rate;
        const payout  = (ask - pctFee) + ship;
        payoutLine = ''
          + '<div style="margin-top:6px;color:var(--text)">'
          + 'You receive <strong style="color:var(--green)">$' + payout.toFixed(2) + '</strong>'
          + ' on sale '
          + '<span style="color:var(--muted)">(ask $' + ask.toFixed(2)
          + ' &minus; ' + ratePct + ' commission $' + pctFee.toFixed(2)
          + (ship > 0 ? ' + shipping $' + ship.toFixed(2) : '')
          + ')</span>'
          + '</div>';
      }

      box.innerHTML = ''
        + tierLabel + ' tier fee: '
        + '<strong style="color:var(--accent)">' + ratePct + '</strong>'
        + ' deducted from your payout on sale &middot; '
        + 'Payouts on Stripe&rsquo;s standard schedule &middot; '
        + '7-day buyer protection via Stripe dispute resolution'
        + payoutLine;
    }

    function openListCardModal(prefill) {
      if (!currentUser) { showToast('Sign in to list a card'); openModal('loginModal'); return; }
      // Coming Soon gate — the marketplace is admin-only during the
      // pre-launch window. Non-admins shouldn't be able to create
      // listings either, since their listings would never become
      // visible to other shoppers. Match the renderBrowse() gate so
      // the rules stay in lockstep.
      if (!currentUser.is_admin) {
        showToast('Marketplace coming soon');
        return;
      }
      // Marketplace selling is gated by subscription tier with per-tier
      // listing caps:
      //   free / collector : cannot sell (cap = 0)
      //   enthusiast       : 40 concurrent active listings
      //   vendor           : 150 listings + non-TCG products + product scanner
      //   shop             : unlimited
      // Bounce non-sellers through the pricing modal at the enthusiast
      // tier (the lowest paid tier with marketplace access).
      if (!tierAtLeast('enthusiast')) {
        if (typeof openPricingModalWithPromo === 'function') {
          openPricingModalWithPromo('enthusiast');
        } else {
          showToast('Enthusiast plan or higher required to list on the marketplace');
        }
        return;
      }
      // Cap enforcement: if at the listing limit, bounce to the next tier
      // up so they can upgrade. Only Infinity-capped tiers skip this check.
      if (!canCreateListing()) {
        var cap = listingCap();
        var nextTier = tierAtLeast('vendor') ? 'shop'
                     : tierAtLeast('enthusiast') ? 'vendor'
                     : 'enthusiast';
        showToast('Listing limit reached (' + cap + '/' + cap + '). Upgrade to ' + nextTier + ' for more slots.');
        if (typeof openPricingModalWithPromo === 'function') {
          openPricingModalWithPromo(nextTier);
        }
        return;
      }
      // Product-type gating:
      //   - Singles (TCG cards): allowed for enthusiast+
      //   - Sealed TCG (booster boxes, ETBs, tins, decks): vendor+ only
      //   - Non-TCG (Funko, Manga, etc.): vendor+ only
      var _ptype = (prefill && prefill.productType) || '';
      var _isSingle = !_ptype || _ptype === 'single' || _ptype === 'tcg_single';
      var _isSealed = _ptype === 'sealed' || _ptype === 'tcg_sealed';
      var _isNonTcg = _ptype && !_isSingle && !_isSealed;

      if (_isSealed && !canListSealed()) {
        showToast('Vendor tier or higher required to sell sealed product');
        if (typeof openPricingModalWithPromo === 'function') {
          openPricingModalWithPromo('vendor');
        }
        return;
      }
      if (_isNonTcg && !canListNonTCG()) {
        showToast('Vendor tier or higher required for non-TCG product listings');
        if (typeof openPricingModalWithPromo === 'function') {
          openPricingModalWithPromo('vendor');
        }
        return;
      }
      lcPhotos = [];
      lcProductType = (prefill && prefill.productType) ? prefill.productType : 'single';
      // Stash the catalog link fields so the listing insert can
      // populate listings.api_card_id / card_number / variant.
      // These fields are pre-filled by the "List for Sale" button
      // on the binder detail modal (where we know the catalog row)
      // and by the marketplace search-then-list flow. Manual /
      // typed listings leave them null, which the schema allows.
      _lcPrefillCatalog = {
        apiCardId:  (prefill && prefill.apiCardId)  || null,
        cardNumber: (prefill && prefill.cardNumber) || null,
        variant:    (prefill && prefill.variant)    || null,
      };
      // Three modes the modal supports:
      //   - 'single' (TCG single card)         → NM/LP/HP/Graded conditions
      //   - 'sealed' / 'tcg_sealed'            → Sealed / Damaged Box / Loose
      //   - 'funko_pop' / anything non-TCG     → no condition field at all
      // isProduct gates the non-TCG branch — wider than just Funko so any
      // future product category (manga, posters, plush, etc.) gets the
      // same treatment without needing a code change.
      const TCG_TYPES = ['single', 'sealed', 'tcg_sealed', 'tcg_single'];
      const isProduct = !TCG_TYPES.includes(lcProductType);
      const isSealed = lcProductType !== 'single' && !isProduct;

      document.getElementById('lcName').value = prefill?.cardName || '';
      document.getElementById('lcGame').value = prefill?.gameType || 'Pokémon';
      document.getElementById('lcPrice').value = '';
      // Shipping default is now empty — the seller decides. Was previously
      // hard-coded to $5.00 which baked an assumption into every listing.
      document.getElementById('lcShipping').value = '';
      // Quantity defaults to 1; only vendor+ can change it.
      const qtyEl = document.getElementById('lcQuantity');
      if (qtyEl) qtyEl.value = '1';
      const qtyWrap = document.getElementById('lcQuantityWrap');
      if (qtyWrap) {
        const canBulk = (typeof tierAtLeast === 'function') && tierAtLeast('vendor');
        qtyWrap.style.display = canBulk ? '' : 'none';
      }
      document.getElementById('lcDescription').value = '';
      document.getElementById('lcMarketPriceResult').style.display = 'none';
      document.getElementById('lcPhotoError').style.display = 'none';
      const _lcErr = document.getElementById('lcSaveError');
      if (_lcErr) _lcErr.style.display = 'none';

      // Swap the Condition dropdown contents for sealed product. Sealed
      // products don't have NM/LP/HP — they have packaging condition.
      // For non-TCG products (Funko etc.) we hide the whole field below.
      const condEl = document.getElementById('lcCondition');
      if (condEl) {
        if (isSealed) {
          condEl.innerHTML = ''
            + '<option value="Sealed">Sealed — Factory Fresh</option>'
            + '<option value="Damaged Box">Damaged Box — Contents Sealed</option>'
            + '<option value="Loose">Loose Items — No Outer Seal</option>';
          condEl.value = prefill?.condition || 'Sealed';
        } else {
          condEl.innerHTML = ''
            + '<option value="NM">NM — Near Mint</option>'
            + '<option value="LP">LP — Lightly Played</option>'
            + '<option value="HP">HP — Heavily Played</option>'
            + '<option value="Graded">Graded / Slabbed</option>';
          condEl.value = prefill?.condition || 'NM';
        }
      }
      // Hide the condition row entirely for non-TCG products. Save flow
      // reads condEl.value regardless — for products it gets whatever was
      // last set (harmless; downstream just ignores it for non-TCG).
      const condWrap = document.getElementById('lcConditionWrap');
      if (condWrap) condWrap.style.display = isProduct ? 'none' : '';

      // Modal title + sub copy + photo label all shift per mode.
      const titleEl = document.querySelector('#listCardModal h3');
      const subEl   = document.querySelector('#listCardModal .modal-sub');
      const photoLabelEl = document.querySelector('#listCardModal label[for="lcPhotoInput"], #listCardModal .form-group label');
      // Grab the photo-section label specifically (it's the one that
      // wraps the dashed photo area).
      const photoSection = document.getElementById('lcPhotoArea');
      const photoSectionLabel = photoSection ? photoSection.parentElement.querySelector('label') : null;
      if (titleEl) {
        titleEl.textContent = isProduct ? 'List Product for Sale'
                            : isSealed  ? 'List Sealed Product for Sale'
                            :             'List Card for Sale';
      }
      if (subEl) {
        subEl.innerHTML = isProduct
          ? 'Required: one photo of the product (front view recommended). Pick a category that fits.'
          : isSealed
              ? 'Required: one photo of the product (box front with seal visible is best). Buyers see market price vs. your ask.'
              : 'Required: front &amp; back photo. Buyers see market price vs. your ask.';
      }
      if (photoSectionLabel) {
        photoSectionLabel.innerHTML = (isSealed || isProduct)
          ? 'Photo * <span style="color:var(--muted);font-size:.72rem">(Front view recommended · up to 8)</span>'
          : 'Photos * <span style="color:var(--muted);font-size:.72rem">(Front &amp; back required · up to 8)</span>';
      }
      // Card Name → Product Name label swap when listing a non-TCG product
      const nameLabelEl = document.getElementById('lcNameLabel');
      if (nameLabelEl) nameLabelEl.textContent = isProduct ? 'Product Name *' : 'Card Name *';
      // List Card → List Product button text swap
      const saveBtnEl = document.querySelector('#listCardModal .lc-save-btn');
      if (saveBtnEl) {
        saveBtnEl.textContent = isProduct ? 'List Product'
                              : isSealed  ? 'List Product'
                              :             'List Card';
      }
      // Swap the Game/Category dropdown options. TCG modes (single +
      // sealed) get the TCG list; product mode gets non-TCG categories
      // (Funko Pop, Manga, Posters, etc.). The selected value is
      // honored if prefill specifies one; otherwise defaults to the
      // first item in the new option list.
      const gameSel = document.getElementById('lcGame');
      if (gameSel) {
        var _TCG_OPTS = [
          ['Pokémon','Pokémon'], ['Magic: The Gathering','Magic: The Gathering'],
          ['Yu-Gi-Oh!','Yu-Gi-Oh!'], ['One Piece','One Piece'],
          ['Gundam','Gundam'], ['Dragon Ball Z','Dragon Ball Z'],
          ['Pokemon Topps','Pokemon Topps'], ['Sports','Sports'], ['Other','Other'],
        ];
        var _PRODUCT_OPTS = [
          ['Funko Pop','Funko Pop'], ['Manga','Manga'],
          ['Posters','Posters'], ['Art Prints','Art Prints'],
          ['Plush','Plush'], ['Figures','Figures'],
          ['Statues','Statues'], ['Apparel','Apparel'],
          ['Pins','Pins'], ['Accessories','Accessories'],
          ['Other','Other'],
        ];
        var _opts = isProduct ? _PRODUCT_OPTS : _TCG_OPTS;
        gameSel.innerHTML = _opts.map(function(o) {
          return '<option value="' + o[0] + '">' + o[1] + '</option>';
        }).join('');
        // Honor prefill, otherwise first option of the list
        gameSel.value = (prefill && prefill.gameType) || _opts[0][0];
      }

      renderLcPhotoPreview();
      toggleLcGrade();
      updateListingFeePreview();

      // Reveal the "Scan Product to Autofill" row only for shop-tier
      // users (since they're the ones with non-TCG inventory to list).
      // openListCardModal already requires shop tier to reach this
      // point, so we can show it unconditionally here — but the tier
      // check is cheap and defensive.
      var _scanRow = document.getElementById('lcScanProductRow');
      if (_scanRow) {
        // Vendor+ tier unlocks the product scanner UI inside the listing
        // modal. Admins always qualify regardless of tier.
        var _showScan = hasProductScanner() || (currentUser && currentUser.is_admin);
        _scanRow.style.display = _showScan ? 'block' : 'none';
      }

      openModal('listCardModal');
    }

    async function saveMarketplaceListing() {
      if (!currentUser) return;
      // Belt-and-suspenders: openListCardModal already gates this, but
      // someone could call save directly via dev tools. Don't trust the UI.
      if (!tierAtLeast('shop')) {
        showToast('Shop plan required to list on the marketplace');
        return;
      }
      const productType = lcProductType || 'single';
      const isSealed = productType !== 'single';

      const name = document.getElementById('lcName').value.trim();
      const game = document.getElementById('lcGame').value;
      const condition = document.getElementById('lcCondition').value;
      const gradingCo = condition === 'Graded' ? document.getElementById('lcGradingCo').value : null;
      const gradeNum = condition === 'Graded' ? parseFloat(document.getElementById('lcGradeNum').value) : null;
      const price = parseFloat(document.getElementById('lcPrice').value);
      const shipping = parseFloat(document.getElementById('lcShipping').value) || 0;
      const description = document.getElementById('lcDescription').value.trim();
      const marketPriceEl = document.getElementById('lcMarketPriceResult');
      const marketPrice = marketPriceEl?.dataset?.marketPrice ? parseFloat(marketPriceEl.dataset.marketPrice) : null;

      // Validation
      if (!name) { showToast(isSealed ? 'Enter a product name' : 'Enter a card name'); return; }
      if (!price || price <= 0) { showToast('Enter a valid price'); return; }
      // Per-tier price ceiling — see TIER_PRICE_CEILINGS. Client-side
      // is informational; the canonical check lives on the server in
      // marketplace-checkout.js (and a Supabase trigger blocks INSERT
      // for safety, identical logic).
      var _ceiling = myPriceCeiling();
      if (_ceiling > 0 && price > _ceiling) {
        var _tname = userTier();
        var _next = _tname === 'enthusiast' ? 'Vendor' : _tname === 'vendor' ? 'Shop' : null;
        var _msg = 'This price exceeds your ' + _tname.charAt(0).toUpperCase() + _tname.slice(1)
                 + ' tier max of $' + _ceiling.toFixed(0) + '.';
        if (_next) _msg += ' Upgrade to ' + _next + ' to list higher-value items.';
        showToast(_msg);
        return;
      }
      const errEl = document.getElementById('lcPhotoError');
      const minPhotos = isSealed ? 1 : 2;
      if (lcPhotos.length < minPhotos) {
        errEl.textContent = isSealed
          ? 'At least 1 photo required (box front)'
          : 'At least 2 photos required (front + back)';
        errEl.style.display = 'block';
        return;
      }

      const saveBtn = document.querySelector('#listCardModal .lc-save-btn');
      if (saveBtn) { saveBtn.textContent = 'Uploading...'; saveBtn.disabled = true; }

      // Upload photos to Supabase Storage (re-encoded as webp on-the-fly
      // for smaller file sizes; falls back to original if encoding fails)
      const photoUrls = [];
      for (const file of lcPhotos) {
        // Generate full-size WebP + 200/400px variants in one decode.
        // Variants are uploaded non-blocking after the main upload so
        // the user flow doesn't wait on them.
        const v = await _imgToWebpAndVariants(file);
        const path = `listings/${currentUser.id}/${Date.now()}_${Math.random().toString(36).slice(2)}.${v.original.ext}`;
        const { data: upData, error: upErr } = await sb.storage.from('card-photos').upload(path, v.original.blob, { upsert: false, contentType: v.original.contentType });
        if (upErr) {
          // If storage bucket doesn't exist, continue without photos
          console.warn('Photo upload failed:', upErr.message);
          break;
        }
        const { data: urlData } = sb.storage.from('card-photos').getPublicUrl(path);
        if (urlData?.publicUrl) photoUrls.push(urlData.publicUrl);
        // Fire-and-forget variant uploads (200/400px WebP siblings).
        _uploadPhotoVariants(path, v.variants);
      }

      if (saveBtn) { saveBtn.textContent = 'Saving...'; }

      const gradeDisplay = condition === 'Graded' ? `${gradingCo} ${gradeNum}` : condition;

      const variantSel = document.getElementById('lcVariant');
      // Variant resolution priority: explicit dropdown > prefill > 'normal'.
      // The dropdown only exists when the listing flow knows about
      // variants for this card; otherwise the prefill value (e.g. the
      // user owns a Reverse Holo in their binder and clicked "List for
      // Sale") wins.
      const lcVariant  = (variantSel && variantSel.value)
                      || (_lcPrefillCatalog && _lcPrefillCatalog.variant)
                      || 'normal';

      // Catalog link — null when the user typed everything by hand or
      // the source didn't carry a catalog id (sealed product, non-TCG).
      // Schema allows NULL; downstream features that need the link
      // (inventory auto-decrement, "view all listings of this card")
      // simply skip rows where it's missing.
      // Quantity — vendor+ may list multiple of the same card on one
      // row. Below vendor tier, the input is hidden and we fall back
      // to 1 (matches historical 1-listing = 1-card behavior). Hard
      // cap at 999 per row to prevent typo'd "list 10000 charizards"
      // events from blowing past the seller's actual stock.
      const _qtyRaw = parseInt(document.getElementById('lcQuantity')?.value, 10);
      const _qty    = Math.min(999, Math.max(1, isFinite(_qtyRaw) ? _qtyRaw : 1));

      const _insertListing = {
        name,
        game_type: game,
        grade: gradeDisplay,
        value: price,
        shipping_price: shipping,
        status: 'active',
        seller_id: currentUser.id,
        seller_name: currentUser.shop_name || currentUser.username || currentUser.name || null,
        is_vendor_listing: true,
        total_slots: 1,
        quantity: _qty,
        photos: photoUrls,
        product_type: productType,
        variant: lcVariant,
        api_card_id: (_lcPrefillCatalog && _lcPrefillCatalog.apiCardId)  || null,
        card_number: (_lcPrefillCatalog && _lcPrefillCatalog.cardNumber) || null,
      };
      let { data, error } = await sb.from('listings').insert(_insertListing).select().single();
      // Schema-error fallback — older envs without the catalog-link
      // migration installed should still be able to list (with the
      // legacy fuzzy-match path). Drops api_card_id + card_number
      // and retries.
      if (error && /api_card_id|card_number|quantity|column|schema cache/i.test((error.message || '') + (error.details || ''))) {
        // Strip every column that might be missing in an env still
        // running pre-sync migrations. Quantity falls back to the
        // implicit 1-row=1-card model.
        const { api_card_id: _a, card_number: _cn, quantity: _q, ..._noLink } = _insertListing;
        const r2 = await sb.from('listings').insert(_noLink).select().single();
        data = r2.data; error = r2.error;
        if (!error) {
          console.log('%c[PathBinder] Run migration_listings_catalog_link.sql + migration_listings_schema_sync.sql to enable the listings catalog link and quantity support.', 'color:#FF9800;font-weight:bold');
        }
      }

      // Step 4 bookkeeping — move N units from on_shelf → listed_online
      // on the matching collection_items row. No-ops cleanly for
      // listings without an api_card_id (sealed / non-TCG) or for
      // sellers who don't have a matching collection row (rare but
      // possible if they listed without first adding to binder).
      if (!error && data && data.api_card_id) {
        try {
          await _invOnListingCreated(currentUser.id, data.api_card_id, data.variant || 'normal', data.quantity || 1);
        } catch (e) {
          console.warn('[inv] post-list bookkeeping failed:', e && e.message);
        }
      }

      // Restore the mode-appropriate label — was hard-coded to 'List Card'
      // before, which silently flipped the button back to card mode after
      // a failed save even when the modal was opened in product/sealed
      // mode.
      var _restoreBtnLabel = isSealed || (lcProductType !== 'single' && lcProductType !== 'tcg_single' && lcProductType !== 'sealed' && lcProductType !== 'tcg_sealed')
        ? 'List Product'
        : 'List Card';
      if (saveBtn) { saveBtn.textContent = _restoreBtnLabel; saveBtn.disabled = false; }
      const lcErr = document.getElementById('lcSaveError');
      if (error) {
        if (lcErr) { lcErr.textContent = '// Error: ' + error.message; lcErr.style.display = 'block'; }
        showToast('Listing error: ' + error.message.slice(0, 80));
        return;
      }
      if (lcErr) lcErr.style.display = 'none';

      if (data) {
        listings.unshift({
          id: data.id, name: data.name, grade: data.grade || '',
          condition: data.condition || 'NM', gradeValue: data.grade_value,
          type: '', gameType: data.game_type || 'Other',
          value: data.value, list_price: data.list_price,
          market_price: data.market_price,
          status: data.status, totalSlots: 1,
          earlyAccessOnly: false, certNumber: '',
          photos: photoUrls, priceHistory: [], sellVotes: [],
          seller_id: data.seller_id, sellerName: currentUser.username || currentUser.name || 'You',
          shipping_price: data.shipping_price || 0,
          product_type: data.product_type || productType
        });
      }
      lcPhotos = [];
      // Reset product type back to single so the next open of the modal
      // (without a prefill) defaults to a normal card listing.
      lcProductType = 'single';
      closeModal('listCardModal');
      showToast(name + ' listed for sale!');
      renderBrowse();
      renderMyListings();
    }

    // ─── Edit Marketplace Listing ──────────────────────────────────────
    // In-memory state for the edit modal. Keyed by listing id; reset on
    // every openEditMarketplaceListing() call.
    let _emlState = {
      listingId:   null,
      existingPhotos: [],   // URLs currently saved on the listing
      newPhotos:      [],   // File objects queued to upload on Save
    };

    function openEditMarketplaceListing(listingId) {
      if (!currentUser) { openModal('loginModal'); return; }
      const l = listings.find(x => String(x.id) === String(listingId));
      if (!l) { showToast('Listing not found'); return; }
      // Permission check — only the owner can edit.
      const ownerId = l.seller_id || l.sellerId;
      if (ownerId !== currentUser.id && !(currentUser && currentUser.is_admin)) {
        showToast('You can only edit your own listings'); return;
      }
      // Sold listings can't be edited — they're locked once a buyer pays.
      if (l.status === 'sold') {
        showToast('Sold listings cannot be edited'); return;
      }

      _emlState.listingId       = listingId;
      _emlState.existingPhotos  = Array.isArray(l.photos) ? l.photos.slice() : [];
      _emlState.newPhotos       = [];

      document.getElementById('emlListingId').value = listingId;
      document.getElementById('emlName').value      = l.name || '';
      document.getElementById('emlGrade').value     = l.grade || '';
      document.getElementById('emlStatus').value    = (l.status === 'sold') ? 'active' : (l.status || 'active');
      document.getElementById('emlPrice').value     = (l.list_price || l.value || 0).toString();
      document.getElementById('emlShipping').value  = (l.shipping_price || 0).toString();

      const titleEl = document.getElementById('emlTitle');
      if (titleEl) titleEl.textContent = 'Edit: ' + (l.name || 'Listing');

      const errEl = document.getElementById('emlSaveError');
      if (errEl) errEl.style.display = 'none';
      const photoErrEl = document.getElementById('emlPhotoError');
      if (photoErrEl) photoErrEl.style.display = 'none';

      renderEditListingPhotos();
      updateEditFeePreview();
      openModal('editMarketplaceListingModal');
    }

    // Renders the existing + queued-new photos with per-photo remove
    // buttons. The newly-queued ones get a small "NEW" pill so the seller
    // can tell which haven't been uploaded yet.
    function renderEditListingPhotos() {
      const grid = document.getElementById('emlPhotoGrid');
      if (!grid) return;
      const existing = _emlState.existingPhotos.map(function(url, idx) {
        return ''
          + '<div style="position:relative;width:78px;height:78px;border:1px solid var(--border);background:var(--surface2)">'
          +   '<img src="' + url + '" style="width:100%;height:100%;object-fit:cover" alt="" / loading="lazy" decoding="async">'
          +   '<button type="button" onclick="removeEditPhoto(\'existing\',' + idx + ')" '
          +     'style="position:absolute;top:-8px;right:-8px;width:22px;height:22px;border-radius:50%;border:1px solid var(--red);background:var(--surface);color:var(--red);font-family:\'Space Mono\',monospace;font-size:.75rem;cursor:pointer;line-height:1">×</button>'
          + '</div>';
      }).join('');
      const queued = _emlState.newPhotos.map(function(file, idx) {
        // Use URL.createObjectURL for the preview — revoked when the
        // modal closes via closeModal hook below.
        const previewUrl = URL.createObjectURL(file);
        return ''
          + '<div style="position:relative;width:78px;height:78px;border:1px dashed var(--accent);background:var(--surface2)">'
          +   '<img src="' + previewUrl + '" style="width:100%;height:100%;object-fit:cover" alt="" / loading="lazy" decoding="async">'
          +   '<div style="position:absolute;bottom:0;left:0;right:0;background:var(--accent);color:var(--text-on-accent);font-family:\'Space Mono\',monospace;font-size:.55rem;letter-spacing:.06em;text-align:center;padding:1px 0">NEW</div>'
          +   '<button type="button" onclick="removeEditPhoto(\'new\',' + idx + ')" '
          +     'style="position:absolute;top:-8px;right:-8px;width:22px;height:22px;border-radius:50%;border:1px solid var(--red);background:var(--surface);color:var(--red);font-family:\'Space Mono\',monospace;font-size:.75rem;cursor:pointer;line-height:1">×</button>'
          + '</div>';
      }).join('');
      grid.innerHTML = existing + queued || '<div style="color:var(--muted);font-size:.74rem">No photos. Buyers can\'t see your listing without at least one.</div>';
    }

    function removeEditPhoto(kind, idx) {
      if (kind === 'existing') _emlState.existingPhotos.splice(idx, 1);
      else if (kind === 'new') _emlState.newPhotos.splice(idx, 1);
      renderEditListingPhotos();
    }

    function handleEditPhotoSelect(evt) {
      const files = Array.from(evt.target.files || []);
      const errEl = document.getElementById('emlPhotoError');
      const MAX_TOTAL = 8;
      const MAX_SIZE  = 5 * 1024 * 1024;
      for (const f of files) {
        const total = _emlState.existingPhotos.length + _emlState.newPhotos.length;
        if (total >= MAX_TOTAL) {
          if (errEl) { errEl.textContent = 'Max ' + MAX_TOTAL + ' photos per listing.'; errEl.style.display = 'block'; }
          break;
        }
        if (f.size > MAX_SIZE) {
          if (errEl) { errEl.textContent = 'Skipped ' + f.name + ' — over 5MB.'; errEl.style.display = 'block'; }
          continue;
        }
        if (!/^image\//.test(f.type)) {
          if (errEl) { errEl.textContent = 'Skipped ' + f.name + ' — not an image.'; errEl.style.display = 'block'; }
          continue;
        }
        _emlState.newPhotos.push(f);
      }
      // Reset the input so re-selecting the same file fires onchange again.
      evt.target.value = '';
      renderEditListingPhotos();
    }

    // Same logic as updateListingFeePreview() on the create flow — kept
    // separate so the two modals can evolve independently without one
    // accidentally repainting the other's box.
    function updateEditFeePreview() {
      const box = document.getElementById('emlFeePreview');
      if (!box) return;
      const rate     = myCommissionRate();
      const ratePct  = (rate * 100).toFixed(0) + '%';
      const tierName = userTier();
      const tierLabel = tierName.charAt(0).toUpperCase() + tierName.slice(1);
      const ask  = parseFloat(document.getElementById('emlPrice').value)    || 0;
      const ship = parseFloat(document.getElementById('emlShipping').value) || 0;
      let payoutLine = '';
      if (ask > 0) {
        const pctFee = ask * rate;
        const payout = (ask - pctFee) + ship;
        payoutLine = ''
          + '<div style="margin-top:6px;color:var(--text)">'
          + 'You receive <strong style="color:var(--green)">$' + payout.toFixed(2) + '</strong> on sale '
          + '<span style="color:var(--muted)">(ask $' + ask.toFixed(2) + ' &minus; ' + ratePct + ' commission $' + pctFee.toFixed(2)
          + (ship > 0 ? ' + shipping $' + ship.toFixed(2) : '') + ')</span>'
          + '</div>';
      }
      box.innerHTML = tierLabel + ' tier fee: <strong style="color:var(--accent)">' + ratePct + '</strong>'
        + ' &middot; deducted from your payout on sale'
        + payoutLine;
    }

    async function saveEditedMarketplaceListing() {
      const btn   = document.getElementById('emlSaveBtn');
      const errEl = document.getElementById('emlSaveError');
      const listingId = document.getElementById('emlListingId').value;
      if (!listingId) return;
      if (!currentUser) { openModal('loginModal'); return; }

      const name     = document.getElementById('emlName').value.trim();
      const grade    = document.getElementById('emlGrade').value.trim();
      const status   = document.getElementById('emlStatus').value;
      const price    = parseFloat(document.getElementById('emlPrice').value);
      const shipping = parseFloat(document.getElementById('emlShipping').value) || 0;

      if (!name)            { _emlError('Name is required'); return; }
      if (!price || price <= 0) { _emlError('Enter a valid price'); return; }
      const totalPhotos = _emlState.existingPhotos.length + _emlState.newPhotos.length;
      if (totalPhotos === 0) { _emlError('Add at least one photo before saving'); return; }

      if (btn) { btn.textContent = 'Uploading…'; btn.disabled = true; }

      // Upload queued new photos (same path/encoding as create flow).
      const newUrls = [];
      try {
        for (const file of _emlState.newPhotos) {
          const v = await _imgToWebpAndVariants(file);
          const path = 'listings/' + currentUser.id + '/' + Date.now() + '_' + Math.random().toString(36).slice(2) + '.' + v.original.ext;
          const { error: upErr } = await sb.storage.from('card-photos').upload(path, v.original.blob, { upsert: false, contentType: v.original.contentType });
          if (upErr) {
            console.warn('Photo upload failed:', upErr.message);
            continue;
          }
          const { data: urlData } = sb.storage.from('card-photos').getPublicUrl(path);
          if (urlData && urlData.publicUrl) newUrls.push(urlData.publicUrl);
          _uploadPhotoVariants(path, v.variants);
        }
      } catch (e) {
        console.error('[edit-listing] photo upload error:', e);
      }

      const finalPhotos = _emlState.existingPhotos.concat(newUrls);

      if (btn) { btn.textContent = 'Saving…'; }

      // Build the patch — RLS on listings already restricts updates to
      // the row owner, so this is safe without an extra ownership filter.
      // We DON'T let edits change product_type / seller_id / sold-state.
      const patch = {
        name:           name,
        grade:          grade || null,
        value:          price,
        shipping_price: shipping,
        status:         (status === 'deactivated' ? 'deactivated' : 'active'),
        photos:         finalPhotos,
      };

      const { data, error } = await sb
        .from('listings')
        .update(patch)
        .eq('id', listingId)
        .eq('seller_id', currentUser.id)   // belt-and-suspenders against RLS misconfig
        .select()
        .single();

      if (btn) { btn.textContent = 'Save Changes'; btn.disabled = false; }
      if (error) {
        _emlError('Save failed: ' + (error.message || 'unknown error'));
        return;
      }

      // Reflect the edit in the local cache so renderMyListings() / browse
      // show the new values immediately without a refetch.
      const idx = listings.findIndex(x => String(x.id) === String(listingId));
      if (idx >= 0 && data) {
        listings[idx] = Object.assign({}, listings[idx], {
          name:           data.name,
          grade:          data.grade || '',
          value:          data.value,
          list_price:     data.list_price != null ? data.list_price : data.value,
          shipping_price: data.shipping_price || 0,
          status:         data.status,
          photos:         data.photos || finalPhotos,
        });
      }

      closeModal('editMarketplaceListingModal');
      showToast('Listing updated');
      if (typeof renderMyListings === 'function') renderMyListings();
      if (typeof renderBrowse === 'function')     renderBrowse();
    }

    function _emlError(msg) {
      const errEl = document.getElementById('emlSaveError');
      if (errEl) { errEl.textContent = msg; errEl.style.display = 'block'; }
    }

    // ─── Marketplace Checkout ──────────────────────────────────────────
    async function buyCard(listingId) {
      if (!currentUser) { showToast('Sign in to purchase'); openModal('loginModal'); return; }
      const listing = listings.find(l => String(l.id) === String(listingId));
      if (!listing) { showToast('Listing not found'); return; }
      if (listing.seller_id === currentUser.id || listing.sellerId === currentUser.id) {
        showToast("You can't buy your own listing"); return;
      }

      document.getElementById('buyCardName').textContent = listing.name;
      document.getElementById('buyCardGrade').textContent = listing.grade || 'Raw';
      const price = listing.list_price || listing.value || 0;
      const shipping = listing.shipping_price || 0;
      document.getElementById('buyCardPrice').textContent = '$' + price.toFixed(2);
      document.getElementById('buyCardShipping').textContent = shipping > 0 ? '$' + shipping.toFixed(2) : 'Free';
      // Total now includes the $0.30 buyer processing fee — same value
      // the Stripe checkout line item charges. Mirrored server-side via
      // BUYER_PROCESSING_FEE_CENTS in marketplace-checkout.js.
      document.getElementById('buyCardTotal').textContent = '$' + (price + shipping + 0.30).toFixed(2);
      document.getElementById('buyCardListingId').value = listingId;
      openModal('buyCardModal');
    }

    async function confirmBuyCard() {
      const listingId = document.getElementById('buyCardListingId').value;
      const listing = listings.find(l => String(l.id) === String(listingId));
      if (!listing) return;
      const price = listing.list_price || listing.value || 0;
      const shipping = listing.shipping_price || 0;
      const total = price + shipping;

      const btn = document.querySelector('#buyCardModal .buy-confirm-btn');
      if (btn) { btn.textContent = 'Redirecting...'; btn.disabled = true; }

      try {
        const { data: { session } } = await sb.auth.getSession();
        const token = session?.access_token;
        const res = await fetch('/api/marketplace-checkout', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
          body: JSON.stringify({
            listingId,
            sellerId: listing.seller_id || listing.sellerId,
            amount: Math.round(total * 100), // cents
            cardName: listing.name,
            successUrl: window.location.origin + window.location.pathname + '?payment=success&type=purchase',
            cancelUrl: window.location.origin + window.location.pathname + '?payment=cancelled',
          })
        });
        const result = await res.json();
        if (result.url) {
          window.location.href = result.url;
        } else {
          showToast('Checkout error: ' + (result.error || 'No URL returned'));
          if (btn) { btn.textContent = 'Proceed to Payment'; btn.disabled = false; }
        }
      } catch(err) {
        showToast('Checkout unavailable — Stripe not yet configured');
        if (btn) { btn.textContent = 'Proceed to Payment'; btn.disabled = false; }
        closeModal('buyCardModal');
      }
    }

    async function loadOrders() {
      if (!currentUser) { orders = []; return; }
      const { data, error } = await sb.from('orders')
        .select('*')
        .or(`buyer_id.eq.${currentUser.id},seller_id.eq.${currentUser.id}`)
        .order('created_at', { ascending: false });
      if (!error && data) orders = data;
    }


    function updateTradeNotification() {
      const pending = tradeOffers.filter(o => o.toUserId === currentUser?.id && o.status === 'pending').length;
      // Update desktop badge
      const badge = document.getElementById('tradeNotification');
      if (pending > 0) {
        badge.textContent = pending;
        badge.style.display = 'flex';
      } else {
        badge.style.display = 'none';
      }
      // Update mobile badge
      const mobileBadge = document.getElementById('mobileTradeNotification');
      if (mobileBadge) {
        if (pending > 0) {
          mobileBadge.textContent = pending;
          mobileBadge.style.display = 'flex';
        } else {
          mobileBadge.style.display = 'none';
        }
      }
    }

    function setMobileNav(page) {
      document.querySelectorAll('.mobile-nav-btn').forEach(b => b.classList.remove('active'));
      const btn = document.getElementById('mobileNav' + page.charAt(0).toUpperCase() + page.slice(1));
      if (btn) btn.classList.add('active');
      // Clear mobile trade badge when account is tapped
      if (page === 'account') {
        const mobileBadge = document.getElementById('mobileTradeNotification');
        if (mobileBadge) mobileBadge.style.display = 'none';
      }
    }

    // ===== VENDOR BULK IMPORT =====
    // Columns match the standard PathBinder vendor upload form
    // Singles sheet — for individual cards (graded or raw). Mirrors
    // the original PathBinder vendor template; old CSVs without
    // Quantity continue to import as qty=1. Game/product_type are
    // implicit (pokemon/single) so the columns stay clean.
    const VENDOR_TEMPLATE_HEADERS = [
      'Card Name',      // required
      'Set Name',
      'Card Number',
      'Condition',      // e.g. Raw, Near Mint, Gem Mint
      'Grade',          // numeric grade if graded, e.g. 10 / 9.5 / 9
      'Certification #',// PSA/BGS/CGC cert number
      'Cost',           // your purchase cost (internal reference, not shown publicly)
      'Price',          // asking price in USD — required
      'Quantity',       // optional — units owned (default 1)
      'Notes'           // optional seller notes visible to buyers
    ];

    // Sealed sheet — for booster boxes / packs / ETBs / tins / theme
    // decks / any non-card-single inventory. No Grade / Cert columns
    // because they don't apply to sealed product. Game + Product Type
    // ARE required here since sealed lives across every TCG and the
    // catalog needs the right enum.
    const VENDOR_TEMPLATE_HEADERS_SEALED = [
      'Product Name',   // required, e.g. "Pokemon TCG: Chaos Rising Booster Pack"
      'Set Name',       // required, e.g. "Mega Evolution: Chaos Rising"
      'Game',           // required — pokemon / mtg / yugioh / onepiece / gundam / dbz
      'Product Type',   // required — booster_pack / booster_box / etb / tin / theme_deck / etc
      'Cost',           // your purchase cost
      'Price',          // asking price in USD
      'Quantity',       // required — units on shelf
      'Notes'           // optional
    ];

    let vendorImportRows = [];

    function openVendorImportModal() {
      vendorImportRows = [];
      document.getElementById('importPreview').style.display = 'none';
      document.getElementById('importError').style.display = 'none';
      document.getElementById('importProgress').style.display = 'none';
      document.getElementById('importSubmitBtn').style.display = 'none';
      const fi = document.getElementById('vendorImportFile');
      if (fi) fi.value = '';
      openModal('vendorImportModal');
    }

    function downloadVendorTemplate() {
      if (typeof XLSX === 'undefined') { _loadXLSX(downloadVendorTemplate); showToast('Loading spreadsheet library…'); return; }
      const wb = XLSX.utils.book_new();

      // ── Sheet 1: Singles ──────────────────────────────────────────
      // Card-shaped inventory. Grade / Cert columns are first-class
      // here because graded cards are the main use case.
      const wsSingles = XLSX.utils.aoa_to_sheet([
        VENDOR_TEMPLATE_HEADERS,
        ['Charizard', 'Base Set', '4',  'Gem Mint', '10', '123456789', '450.00', '869.51', '1', 'Near-perfect centering'],
        ['Pikachu',   'Base Set', '58', 'Raw',      '',   '',          '4.00',   '12.00',  '1', 'Lightly played'],
      ]);
      wsSingles['!cols'] = [22,18,10,14,8,16,10,10,9,32].map(w => ({ wch: w }));
      XLSX.utils.book_append_sheet(wb, wsSingles, 'Singles');

      // ── Sheet 2: Sealed ──────────────────────────────────────────
      // Booster boxes / packs / ETBs / tins / decks. No grade or cert
      // columns since sealed product doesn't get graded. Game and
      // Product Type are required so the catalog has the right enum
      // values without us guessing.
      const wsSealed = XLSX.utils.aoa_to_sheet([
        VENDOR_TEMPLATE_HEADERS_SEALED,
        ['Pokemon TCG: Chaos Rising Booster Pack',         'Mega Evolution: Chaos Rising', 'pokemon', 'booster_pack', '3.00',  '4.99',  '36', 'Pulled from a sealed booster box'],
        ['Pokemon TCG: Chaos Rising Elite Trainer Box',    'Mega Evolution: Chaos Rising', 'pokemon', 'etb',          '45.00', '54.99', '6',  ''],
        ['Pokemon TCG: Scarlet & Violet 151 Booster Box',  'Scarlet & Violet 151',         'pokemon', 'booster_box',  '180.00','249.99','3',  'Sealed cases on hand'],
        ['Magic the Gathering: Foundations Play Booster',  'Foundations',                  'mtg',     'play_booster', '4.50',  '6.99',  '24', ''],
        ['One Piece TCG: Pillars of Strength Booster Box', 'Pillars of Strength',          'onepiece','booster_box',  '90.00', '129.99','2',  ''],
      ]);
      wsSealed['!cols'] = [40,30,10,16,10,10,10,32].map(w => ({ wch: w }));
      XLSX.utils.book_append_sheet(wb, wsSealed, 'Sealed');

      XLSX.writeFile(wb, 'PathBinder_Vendor_Template.xlsx');
    }

    function handleVendorImportFile(file) {
      if (!file) return;
      const errEl  = document.getElementById('importError');
      const prevEl = document.getElementById('importPreview');
      const infoEl = document.getElementById('importPreviewInfo');
      const tblEl  = document.getElementById('importPreviewTable');
      const subBtn = document.getElementById('importSubmitBtn');
      errEl.style.display = 'none';

      if (typeof XLSX === 'undefined') {
        _loadXLSX(() => handleVendorImportFile(file));
        errEl.textContent = 'Loading spreadsheet library, please wait…';
        errEl.style.display = 'block'; return;
      }

      const reader = new FileReader();
      reader.onload = e => {
        try {
          const wb   = XLSX.read(e.target.result, { type: 'array' });

          // Pull both sheets if present. "Singles" / "Sealed" are
          // the canonical names from the template; we also recognize
          // the legacy single-sheet "Inventory" name so vendors with
          // old downloaded templates don't break. Sheets are tagged
          // with `_sourceSheet` so the import loop knows which
          // column map applies.
          const allRows = [];
          const seenSheet = new Set();
          function _pullSheet(name, kind) {
            if (!name || seenSheet.has(name)) return;
            const ws = wb.Sheets[name];
            if (!ws) return;
            seenSheet.add(name);
            const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
            rows.forEach(r => { r._sourceSheet = kind; });
            Array.prototype.push.apply(allRows, rows);
          }
          // Canonical names
          _pullSheet('Singles', 'singles');
          _pullSheet('Sealed',  'sealed');
          // Legacy single-sheet template
          if (allRows.length === 0) _pullSheet('Inventory', 'singles');
          // Last-resort: first sheet, treat as singles (covers
          // vendors who hand-rolled a CSV with their own sheet name)
          if (allRows.length === 0 && wb.SheetNames[0]) {
            _pullSheet(wb.SheetNames[0], 'singles');
          }

          if (!allRows.length) {
            errEl.textContent = 'No data rows found in the file.';
            errEl.style.display = 'block'; return;
          }

          // Validate required columns per sheet. Singles needs Card
          // Name + Price; Sealed needs Product Name + Game + Product
          // Type + Quantity + Price.
          const SINGLES_REQUIRED = ['Card Name', 'Price'];
          const SEALED_REQUIRED  = ['Product Name', 'Game', 'Product Type', 'Quantity', 'Price'];
          for (const r of allRows) {
            const req = r._sourceSheet === 'sealed' ? SEALED_REQUIRED : SINGLES_REQUIRED;
            const firstMissing = req.find(h => !(h in r));
            if (firstMissing) {
              errEl.textContent = `Missing required columns on the ${r._sourceSheet === 'sealed' ? 'Sealed' : 'Singles'} sheet: ${firstMissing}. Make sure you're using the latest PathBinder vendor template.`;
              errEl.style.display = 'block'; return;
            }
          }

          // Filter empty rows per sheet. Singles needs Card Name +
          // Price; Sealed needs Product Name + Price.
          vendorImportRows = allRows.filter(r => {
            if (r._sourceSheet === 'sealed') {
              return r['Product Name'] && r['Price'];
            }
            return r['Card Name'] && r['Price'];
          });

          // Preview table — unified columns that work for both sheets
          // by falling back per row. "Product/Card" picks whichever
          // name column is populated, "Format/Grade" same idea.
          const singlesCount = vendorImportRows.filter(r => r._sourceSheet !== 'sealed').length;
          const sealedCount  = vendorImportRows.filter(r => r._sourceSheet === 'sealed').length;
          const summaryBits = [];
          if (singlesCount) summaryBits.push(`${singlesCount} single${singlesCount !== 1 ? 's' : ''}`);
          if (sealedCount)  summaryBits.push(`${sealedCount} sealed`);
          infoEl.textContent = `// ${summaryBits.join(' · ')} ready to import`;
          const previewCols = ['Name','Set','Format / Grade','Qty','Price'];
          function _cellFor(r, col) {
            const isSealed = r._sourceSheet === 'sealed';
            switch (col) {
              case 'Name':           return r[isSealed ? 'Product Name' : 'Card Name'] || '—';
              case 'Set':            return r['Set Name'] || '—';
              case 'Format / Grade': return isSealed ? (r['Product Type'] || '—') : (r['Grade'] || r['Condition'] || '—');
              case 'Qty':            return r['Quantity'] || '1';
              case 'Price':          return r['Price'] || '—';
            }
            return '—';
          }
          tblEl.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:.75rem">
            <thead><tr style="border-bottom:1px solid var(--border)">${
              previewCols.map(h => `<th style="text-align:left;padding:4px 6px;color:var(--muted)">${h}</th>`).join('')
            }</tr></thead>
            <tbody>${vendorImportRows.slice(0,10).map(r => `<tr style="border-bottom:1px solid rgba(255,255,255,.05)">${
              previewCols.map(h => `<td style="padding:4px 6px;color:var(--text)">${_cellFor(r, h)}</td>`).join('')
            }</tr>`).join('')}
            ${vendorImportRows.length > 10 ? `<tr><td colspan="${previewCols.length}" style="padding:6px;color:var(--muted)">… and ${vendorImportRows.length - 10} more</td></tr>` : ''}
            </tbody></table>`;

          prevEl.style.display = 'block';
          subBtn.style.display = 'block';
        } catch(err) {
          errEl.textContent = 'Could not parse file: ' + err.message;
          errEl.style.display = 'block';
        }
      };
      reader.readAsArrayBuffer(file);
    }

    async function submitVendorImport() {
      if (!vendorImportRows.length || !currentUser) return;
      const btn      = document.getElementById('importSubmitBtn');
      const progEl   = document.getElementById('importProgress');
      const errEl    = document.getElementById('importError');
      btn.disabled   = true;
      btn.textContent = 'Importing…';
      progEl.style.display = 'block';
      errEl.style.display  = 'none';

      let success = 0, failed = 0;
      const insertedIds = [];

      const isVendorPlus = (typeof tierAtLeast === 'function') && tierAtLeast('vendor');
      const VALID_GAMES = new Set(['pokemon','mtg','yugioh','onepiece','gundam','dbz']);
      // Known product_type enum values from sync_sealed_products.py
      // SEALED_PATTERNS. Anything not in this set falls back to
      // 'single' so we never write garbage into the column.
      const VALID_PRODUCT_TYPES = new Set([
        'single','tcg_single',
        'booster_pack','booster_box','booster_bundle','set_booster','draft_booster',
        'collector_booster','jumpstart_booster','play_booster','commander_deck',
        'planeswalker_deck','secret_lair','etb','utb','premium_collection',
        'starter_deck','theme_deck','structure_deck','battle_deck','build_and_battle',
        'tin','tin_mini','bundle','gift_bundle','deck','toolkit','binder_collection',
        'funko_pop','manga','poster','plush','statue',
      ]);

      for (let i = 0; i < vendorImportRows.length; i++) {
        const r = vendorImportRows[i];
        progEl.textContent = `// Importing ${i + 1} / ${vendorImportRows.length}…`;

        const sheet = r._sourceSheet === 'sealed' ? 'sealed' : 'singles';
        const cardName = String((sheet === 'sealed' ? r['Product Name'] : r['Card Name']) || '').trim();
        const setName  = String(r['Set Name'] || '').trim();
        const notes    = String(r['Notes']    || '').trim();

        // Normalize card number: Excel often stores integers as floats (e.g. 101.0 → "101")
        let cardNumber = String(r['Card Number'] || '').trim();
        if (/^\d+\.0$/.test(cardNumber)) cardNumber = cardNumber.slice(0, -2);

        // Cert number: same float issue
        let certNum = String(r['Certification #'] || '').trim();
        if (/^\d+\.0$/.test(certNum)) certNum = certNum.slice(0, -2);

        const cost  = parseFloat(r['Cost'])  || 0;
        const price = parseFloat(r['Price']) || 0;

        // Quantity — defaults to 1, clamped 1-9999. Sealed sheet
        // requires it explicitly (validated above), Singles inherits
        // the default for backward compat.
        let qty = parseInt(String(r['Quantity'] || '1'), 10);
        if (!Number.isFinite(qty) || qty < 1) qty = 1;
        if (qty > 9999) qty = 9999;

        // Game type — sealed sheet requires it; singles defaults to
        // pokemon since the singles template doesn't have a Game
        // column at all.
        const gameRaw = String(r['Game'] || (sheet === 'sealed' ? '' : 'pokemon'))
          .trim().toLowerCase().replace(/\s+/g, '');
        const gameType = VALID_GAMES.has(gameRaw) ? gameRaw : 'pokemon';

        // Product type — sealed sheet uses the Product Type column;
        // singles sheet always means 'single' (no column at all).
        const productRaw = sheet === 'sealed'
          ? String(r['Product Type'] || '').trim().toLowerCase().replace(/[\s-]+/g, '_')
          : 'single';
        const productType = VALID_PRODUCT_TYPES.has(productRaw) ? productRaw : 'single';
        const isSealed = productType !== 'single' && productType !== 'tcg_single';

        // Grading only applies on the Singles sheet — sealed sheet
        // skips grade/cert entirely so no column reads needed.
        const gradeRaw = sheet === 'singles' ? String(r['Grade'] || '').trim() : '';
        const gradeNum = gradeRaw !== '' ? parseFloat(gradeRaw) : null;
        const isGraded = gradeNum !== null && !isNaN(gradeNum);
        // Sealed sheet → condition='sealed' implicitly.
        // Singles sheet → respect Condition column, default 'raw'.
        const condRaw = sheet === 'singles' ? String(r['Condition'] || '').trim() : '';
        const condition = sheet === 'sealed' ? 'sealed'
                        : isGraded ? 'graded'
                        : condRaw  ? condRaw.toLowerCase()
                        :            'raw';
        const gradeVal = isGraded ? gradeNum : null;

        const _insertPayload = {
          user_id:        currentUser.id,
          card_name:      cardName,
          set_name:       setName    || null,
          card_number:    cardNumber || null,
          game_type:      gameType,
          product_type:   productType,
          condition,
          grade_value:    gradeVal,
          cert_number:    certNum    || null,
          purchase_price: cost       || null,
          current_value:  price      || null,
          quantity:       qty,
          on_shelf_qty:   isVendorPlus ? qty : undefined,
          notes:          notes      || null,
          is_ghost:       false,
          sold_offline:   false,
        };
        let { data: newRow, error } = await sb.from('collection_items')
          .insert(_insertPayload).select('id').single();
        // Schema-fallback cascade for older DBs: drop on_shelf_qty,
        // then product_type, before giving up. Same pattern as
        // quickAddScannedCard so behavior stays consistent.
        if (error && /on_shelf_qty/i.test(error.message || '')) {
          const { on_shelf_qty: _osq, ..._noShelf } = _insertPayload;
          const r1 = await sb.from('collection_items').insert(_noShelf).select('id').single();
          error = r1.error; newRow = r1.data;
        }
        if (error && /product_type/i.test(error.message || '')) {
          const { product_type: _pt, on_shelf_qty: _osq2, ..._noPt } = _insertPayload;
          const r2 = await sb.from('collection_items').insert(_noPt).select('id').single();
          error = r2.error; newRow = r2.data;
        }

        if (error) { console.error('Import row error:', error.message); failed++; }
        else { success++; if (newRow?.id) insertedIds.push(newRow.id); }
      }

      progEl.textContent = `// Done — ${success} card${success !== 1 ? 's' : ''} added. Matching images…`;
      btn.textContent = 'Import →';
      btn.disabled = false;
      vendorImportRows = [];
      document.getElementById('importSubmitBtn').style.display = 'none';
      showToast(`✓ ${success} card${success !== 1 ? 's' : ''} added — matching images in background`);
      closeModal('vendorImportModal');

      // Show cards immediately (no images yet), then enrich in background
      await loadCollection();
      renderBinder();
      renderDashboard();

      // Background enrichment: match each card against Pokémon TCG API
      if (insertedIds.length) enrichImportedCards(insertedIds);
    }

    // ── Card version picker — shown when multiple different sets are found ─────
    // Returns a Promise<card|null>. null means the user chose to skip this card.
    function _pickCardVersion(candidates, itemName, remaining) {
      return new Promise(resolve => {
        const overlay = document.createElement('div');
        overlay.style.cssText = `
          position:fixed;inset:0;background:rgba(0,5,0,.92);z-index:10100;
          display:flex;align-items:center;justify-content:center;padding:16px;
        `;

        const box = document.createElement('div');
        box.style.cssText = `
          background:var(--surface);border:1px solid var(--border);
          border-radius:0;padding:22px;width:100%;max-width:520px;
          max-height:88vh;overflow-y:auto;
          box-shadow:3px 3px 0 var(--shadow);
          font-family:'Space Mono','Share Tech Mono',monospace;
        `;

        const queueNote = remaining > 1
          ? `<span style="color:var(--muted);font-size:.72rem"> — ${remaining - 1} card${remaining - 1 !== 1 ? 's' : ''} queued after this</span>`
          : '';

        box.innerHTML = `
          <div style="font-size:.72rem;color:var(--teal);letter-spacing:.08em;margin-bottom:6px">// MULTIPLE VERSIONS FOUND</div>
          <div style="font-size:.95rem;font-weight:700;color:var(--text);margin-bottom:4px">${itemName}${queueNote}</div>
          <div style="font-size:.75rem;color:var(--muted);margin-bottom:16px">Choose the correct version, or skip to leave unmatched.</div>
          <div id="_pickerGrid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:10px;margin-bottom:16px"></div>
          <button id="_pickerSkip" style="width:100%;padding:10px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.8rem;cursor:pointer">Skip →</button>
        `;

        overlay.appendChild(box);
        document.body.appendChild(overlay);

        function pick(card) {
          document.body.removeChild(overlay);
          resolve(card);
        }

        // Build card tiles
        const grid = box.querySelector('#_pickerGrid');
        for (const c of candidates) {
          const tile = document.createElement('div');
          tile.style.cssText = `
            border:1px solid var(--border);border-radius:6px;overflow:hidden;
            cursor:pointer;transition:border-color .15s,transform .12s;
            background:var(--surface2);
          `;
          tile.onmouseenter = () => { tile.style.borderColor = 'var(--accent)'; tile.style.transform = 'scale(1.03)'; };
          tile.onmouseleave = () => { tile.style.borderColor = 'var(--border)';  tile.style.transform = ''; };
          tile.onclick = () => pick(c);

          const img = c.images?.small
            ? `<img src="${c.images.small}" style="width:100%;aspect-ratio:245/342;object-fit:contain;display:block;background:#111" loading="lazy" decoding="async">`
            : `<div style="width:100%;aspect-ratio:245/342;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:1.4rem">?</div>`;

          tile.innerHTML = `
            ${img}
            <div style="padding:5px 6px">
              <div style="font-size:.65rem;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${c.set?.name || '—'}</div>
              <div style="font-size:.6rem;color:var(--muted)">#${c.number}</div>
            </div>
          `;
          grid.appendChild(tile);
        }

        box.querySelector('#_pickerSkip').onclick = () => pick(null);

        // Close on backdrop click
        overlay.addEventListener('click', e => { if (e.target === overlay) pick(null); });
      });
    }

    // ── Levenshtein distance for fuzzy card name matching ─────────────────────
    function _levenshtein(a, b) {
      a = a.toLowerCase(); b = b.toLowerCase();
      const m = a.length, n = b.length;
      const dp = Array.from({ length: m + 1 }, (_, i) =>
        Array.from({ length: n + 1 }, (_, j) => (j === 0 ? i : 0)));
      for (let j = 1; j <= n; j++) dp[0][j] = j;
      for (let i = 1; i <= m; i++)
        for (let j = 1; j <= n; j++)
          dp[i][j] = a[i-1] === b[j-1]
            ? dp[i-1][j-1]
            : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
      return dp[m][n];
    }

    // ── Match imported cards against Pokémon TCG API to fill in images / IDs ─
    function _enrichBanner(msg) {
      let el = document.getElementById('enrichBanner');
      if (!msg) { if (el) el.remove(); return; }
      if (!el) {
        el = document.createElement('div');
        el.id = 'enrichBanner';
        Object.assign(el.style, {
          position:'fixed', bottom:'72px', left:'50%', transform:'translateX(-50%)',
          background:'var(--surface2)', border:'1px solid var(--border)',
          color:'var(--muted)', fontFamily:"'Share Tech Mono',monospace",
          fontSize:'.78rem', padding:'7px 18px', borderRadius:'6px',
          zIndex:'9000', pointerEvents:'none', whiteSpace:'nowrap',
          boxShadow:'0 4px 20px rgba(0,0,0,0.4)',
        });
        document.body.appendChild(el);
      }
      el.textContent = msg;
    }

    async function enrichImportedCards(itemIds) {
      const items = collectionItems.filter(c => itemIds.includes(c.id));
      if (!items.length) return;
      console.log(`[PathBinder] Enriching ${items.length} imported card(s)…`);

      let matched = 0;
      for (let idx = 0; idx < items.length; idx++) {
        const item = items[idx];
        _enrichBanner(`// Matching images… ${idx + 1} / ${items.length}`);
        try {
          // Normalize card number — Excel stores integers as floats (101.0 → "101")
          const num = item.card_number
            ? String(item.card_number).replace(/\.0$/, '').trim()
            : null;

          // Build progressively looser queries until we get a hit
          // set.name must be quoted when it contains spaces (Lucene stops at whitespace otherwise)
          const setQ = item.set_name ? `set.name:"${item.set_name}"` : null;
          const queries = [];
          if (num && setQ) queries.push(`name:"${item.card_name}" number:${num} ${setQ}`);
          if (num)         queries.push(`name:"${item.card_name}" number:${num}`);
          if (setQ)        queries.push(`name:"${item.card_name}" ${setQ}`);
                           queries.push(`name:"${item.card_name}"`);

          let card = null;
          for (const q of queries) {
            try {
              const res  = await fetch(`https://api.pokemontcg.io/v2/cards?q=${encodeURIComponent(q)}&pageSize=8`);
              const data = await res.json();
              if (data?.data?.length) {
                // 1. Filter to exact card number match if we have one
                let candidates = data.data;
                if (num) {
                  const byNum = candidates.filter(c => String(c.number) === num);
                  if (byNum.length) candidates = byNum;
                }

                // 2. Check if candidates span multiple distinct sets
                const distinctSets = [...new Set(candidates.map(c => c.set?.id).filter(Boolean))];

                if (candidates.length === 1 || distinctSets.length <= 1) {
                  // Only one real option — auto-pick
                  card = candidates[0];
                } else {
                  // Multiple versions from different sets — let the user choose
                  _enrichBanner(null); // hide progress banner while picker is open
                  card = await _pickCardVersion(
                    candidates,
                    item.card_name,
                    items.length - idx  // how many cards remain including this one
                  );
                  // null means user skipped; card stays null → continue loop
                }
                break;
              }
            } catch (_) {}
            await new Promise(r => setTimeout(r, 200));
          }

          // ── Fuzzy fallback: prefix wildcard + Levenshtein pick ──────────────
          // Catches typos like "feraligatir" → finds "Feraligatr" (distance 1)
          if (!card && item.card_name.length >= 3) {
            try {
              // Use first ~55% of name chars as prefix (min 4, capped at full length)
              const prefixLen = Math.min(item.card_name.length, Math.max(4, Math.floor(item.card_name.length * 0.55)));
              const prefix = item.card_name.slice(0, prefixLen).replace(/[^a-zA-Z0-9]/g, '');
              const fuzzyQ = num
                ? `name:${prefix}* number:${num}`
                : `name:${prefix}*`;
              const res  = await fetch(`https://api.pokemontcg.io/v2/cards?q=${encodeURIComponent(fuzzyQ)}&pageSize=20`);
              const data = await res.json();
              if (data?.data?.length) {
                // Pick candidate with smallest Levenshtein distance to entered name
                let best = null, bestDist = Infinity;
                for (const c of data.data) {
                  const dist = _levenshtein(item.card_name, c.name);
                  if (dist < bestDist) { bestDist = dist; best = c; }
                }
                // Accept only if close enough: within 40% of name length (min tolerance 3)
                const threshold = Math.max(3, Math.floor(item.card_name.length * 0.4));
                if (best && bestDist <= threshold) {
                  card = best;
                  console.log(`[enrich] fuzzy match: "${item.card_name}" → "${card.name}" (dist ${bestDist})`);
                }
              }
            } catch (_) {}
          }

          if (!card) {
            console.log(`[enrich] no match: ${item.card_name} #${num}`);
            continue;
          }

          console.log(`[enrich] matched ${item.card_name} → ${card.id}`);

          const imageUrl     = card.images?.small  || null;
          const apiCardId    = card.id             || null;
          const setCode      = card.set?.id        || null;
          const setNameFound = card.set?.name      || item.set_name || null;
          const tcgplayerUrl = card.tcgplayer?.url || null;

          // Pull price source URL from card_price_urls if we don't have one
          let priceSourceUrl = item.price_source_url || null;
          if (!priceSourceUrl && apiCardId) {
            const { data: urlRow } = await sb
              .from('card_price_urls')
              .select('price_source_url')
              .eq('api_card_id', apiCardId)
              .maybeSingle();
            priceSourceUrl = urlRow?.price_source_url || null;
          }

          const patch = {
            card_image_url:   imageUrl,
            api_card_id:      apiCardId,
            set_code:         setCode,
            set_name:         setNameFound,
            card_number:      num || item.card_number,  // store clean number
            price_source_url: priceSourceUrl,
          };
          // Note: tcgplayer_url intentionally excluded — not in collection_items schema

          const { error } = await sb.from('collection_items').update(patch).eq('id', item.id);
          if (error) {
            console.error(`[enrich] DB update failed for ${item.card_name}:`, error.message);
          } else {
            Object.assign(item, patch);
            matched++;
          }

          // Re-render binder after each card so images appear as they come in
          renderBinder();
        } catch (err) {
          console.warn(`[enrich] ${item.card_name}:`, err.message);
        }

        await new Promise(r => setTimeout(r, 350));
      }

      _enrichBanner(null);  // hide banner
      renderDashboard();
      if (matched > 0) showToast(`✓ Matched images for ${matched} card${matched !== 1 ? 's' : ''} — fetching prices…`);
      console.log(`[PathBinder] Enrichment complete — ${matched}/${items.length} matched.`);

      // ── Price refresh for newly imported cards ──────────────────────────────
      // Now that enrichment has filled in price_source_url, look up market prices
      const toPrice = items.filter(c => c.price_source_url && !c.sold_offline && !c.is_ghost);
      if (!toPrice.length) return;

      const todayStr = new Date().toISOString().slice(0, 10);
      let priced = 0;
      for (let i = 0; i < toPrice.length; i++) {
        const item = toPrice[i];
        _enrichBanner(`// Fetching prices… ${i + 1} / ${toPrice.length}`);
        try {
          const condition = _priceCondition(item);
          const res  = await fetch('/api/lookup-price', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: item.card_name, condition, url: item.price_source_url })
          });
          const data = await res.json();
          if (data.price) {
            const { error } = await sb.from('collection_items')
              .update({ current_value: data.price }).eq('id', item.id);
            if (!error) {
              const old = item.current_value;
              item.current_value = data.price;
              priced++;
              if (old !== data.price) {
                sb.from('price_history').upsert({
                  collection_item_id: item.id, user_id: currentUser.id,
                  recorded_value: data.price, recorded_at: todayStr
                }, { onConflict: 'collection_item_id,recorded_at' }).catch(() => {});
              }
            }
          }
        } catch (_) {}
        await new Promise(r => setTimeout(r, 650));
      }

      _enrichBanner(null);
      if (priced > 0) {
        renderBinder();
        renderDashboard();
        showToast(`✓ Prices updated for ${priced} card${priced !== 1 ? 's' : ''}`);
      }
    }

    // ===== ADMIN PAGE =====
    // ── Vendor Application Functions ─────────────────────────────────────────

    async function openVendorApplicationModal() {
      if (!currentUser) { showToast('Sign in first'); return; }
      // Check if already applied
      const { data } = await sb.from('vendor_applications').select('status').eq('user_id', currentUser.id).maybeSingle();
      const statusEl = document.getElementById('vendorAppStatus');
      if (data) {
        statusEl.style.display = 'block';
        if (data.status === 'pending') {
          statusEl.style.background = 'var(--accent)'; statusEl.style.color = 'var(--accent)';
          statusEl.textContent = '⏳ Your application is pending review. We\'ll be in touch soon.';
        } else if (data.status === 'approved') {
          statusEl.style.background = 'rgba(210,120,40,.1)'; statusEl.style.color = 'var(--green)';
          statusEl.textContent = '✓ Your application was approved! Refresh the page to start listing.';
        } else if (data.status === 'rejected') {
          statusEl.style.background = 'rgba(255,60,60,.1)'; statusEl.style.color = 'var(--red)';
          statusEl.textContent = 'Your previous application was not approved. You may reapply below.';
        }
      } else {
        statusEl.style.display = 'none';
      }
      openModal('vendorApplicationModal');
    }

    async function saveVendorApplication() {
      const shopName    = document.getElementById('vaShopName').value.trim();
      const description = document.getElementById('vaDescription').value.trim();
      const location    = document.getElementById('vaLocation').value.trim();
      const instagram   = document.getElementById('vaInstagram').value.trim();
      const website     = document.getElementById('vaWebsite').value.trim();
      if (!shopName)    { showToast('Please enter your shop name'); return; }
      if (!description) { showToast('Please describe your shop'); return; }
      const btn = document.querySelector('#vendorApplicationModal button[onclick="saveVendorApplication()"]');
      if (btn) { btn.textContent = 'Submitting...'; btn.disabled = true; }
      const { error } = await sb.from('vendor_applications').upsert({
        user_id: currentUser.id, shop_name: shopName, shop_description: description,
        shop_location: location, instagram, shop_website: website, status: 'pending',
        submitted_at: new Date().toISOString()
      }, { onConflict: 'user_id' });
      if (btn) { btn.textContent = 'Submit Application'; btn.disabled = false; }
      if (error) { showToast('Error: ' + error.message); return; }
      showToast('Application submitted! We\'ll review it within 2–3 business days.');
      closeModal('vendorApplicationModal');
    }

    // Admin: load and render vendor applications
    let vendorApplications = [];
    async function loadVendorApplications() {
      if (!currentUser?.is_admin) return;
      // Fetch applications first (no join — avoids 400 if FK not in schema cache)
      const { data: apps } = await sb.from('vendor_applications').select('*').order('submitted_at', { ascending: false });
      if (!apps || !apps.length) { vendorApplications = []; return; }
      // Then fetch matching profiles separately and merge in
      const userIds = [...new Set(apps.map(a => a.user_id).filter(Boolean))];
      let profileMap = {};
      if (userIds.length) {
        const { data: profs } = await sb.from('profiles').select('id, email, username').in('id', userIds);
        if (profs) profs.forEach(p => { profileMap[p.id] = p; });
      }
      vendorApplications = apps.map(a => ({ ...a, profiles: profileMap[a.user_id] || null }));
    }

    async function approveVendorApplication(userId, appId) {
      await sb.from('profiles').update({ is_vendor: true }).eq('id', userId);
      await sb.from('vendor_applications').update({ status: 'approved', reviewed_at: new Date().toISOString() }).eq('id', appId);
      vendorApplications = vendorApplications.map(a => a.id === appId ? { ...a, status: 'approved' } : a);
      renderAdminVendorApplications();
      showToast('Vendor approved ✓');
    }

    async function rejectVendorApplication(appId) {
      const notes = prompt('Optional: reason for rejection (shown to admin only)');
      await sb.from('vendor_applications').update({ status: 'rejected', reviewed_at: new Date().toISOString(), reviewer_notes: notes || null }).eq('id', appId);
      vendorApplications = vendorApplications.map(a => a.id === appId ? { ...a, status: 'rejected' } : a);
      renderAdminVendorApplications();
      showToast('Application rejected');
    }

    function renderAdminVendorApplications() {
      const el = document.getElementById('vendorApplicationsPanel');
      if (!el) return;
      if (!vendorApplications.length) { el.innerHTML = '<div style="color:var(--muted);font-size:.8rem;padding:12px 0">No applications yet.</div>'; return; }
      el.innerHTML = vendorApplications.map(a => {
        const statusColor = { pending: 'var(--accent)', approved: 'var(--green)', rejected: 'var(--red)' }[a.status] || 'var(--muted)';
        return `<div style="border:1px solid var(--border);border-radius:8px;padding:14px;margin-bottom:12px">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap">
            <div>
              <div style="font-size:.9rem;color:var(--text);font-weight:700">${a.shop_name}</div>
              <div style="font-size:.72rem;color:var(--muted);margin-top:2px">${a.profiles?.email || a.user_id} · ${new Date(a.submitted_at).toLocaleDateString()}</div>
              ${a.shop_location ? `<div style="font-size:.72rem;color:var(--muted)">${a.shop_location}</div>` : ''}
              ${a.instagram ? `<div style="font-size:.72rem;color:var(--teal)">@${a.instagram.replace('@','')}</div>` : ''}
              ${a.shop_website ? `<div style="font-size:.72rem"><a href="${a.shop_website}" target="_blank" style="color:var(--accent);text-decoration:none">↗ ${a.shop_website}</a></div>` : ''}
              <div style="font-size:.78rem;color:var(--muted);margin-top:8px;max-width:400px">${a.shop_description || ''}</div>
            </div>
            <div style="display:flex;flex-direction:column;align-items:flex-end;gap:8px">
              <span style="font-size:.7rem;color:${statusColor};letter-spacing:.06em;text-transform:uppercase">${a.status}</span>
              ${a.status === 'pending' ? `
                <button onclick="approveVendorApplication('${a.user_id}','${a.id}')" style="padding:6px 14px;background:rgba(210,120,40,.12);border:1px solid var(--green);color:var(--green);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;cursor:pointer">✓ Approve</button>
                <button onclick="rejectVendorApplication('${a.id}')" style="padding:6px 14px;background:transparent;border:1px solid var(--red);color:var(--red);font-family:'Space Mono','Share Tech Mono',monospace;font-size:.72rem;cursor:pointer">✗ Reject</button>
              ` : ''}
            </div>
          </div>
        </div>`;
      }).join('');
    }

    function renderAdmin() {
      renderAdminTable();
      updateRevenuePanel();
      loadVendorApplications().then(renderAdminVendorApplications);
      loadAdminClearCollectionUsers();
      renderAdminBetaTesters();
      renderAdminImageReviewQueue();
      // Auto-loads the pending catalog photo contributions panel.
      // No-op when the migration isn't applied (renders a hint).
      if (typeof renderAdminContributionQueue === 'function') {
        renderAdminContributionQueue();
      }
      // Admin moderation panels — disputes, user search, suspended listings.
      loadAdminDisputes();
      loadSuspendedListings();
      // Deep-link handler: emails / notifications use ?admin=disputes&order=xxx.
      maybeFocusAdminDispute();
    }

    // ─── Admin: Disputes panel ─────────────────────────────────────────
    // Pulls every order currently in 'disputed' status and renders an
    // action card per row. Two paths from here:
    //   - Refund Buyer    → /api/refund-order (admin path, Connect-aware)
    //   - Resolve for Seller → admin_resolve_dispute_for_seller RPC
    let _adminDisputeCache = [];

    // Manually fires the /api/admin-notify-dispute endpoint for the most
    // recent disputed order so the admin can verify Resend is wired up
    // without waiting for a real seller to decline a return. Useful right
    // after configuring RESEND_API_KEY / RESEND_FROM / ADMIN_EMAIL_RECIPIENTS
    // in Vercel — confirms the email fires end-to-end. The in-app
    // notification side fires automatically via the Postgres trigger
    // whenever an order's status flips to 'disputed'; this button only
    // tests the email channel which is client-driven.
    async function sendAdminTestEmail() {
      if (!userIsAdmin()) { showToast('Admins only'); return; }
      try {
        // Test mode — POSTs { test: true } to the endpoint which
        // bypasses the disputed-order DB lookup and fires a synthetic
        // "wiring check" email to ADMIN_EMAIL_RECIPIENTS. Useful for
        // verifying Resend env vars without polluting the DB.
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) { showToast('Sign in again'); return; }

        showToast('Firing admin-notify-dispute test…');
        const r = await fetch('/api/admin-notify-dispute', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
          body:    JSON.stringify({ test: true }),
        });
        const result = await r.json();
        if (!r.ok) {
          showToast('Endpoint error: ' + (result.error || r.status));
          console.error('[test-email] error response:', result);
          return;
        }
        // Distinguish the two soft-failure modes:
        //   emailed=0 with skipped='resend_not_configured' → env vars missing
        //   emailed=0 with skipped='no_admin_emails' → recipient list is empty
        //   emailed=N → success, email actually sent
        if (result.emailed > 0) {
          showToast('Email sent to ' + result.emailed + ' admin(s). Check inboxes.');
        } else if (result.skipped === 'resend_not_configured') {
          showToast('Resend not configured — set RESEND_API_KEY + RESEND_FROM in Vercel.');
        } else if (result.skipped === 'no_admin_emails') {
          showToast('No admin recipients found. Set ADMIN_EMAIL_RECIPIENTS in Vercel.');
        } else {
          showToast('Endpoint returned: emailed=' + result.emailed + ' skipped=' + result.skipped);
        }
        console.log('[test-email] response:', result);
      } catch (e) {
        console.error('[test-email] threw:', e);
        showToast('Test email failed: ' + (e.message || ''));
      }
    }

    async function loadAdminDisputes() {
      const host = document.getElementById('adminDisputesList');
      if (!host) return;
      if (!userIsAdmin()) { host.innerHTML = '<div style="color:var(--muted);font-size:.8rem">Admins only.</div>'; return; }
      host.innerHTML = '<div style="color:var(--muted);font-size:.8rem">Loading…</div>';
      try {
        const { data, error } = await sb
          .from('orders')
          .select('id, status, amount, created_at, buyer_id, seller_id, listing_id, return_reason, return_reason_detail, return_requested_at, disputed_at, stripe_payment_intent, payment_route')
          .eq('status', 'disputed')
          .order('disputed_at', { ascending: false })
          .limit(100);
        if (error) throw error;
        _adminDisputeCache = data || [];
        // Hydrate buyer/seller names + listing names in parallel.
        const userIds = Array.from(new Set([].concat(
          _adminDisputeCache.map(d => d.buyer_id),
          _adminDisputeCache.map(d => d.seller_id),
        ).filter(Boolean)));
        const listingIds = Array.from(new Set(_adminDisputeCache.map(d => d.listing_id).filter(Boolean)));
        const [{ data: profs }, { data: lsts }] = await Promise.all([
          userIds.length    ? sb.from('profiles').select('id, name, username, email').in('id', userIds)         : Promise.resolve({ data: [] }),
          listingIds.length ? sb.from('listings').select('id, name, photos').in('id', listingIds)               : Promise.resolve({ data: [] }),
        ]);
        const pm = {}; (profs || []).forEach(p => pm[p.id] = p);
        const lm = {}; (lsts  || []).forEach(l => lm[l.id] = l);
        renderAdminDisputesList(pm, lm);
      } catch (e) {
        console.error('[admin-disputes] load failed:', e);
        host.innerHTML = '<div style="color:var(--red);font-size:.78rem">Failed to load disputes: ' + (e.message || e) + '</div>';
      }
    }

    function renderAdminDisputesList(profileMap, listingMap) {
      const host  = document.getElementById('adminDisputesList');
      const count = document.getElementById('adminDisputesCount');
      if (count) count.textContent = '(' + _adminDisputeCache.length + ')';
      if (!host) return;
      if (!_adminDisputeCache.length) {
        host.innerHTML = '<div style="color:var(--muted);font-size:.85rem;padding:14px 0;text-align:center">No open disputes. Nice.</div>';
        return;
      }
      const reasonLabels = {
        not_as_described: 'Not as described',
        damaged:          'Arrived damaged',
        never_arrived:    'Never arrived',
        wrong_item:       'Wrong item',
        other:            'Other',
      };
      host.innerHTML = _adminDisputeCache.map(function(o) {
        const buyer  = profileMap[o.buyer_id]  || {};
        const seller = profileMap[o.seller_id] || {};
        const listng = listingMap[o.listing_id] || {};
        const short  = String(o.id).slice(0, 8).toUpperCase();
        const reason = reasonLabels[o.return_reason] || o.return_reason || 'unspecified';
        const detail = String(o.return_reason_detail || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const photo  = (listng.photos && listng.photos[0]) ? listng.photos[0] : '';
        const buyerName  = buyer.name  || buyer.username  || buyer.email  || 'Buyer';
        const sellerName = seller.name || seller.username || seller.email || 'Seller';
        const disputedDate = o.disputed_at ? new Date(o.disputed_at).toLocaleString(undefined, { dateStyle:'medium', timeStyle:'short' }) : '';
        return ''
          + '<div id="admin-dispute-' + o.id + '" style="padding:14px;border:1px solid var(--border);background:var(--surface2);margin-bottom:10px">'
          +   '<div style="display:flex;gap:12px;align-items:flex-start;flex-wrap:wrap">'
          +     (photo ? '<img src="' + photo + '" style="width:60px;height:60px;object-fit:cover;border:1px solid var(--border);flex-shrink:0" alt="" / loading="lazy" decoding="async">' : '')
          +     '<div style="flex:1;min-width:240px">'
          +       '<div style="display:flex;gap:10px;align-items:baseline;flex-wrap:wrap;margin-bottom:4px">'
          +         '<div style="color:var(--text);font-size:.92rem;font-weight:700">' + (listng.name || 'Listing') + '</div>'
          +         '<div style="font-family:\'Space Mono\',monospace;color:var(--muted);font-size:.7rem">#' + short + ' &middot; $' + (o.amount || 0).toFixed(2) + '</div>'
          +       '</div>'
          +       '<div style="font-size:.72rem;color:var(--muted);margin-bottom:6px">'
          +         'Buyer: <span style="color:var(--text)">' + buyerName + '</span>'
          +         ' &middot; Seller: <span style="color:var(--text)">' + sellerName + '</span>'
          +         ' &middot; Disputed: ' + disputedDate
          +       '</div>'
          +       '<div style="padding:8px 10px;border-left:3px solid var(--yellow);background:rgba(255,217,61,.06);font-size:.74rem;color:var(--muted);line-height:1.55;margin-top:6px">'
          +         '<div style="color:var(--yellow);font-weight:700;letter-spacing:.04em;margin-bottom:2px">' + reason.toUpperCase() + '</div>'
          +         (detail ? '<div style="color:var(--text)">"' + detail + '"</div>' : '')
          +       '</div>'
          +     '</div>'
          +     '<div style="display:flex;flex-direction:column;gap:6px;min-width:170px">'
          +       '<button type="button" onclick="adminResolveDisputeForBuyer(\'' + o.id + '\')" '
          +         'style="padding:8px 12px;background:var(--red);color:var(--surface);border:none;font-family:\'Space Mono\',monospace;font-size:.72rem;font-weight:700;cursor:pointer">'
          +         'Refund Buyer'
          +       '</button>'
          +       '<button type="button" onclick="adminResolveDisputeForSeller(\'' + o.id + '\')" '
          +         'style="padding:8px 12px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.72rem;cursor:pointer">'
          +         'Resolve for Seller'
          +       '</button>'
          +     '</div>'
          +   '</div>'
          + '</div>';
      }).join('');
    }

    async function adminResolveDisputeForBuyer(orderId) {
      if (!confirm('Refund the buyer in full? This issues a Stripe refund (reverses the application fee on Connect orders) and restores the listing. Cannot be undone.')) return;
      try {
        const sess = await sb.auth.getSession();
        const tok  = sess && sess.data && sess.data.session && sess.data.session.access_token;
        if (!tok) { showToast('Sign in again'); return; }
        showToast('Refunding…');
        const r = await fetch('/api/refund-order', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + tok },
          body:    JSON.stringify({ orderId: orderId, reason: 'requested_by_customer' }),
        });
        const data = await r.json();
        if (!r.ok || !data.success) throw new Error(data.error || 'Refund failed');
        showToast('Refunded $' + (data.amount || 0).toFixed(2) + '.');
        loadAdminDisputes();
      } catch (e) {
        console.error('[admin-refund] error:', e);
        showToast('Refund failed: ' + (e.message || ''));
      }
    }

    async function adminResolveDisputeForSeller(orderId) {
      const note = prompt('Resolution note (visible to buyer + seller). Required.\n\nExample: "Reviewed listing photos vs. buyer images — wear matches what was disclosed."');
      if (!note || note.trim().length < 10) {
        if (note !== null) showToast('Note must be at least 10 characters.');
        return;
      }
      try {
        const { error } = await sb.rpc('admin_resolve_dispute_for_seller', {
          p_order_id: orderId,
          p_note:     note.trim(),
        });
        if (error) throw error;
        showToast('Dispute closed in seller\'s favor.');
        loadAdminDisputes();
      } catch (e) {
        console.error('[admin-resolve] error:', e);
        showToast('Resolve failed: ' + (e.message || ''));
      }
    }

    // ─── Admin: User search + ban/unban ────────────────────────────────
    async function searchAdminUsers() {
      const host = document.getElementById('adminUserResults');
      const q    = document.getElementById('adminUserSearch').value.trim();
      if (!host) return;
      if (!q) { host.innerHTML = '<div style="color:var(--muted);font-size:.78rem">Type an email or username and hit Search.</div>'; return; }
      host.innerHTML = '<div style="color:var(--muted);font-size:.78rem">Searching…</div>';
      try {
        // ILIKE on email OR username — PostgREST OR filter syntax.
        const { data, error } = await sb
          .from('profiles')
          .select('id, email, username, name, is_admin, is_banned, banned_reason, banned_at, is_deleted, subscription_tier, created_at')
          .or('email.ilike.%' + q + '%,username.ilike.%' + q + '%,name.ilike.%' + q + '%')
          .limit(20);
        if (error) throw error;
        renderAdminUserResults(data || []);
      } catch (e) {
        console.error('[admin-user-search] failed:', e);
        host.innerHTML = '<div style="color:var(--red);font-size:.78rem">Search failed: ' + (e.message || '') + '</div>';
      }
    }

    function renderAdminUserResults(rows) {
      const host = document.getElementById('adminUserResults');
      if (!host) return;
      if (!rows.length) { host.innerHTML = '<div style="color:var(--muted);font-size:.78rem">No matches.</div>'; return; }
      host.innerHTML = rows.map(function(u) {
        const label = u.name || u.username || u.email || u.id.slice(0,8);
        const tierBadge = u.subscription_tier ? '<span style="font-family:\'Space Mono\',monospace;font-size:.62rem;letter-spacing:.06em;padding:2px 6px;border:1px solid var(--border);color:var(--muted);margin-left:6px">' + u.subscription_tier.toUpperCase() + '</span>' : '';
        const flags = [];
        if (u.is_admin)   flags.push('<span style="color:var(--copper);font-size:.66rem">ADMIN</span>');
        if (u.is_banned)  flags.push('<span style="color:var(--red);font-size:.66rem">BANNED</span>');
        if (u.is_deleted) flags.push('<span style="color:var(--muted);font-size:.66rem">DELETED</span>');
        const flagHtml = flags.length ? ' &middot; ' + flags.join(' &middot; ') : '';
        const bannedNote = u.is_banned && u.banned_reason
          ? '<div style="font-size:.7rem;color:var(--muted);margin-top:4px;font-style:italic">Reason: "' + String(u.banned_reason).replace(/</g,'&lt;') + '"</div>'
          : '';
        const banBtn = u.is_admin
          ? '<span style="color:var(--muted);font-size:.7rem">Cannot ban admins</span>'
          : (u.is_banned
              ? '<button type="button" onclick="adminUnbanUser(\'' + u.id + '\')" style="padding:6px 12px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.7rem;cursor:pointer">Unban</button>'
              : '<button type="button" onclick="adminBanUser(\'' + u.id + '\',\'' + (u.username || u.email || '').replace(/\'/g,"\\'") + '\')" style="padding:6px 12px;border:1px solid var(--red);background:transparent;color:var(--red);font-family:\'Space Mono\',monospace;font-size:.7rem;cursor:pointer">Ban</button>');
        return ''
          + '<div style="padding:10px 14px;border:1px solid var(--border);background:var(--surface2);display:flex;gap:10px;align-items:center;justify-content:space-between;flex-wrap:wrap">'
          +   '<div style="flex:1;min-width:220px">'
          +     '<div style="color:var(--text);font-size:.85rem">' + label + tierBadge + flagHtml + '</div>'
          +     '<div style="color:var(--muted);font-size:.7rem;font-family:\'Space Mono\',monospace;margin-top:3px">' + (u.email || '') + ' &middot; ' + u.id + '</div>'
          +     bannedNote
          +   '</div>'
          +   '<div>' + banBtn + '</div>'
          + '</div>';
      }).join('');
    }

    async function adminBanUser(userId, label) {
      const reason = prompt('Ban ' + (label || 'this user') + '?\n\nEnter a reason (required, visible internally; user just sees "account suspended"):');
      if (!reason || reason.trim().length < 5) {
        if (reason !== null) showToast('Reason must be at least 5 characters.');
        return;
      }
      try {
        const { error } = await sb.rpc('admin_set_user_banned', {
          p_user_id: userId,
          p_banned:  true,
          p_reason:  reason.trim(),
        });
        if (error) throw error;
        showToast('User banned. Active listings suspended.');
        searchAdminUsers();
        loadSuspendedListings();
      } catch (e) {
        console.error('[admin-ban] error:', e);
        showToast('Ban failed: ' + (e.message || ''));
      }
    }

    async function adminUnbanUser(userId) {
      if (!confirm('Unban this user? They will be able to sign in immediately. Previously-suspended listings stay suspended — restore those individually.')) return;
      try {
        const { error } = await sb.rpc('admin_set_user_banned', {
          p_user_id: userId,
          p_banned:  false,
          p_reason:  null,
        });
        if (error) throw error;
        showToast('User unbanned.');
        searchAdminUsers();
      } catch (e) {
        console.error('[admin-unban] error:', e);
        showToast('Unban failed: ' + (e.message || ''));
      }
    }

    // ─── Admin: Suspended listings list + restore ──────────────────────
    async function loadSuspendedListings() {
      const host = document.getElementById('adminSuspendedList');
      if (!host) return;
      if (!userIsAdmin()) { host.innerHTML = '<div style="color:var(--muted);font-size:.8rem">Admins only.</div>'; return; }
      host.innerHTML = '<div style="color:var(--muted);font-size:.8rem">Loading…</div>';
      try {
        const { data, error } = await sb
          .from('listings')
          .select('id, name, photos, suspended_reason, suspended_at, seller_id, value')
          .eq('status', 'suspended')
          .order('suspended_at', { ascending: false })
          .limit(100);
        if (error) throw error;
        const rows = data || [];
        if (!rows.length) { host.innerHTML = '<div style="color:var(--muted);font-size:.85rem;padding:8px 0">No suspended listings.</div>'; return; }
        host.innerHTML = rows.map(function(l) {
          const photo = (l.photos && l.photos[0]) ? l.photos[0] : '';
          const price = (l.list_price != null ? l.list_price : l.value) || 0;
          const when  = l.suspended_at ? new Date(l.suspended_at).toLocaleString(undefined, { dateStyle:'medium', timeStyle:'short' }) : '';
          const reason = String(l.suspended_reason || '').replace(/</g,'&lt;');
          return ''
            + '<div style="padding:10px 14px;border:1px solid var(--border);background:var(--surface2);display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-bottom:8px">'
            +   (photo ? '<img src="' + photo + '" style="width:48px;height:48px;object-fit:cover;border:1px solid var(--border)" / loading="lazy" decoding="async">' : '')
            +   '<div style="flex:1;min-width:220px">'
            +     '<div style="color:var(--text);font-size:.85rem">' + (l.name || 'Listing') + ' <span style="color:var(--muted);font-size:.72rem">&middot; $' + price.toFixed(2) + '</span></div>'
            +     '<div style="color:var(--muted);font-size:.7rem;margin-top:3px">' + when + (reason ? ' &middot; <em>"' + reason + '"</em>' : '') + '</div>'
            +   '</div>'
            +   '<button type="button" onclick="adminRestoreListing(\'' + l.id + '\')" style="padding:6px 12px;border:1px solid var(--accent);background:transparent;color:var(--accent);font-family:\'Space Mono\',monospace;font-size:.7rem;cursor:pointer">Restore</button>'
            +   '<button type="button" onclick="adminSuspendListingPrompt(\'' + l.id + '\')" style="padding:6px 12px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:\'Space Mono\',monospace;font-size:.7rem;cursor:pointer">Edit reason</button>'
            + '</div>';
        }).join('');
      } catch (e) {
        console.error('[admin-suspended] load failed:', e);
        host.innerHTML = '<div style="color:var(--red);font-size:.78rem">Failed to load: ' + (e.message || '') + '</div>';
      }
    }

    async function adminSuspendListingPrompt(listingId) {
      const reason = prompt('Reason for suspending this listing? (Surfaced to the seller so they know what to fix.)');
      if (!reason || reason.trim().length < 5) {
        if (reason !== null) showToast('Reason must be at least 5 characters.');
        return;
      }
      try {
        const { error } = await sb.rpc('admin_set_listing_suspended', {
          p_listing_id: listingId,
          p_suspended:  true,
          p_reason:     reason.trim(),
        });
        if (error) throw error;
        showToast('Listing suspended.');
        loadSuspendedListings();
        if (typeof renderAdminTable === 'function') renderAdminTable();
      } catch (e) {
        console.error('[admin-suspend] error:', e);
        showToast('Suspend failed: ' + (e.message || ''));
      }
    }

    async function adminRestoreListing(listingId) {
      if (!confirm('Restore this listing to the marketplace?')) return;
      try {
        const { error } = await sb.rpc('admin_set_listing_suspended', {
          p_listing_id: listingId,
          p_suspended:  false,
          p_reason:     null,
        });
        if (error) throw error;
        showToast('Listing restored.');
        loadSuspendedListings();
      } catch (e) {
        console.error('[admin-restore] error:', e);
        showToast('Restore failed: ' + (e.message || ''));
      }
    }

    // ─── Admin deep-link handler ───────────────────────────────────────
    // ?admin=disputes&order=<uuid> opens the admin page, scrolls the
    // specific dispute card into view, and gives it a 2s pulse so it's
    // visually obvious which one the email/notification was about.
    function maybeFocusAdminDispute() {
      try {
        const q = new URLSearchParams(location.search);
        if (q.get('admin') !== 'disputes') return;
        const orderId = q.get('order');
        // Clean the query off the URL.
        q.delete('admin'); q.delete('order');
        const newSearch = q.toString();
        history.replaceState(null, '', location.pathname + (newSearch ? '?' + newSearch : '') + location.hash);
        if (!orderId) return;
        // Wait for the dispute list to render then scroll + highlight.
        let tries = 0;
        const tick = setInterval(function() {
          tries++;
          const el = document.getElementById('admin-dispute-' + orderId);
          if (el) {
            clearInterval(tick);
            el.scrollIntoView({ behavior: 'smooth', block: 'center' });
            const orig = el.style.boxShadow;
            el.style.transition = 'box-shadow .3s';
            el.style.boxShadow  = '0 0 0 3px var(--copper)';
            setTimeout(function() { el.style.boxShadow = orig; }, 2400);
          } else if (tries > 30) {
            clearInterval(tick);
          }
        }, 150);
      } catch (_) { /* no-op */ }
    }

    // ── Admin: image-review queue ───────────────────────────────────────
    // Pulls every listing where needs_image_review = true, sorted oldest-
    // flag-first (so backlog gets worked in flag order). Shows a compact
    // row per listing with: thumbnail · name + admin note · "View" + "Clear".
    // View opens the listing's buy-card detail (admin can swap photos in
    // edit flow); Clear toggles the flag off via the existing function.
    async function renderAdminImageReviewQueue() {
      const container = document.getElementById('adminImageReviewQueue');
      if (!container || !currentUser?.is_admin) return;
      container.innerHTML = '<div style="font-size:.6rem;color:var(--muted)">Loading…</div>';
      var res;
      try {
        // Queue now reads from catalog (sealed products + any catalog
        // row admins flag) — see migration_catalog_image_review.sql.
        // Previously queried listings; the flag moved to catalog so
        // every reference to the same product shares one flag state.
        res = await sb.from('catalog')
          .select('id, name, set_name, image_url, product_type, image_review_note, image_review_flagged_at')
          .eq('needs_image_review', true)
          .order('image_review_flagged_at', { ascending: true, nullsFirst: true });
      } catch (e) {
        container.innerHTML = '<div style="font-size:.6rem;color:var(--red)">Query failed — apply migration_catalog_image_review.sql.</div>';
        return;
      }
      if (res.error) {
        // Column-missing error → migration not applied yet
        var msg = String(res.error.message || '');
        if (msg.toLowerCase().indexOf('column') >= 0 || msg.toLowerCase().indexOf('schema') >= 0) {
          container.innerHTML = '<div style="font-size:.6rem;color:var(--red)">Apply <code>migration_catalog_image_review.sql</code> in Supabase before using this queue.</div>';
        } else {
          container.innerHTML = '<div style="font-size:.6rem;color:var(--red)">Error: ' + _escHtml(msg) + '</div>';
        }
        return;
      }
      var rows = res.data || [];
      if (!rows.length) {
        container.innerHTML = '<div style="font-size:.6rem;color:var(--muted)">Queue empty — no catalog rows flagged for image review.</div>';
        return;
      }
      container.innerHTML = rows.map(function(r) {
        var thumb = r.image_url || '';
        var when  = r.image_review_flagged_at
          ? new Date(r.image_review_flagged_at).toLocaleDateString()
          : '—';
        var ptype = (r.product_type || 'single').toUpperCase().replace(/_/g, ' ');
        return '<div style="display:flex;align-items:center;gap:12px;padding:10px;border:1px solid var(--copper-dim);background:rgba(184,115,51,.06)">' +
          (thumb
            ? '<img src="' + thumb + '" alt="" style="width:48px;height:64px;object-fit:cover;border:1px solid var(--border);flex-shrink:0;border-radius:3px" loading="lazy" decoding="async">'
            : '<div style="width:48px;height:64px;background:var(--surface2);border:1px dashed var(--copper-dim);flex-shrink:0;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:.7rem">?</div>') +
          '<div style="flex:1;min-width:0">' +
            '<div style="font-size:.74rem;color:var(--text);font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + _escHtml(r.name || '(no name)') + '</div>' +
            '<div style="font-size:.6rem;color:var(--muted);margin-top:2px">' + _escHtml(ptype) + ' · ' + _escHtml(r.set_name || '—') + ' · flagged ' + when + '</div>' +
            (r.image_review_note
              ? '<div style="font-size:.6rem;color:var(--copper);margin-top:4px;font-style:italic">"' + _escHtml(r.image_review_note) + '"</div>'
              : '') +
          '</div>' +
          '<div style="display:flex;flex-direction:column;gap:4px;flex-shrink:0">' +
            '<button onclick="openSealedProductDetail(\'' + _escJsAttr(r.id) + '\')" class="pb-panel-link" style="border-color:var(--copper-dim);color:var(--copper);font-size:.58rem;padding:4px 10px">VIEW</button>' +
            '<button onclick="flagCatalogImage(\'' + _escJsAttr(r.id) + '\', true)" class="pb-panel-link" style="border-color:var(--border);color:var(--muted);font-size:.58rem;padding:4px 10px">CLEAR</button>' +
          '</div>' +
        '</div>';
      }).join('');
    }

    async function loadAdminClearCollectionUsers() {
      const container = document.getElementById('adminClearCollectionUsers');
      if (!container || !currentUser?.is_admin) return;

      // Load profiles with card counts
      const { data: profiles } = await sb.from('profiles').select('id, email, username').order('email');
      if (!profiles || !profiles.length) {
        container.innerHTML = '<div style="font-size:.6rem;color:var(--muted)">No users found.</div>';
        return;
      }

      // Get card counts per user
      const { data: counts } = await sb.from('collection_items').select('user_id');
      const countMap = {};
      (counts || []).forEach(r => { countMap[r.user_id] = (countMap[r.user_id] || 0) + 1; });

      container.innerHTML = profiles.map(p => {
        const n = countMap[p.id] || 0;
        const label = p.username || p.email || p.id.slice(0, 8);
        return `<div style="display:flex;align-items:center;gap:12px;padding:8px 10px;border:1px solid rgba(255,60,60,.2);background:rgba(0,0,0,.2)">
          <div style="flex:1;font-family:'Space Mono','Share Tech Mono',monospace;font-size:.65rem;color:var(--text)">${label}</div>
          <div style="font-size:.6rem;color:var(--muted);white-space:nowrap">${n} card${n !== 1 ? 's' : ''}</div>
          <button onclick="adminClearUserCollection('${p.id}','${label.replace(/'/g,"\\'")}',${n})"
            ${n === 0 ? 'disabled' : ''}
            style="font-family:'Space Mono','Share Tech Mono',monospace;font-size:.55rem;letter-spacing:.06em;padding:4px 10px;border:1px solid rgba(255,60,60,.5);background:transparent;color:rgba(255,100,100,.85);cursor:${n===0?'not-allowed':'pointer'};opacity:${n===0?'.4':'1'};white-space:nowrap;transition:all .15s"
            onmouseover="if(${n}>0){this.style.background='rgba(255,60,60,.12)'}" onmouseout="this.style.background='transparent'">
            Delete ${n > 0 ? n + ' cards' : 'cards'}
          </button>
        </div>`;
      }).join('');
    }

    // ── Catalog Image Contribution Queue ─────────────────────────
    // Admin queue for user-submitted catalog photos. Each row shows
    // side-by-side: contributor's photo + card metadata + current
    // catalog image (likely NULL since this flow only triggers when
    // image_url is missing). Buttons fire apply_image_contribution
    // or reject_image_contribution RPCs.
    async function renderAdminContributionQueue() {
      const container = document.getElementById('adminContributionQueue');
      if (!container || !currentUser?.is_admin) return;
      container.innerHTML = '<div style="font-size:.6rem;color:var(--muted)">Loading…</div>';

      // Pull pending submissions with joined catalog + profile rows
      // so we can show everything without a second round-trip per row.
      const res = await sb.from('catalog_image_contributions')
        .select(`
          id, user_id, catalog_id, image_url, image_width, image_height,
          submitted_at, notes,
          profiles:user_id ( username, email, subscription_tier ),
          catalog:catalog_id ( name, set_name, set_code, card_number, image_url, product_type, game_type )
        `)
        .eq('status', 'pending')
        .order('submitted_at', { ascending: true })
        .limit(50);

      if (res.error) {
        const msg = String(res.error.message || '');
        if (/relation .*catalog_image_contributions.* does not exist/i.test(msg)) {
          container.innerHTML = '<div style="font-size:.6rem;color:var(--red)">Apply <code>migration_catalog_image_contributions.sql</code> in Supabase before using this queue.</div>';
        } else {
          container.innerHTML = '<div style="font-size:.6rem;color:var(--red)">Error: ' + _escHtml(msg) + '</div>';
        }
        return;
      }

      const rows = res.data || [];
      if (!rows.length) {
        container.innerHTML = '<div style="font-size:.6rem;color:var(--muted)">Queue empty — no pending contributions.</div>';
        return;
      }

      container.innerHTML = rows.map(function(r) {
        const cat   = r.catalog || {};
        const prof  = r.profiles || {};
        const dims  = (r.image_width && r.image_height)
          ? r.image_width + '×' + r.image_height : '—';
        const tier  = String(prof.subscription_tier || 'free').toUpperCase();
        const setLine = [cat.set_name, cat.card_number ? '#' + cat.card_number : '']
          .filter(Boolean).join(' · ');
        const submittedAgo = (function() {
          const ms = Date.now() - new Date(r.submitted_at).getTime();
          const h  = Math.floor(ms / 3600000);
          if (h < 1) return Math.max(1, Math.floor(ms / 60000)) + 'm ago';
          if (h < 24) return h + 'h ago';
          return Math.floor(h / 24) + 'd ago';
        })();
        return ''
        + '<div style="display:flex;gap:12px;padding:12px;border:1px solid var(--accent);background:rgba(26,199,160,.04);border-radius:4px">'
        +   '<div style="flex-shrink:0">'
        +     '<div style="font-size:.5rem;color:var(--accent);letter-spacing:.08em;margin-bottom:4px">SUBMITTED</div>'
        +     '<img src="' + _escHtml(r.image_url) + '" alt="" loading="lazy" style="width:140px;height:auto;border:1px solid var(--accent);border-radius:3px;display:block">'
        +     '<div style="font-size:.55rem;color:var(--muted);margin-top:4px;text-align:center">' + _escHtml(dims) + '</div>'
        +   '</div>'
        +   '<div style="flex:1;min-width:0">'
        +     '<div style="font-size:.78rem;color:var(--text);font-weight:700;margin-bottom:3px">' + _escHtml(cat.name || '(unknown card)') + '</div>'
        +     (setLine ? '<div style="font-size:.62rem;color:var(--muted);margin-bottom:8px">' + _escHtml(setLine) + '</div>' : '')
        +     '<div style="font-size:.58rem;color:var(--muted);margin-bottom:8px;line-height:1.5">'
        +       '<div><span style="color:var(--accent)">By</span> ' + _escHtml(prof.username || prof.email || r.user_id.slice(0, 8)) + ' (' + _escHtml(tier) + ')</div>'
        +       '<div><span style="color:var(--accent)">When</span> ' + _escHtml(submittedAgo) + '</div>'
        +       '<div><span style="color:var(--accent)">Catalog id</span> <code style="color:var(--muted);font-size:.55rem">' + _escHtml(r.catalog_id) + '</code></div>'
        +       (cat.image_url ? '<div style="color:var(--copper);margin-top:4px">⚠ Catalog row ALREADY has an image — this would replace it.</div>' : '')
        +       (r.notes ? '<div style="margin-top:4px;color:var(--text)">Note: <em>' + _escHtml(r.notes) + '</em></div>' : '')
        +     '</div>'
        +     '<div style="display:flex;gap:6px">'
        +       '<button onclick="adminApproveContribution(\'' + _escJsAttr(r.id) + '\')" '
        +         'style="padding:7px 14px;border:1px solid var(--accent);background:var(--accent);color:var(--text-on-accent);font-family:\'Space Mono\',monospace;font-size:.62rem;font-weight:700;cursor:pointer;letter-spacing:.06em">'
        +         'APPROVE'
        +       '</button>'
        +       '<button onclick="adminRejectContribution(\'' + _escJsAttr(r.id) + '\')" '
        +         'style="padding:7px 14px;border:1px solid rgba(255,80,80,.5);background:transparent;color:rgba(255,100,100,.85);font-family:\'Space Mono\',monospace;font-size:.62rem;cursor:pointer;letter-spacing:.06em">'
        +         'REJECT'
        +       '</button>'
        +       (cat.image_url
          ? '<a href="' + _escHtml(cat.image_url) + '" target="_blank" rel="noopener" '
            + 'style="padding:7px 14px;border:1px solid var(--copper-dim);background:transparent;color:var(--copper);font-family:\'Space Mono\',monospace;font-size:.62rem;cursor:pointer;letter-spacing:.06em;text-decoration:none;display:inline-block">'
            + 'CURRENT IMG'
            + '</a>'
          : '')
        +     '</div>'
        +   '</div>'
        + '</div>';
      }).join('');
    }

    window.renderAdminContributionQueue = renderAdminContributionQueue;

    async function adminApproveContribution(contribId) {
      if (!currentUser?.is_admin) return;
      try {
        const r = await sb.rpc('apply_image_contribution', {
          p_contribution_id: contribId,
          p_reviewer_id:     currentUser.id,
        });
        if (r && r.error) { showToast('Approve failed: ' + r.error.message); return; }
        showToast('Approved — catalog updated');
        renderAdminContributionQueue();
      } catch (e) {
        showToast('Approve failed: ' + (e.message || 'unknown'));
      }
    }
    window.adminApproveContribution = adminApproveContribution;

    async function adminRejectContribution(contribId) {
      if (!currentUser?.is_admin) return;
      const reason = prompt('Reject reason (visible to contributor):', 'Image quality too low / watermarked / wrong card');
      if (!reason) return;
      try {
        const r = await sb.rpc('reject_image_contribution', {
          p_contribution_id: contribId,
          p_reviewer_id:     currentUser.id,
          p_reason:          reason,
        });
        if (r && r.error) { showToast('Reject failed: ' + r.error.message); return; }
        showToast('Rejected');
        renderAdminContributionQueue();
      } catch (e) {
        showToast('Reject failed: ' + (e.message || 'unknown'));
      }
    }
    window.adminRejectContribution = adminRejectContribution;

    async function adminClearUserCollection(userId, label, count) {
      if (!currentUser?.is_admin) return;
      if (!confirm(`Delete all ${count} cards from ${label}'s collection?\n\nThis cannot be undone.`)) return;

      const { error } = await sb
        .from('collection_items')
        .delete()
        .eq('user_id', userId);

      if (error) { showToast('Error: ' + error.message); return; }
      showToast(`Deleted ${count} cards from ${label}'s collection`);
      loadAdminClearCollectionUsers(); // refresh counts
    }

    // ── Admin Card Editor — manages card_reports and card_overrides ──────
    var _adminCardReportsCache = [];

    function _adminSetCRTab(active) {
      var open     = document.getElementById('adminCRTabOpen');
      var resolved = document.getElementById('adminCRTabResolved');
      function activate(el)   { if (el) { el.style.borderColor='var(--copper)'; el.style.background='rgba(184,115,51,.12)'; el.style.color='var(--copper)'; } }
      function deactivate(el) { if (el) { el.style.borderColor='var(--border)'; el.style.background='transparent'; el.style.color='var(--muted)'; } }
      if (active === 'open')     { activate(open); deactivate(resolved); }
      else if (active === 'resolved') { activate(resolved); deactivate(open); }
    }

    async function adminLoadCardReports(filter) {
      if (!currentUser?.is_admin) return;
      var list = document.getElementById('adminCardReportsList');
      if (!list) return;
      _adminSetCRTab(filter);
      list.innerHTML = '<div style="font-size:.62rem;color:rgba(26,199,160,.4);letter-spacing:.08em">Loading reports…</div>';

      var query = sb.from('card_reports').select('*').order('created_at', { ascending: false }).limit(60);
      if (filter === 'open')     query = query.eq('status', 'open');
      if (filter === 'resolved') query = query.eq('status', 'resolved');
      var res = await query;
      if (res.error) {
        var msg = (res.error.message || '').toLowerCase();
        if (msg.indexOf('relation') !== -1 || msg.indexOf('does not exist') !== -1) {
          printAdminCardSQL();
          list.innerHTML = '<div style="font-size:.7rem;color:#ff6b6b">Migration required — see console for SQL.</div>';
          return;
        }
        list.innerHTML = '<div style="font-size:.7rem;color:#ff6b6b">Error: ' + _escHtml(res.error.message) + '</div>';
        return;
      }

      _adminCardReportsCache = res.data || [];
      if (!_adminCardReportsCache.length) {
        list.innerHTML = '<div style="font-size:.7rem;color:var(--muted);font-style:italic;padding:8px 0">No ' + filter + ' reports.</div>';
        return;
      }

      // Look up reporter usernames in one query for the rendered list.
      var userIds = Array.from(new Set(_adminCardReportsCache.map(function(r) { return r.user_id; }).filter(Boolean)));
      var nameMap = {};
      if (userIds.length) {
        try {
          var pf = await sb.from('profiles').select('id, username, name').in('id', userIds);
          (pf.data || []).forEach(function(p) { nameMap[p.id] = p.username || p.name || ''; });
        } catch(_) {}
      }

      list.innerHTML = _adminCardReportsCache.map(function(r) {
        var who   = nameMap[r.user_id] ? '@' + _escHtml(nameMap[r.user_id]) : 'Anonymous';
        var when  = r.created_at ? new Date(r.created_at).toLocaleString() : '';
        var card  = (r.card_name || 'Unknown card') + (r.set_name ? ' · ' + r.set_name : '');
        var apiId = r.api_card_id || '';
        var statusBadge = r.status === 'resolved'
          ? '<span style="font-size:.55rem;color:var(--green);border:1px solid var(--green);padding:1px 6px;letter-spacing:.06em">RESOLVED</span>'
          : '<span style="font-size:.55rem;color:var(--copper);border:1px solid var(--copper);padding:1px 6px;letter-spacing:.06em">OPEN</span>';
        return (
          '<div style="border:1px solid var(--border);background:var(--surface2);padding:10px 12px;font-family:\'Space Mono\',monospace">' +
            '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap">' +
              '<div style="flex:1;min-width:0">' +
                '<div style="display:flex;gap:8px;align-items:center;font-size:.62rem;color:var(--muted);margin-bottom:4px">' +
                  statusBadge +
                  '<span>' + _escHtml(who) + '</span>' +
                  '<span>·</span>' +
                  '<span>' + _escHtml(when) + '</span>' +
                '</div>' +
                '<div style="font-size:.78rem;font-weight:600;color:var(--text);margin-bottom:2px">' + _escHtml(card) + '</div>' +
                (apiId ? '<div style="font-size:.58rem;color:rgba(26,199,160,.5)">api_card_id: ' + _escHtml(apiId) + '</div>' : '') +
                '<div style="font-size:.7rem;color:rgba(210,240,255,.78);margin-top:6px;line-height:1.5;white-space:pre-wrap;border-left:2px solid rgba(184,115,51,.4);padding-left:8px">' + _escHtml(r.description || '') + '</div>' +
              '</div>' +
              '<div style="display:flex;flex-direction:column;gap:5px;flex-shrink:0">' +
                (r.api_card_id
                  ? '<button onclick="adminOpenCardOverrideEditor(\'' + r.api_card_id + '\',\'' + r.id + '\')" style="font-size:.6rem;padding:5px 11px;border:1px solid var(--accent);background:transparent;color:var(--accent);cursor:pointer;font-family:inherit;letter-spacing:.04em">Edit Card Data</button>'
                  : '<button disabled style="font-size:.6rem;padding:5px 11px;border:1px solid var(--border);background:transparent;color:var(--muted);font-family:inherit;letter-spacing:.04em;cursor:not-allowed" title="No api_card_id — manual override only">No API ID</button>'
                ) +
                (r.status === 'open'
                  ? '<button onclick="adminResolveCardReport(\'' + r.id + '\', \'dismissed\')" style="font-size:.55rem;padding:4px 10px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-family:inherit;letter-spacing:.04em">Dismiss</button>'
                  : '<button onclick="adminResolveCardReport(\'' + r.id + '\', \'open\')" style="font-size:.55rem;padding:4px 10px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-family:inherit;letter-spacing:.04em">Reopen</button>'
                ) +
              '</div>' +
            '</div>' +
          '</div>'
        );
      }).join('');
    }

    async function adminResolveCardReport(reportId, newStatus) {
      if (!currentUser?.is_admin) return;
      var patch = { status: newStatus };
      if (newStatus === 'resolved') {
        patch.resolved_at = new Date().toISOString();
        patch.resolved_by = currentUser.id;
      } else if (newStatus === 'open') {
        patch.resolved_at = null;
        patch.resolved_by = null;
      }
      var res = await sb.from('card_reports').update(patch).eq('id', reportId);
      if (res.error) { showToast('Error: ' + res.error.message); return; }
      showToast('Report ' + newStatus);
      // Refresh whichever tab is currently active
      var activeOpen = document.getElementById('adminCRTabOpen');
      var current = (activeOpen && activeOpen.style.background.indexOf('184,115,51') !== -1) ? 'open' : 'resolved';
      adminLoadCardReports(current);
    }

    // Override editor — opens an inline form keyed by api_card_id.
    // Pass reportId to auto-resolve the linked report on save.
    async function adminOpenCardOverrideEditor(apiCardId, reportId) {
      if (!currentUser?.is_admin) return;
      // If apiCardId is null we're in "manual" mode — let the admin type it
      var prompted = apiCardId;
      if (!prompted) {
        prompted = prompt('Enter the api_card_id of the card to override (e.g. xy7-54):');
        if (!prompted) return;
        prompted = prompted.trim();
      }

      // Fetch existing override (if any) + the live API data for context
      var override = null, apiData = null;
      try {
        var ov = await sb.from('card_overrides').select('*').eq('api_card_id', prompted).maybeSingle();
        override = ov.data || null;
      } catch(_) {}
      try {
        var ar = await fetch('https://api.pokemontcg.io/v2/cards/' + encodeURIComponent(prompted));
        if (ar.ok) {
          var aj = await ar.json();
          apiData = aj.data || null;
        }
      } catch(_) {}

      // Render the editor inline at the top of the reports list
      var list = document.getElementById('adminCardReportsList');
      if (!list) return;
      var current = function(field, fallback) {
        if (override && override[field] != null && override[field] !== '') return override[field];
        return fallback != null ? fallback : '';
      };
      var hint = function(label, val) { return '<div style="font-size:.55rem;color:var(--muted);margin-top:2px">' + label + ': <span style="color:rgba(210,240,255,.6)">' + (val ? _escHtml(String(val)) : '<em>none</em>') + '</span></div>'; };

      var apiName  = apiData ? apiData.name : '';
      var apiSet   = apiData && apiData.set ? (apiData.set.name || '') : '';
      var apiCode  = apiData && apiData.set ? (apiData.set.id || '') : '';
      var apiNum   = apiData ? apiData.number : '';
      var apiImg   = apiData && apiData.images ? (apiData.images.large || apiData.images.small || '') : '';
      var apiRare  = apiData ? apiData.rarity : '';

      var editor =
        '<div id="adminOverrideEditor" style="border:1px solid var(--copper);background:rgba(184,115,51,.06);padding:14px 16px;font-family:\'Space Mono\',monospace">' +
          '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;flex-wrap:wrap;gap:8px">' +
            '<div style="font-size:.7rem;color:var(--copper);letter-spacing:.08em;font-weight:700">EDITING OVERRIDE · ' + _escHtml(prompted) + '</div>' +
            '<button onclick="document.getElementById(\'adminOverrideEditor\').remove()" style="font-size:.55rem;padding:3px 9px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-family:inherit">Close Editor</button>' +
          '</div>' +
          (apiData
            ? '<div style="display:flex;gap:12px;margin-bottom:12px">' +
                (apiImg ? '<img src="' + apiImg + '" style="width:80px;height:auto;flex-shrink:0;border:1px solid var(--border)" alt="" loading="lazy" decoding="async">' : '') +
                '<div style="flex:1;font-size:.6rem;color:var(--muted);line-height:1.6">' +
                  '<div style="color:var(--text);font-size:.66rem;font-weight:600;margin-bottom:2px">CATALOG (live):</div>' +
                  '<div>' + _escHtml(apiName || '—') + '</div>' +
                  '<div>' + _escHtml(apiSet || '—') + (apiNum ? ' · #' + _escHtml(apiNum) : '') + '</div>' +
                  '<div>Rarity: ' + _escHtml(apiRare || '—') + '</div>' +
                '</div>' +
              '</div>'
            : '<div style="font-size:.62rem;color:#ff8888;margin-bottom:10px">No live catalog data — pokemontcg.io returned nothing for this id. Override fields will be applied as-is.</div>') +
          '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">' +
            _ovField('Card name',     'ovName',  current('card_name', ''),       apiName) +
            _ovField('Set name',      'ovSet',   current('set_name', ''),        apiSet) +
            _ovField('Set code',      'ovCode',  current('set_code', ''),        apiCode) +
            _ovField('Card number',   'ovNum',   current('card_number', ''),     apiNum) +
            _ovField('Rarity',        'ovRare',  current('rarity', ''),          apiRare) +
            _ovField('Image URL',     'ovImg',   current('card_image_url', ''),  apiImg) +
          '</div>' +
          '<label style="font-size:.58rem;color:var(--muted);letter-spacing:.06em;display:block;margin-bottom:4px">Admin notes (optional)</label>' +
          '<textarea id="ovNotes" rows="2" style="width:100%;background:var(--surface2);border:1px solid var(--border);color:var(--text);padding:6px 8px;font-family:inherit;font-size:.65rem;box-sizing:border-box;margin-bottom:10px">' + _escHtml(current('notes', '')) + '</textarea>' +
          '<div style="display:flex;gap:8px;flex-wrap:wrap">' +
            '<button onclick="adminSaveCardOverride(\'' + prompted + '\',' + (reportId ? '\'' + reportId + '\'' : 'null') + ')" style="font-size:.65rem;padding:7px 14px;border:1px solid var(--copper);background:var(--copper);color:#000;cursor:pointer;font-family:inherit;letter-spacing:.04em;font-weight:700">Save Override' + (reportId ? ' + Resolve Report' : '') + '</button>' +
            (override
              ? '<button onclick="adminDeleteCardOverride(\'' + prompted + '\')" style="font-size:.6rem;padding:7px 14px;border:1px solid #ff6b6b;background:transparent;color:#ff6b6b;cursor:pointer;font-family:inherit;letter-spacing:.04em">Delete Override</button>'
              : '') +
            '<button onclick="adminPrefillFromCatalog(' + (apiData ? 'true' : 'false') + ')" style="font-size:.6rem;padding:7px 14px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-family:inherit;letter-spacing:.04em">Prefill from Catalog</button>' +
          '</div>' +
          '<div id="ovStatus" style="font-size:.62rem;color:var(--muted);margin-top:8px;min-height:1em"></div>' +
        '</div>';

      // Insert at the top of the reports list, leaving the report list visible below.
      var existing = document.getElementById('adminOverrideEditor');
      if (existing) existing.remove();
      list.insertAdjacentHTML('afterbegin', editor);
      // Stash live API data so prefill button works without refetching
      window._adminLastApiData = apiData;
    }

    function _ovField(label, id, value, placeholder) {
      var safeVal  = _escHtml(value || '');
      var safePh   = _escHtml(placeholder || '');
      return (
        '<div>' +
          '<label style="font-size:.58rem;color:var(--muted);letter-spacing:.06em;display:block;margin-bottom:3px">' + label + '</label>' +
          '<input type="text" id="' + id + '" value="' + safeVal + '" placeholder="' + safePh + '" ' +
            'style="width:100%;background:var(--surface2);border:1px solid var(--border);color:var(--text);padding:6px 8px;font-family:inherit;font-size:.66rem;box-sizing:border-box">' +
        '</div>'
      );
    }

    function adminPrefillFromCatalog(haveApi) {
      if (!haveApi) { showToast('No catalog data to prefill from'); return; }
      var ad = window._adminLastApiData;
      if (!ad) return;
      function setIf(id, val) { var el = document.getElementById(id); if (el && val) el.value = val; }
      setIf('ovName', ad.name);
      setIf('ovSet',  ad.set && ad.set.name);
      setIf('ovCode', ad.set && ad.set.id);
      setIf('ovNum',  ad.number);
      setIf('ovRare', ad.rarity);
      setIf('ovImg',  ad.images && (ad.images.large || ad.images.small));
    }

    async function adminSaveCardOverride(apiCardId, reportId) {
      if (!currentUser?.is_admin) return;
      var st = document.getElementById('ovStatus');
      function readVal(id) { var el = document.getElementById(id); return el ? (el.value || '').trim() : ''; }
      var payload = {
        api_card_id:    apiCardId,
        card_name:      readVal('ovName')  || null,
        set_name:       readVal('ovSet')   || null,
        set_code:       readVal('ovCode')  || null,
        card_number:    readVal('ovNum')   || null,
        rarity:         readVal('ovRare')  || null,
        card_image_url: readVal('ovImg')   || null,
        notes:          readVal('ovNotes') || null,
        updated_at:     new Date().toISOString(),
        updated_by:     currentUser.id
      };
      if (st) _setProcessingText(st, 'Saving override…');
      var res = await sb.from('card_overrides').upsert(payload, { onConflict: 'api_card_id' });
      if (res.error) {
        var msg = (res.error.message || '').toLowerCase();
        if (msg.indexOf('relation') !== -1 || msg.indexOf('does not exist') !== -1) {
          printAdminCardSQL();
          if (st) _setProcessingText(st, 'Migration required — see console for SQL');
          return;
        }
        if (st) _setProcessingText(st, 'Save failed: ' + res.error.message);
        return;
      }

      // If a report was attached, mark it resolved
      if (reportId) {
        await sb.from('card_reports').update({
          status: 'resolved',
          resolved_at: new Date().toISOString(),
          resolved_by: currentUser.id
        }).eq('id', reportId);
      }
      // Refresh in-memory override cache so the new values flow to all
      // subsequent add-card operations in this session.
      try { await _loadCardOverrides(); } catch(_) {}

      if (st) _setProcessingText(st, 'Saved');
      showToast('Override saved' + (reportId ? ' · report resolved' : ''));
      var existing = document.getElementById('adminOverrideEditor');
      if (existing) existing.remove();
      adminLoadCardReports(reportId ? 'open' : 'open');
    }

    async function adminDeleteCardOverride(apiCardId) {
      if (!currentUser?.is_admin) return;
      if (!confirm('Delete the override for ' + apiCardId + '? Catalog data will be used as-is again.')) return;
      var res = await sb.from('card_overrides').delete().eq('api_card_id', apiCardId);
      if (res.error) { showToast('Delete failed: ' + res.error.message); return; }
      showToast('Override deleted');
      var existing = document.getElementById('adminOverrideEditor');
      if (existing) existing.remove();
    }
    // ── End Admin Card Editor ─────────────────────────────────────────────

    // ── Card Overrides — admin-curated corrections to catalog data ────────
    // Cached in memory and applied to insert-row payloads so corrections
    // flow into every newly-added collection item, regardless of which
    // add-card path the user took (search detail, scan, multi-scan, JP,
    // sets browser, trade-received).
    var _cardOverridesCache = {};        // { api_card_id → override row }
    var _cardOverridesLoaded = false;

    async function _loadCardOverrides() {
      try {
        var res = await sb.from('card_overrides').select('*');
        if (res.error) {
          // Missing table is fine — the feature just stays inert until
          // the admin runs the migration.
          var msg = (res.error.message || '').toLowerCase();
          if (msg.indexOf('relation') === -1 && msg.indexOf('does not exist') === -1) {
            console.warn('[CardOverrides] load error:', res.error.message);
          }
          _cardOverridesCache = {};
          _cardOverridesLoaded = true;
          return;
        }
        var map = {};
        (res.data || []).forEach(function(o) { if (o.api_card_id) map[o.api_card_id] = o; });
        _cardOverridesCache = map;
        _cardOverridesLoaded = true;
      } catch(e) {
        console.warn('[CardOverrides] fetch failed:', e);
        _cardOverridesCache = {};
        _cardOverridesLoaded = true;
      }
    }

    // Get the override row for a given api_card_id (or null).
    function getCardOverride(apiCardId) {
      if (!apiCardId) return null;
      return _cardOverridesCache[apiCardId] || null;
    }

    // Mutate a collection_items insert payload in-place: any non-null
    // override field replaces the corresponding row field. Returns the
    // same row for chaining. Safe to call when no override exists.
    function applyOverrideToInsertRow(row) {
      if (!row) return row;
      var apiId = row.api_card_id;
      var ov = getCardOverride(apiId);
      if (!ov) return row;
      if (ov.card_name      != null && ov.card_name      !== '') row.card_name      = ov.card_name;
      if (ov.set_name       != null && ov.set_name       !== '') row.set_name       = ov.set_name;
      if (ov.set_code       != null && ov.set_code       !== '') row.set_code       = ov.set_code;
      if (ov.card_number    != null && ov.card_number    !== '') row.card_number    = ov.card_number;
      if (ov.rarity         != null && ov.rarity         !== '') row.rarity         = ov.rarity;
      if (ov.card_image_url != null && ov.card_image_url !== '') row.card_image_url = ov.card_image_url;
      return row;
    }
    // ── End Card Overrides ────────────────────────────────────────────────

    // ── Sealed BG Review Queue ────────────────────────────────────────────
    // Admin queue for sealed products whose automated bg removal couldn't
    // strip the background (cream / yellow / gradient / photo bg). The
    // restore_sealed_bg.py --redo flow flags them via PATCH to catalog,
    // setting needs_manual_bg=true. This queue lets the admin upload a
    // hand-cleaned image to replace the flagged one in Supabase Storage.
    // The upload writes to the same storage path so the existing
    // catalog.image_url keeps pointing to the right file; on success we
    // PATCH the row to clear needs_manual_bg.
    async function adminLoadBgReviewQueue() {
      if (!currentUser?.is_admin) return;
      var list = document.getElementById('adminBgReviewList');
      var countEl = document.getElementById('adminBgReviewCount');
      if (!list) return;
      list.innerHTML = '<div style="font-size:.62rem;color:var(--muted)">Loading queue…</div>';
      if (countEl) countEl.textContent = '';

      var rows = [];
      try {
        var res = await sb
          .from('catalog')
          .select('id,name,set_name,set_code,product_type,image_url,price_source_url,bg_failure_reason,bg_flagged_at')
          .eq('needs_manual_bg', true)
          .order('bg_flagged_at', { ascending: false, nullsFirst: false })
          .limit(500);
        if (res.error) throw res.error;
        rows = res.data || [];
      } catch (e) {
        list.innerHTML = '<div style="font-size:.62rem;color:var(--red)">// Error loading queue: ' + _escHtml(e.message || String(e)) + '</div>' +
                         '<div style="font-size:.6rem;color:var(--muted);margin-top:4px">Has the migration_needs_manual_bg.sql been run? It adds the needs_manual_bg column.</div>';
        return;
      }

      if (countEl) countEl.textContent = rows.length ? (rows.length + ' flagged') : '0 flagged — queue empty';

      if (!rows.length) {
        list.innerHTML = '<div style="font-size:.65rem;color:var(--green);letter-spacing:.06em">// No products flagged for manual review. Run restore_sealed_bg.py --redo to populate.</div>';
        return;
      }

      list.innerHTML = rows.map(function(r) {
        var when = r.bg_flagged_at
          ? new Date(r.bg_flagged_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })
          : '—';
        var sub = [r.set_name, r.set_code, (r.product_type || '').replace(/_/g, ' ').toUpperCase()]
          .filter(Boolean).join(' · ');
        return '<div id="bgrev_' + _escJsAttr(r.id) + '" style="display:flex;gap:12px;border:1px solid var(--border);background:var(--surface2);padding:10px;align-items:flex-start">' +
          // Clickable thumbnail — opens the full-size image in a new
          // tab so the admin can preview the actual artwork at native
          // size. Box is portrait (96x140) so vertical products like
          // sleeved booster packs render at usable size; wide products
          // (booster boxes) still fit via object-fit:contain. Click
          // opens full-size in case the thumbnail itself doesn't tell
          // the whole story.
          (r.image_url
            ? '<a href="' + _escHtml(r.image_url) + '" target="_blank" rel="noopener" ' +
              'title="Click to view full-size image" ' +
              'style="width:96px;height:140px;flex-shrink:0;background:var(--surface);border:1px solid var(--border);display:flex;align-items:center;justify-content:center;overflow:hidden;cursor:zoom-in;text-decoration:none">' +
                // Raw image — admin tooling, low traffic, no transformation needed.
                '<img src="' + _escHtml(r.image_url) + '" alt="" loading="lazy" decoding="async" ' +
                  'style="max-width:100%;max-height:100%;object-fit:contain">' +
              '</a>'
            : '<div style="width:96px;height:140px;flex-shrink:0;background:var(--surface);border:1px solid var(--border);display:flex;align-items:center;justify-content:center;overflow:hidden">' +
                '<span style="color:var(--muted);font-size:.55rem">no img</span>' +
              '</div>') +
          '<div style="flex:1;min-width:0">' +
            '<div style="font-family:\'Space Mono\',monospace;font-size:.74rem;color:var(--text);font-weight:700;line-height:1.3">' + _escHtml(r.name || '—') + '</div>' +
            '<div style="font-family:\'Space Mono\',monospace;font-size:.58rem;color:var(--muted);letter-spacing:.04em;margin-top:2px">' + _escHtml(sub) + '</div>' +
            '<div style="font-family:\'Space Mono\',monospace;font-size:.55rem;color:rgba(184,115,51,.8);letter-spacing:.05em;margin-top:4px">FLAGGED ' + when + ' · ' + _escHtml((r.bg_failure_reason || 'no reason recorded').slice(0, 120)) + '</div>' +
            '<div style="display:flex;gap:6px;margin-top:8px;flex-wrap:wrap;align-items:center">' +
              '<input type="file" id="bgrevFile_' + _escJsAttr(r.id) + '" accept="image/*" style="display:none" onchange="adminBgReviewUpload(\'' + _escJsAttr(r.id) + '\', this.files[0])">' +
              '<button onclick="document.getElementById(\'bgrevFile_' + _escJsAttr(r.id) + '\').click()" style="font-family:\'Space Mono\',monospace;font-size:.58rem;letter-spacing:.05em;padding:5px 10px;border:1px solid var(--accent);background:transparent;color:var(--accent);cursor:pointer">Upload Cleaned Image</button>' +
              (r.price_source_url
                ? '<a href="' + _escHtml(r.price_source_url) + '" target="_blank" rel="noopener" style="font-family:\'Space Mono\',monospace;font-size:.58rem;letter-spacing:.05em;padding:5px 10px;border:1px solid var(--border);color:var(--muted);text-decoration:none">↗ PC Page</a>'
                : '') +
              '<button onclick="adminBgReviewApproveAsIs(\'' + _escJsAttr(r.id) + '\')" style="font-family:\'Space Mono\',monospace;font-size:.58rem;letter-spacing:.05em;padding:5px 10px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer" title="Mark this product as OK with its current image — clears the flag without uploading a new image">Approve As-Is</button>' +
              '<span id="bgrevStatus_' + _escJsAttr(r.id) + '" style="font-family:\'Space Mono\',monospace;font-size:.55rem;color:var(--muted);margin-left:4px"></span>' +
            '</div>' +
          '</div>' +
        '</div>';
      }).join('');
    }

    // Replace the flagged product's image in Supabase Storage with the
    // admin's hand-cleaned upload, then clear the needs_manual_bg flag.
    // Re-encodes to webp via _imgToWebpBlob so file sizes stay small.
    async function adminBgReviewUpload(rowId, file) {
      if (!currentUser?.is_admin) return;
      if (!file) return;
      var statusEl = document.getElementById('bgrevStatus_' + rowId);
      var setStat = function(msg, color) {
        if (statusEl) { statusEl.style.color = color || 'var(--muted)'; statusEl.textContent = '// ' + msg; }
      };
      setStat('reading file…');

      // Look up the row so we know the current storage path.
      var row;
      try {
        var res = await sb.from('catalog').select('id,image_url').eq('id', rowId).maybeSingle();
        if (res.error) throw res.error;
        row = res.data;
      } catch (e) {
        setStat('lookup error: ' + (e.message || e), 'var(--red)');
        return;
      }
      if (!row || !row.image_url) {
        setStat('row has no image_url', 'var(--red)');
        return;
      }

      // Parse storage path from public URL.
      var marker = '/storage/v1/object/public/card-images/';
      var i = row.image_url.indexOf(marker);
      if (i < 0) {
        setStat('image_url is not a Supabase Storage URL', 'var(--red)');
        return;
      }
      var storagePath = row.image_url.substring(i + marker.length).split('?')[0];

      // Re-encode upload to webp (smaller, faster). Fallback to original
      // bytes if webp encoding fails (some PNGs with weird color profiles).
      var conv;
      try {
        conv = await _imgToWebpBlob(file);
      } catch (e) {
        conv = { blob: file, ext: (file.name || '').split('.').pop() || 'png',
                 contentType: file.type || 'image/png' };
      }

      setStat('uploading ' + Math.round(conv.blob.size / 1024) + 'KB…');

      try {
        var up = await sb.storage.from('card-images').upload(storagePath, conv.blob, {
          upsert: true, contentType: 'image/webp'
        });
        if (up.error) throw up.error;
      } catch (e) {
        setStat('upload error: ' + (e.message || e), 'var(--red)');
        return;
      }

      // Clear the flag now that a fresh image is in place.
      try {
        var clear = await sb.from('catalog').update({
          needs_manual_bg:   false,
          bg_failure_reason: null,
          bg_flagged_at:     null,
        }).eq('id', rowId);
        if (clear.error) throw clear.error;
      } catch (e) {
        setStat('uploaded but flag-clear failed: ' + (e.message || e), 'var(--red)');
        return;
      }

      setStat('done · row removed from queue', 'var(--green)');
      // Remove the card from the UI after a beat so the admin sees the
      // confirmation before it disappears.
      setTimeout(function() {
        var el = document.getElementById('bgrev_' + rowId);
        if (el) el.remove();
        var countEl = document.getElementById('adminBgReviewCount');
        if (countEl) {
          var m = (countEl.textContent || '').match(/^(\d+)/);
          if (m) countEl.textContent = (parseInt(m[1], 10) - 1) + ' flagged';
        }
      }, 900);
    }

    // Clears needs_manual_bg without uploading a new image — useful when
    // the admin reviews the current image and decides it's acceptable
    // as-is (e.g. the off-white bg actually looks fine on the binder
    // surface).
    async function adminBgReviewApproveAsIs(rowId) {
      if (!currentUser?.is_admin) return;
      if (!confirm('Mark this product as OK with its current image and clear the manual-review flag?')) return;
      var statusEl = document.getElementById('bgrevStatus_' + rowId);
      var setStat = function(msg, color) {
        if (statusEl) { statusEl.style.color = color || 'var(--muted)'; statusEl.textContent = '// ' + msg; }
      };
      try {
        var clear = await sb.from('catalog').update({
          needs_manual_bg:   false,
          bg_failure_reason: null,
          bg_flagged_at:     null,
        }).eq('id', rowId);
        if (clear.error) throw clear.error;
      } catch (e) {
        setStat('flag-clear error: ' + (e.message || e), 'var(--red)');
        return;
      }
      setStat('approved as-is', 'var(--green)');
      setTimeout(function() {
        var el = document.getElementById('bgrev_' + rowId);
        if (el) el.remove();
        var countEl = document.getElementById('adminBgReviewCount');
        if (countEl) {
          var m = (countEl.textContent || '').match(/^(\d+)/);
          if (m) countEl.textContent = (parseInt(m[1], 10) - 1) + ' flagged';
        }
      }, 700);
    }
    // ── End Sealed BG Review Queue ────────────────────────────────────────

    // Admin: refund a marketplace order via the Stripe refund API.
    // Calls /api/refund-order with the current user's auth token; the
    // backend re-verifies admin status before issuing the Stripe refund.
    async function adminRefundOrder() {
      if (!currentUser?.is_admin) return;
      var idEl     = document.getElementById('adminRefundOrderId');
      var reasonEl = document.getElementById('adminRefundReason');
      var statusEl = document.getElementById('adminRefundStatus');
      var orderId  = (idEl?.value || '').trim();
      var reason   = reasonEl?.value || 'requested_by_customer';
      if (!orderId) {
        if (statusEl) { statusEl.style.color = 'var(--red)'; statusEl.textContent = '// Enter an order id'; }
        return;
      }
      if (!confirm('Refund order ' + orderId.slice(0, 8) + '…?\n\nThis will refund the buyer via Stripe, mark the order refunded, and restore the listing to available.')) return;

      if (statusEl) { statusEl.style.color = 'var(--muted)'; statusEl.textContent = '// Refunding via Stripe…'; }

      try {
        var session = await sb.auth.getSession();
        var token = session?.data?.session?.access_token || '';
        var res = await fetch('/api/refund-order', {
          method: 'POST',
          headers: {
            'Content-Type':  'application/json',
            'Authorization': 'Bearer ' + token,
          },
          body: JSON.stringify({ orderId: orderId, reason: reason }),
        });
        var body = await res.json();
        if (!res.ok || !body.success) {
          if (statusEl) { statusEl.style.color = 'var(--red)'; statusEl.textContent = '// Error: ' + (body.error || ('HTTP ' + res.status)); }
          return;
        }
        if (statusEl) {
          statusEl.style.color = 'var(--accent)';
          statusEl.textContent = '// Refunded $' + Number(body.amount).toFixed(2) + ' (' + body.status + ') · refund id ' + (body.refundId || '').slice(0, 16);
        }
        if (idEl) idEl.value = '';
        // Refresh local orders cache so the admin sees the new status
        try { loadOrders(); } catch (_) {}
      } catch (e) {
        if (statusEl) { statusEl.style.color = 'var(--red)'; statusEl.textContent = '// Network error: ' + e.message; }
      }
    }

    // ── Shop tier sales metrics ─────────────────────────────────────────────
    // Pulls aggregated marketplace numbers from the two SQL views:
    //   shop_tier_platform_metrics  — single-row rollup (platform-wide)
    //   shop_seller_metrics         — per-shop breakdown
    // Used by:
    //   #1 admin panel section (full table, this function)
    //   #2 per-shop "My Business" dashboard widget (own row only)
    //   #3 public marketing snippet — gated by _FEATURE_SHOP_MARKETING flag
    //      (hidden for now per product decision; flip flag when ready)
    window._FEATURE_SHOP_MARKETING = false;

    async function _fetchShopTierPlatformMetrics() {
      try {
        var res = await sb.from('shop_tier_platform_metrics').select('*').maybeSingle();
        if (res.error) {
          if (String(res.error.message || '').toLowerCase().includes('does not exist')) {
            return { _missing: true };
          }
          throw res.error;
        }
        return res.data || {};
      } catch (e) {
        return { _error: e.message || String(e) };
      }
    }
    async function _fetchShopSellerMetrics(sellerId) {
      try {
        var q = sb.from('shop_seller_metrics').select('*');
        if (sellerId) q = q.eq('seller_id', sellerId).maybeSingle();
        else          q = q.order('gross_gmv', { ascending: false }).limit(50);
        var res = await q;
        if (res.error) {
          if (String(res.error.message || '').toLowerCase().includes('does not exist')) {
            return { _missing: true };
          }
          throw res.error;
        }
        return res.data || (sellerId ? null : []);
      } catch (e) {
        return { _error: e.message || String(e) };
      }
    }

    function _fmtMoney(n) {
      var num = Number(n || 0);
      if (num >= 1000) return '$' + (num / 1000).toFixed(1) + 'k';
      return '$' + num.toFixed(2);
    }
    function _fmtDate(s) {
      if (!s) return '—';
      // Sitewide compact format — delegates to _pbCompactDate so M/D/YY
      // is consistent across the app. _pbCompactDate handles weird
      // input shapes (YYYY/MM/DD, ISO, Date objects) and returns ''.
      var compact = typeof _pbCompactDate === 'function' ? _pbCompactDate(s) : '';
      if (compact) return compact;
      try { return new Date(s).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' }); }
      catch(_) { return s; }
    }

    async function adminLoadShopMetrics() {
      if (!currentUser?.is_admin) return;
      var panel = document.getElementById('adminShopMetricsPanel');
      if (!panel) return;
      panel.innerHTML = '<div style="color:var(--muted)">Loading metrics…</div>';

      var [platform, sellers] = await Promise.all([
        _fetchShopTierPlatformMetrics(),
        _fetchShopSellerMetrics(),
      ]);

      if (platform && platform._missing) {
        panel.innerHTML = '<div style="color:var(--red)">SQL views not installed. Run <code>migration_shop_seller_metrics.sql</code> first.</div>';
        return;
      }
      if (platform && platform._error) {
        panel.innerHTML = '<div style="color:var(--red)">Load error: ' + _escHtml(platform._error) + '</div>';
        return;
      }

      // Platform rollup tiles
      var p = platform || {};
      var rollupHtml = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px;margin-bottom:14px">' +
        '<div style="border:1px solid var(--border);padding:10px 12px;background:var(--surface2)">' +
          '<div style="font-size:.55rem;letter-spacing:.1em;color:var(--muted);margin-bottom:4px">ACTIVE SHOPS</div>' +
          '<div style="font-size:1.05rem;font-weight:700;color:var(--text)">' + (p.active_shops || 0) + '</div>' +
        '</div>' +
        '<div style="border:1px solid var(--border);padding:10px 12px;background:var(--surface2)">' +
          '<div style="font-size:.55rem;letter-spacing:.1em;color:var(--muted);margin-bottom:4px">TOTAL GMV</div>' +
          '<div style="font-size:1.05rem;font-weight:700;color:var(--green)">' + _fmtMoney(p.total_platform_gmv) + '</div>' +
        '</div>' +
        '<div style="border:1px solid var(--border);padding:10px 12px;background:var(--surface2)">' +
          '<div style="font-size:.55rem;letter-spacing:.1em;color:var(--muted);margin-bottom:4px">GMV · LAST 30D</div>' +
          '<div style="font-size:1.05rem;font-weight:700;color:var(--accent)">' + _fmtMoney(p.gmv_last_30d) + '</div>' +
        '</div>' +
        '<div style="border:1px solid var(--border);padding:10px 12px;background:var(--surface2)">' +
          '<div style="font-size:.55rem;letter-spacing:.1em;color:var(--muted);margin-bottom:4px">SALES · LAST 30D</div>' +
          '<div style="font-size:1.05rem;font-weight:700;color:var(--text)">' + (p.sales_last_30d || 0) + '</div>' +
        '</div>' +
      '</div>';

      // Per-shop table
      var rows = Array.isArray(sellers) ? sellers : [];
      var tableHtml;
      if (!rows.length) {
        tableHtml = '<div style="color:var(--muted);padding:10px 0">No shop sellers with sales yet.</div>';
      } else {
        tableHtml = '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:.6rem">' +
          '<thead><tr style="text-align:left;color:var(--muted);letter-spacing:.08em">' +
            '<th style="padding:6px 8px;border-bottom:1px solid var(--border)">SHOP</th>' +
            '<th style="padding:6px 8px;border-bottom:1px solid var(--border);text-align:right">GMV</th>' +
            '<th style="padding:6px 8px;border-bottom:1px solid var(--border);text-align:right">SALES</th>' +
            '<th style="padding:6px 8px;border-bottom:1px solid var(--border);text-align:right">30D GMV</th>' +
            '<th style="padding:6px 8px;border-bottom:1px solid var(--border);text-align:right">30D SALES</th>' +
            '<th style="padding:6px 8px;border-bottom:1px solid var(--border)">LAST SALE</th>' +
          '</tr></thead><tbody>' +
          rows.map(function(r) {
            var label = r.username ? '@' + r.username : (r.name || r.seller_id);
            return '<tr style="border-bottom:1px solid var(--border)">' +
              '<td style="padding:6px 8px;color:var(--text)">' + _escHtml(label) + '</td>' +
              '<td style="padding:6px 8px;color:var(--green);text-align:right">' + _fmtMoney(r.gross_gmv) + '</td>' +
              '<td style="padding:6px 8px;text-align:right">' + (r.confirmed_sales || 0) + '</td>' +
              '<td style="padding:6px 8px;color:var(--accent);text-align:right">' + _fmtMoney(r.gmv_last_30d) + '</td>' +
              '<td style="padding:6px 8px;text-align:right">' + (r.sales_last_30d || 0) + '</td>' +
              '<td style="padding:6px 8px;color:var(--muted)">' + _fmtDate(r.last_sale_at) + '</td>' +
            '</tr>';
          }).join('') +
          '</tbody></table></div>';
      }

      panel.innerHTML = rollupHtml + tableHtml;
    }

    // Per-shop "My Business" dashboard widget HTML. Returns '' when the
    // current user isn't shop-tier or the views aren't installed yet —
    // dashboard render gracefully skips an empty string.
    async function buildShopBusinessWidget() {
      if (!currentUser) return '';
      var tier = (currentUser && currentUser.subscription_tier) ||
                 (typeof currentTier === 'string' ? currentTier : '');
      if (tier !== 'shop') return '';
      var me = await _fetchShopSellerMetrics(currentUser.id);
      if (!me || me._missing || me._error) return '';
      var stats = me || {};
      return '<div class="ndash-panel" data-panel-id="my-business" style="margin-bottom:14px">' +
        '<div class="ndash-panel-h">' +
          '<div class="ndash-panel-title">My Business</div>' +
        '</div>' +
        '<div class="ndash-panel-body" style="padding:12px">' +
          '<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px">' +
            '<div style="border:1px solid var(--border);padding:8px 10px;background:var(--surface2)">' +
              '<div style="font-size:.55rem;color:var(--muted);letter-spacing:.08em">LIFETIME GMV</div>' +
              '<div style="font-size:1rem;font-weight:700;color:var(--green)">' + _fmtMoney(stats.gross_gmv) + '</div>' +
            '</div>' +
            '<div style="border:1px solid var(--border);padding:8px 10px;background:var(--surface2)">' +
              '<div style="font-size:.55rem;color:var(--muted);letter-spacing:.08em">SALES</div>' +
              '<div style="font-size:1rem;font-weight:700;color:var(--text)">' + (stats.confirmed_sales || 0) + '</div>' +
            '</div>' +
            '<div style="border:1px solid var(--border);padding:8px 10px;background:var(--surface2)">' +
              '<div style="font-size:.55rem;color:var(--muted);letter-spacing:.08em">30D GMV</div>' +
              '<div style="font-size:1rem;font-weight:700;color:var(--accent)">' + _fmtMoney(stats.gmv_last_30d) + '</div>' +
            '</div>' +
            '<div style="border:1px solid var(--border);padding:8px 10px;background:var(--surface2)">' +
              '<div style="font-size:.55rem;color:var(--muted);letter-spacing:.08em">UNIQUE BUYERS</div>' +
              '<div style="font-size:1rem;font-weight:700;color:var(--text)">' + (stats.unique_buyers || 0) + '</div>' +
            '</div>' +
          '</div>' +
        '</div>' +
      '</div>';
    }

    // Marketing snippet — hidden by default per product decision. Flip
    // window._FEATURE_SHOP_MARKETING to true to render on the Shop card
    // of the pricing modal. Numbers come from the platform rollup view.
    async function buildShopMarketingSnippet() {
      if (!window._FEATURE_SHOP_MARKETING) return '';
      var p = await _fetchShopTierPlatformMetrics();
      if (!p || p._missing || p._error) return '';
      return '<div style="margin-top:12px;padding:10px 12px;border:1px solid rgba(26,199,160,.3);background:rgba(26,199,160,.05);border-radius:4px">' +
        '<div style="font-size:.55rem;letter-spacing:.1em;color:var(--accent);margin-bottom:6px">SHOPS ON PATHBINDER</div>' +
        '<div style="display:flex;gap:14px;flex-wrap:wrap;font-size:.68rem">' +
          '<span><strong style="color:var(--green)">' + _fmtMoney(p.total_platform_gmv) + '</strong> <span style="color:var(--muted)">moved</span></span>' +
          '<span><strong style="color:var(--text)">' + (p.total_confirmed_sales || 0) + '</strong> <span style="color:var(--muted)">sales</span></span>' +
          '<span><strong style="color:var(--accent)">' + (p.active_shops || 0) + '</strong> <span style="color:var(--muted)">active shops</span></span>' +
        '</div>' +
      '</div>';
    }

    async function adminBackfillUserImages() {
      if (!currentUser?.is_admin) return;
      const val = (document.getElementById('adminBackfillUsername')?.value || '').trim();
      const statusEl = document.getElementById('adminBackfillStatus');
      if (!val || !statusEl) return;
      statusEl.textContent = '// Looking up user…';

      // Match by username or display name (case-insensitive)
      const { data: profiles } = await sb.from('profiles')
        .select('id, name, username')
        .or(`username.ilike.%${val}%,name.ilike.%${val}%`)
        .limit(5);

      if (!profiles?.length) { statusEl.textContent = '// No matching user found.'; return; }

      // If multiple matches, show the list so admin can be more specific
      if (profiles.length > 1) {
        statusEl.innerHTML = `// Multiple matches — be more specific:<br>` +
          profiles.map(p => `&nbsp;• ${p.name || '—'} (@${p.username || '—'})`).join('<br>');
        return;
      }

      const profile = profiles[0];
      const label = profile.name || profile.username || profile.id;
      statusEl.textContent = `// Found: ${label}. Fetching cards with missing images…`;

      // Cards that have api_card_id but no card_image_url
      const { data: items, error: fetchErr } = await sb.from('collection_items')
        .select('id, card_name, api_card_id')
        .eq('user_id', profile.id)
        .not('api_card_id', 'is', null)
        .is('card_image_url', null);

      if (fetchErr) { statusEl.textContent = `// DB error: ${fetchErr.message}`; return; }
      if (!items?.length) {
        statusEl.textContent = `// ${label}: no cards need backfill (all have images or no api_card_id).`;
        return;
      }

      statusEl.textContent = `// ${items.length} card(s) to backfill for ${label}. Running…`;
      let fixed = 0, notFound = 0;

      for (let i = 0; i < items.length; i++) {
        const item = items[i];
        statusEl.textContent = `// Backfilling ${i + 1}/${items.length}: ${item.card_name}…`;
        try {
          const { data: catRow } = await sb.from('catalog')
            .select('image_url').eq('id', item.api_card_id).maybeSingle();
          if (catRow?.image_url) {
            await sb.from('collection_items')
              .update({ card_image_url: catRow.image_url })
              .eq('id', item.id);
            fixed++;
          } else { notFound++; }
        } catch(_) { notFound++; }
      }

      statusEl.innerHTML = `// Done for <strong>${label}</strong>: ✓ ${fixed} backfilled${notFound ? `, ${notFound} not in catalog (may need manual entry)` : ''}.`;
    }

    function renderAdminTable() {
      const tbody = document.getElementById('listingsTable');
      tbody.innerHTML = listings.map((l, i) => `<tr>
        <td><img src="${(l.photos && l.photos[0]) ? _pickThumbVariant(l.photos[0], 200) : ''}" data-fallback="${(l.photos && l.photos[0]) ? l.photos[0] : ''}" alt="" class="admin-card-img" onerror="if(this.dataset.fallback&&this.src!==this.dataset.fallback){this.src=this.dataset.fallback}else{this.style.display='none';this.onerror=null}" / loading="lazy" decoding="async"></td>
        <td>${l.name}</td>
        <td>${l.grade}</td>
        <td>${l.type}</td>
        <td>$${l.value ? Number(l.value).toLocaleString() : '—'}</td>
        <td>${l.totalSlots}</td>
        <td><span class="badge badge-${l.status}">${l.status}</span></td>
        <td>
          <button class="action-btn" onclick="openEditListing('${l.id}')">Edit</button>
          <button class="action-btn danger" onclick="confirmDeleteListing('${l.id}')">Delete</button>
        </td>
      </tr>`).join('');
    }

    function adminLookupUser(val) {
      return; // slot assignment removed
      clearTimeout(assignLookupTimer);
      const resultEl = document.getElementById('assignUserResult');
      resolvedAssignUser = null;
      if (!val || val.length < 2) { resultEl.textContent = ''; return; }
      resultEl.textContent = 'Searching...';
      resultEl.style.color = 'var(--muted)';
      assignLookupTimer = setTimeout(async () => {
        try {
          // Search by username first
          let found = null;
          const { data: byUsername } = await sb.from('profiles')
            .select('id, name, username, email')
            .ilike('username', `%${val}%`)
            .limit(5);
          if (byUsername?.length > 0) {
            found = byUsername[0];
          } else {
            // Try email if username didn't match
            const { data: byEmail } = await sb.from('profiles')
              .select('id, name, username, email')
              .ilike('email', `%${val}%`)
              .limit(5);
            if (byEmail?.length > 0) found = byEmail[0];
          }
          if (found) {
            resolvedAssignUser = found;
            resultEl.style.color = 'var(--green, #10b981)';
            resultEl.textContent = `✅ Found: ${found.name} (@${found.username})${found.email ? ' — ' + found.email : ''}`;
          } else {
            resultEl.style.color = '#ef4444';
            resultEl.textContent = '⚠️ No user found. Make sure they have registered.';
          }
        } catch (err) {
          resultEl.style.color = '#ef4444';
          resultEl.textContent = '⚠️ Search error: ' + err.message;
        }
      }, 400);
    }

    async function adminAssignSlot() {
      const listingId = document.getElementById('assignListingId').value;
      const slotIdxInput = document.getElementById('assignSlotIdx').value.trim();
      const slotCountInput = parseInt(document.getElementById('assignSlotCount')?.value) || 0;
      const userSearch = document.getElementById('assignUserSearch').value.trim();
      const statusEl = document.getElementById('assignStatus');

      if (!listingId || !userSearch) {
        statusEl.textContent = '⚠️ Please select a listing and enter a user.';
        statusEl.style.color = '#ef4444';
        return;
      }

      // Use already-resolved user or look up now
      let profile = resolvedAssignUser;
      if (!profile) {
        const { data: byUsername } = await sb.from('profiles')
          .select('id, name, username, email')
          .ilike('username', `%${userSearch}%`)
          .limit(1);
        if (byUsername?.length > 0) {
          profile = byUsername[0];
        } else {
          const { data: byEmail } = await sb.from('profiles')
            .select('id, name, username, email')
            .ilike('email', `%${userSearch}%`)
            .limit(1);
          if (byEmail?.length > 0) profile = byEmail[0];
        }
      }

      if (!profile) {
        statusEl.textContent = '⚠️ User not found. Make sure they have registered and confirmed their email.';
        statusEl.style.color = '#ef4444';
        return;
      }

      const userId = profile.id;
      const userName = profile.name || profile.username;
      statusEl.textContent = 'Assigning slots...';
      statusEl.style.color = 'var(--muted)';

      // Build list of slot indices from input (supports "1,2,3" or "5-10" or "1,3,7-9")
      let targetIndices = [];
      if (slotIdxInput) {
        for (const part of slotIdxInput.split(',')) {
          const range = part.trim().split('-');
          if (range.length === 2) {
            const from = parseInt(range[0]), to = parseInt(range[1]);
            for (let i = from; i <= to; i++) targetIndices.push(i);
          } else {
            const n = parseInt(part.trim());
            if (!isNaN(n)) targetIndices.push(n);
          }
        }
      }

      let slotsToAssign = [];
      if (targetIndices.length > 0) {
        const { data: found } = await sb.from('slots')
          .select('*').eq('listing_id', listingId).in('idx', targetIndices);
        const already = found?.filter(s => s.user_id) || [];
        if (already.length > 0) {
          statusEl.textContent = `⚠️ Already owned: slot(s) #${already.map(s => s.idx).join(', ')}`;
          statusEl.style.color = '#ef4444';
          return;
        }
        slotsToAssign = found || [];
      } else {
        // Next X available slots
        const count = slotCountInput || 1;
        const { data: available } = await sb.from('slots')
          .select('*').eq('listing_id', listingId).is('user_id', null)
          .order('idx').limit(count);
        if (!available || available.length === 0) {
          statusEl.textContent = '⚠️ No available slots on this listing.';
          statusEl.style.color = '#ef4444';
          return;
        }
        slotsToAssign = available;
      }

      // Assign all slots
      const assignListing = listings.find(l => String(l.id) === String(listingId));
      const assignSlotPrice = assignListing && assignListing.totalSlots > 0
        ? Math.ceil(assignListing.value / assignListing.totalSlots) : 0;
      const assigned = [];
      for (const slot of slotsToAssign) {
        const { error } = await sb.from('slots')
          .update({ user_id: userId, ask_price: 0, trade_open: false }).eq('id', slot.id);
        if (error) { statusEl.textContent = `⚠️ Error on slot #${slot.idx}: ${error.message}`; statusEl.style.color = '#ef4444'; return; }
        await sb.from('transactions').insert({
          type: 'buy', listing_id: listingId, slot_idx: slot.idx,
          user_id: userId, amount: assignSlotPrice, fee: 0, note: 'Admin assignment'
        });
        const localSlot = slots.find(s => s.listingId === listingId && s.idx === slot.idx);
        if (localSlot) { localSlot.userId = userId; localSlot.name = userName; }
        assigned.push(slot.idx);
      }

      const listing = listings.find(l => l.id == listingId);
      statusEl.textContent = `✅ Assigned ${assigned.length} slot(s) [#${assigned.join(', ')}] of "${listing?.name}" to ${userName}!`;
      statusEl.style.color = 'var(--green, #10b981)';
      document.getElementById('assignSlotIdx').value = '';
      if (document.getElementById('assignSlotCount')) document.getElementById('assignSlotCount').value = '';
      resolvedAssignUser = null;
      document.getElementById('assignUserSearch').value = '';
      document.getElementById('assignUserResult').textContent = '';
    }

    async function triggerPriceRefresh() {
      const btn      = document.getElementById('refreshPricesBtn');
      const statusEl = document.getElementById('priceRefreshStatus');

      // Build the list of cards that have a price source URL to look up
      const toRefresh = collectionItems.filter(c => !c.sold_offline && c.price_source_url);
      if (!toRefresh.length) {
        statusEl.style.display = 'block';
        statusEl.textContent = '[ INFO ] No cards with price URLs found. Add a price source URL to a card first.';
        return;
      }

      btn.disabled = true;
      btn.textContent = 'Refreshing...';
      statusEl.style.display = 'block';

      let updated = 0, errors = 0;
      for (let i = 0; i < toRefresh.length; i++) {
        const item = toRefresh[i];
        statusEl.textContent = `[ ${i + 1}/${toRefresh.length} ] Looking up ${item.card_name}…`;
        try {
          const condition = _priceCondition(item);
          const res = await fetch('/api/lookup-price', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: item.card_name, condition, url: item.price_source_url })
          });
          const data = await res.json();
          if (data.price) {
            const oldPrice = item.current_value;
            const { error } = await sb.from('collection_items')
              .update({ current_value: data.price })
              .eq('id', item.id);
            if (!error) {
              item.current_value = data.price;
              if (oldPrice !== data.price) {
                const todayStr = new Date().toISOString().slice(0, 10);
                sb.from('price_history').upsert({
                  collection_item_id: item.id,
                  user_id: currentUser.id,
                  recorded_value: data.price,
                  recorded_at: todayStr
                }, { onConflict: 'collection_item_id,recorded_at' }).then(null, () => {});
              }
              updated++;
            } else { errors++; }
          }
        } catch (_) { errors++; }
        // Polite pause between requests — avoids hammering the price API
        await new Promise(r => setTimeout(r, 500));
      }

      btn.disabled = false;
      btn.textContent = 'Refresh Prices';
      statusEl.textContent = `[ DONE ] ${updated} updated, ${errors} errors out of ${toRefresh.length} cards.`;
      if (updated > 0) {
        renderBinder();
        renderDashboard();
        showToast(`${updated} price(s) updated`);
      }
    }

    function toggleAddForm() {
      document.getElementById('addFormWrap').classList.toggle('open');
    }

    async function addListing() {
      // Clear previous validation errors
      ['cardName','cardGrade','cardType','cardValue','cardSlots'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.border = '';
      });

      const name = document.getElementById('cardName').value.trim();
      const grade = document.getElementById('cardGrade').value;
      const type = document.getElementById('cardType').value.trim();
      const gameType = document.getElementById('cardGameType')?.value || type;
      const value = parseInt(document.getElementById('cardValue').value);
      const totalSlots = parseInt(document.getElementById('cardSlots').value);
      const status = document.getElementById('cardStatus').value;
      const certNumber = document.getElementById('cardCertNumber')?.value || 'N/A';
      const vaultLocation = document.getElementById('cardVaultLocation')?.value || 'Standard Vault';
      const insured = document.getElementById('cardInsured')?.checked || true;
      const priceSourceUrl = document.getElementById('cardPriceSourceUrl')?.value?.trim() || null;

      // Validate each field and collect errors
      const missing = [];
      if (!name) { missing.push('Card Name'); document.getElementById('cardName').style.border = '2px solid #ef4444'; }
      if (!grade) { missing.push('Grade'); document.getElementById('cardGrade').style.border = '2px solid #ef4444'; }
      if (!type) { missing.push('Card Type'); document.getElementById('cardType').style.border = '2px solid #ef4444'; }
      if (!value || isNaN(value) || value <= 0) { missing.push('Card Value'); document.getElementById('cardValue').style.border = '2px solid #ef4444'; }
      if (!totalSlots || isNaN(totalSlots) || totalSlots <= 0) { missing.push('Number of Slots'); document.getElementById('cardSlots').style.border = '2px solid #ef4444'; }
      if (pendingPhotoUrls.length === 0) { missing.push('At least one photo'); document.getElementById('photoUploadArea').style.border = '2px dashed #ef4444'; }
      else { document.getElementById('photoUploadArea').style.border = '2px dashed var(--border)'; }

      if (missing.length > 0) {
        showToast('Please fill in: ' + missing.join(', '));
        return;
      }

      const newListing = {
        name, grade, type, gameType, value, totalSlots, status,
        earlyAccessOnly: status === 'early',
        photos: [...pendingPhotoUrls],
        countdown: null,
        certNumber, vaultLocation, insured,
        priceHistory: [{date: new Date().toISOString().split('T')[0], price: value}],
        sellVotes: []
      };

      // Write to Supabase first to get a real UUID
      const { data: dbListing, error } = await sb.from('listings').insert({
        name: newListing.name,
        grade: newListing.grade,
        game_type: newListing.gameType || 'Other',
        card_type: newListing.type || '',
        value: newListing.value,
        total_slots: newListing.totalSlots,
        status: newListing.status,
        early_access_only: newListing.earlyAccessOnly || false,
        cert_number: newListing.certNumber || '',
        vault_location: newListing.vaultLocation || '',
        insured: newListing.insured !== false,
        price_source_url: priceSourceUrl,
        photos: newListing.photos || [],
        price_history: [],
        sell_votes: []
      }).select().single();

      if (error) {
        showToast('Error saving listing: ' + error.message);
        return;
      }

      // Use the real DB id
      newListing.id = dbListing.id;
      listings.unshift(newListing);

      // Create slots in Supabase
      const slotRows = Array.from({ length: newListing.totalSlots }, (_, i) => ({
        listing_id: dbListing.id,
        idx: i + 1,
        user_id: null,
        ask_price: 0,
        trade_open: false
      }));

      // Insert slots in batches of 100 to avoid request size limits
      for (let i = 0; i < slotRows.length; i += 100) {
        const { error: slotErr } = await sb.from('slots').insert(slotRows.slice(i, i + 100));
        if (slotErr) {
          showToast('Warning: slots may not have saved — ' + slotErr.message);
          console.error('Slots insert error:', slotErr);
        }
      }

      // Re-fetch the newly inserted slots from DB to get real UUIDs
      const { data: freshSlots } = await sb.from('slots').select('*').eq('listing_id', dbListing.id).order('idx');
      if (freshSlots && freshSlots.length > 0) {
        freshSlots.forEach(s => {
          slots.push({
            id: s.id,
            listingId: s.listing_id,
            idx: s.idx,
            userId: s.user_id,
            name: null,
            askPrice: s.ask_price > 0 ? s.ask_price : null,
            tradeOpen: s.trade_open || false
          });
        });
      } else {
        // Fallback: add to local array without real IDs (better than nothing)
        slotRows.forEach((s, i) => {
          slots.push({
            id: null,
            listingId: dbListing.id,
            idx: i + 1,
            userId: null,
            name: null,
            askPrice: null,
            tradeOpen: false
          });
        });
      }

      // Reset form state FIRST before any re-renders
      pendingPhotoUrls = [];
      document.getElementById('cardName').value = '';
      document.getElementById('cardGrade').value = '';
      document.getElementById('cardType').value = '';
      document.getElementById('cardValue').value = '';
      document.getElementById('cardSlots').value = '';
      const previewGrid = document.getElementById('photoPreviewGrid');
      if (previewGrid) previewGrid.innerHTML = '';
      const uploadStatus = document.getElementById('photoUploadStatus');
      if (uploadStatus) uploadStatus.textContent = '';
      const fileInput = document.getElementById('photoFileInput');
      if (fileInput) fileInput.value = '';
      const uploadArea = document.getElementById('photoUploadArea');
      if (uploadArea) uploadArea.style.border = '2px dashed var(--border)';

      toggleAddForm();
      renderAdmin();
      renderBrowse();
      showToast('Listing added successfully!');
    }

