    function openShopIntake() {
      document.getElementById('shopIntakeForm').style.display = 'block';
      document.getElementById('shopIntakeForm').scrollIntoView({ behavior: 'smooth' });
      if (currentUser?.email) document.getElementById('shopEmail').value = currentUser.email;
    }

    async function submitShopIntake() {
      const bizName = document.getElementById('shopBizName').value.trim();
      const bizType = document.getElementById('shopBizType').value;
      const volume  = document.getElementById('shopVolume').value.trim();
      const email   = document.getElementById('shopEmail').value.trim();
      if (!bizName || !bizType || !email) { showToast('Please fill in all required fields'); return; }
      try {
        await sb.from('shop_inquiries').insert({
          user_id: currentUser?.id || null,
          business_name: bizName, business_type: bizType,
          monthly_volume: volume, contact_email: email,
          submitted_at: new Date().toISOString(),
        });
      } catch (_) {}
      showToast('✓ Submitted! The PathBinder team will be in touch shortly.');
      closeModal('membershipModal');
    }

    function upgradeTier(tierId) {
      if (!currentUser) { openModal('loginModal'); closeModal('membershipModal'); return; }
      closeModal('membershipModal');
      initiateMembershipCheckout(tierId);
    }

    document.getElementById('membershipBtn').addEventListener('click', () => openPricingModal());

    // Legacy compat — kept in case other code calls it
    function upgradeMembership() { openPricingModal(); }

    // ===== TOAST & NOTIFICATIONS =====
    function showToast(message) {
      const toast = document.createElement('div');
      toast.className = 'toast';
      toast.textContent = message;
      document.body.appendChild(toast);
      setTimeout(() => {
        toast.style.animation = 'slideOutLeft .3s ease';
        setTimeout(() => toast.remove(), 300);
      }, 2000);
    }

    // ── Global error boundary ──────────────────────────────────────────
    // Catches uncaught synchronous errors AND unhandled promise rejections
    // so a single misbehaving handler doesn't dump the user on a silent
    // white screen. Logs detail to the console for debugging, surfaces a
    // user-friendly toast, and rate-limits to one toast per 5s so a
    // runaway error loop doesn't spam the screen.
    let _lastErrorToastAt = 0;
    function _surfaceCaughtError(detail) {
      const now = Date.now();
      console.error('[caught]', detail);
      if (now - _lastErrorToastAt < 5000) return;
      _lastErrorToastAt = now;
      try { showToast('Something went wrong — refresh if it sticks'); } catch (_) {}
    }
    window.addEventListener('error', function(ev) {
      // Ignore network-only errors from images / scripts loaded via <img loading="lazy" decoding="async">
      // / <link> — those are noisy and not actionable for the user.
      if (ev && ev.target && ev.target !== window
          && (ev.target.tagName === 'IMG' || ev.target.tagName === 'LINK' || ev.target.tagName === 'SCRIPT')) {
        return;
      }
      _surfaceCaughtError({
        message: ev.message,
        source:  ev.filename + ':' + ev.lineno + ':' + ev.colno,
        error:   ev.error && ev.error.stack ? ev.error.stack : (ev.error || null),
      });
    });
    window.addEventListener('unhandledrejection', function(ev) {
      _surfaceCaughtError({
        message: 'unhandled promise rejection',
        reason:  ev.reason && ev.reason.stack ? ev.reason.stack : (ev.reason || null),
      });
    });




    // ===== PRICE ALERTS =====
    async function togglePriceAlert(listingId) {
      if (!currentUser) { openModal('loginModal'); return; }
      const existing = currentUser.watchlist || [];
      const isWatching = existing.includes(listingId);
      // Reuse watchlist as the alert list (already stored in profiles)
      // Toggle
      let newList = isWatching ? existing.filter(id => id !== listingId) : [...existing, listingId];
      await sb.from('profiles').update({ watchlist: newList }).eq('id', currentUser.id);
      currentUser.watchlist = newList;
      showToast(isWatching ? 'Alert removed' : 'You\'ll be notified when this listing changes');
      // Re-render current detail if open
      const detailEl = document.getElementById('detailView');
      if (detailEl && detailEl.dataset.listingId === String(listingId)) {
        viewDetail(listingId);
      }
    }

    // ===== LEADERBOARD =====
    function renderLeaderboard(mode) {
      // Update active tab
      if (mode) {
        document.querySelectorAll('#leaderboardPage .section-tab').forEach(t => t.classList.remove('active'));
        const idx = ['value','slots','diverse'].indexOf(mode);
        const tabs = document.querySelectorAll('#leaderboardPage .section-tab');
        if (tabs[idx]) tabs[idx].classList.add('active');
      }
      const activeMode = mode || 'value';

      const el = document.getElementById('leaderboardContent');
      if (!el) return;
      if (!listings.length || !slots.length) {
        el.innerHTML = '<div style="text-align:center;padding:40px;color:var(--muted)">Loading data...</div>';
        return;
      }

      // Build stats per user from slots + listings
      const byUser = {};
      slots.forEach(s => {
        if (!s.userId) return;
        const listing = listings.find(l => String(l.id) === String(s.listingId));
        if (!listing || !listing.value || !listing.totalSlots) return;
        const slotValue = Math.ceil(listing.value / listing.totalSlots);
        if (!byUser[s.userId]) byUser[s.userId] = { userId: s.userId, slotCount: 0, totalValue: 0, cards: new Set() };
        byUser[s.userId].slotCount++;
        byUser[s.userId].totalValue += slotValue;
        byUser[s.userId].cards.add(String(s.listingId));
      });

      if (Object.keys(byUser).length === 0) {
        el.innerHTML = '<div style="text-align:center;padding:40px;color:var(--muted)">No data yet — be the first to buy a slot!</div>';
        return;
      }

      // Sort by active mode
      const ranked = Object.values(byUser).sort((a, b) => {
        if (activeMode === 'slots')   return b.slotCount - a.slotCount;
        if (activeMode === 'diverse') return b.cards.size - a.cards.size;
        return b.totalValue - a.totalValue; // 'value' default
      }).slice(0, 50);

      // Column config per mode
      const colHeader = activeMode === 'slots' ? 'Slots Owned'
                      : activeMode === 'diverse' ? 'Unique Cards'
                      : 'Portfolio Value';

      // Use profilesMap for names (already loaded) + fetch any missing
      const missingIds = ranked.map(r => r.userId).filter(id => !profilesMap[id]);
      const fetchProfiles = missingIds.length > 0
        ? sb.from('profiles').select('id, name, username, is_premium, is_admin').in('id', missingIds)
            .then(({ data }) => { (data || []).forEach(p => { profilesMap[p.id] = p; }); })
        : Promise.resolve();

      fetchProfiles.then(() => {
        const medals = ['1ST', '2ND', '3RD'];
        const rows = ranked.map((r, i) => {
          const profile = profilesMap[r.userId] || {};
          const displayName = profile.username || profile.name || 'Anonymous';
          const isPrem = profile.is_premium || profile.is_admin;
          const medal = medals[i] || `#${i + 1}`;
          const isMe = currentUser && r.userId === currentUser.id;
          const statVal = activeMode === 'slots'   ? r.slotCount
                        : activeMode === 'diverse' ? r.cards.size
                        : '$' + r.totalValue.toLocaleString();
          const statColor = activeMode === 'value' ? 'var(--green)' : 'var(--teal)';
          // On mobile, hide the two columns that aren't the primary stat for this mode
          const hideSlots   = activeMode !== 'slots'   ? 'class="hm"' : '';
          const hideCards   = activeMode !== 'diverse' ? 'class="hm"' : '';
          const hideValue   = activeMode !== 'value'   ? 'class="hm"' : '';
          return `<tr style="${isMe ? 'background:rgba(124,92,252,.08);' : ''}">
            <td style="font-size:1.1rem;text-align:center;width:48px">${medal}</td>
            <td>
              <div style="font-weight:600;color:${isMe ? 'var(--accent)' : 'var(--text)'}">${displayName}${isMe ? ' <span style="font-size:.7rem;color:var(--accent)">(you)</span>' : ''}</div>
              ${isPrem ? '<div style="font-size:.7rem;color:var(--gold);margin-top:2px">★ Premium</div>' : ''}
            </td>
            <td ${hideSlots} style="text-align:center;color:var(--muted)">${r.slotCount}</td>
            <td ${hideCards} style="text-align:center;color:var(--muted)">${r.cards.size}</td>
            <td ${hideValue} style="text-align:right;font-weight:700;color:${statColor}">${statVal}</td>
          </tr>`;
        }).join('');

        el.innerHTML = `
          <div style="overflow-x:auto">
            <table class="tx-table" style="width:100%">
              <thead>
                <tr>
                  <th style="text-align:center">Rank</th>
                  <th>Collector</th>
                  <th ${activeMode !== 'slots'   ? 'class="hm"' : ''} style="text-align:center">Slots</th>
                  <th ${activeMode !== 'diverse' ? 'class="hm"' : ''} style="text-align:center">Cards</th>
                  <th ${activeMode !== 'value'   ? 'class="hm"' : ''} style="text-align:right">${colHeader}</th>
                </tr>
              </thead>
              <tbody>${rows}</tbody>
            </table>
          </div>
          ${currentUser && !byUser[currentUser.id] ? '<div style="margin-top:20px;padding:14px;background:var(--surface2);border-radius:8px;text-align:center;font-size:.9rem;color:var(--muted)">You\'re not ranked yet \u2014 buy your first slot to join the leaderboard!</div>' : ''}
        `;
      });
    }

