    // ===== COLLECTION PAGE (Phase 2) =====

    async function loadCollection() {
      if (!currentUser) { collectionItems = []; return; }
      const sevenAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
      const [collResult, histResult] = await Promise.all([
        sb.from('collection_items')
          .select('*')
          .eq('user_id', currentUser.id)
          .order('sort_order', { ascending: true, nullsFirst: false })
          .order('created_at',  { ascending: true }),
        sb.from('price_history')
          .select('collection_item_id, recorded_at, recorded_value')
          .eq('user_id', currentUser.id)
          .gte('recorded_at', sevenAgo)
          .order('recorded_at', { ascending: true })
      ]);
      if (!collResult.error && collResult.data) {
        // Attach price history log to each item
        const histMap = {};
        if (!histResult.error && histResult.data) {
          for (const h of histResult.data) {
            const cid = String(h.collection_item_id);
            if (!histMap[cid]) histMap[cid] = [];
            histMap[cid].push({ date: h.recorded_at, value: h.recorded_value });
          }
        }
        collectionItems = collResult.data.map(c => ({
          ...c,
          price_history_log: histMap[String(c.id)] || []
        }));
        // Pull live catalog.current_value into in-memory ghost rows so
        // wishlist progress + alerts reflect today's market price even
        // when the row was added long before the most recent daily refresh.
        // No DB writes — strictly in-memory enrichment.
        try { await _enrichGhostsFromCatalog(collectionItems); } catch(_) {}
        // Also enrich owned rows that have no current_value so the list
        // shows a comp-derived estimate instead of an em-dash when
        // PriceCharting has no row but TCGplayer (or vice versa) does.
        try { await _enrichOwnedFromComps(collectionItems); } catch(_) {}
        // Safety net — every collection refresh re-checks size-based badges
        // so any add-card path that calls loadCollection picks up the
        // STACKED + PHANTOM badge progress, even if it skipped a direct
        // checkBadge call.
        try { checkBadge_stacked(); } catch(_) {}
        try { checkBadge_phantom_p2(); } catch(_) {}
      }
    }

    async function loadPortfolioSnapshots() {
      if (!currentUser) return;
      const yearStart = new Date(new Date().getFullYear(), 0, 1).toISOString().slice(0, 10);
      const todayStr  = new Date().toISOString().slice(0, 10);

      // ── 1. Try the portfolio_snapshots table first ──────────────────────────
      const { data: snapData, error: snapError } = await sb
        .from('portfolio_snapshots')
        .select('snapshot_date, total_value')
        .eq('user_id', currentUser.id)
        .gte('snapshot_date', yearStart)
        .order('snapshot_date', { ascending: true });

      const tableExists = !snapError || !snapError.message?.includes('does not exist');

      if (!snapError && snapData && snapData.length > 0) {
        // Table has historical data — use it, write today's snapshot, done
        window._portfolioSnapshots = snapData;
        _writePortfolioSnapshot(todayStr, tableExists);
        return;
      }

      // ── 2. Fallback: synthesise chart from price_history ───────────────────
      // Fetch this user's full-year price history + owned card list in parallel
      const [histResult, collResult] = await Promise.all([
        sb.from('price_history')
          .select('collection_item_id, recorded_at, recorded_value')
          .eq('user_id', currentUser.id)
          .gte('recorded_at', yearStart)
          .order('recorded_at', { ascending: true }),
        sb.from('collection_items')
          .select('id, current_value, purchase_price, quantity, is_ghost, sold_offline')
          .eq('user_id', currentUser.id)
      ]);

      if (!histResult.error && histResult.data?.length && !collResult.error && collResult.data?.length) {
        window._portfolioSnapshots = _buildSnapshotsFromHistory(histResult.data, collResult.data);
      }

      // Write today's snapshot so the table starts accumulating going forward
      _writePortfolioSnapshot(todayStr, tableExists);
    }

    // Build synthetic portfolio snapshots by aggregating per-card price_history
    function _buildSnapshotsFromHistory(histEntries, cardItems) {
      const owned = cardItems.filter(c => !c.is_ghost && !c.sold_offline);

      // Map cardId → sorted price entries
      const cardHistMap = {};
      for (const h of histEntries) {
        const cid = String(h.collection_item_id);
        if (!cardHistMap[cid]) cardHistMap[cid] = [];
        cardHistMap[cid].push({ date: h.recorded_at.slice(0, 10), value: Number(h.recorded_value) });
      }

      // All unique dates where any price was logged
      const allDates = [...new Set(histEntries.map(h => h.recorded_at.slice(0, 10)))].sort();
      if (!allDates.length) return [];

      return allDates.map(date => {
        let total = 0;
        for (const card of owned) {
          const qty = card.quantity || 1;
          const hist = cardHistMap[String(card.id)] || [];
          // Most recent recorded price on or before this date
          const relevant = hist.filter(h => h.date <= date);
          const price = relevant.length
            ? relevant[relevant.length - 1].value
            : (card.current_value || card.purchase_price || 0);
          total += price * qty;
        }
        return { snapshot_date: date, total_value: total };
      });
    }

    function _writePortfolioSnapshot(todayStr, tableExists) {
      if (!tableExists || !currentUser) return;
      const ownedVal = collectionItems
        .filter(c => !c.is_ghost && !c.sold_offline)
        .reduce((s, c) => s + ((c.current_value || c.purchase_price || 0) * (c.quantity || 1)), 0);
      if (ownedVal > 0) {
        sb.from('portfolio_snapshots').upsert({
          user_id:       currentUser.id,
          snapshot_date: todayStr,
          total_value:   ownedVal,
          card_count:    collectionItems.filter(c => !c.is_ghost && !c.sold_offline).length
        }, { onConflict: 'user_id,snapshot_date' }).then(null, () => {});
      }
    }

