    // ===== ALL CARDS SORT =====
    // Sort state only applies to the "All Cards" view — never bleeds into individual binders.
    let allCardsSort = 'name'; // 'name' | 'rarity' | 'set' | 'value' | 'lang'
    let allCardsSortDir = { name: 1, rarity: 1, set: 1, value: -1, lang: 1 }; // 1=asc, -1=desc; rarity 1=highest first
    let _allCardsView = localStorage.getItem('pb_acView') || 'list'; // 'list' | 'acgrid'
    let _acOffset = 0, _acObserver = null, _acItems = [];
    const _AC_BATCH = 40;

    const _RARITY_SCORE = (r) => {
      if (!r) return -1;
      const k = r.toLowerCase();
      if (k.includes('special illustration') || k.includes('rainbow'))    return 10;
      if (k.includes('hyper') || k.includes('gold'))                       return 9;
      if (k.includes('secret'))                                             return 8;
      if (k.includes('full art') || k.includes('alternative art'))         return 7;
      if (k.includes('ultra') || k.includes('vmax') || k.includes('vstar'))return 6;
      if (k.includes('double rare'))                                        return 5;
      if (k.includes('holo v') || k.includes('rare holo ex'))              return 4;
      if (k.includes('holo'))                                               return 3;
      if (k.includes('rare'))                                               return 2;
      if (k.includes('uncommon'))                                           return 1;
      if (k.includes('common'))                                             return 0;
      return -1;
    };

    function setAllCardsSort(key, forceDir) {
      // forceDir lets callers (e.g. the mobile popover's ↓/↑ rows) pick
      // direction explicitly. Without it, clicking the same sort key
      // again toggles direction — the desktop pill-row behaviour.
      if (typeof forceDir === 'number') {
        allCardsSort = key;
        allCardsSortDir[key] = forceDir;
      } else if (allCardsSort === key) {
        allCardsSortDir[key] = allCardsSortDir[key] * -1; // toggle direction
      } else {
        allCardsSort = key;
      }
      // Update button labels to show current direction
      const dirSymbols = { name: ['Name A→Z','Name Z→A'], rarity: ['Rarity ↓','Rarity ↑'], set: ['Set A→Z','Set Z→A'], value: ['Value ↓','Value ↑'], lang: ['Language','Language'] };
      document.querySelectorAll('.allcards-sort-btn').forEach(b => b.classList.remove('active'));
      const btn = document.getElementById('sortBtn-' + key);
      const syms = dirSymbols[key] || [key, key];
      const currentLabel = allCardsSortDir[key] === 1 ? syms[0] : syms[1];
      if (btn) {
        btn.textContent = currentLabel;
        btn.classList.add('active');
      }
      // Mobile popover: sync trigger label + item active state
      const mLbl = document.getElementById('acSortLbl');
      if (mLbl) mLbl.textContent = currentLabel;
      // Active state for the popover:
      //  • All rows (.ac-sort-pop-item) get .active when their data-sort
      //    matches the current sort key — this includes Rarity / Value
      //    which use the same row class but also carry .ac-sort-pop-toggle.
      //  • Inside Rarity / Value rows the two ↓/↑ glyphs (.ac-sort-arrow)
      //    are static — we add .arrow-active to the one matching the
      //    current direction so the user sees which way it's sorting.
      document.querySelectorAll('.ac-sort-pop-item').forEach(el => {
        el.classList.toggle('active', el.dataset.sort === key);
      });
      document.querySelectorAll('.ac-sort-arrow').forEach(el => {
        const row = el.closest('[data-sort]');
        const rowKey = row?.dataset?.sort;
        const matches = rowKey === key
                     && parseInt(el.dataset.dir, 10) === allCardsSortDir[key];
        el.classList.toggle('arrow-active', matches);
      });
      binderPage = 0;
      renderBinder();
    }

