(function () {
  return; // panel decoration disabled — see notes above
  /* eslint-disable */
  const C = '#1AC7A0'; // accent cyan

  const cornerSVGs = {
    tl: `<svg width="32" height="32" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M2 16 L2 2 L16 2" stroke="${C}" stroke-width="1.2" fill="none" stroke-linecap="round"/><path d="M7 7 L11 7 L11 11" stroke="${C}" stroke-width="1" fill="none" stroke-linecap="round"/><circle cx="2" cy="2" r="1.8" fill="${C}"/></svg>`,
    tr: `<svg width="32" height="32" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M30 16 L30 2 L16 2" stroke="${C}" stroke-width="1.2" fill="none" stroke-linecap="round"/><path d="M25 7 L21 7 L21 11" stroke="${C}" stroke-width="1" fill="none" stroke-linecap="round"/><circle cx="30" cy="2" r="1.8" fill="${C}"/></svg>`,
    bl: `<svg width="32" height="32" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M2 16 L2 30 L16 30" stroke="${C}" stroke-width="1.2" fill="none" stroke-linecap="round"/><path d="M7 25 L11 25 L11 21" stroke="${C}" stroke-width="1" fill="none" stroke-linecap="round"/><circle cx="2" cy="30" r="1.8" fill="${C}"/></svg>`,
    br: `<svg width="32" height="32" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M30 16 L30 30 L16 30" stroke="${C}" stroke-width="1.2" fill="none" stroke-linecap="round"/><path d="M25 25 L21 25 L21 21" stroke="${C}" stroke-width="1" fill="none" stroke-linecap="round"/><circle cx="30" cy="30" r="1.8" fill="${C}"/></svg>`,
  };

  const railLeft = `<svg width="20" height="120" viewBox="0 0 20 120" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <g transform="translate(0,12)"><circle cx="10" cy="10" r="7" stroke="${C}" stroke-width="1" fill="none"/><rect x="6" y="6" width="8" height="8" stroke="${C}" stroke-width="0.9" fill="none"/></g>
    <line x1="10" y1="32" x2="10" y2="88" stroke="${C}" stroke-width="0.8" stroke-dasharray="2 3" opacity="0.45"/>
    <g transform="translate(0,90)"><path d="M3 6 L17 6 L10 18 Z" stroke="${C}" stroke-width="0.9" fill="none"/><line x1="6" y1="10" x2="14" y2="10" stroke="${C}" stroke-width="0.8"/></g>
  </svg>`;

  const railRight = `<svg width="20" height="120" viewBox="0 0 20 120" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <g transform="translate(0,12)"><path d="M10 2 L17 16 L3 16 Z" stroke="${C}" stroke-width="0.9" fill="none"/><circle cx="10" cy="10" r="1.5" fill="${C}"/></g>
    <line x1="10" y1="32" x2="10" y2="88" stroke="${C}" stroke-width="0.8" stroke-dasharray="2 3" opacity="0.45"/>
    <g transform="translate(0,90)"><path d="M3 4 Q10 1 17 4" stroke="${C}" stroke-width="0.9" fill="none"/><path d="M3 11 Q10 8 17 11" stroke="${C}" stroke-width="0.9" fill="none"/><path d="M3 18 Q10 15 17 18" stroke="${C}" stroke-width="0.9" fill="none"/></g>
  </svg>`;

  function decoratePanel(el) {
    if (el.dataset.acInit) return;
    el.dataset.acInit = '1';
    // 4 corner brackets
    ['tl','tr','bl','br'].forEach(pos => {
      const span = document.createElement('span');
      span.className = `ac-corner ac-${pos}`;
      span.innerHTML = cornerSVGs[pos];
      el.appendChild(span);
    });
    // Left rail (Earth ↔ Water) and Right rail (Fire ↔ Wind)
    const lRail = document.createElement('span');
    lRail.className = 'ac-rail ac-rail-l';
    lRail.innerHTML = railLeft;
    el.appendChild(lRail);

    const rRail = document.createElement('span');
    rRail.className = 'ac-rail ac-rail-r';
    rRail.innerHTML = railRight;
    el.appendChild(rRail);
  }

  function decorateAll(root) {
    (root || document).querySelectorAll('.pb-panel:not([data-ac-init])').forEach(decoratePanel);
  }

  // Initial pass after DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => decorateAll());
  } else {
    decorateAll();
  }

  // Watch for panels added dynamically (dashboard render, page switches, etc.)
  new MutationObserver(mutations => {
    mutations.forEach(m => {
      m.addedNodes.forEach(node => {
        if (node.nodeType !== 1) return;
        if (node.classList && node.classList.contains('pb-panel')) decoratePanel(node);
        node.querySelectorAll && node.querySelectorAll('.pb-panel:not([data-ac-init])').forEach(decoratePanel);
      });
    });
  }).observe(document.body, { childList: true, subtree: true });
})();
  


// ── Block 9 (avatar) — lazy-loaded ─────────────────────────────────
// The actual avatar engine (~1000 lines) lives in /pb-avatar.js and
// only loads when needed. Until it loads, window.AvatarCreator is a
// proxy that queues method calls; once the real engine takes over
// it replaces the proxy and replays any queued calls.
//
// Idle prefetch means the avatar usually loads within a few seconds
// of page interactive, so the PFP appears with only a brief lag.
(function() {
  var _avLoaded   = false;
  var _avPromise  = null;
  var _avQueue    = [];
  function _ensureAvatar() {
    if (_avLoaded) return Promise.resolve();
    if (_avPromise) return _avPromise;
    _avPromise = new Promise(function(resolve, reject) {
      var s = document.createElement('script');
      s.src = '/pb-avatar.js';
      s.onload  = function() {
        _avLoaded = true;
        // Replay any queued method calls against the now-real engine
        var ac = window.AvatarCreator;
        _avQueue.forEach(function(q) {
          try {
            if (ac && typeof ac[q.name] === 'function') ac[q.name].apply(ac, q.args);
          } catch (e) { console.warn('[avatar] replay ' + q.name + ' failed:', e && e.message); }
        });
        _avQueue = [];
        resolve();
      };
      s.onerror = function(e) { _avPromise = null; reject(e); };
      document.head.appendChild(s);
    });
    return _avPromise;
  }
  window._ensureAvatar = _ensureAvatar;

  // Proxy that queues calls until the real engine loads. Once loaded,
  // pb-avatar.js's `window.AvatarCreator = {...}` overwrites this proxy
  // with the real object.
  window.AvatarCreator = new Proxy({}, {
    get: function(target, prop) {
      // Return a function that queues the call AND triggers a load.
      // The trigger means even non-PFP code paths cause the engine to
      // load on first use (matching the scanner-stub semantics).
      return function() {
        var args = Array.prototype.slice.call(arguments);
        _avQueue.push({ name: prop, args: args });
        _ensureAvatar().catch(function(){});
        // Some callers await the return value (e.g. renderCommittedToPfp
        // returns a Promise). Return a thenable so `await` doesn't break.
        return Promise.resolve();
      };
    }
  });

  // Idle prefetch — PFP usually only takes a couple seconds to paint
  // after page load, which is acceptable for an avatar that wasn't
  // rendered before extraction either (the IIFE used to fire on
  // pb-app.js parse, which was already deferred).
  if (typeof requestIdleCallback === 'function') {
    requestIdleCallback(function() { _ensureAvatar().catch(function(){}); }, { timeout: 6000 });
  } else {
    setTimeout(function() { _ensureAvatar().catch(function(){}); }, 4000);
  }
})();

  
